-- ── public.admin_audit_log ──
CREATE TABLE public.admin_audit_log (
    id uuid NOT NULL DEFAULT gen_random_uuid(),
    admin_id uuid,
    action text NOT NULL,
    entity_type text NOT NULL,
    entity_id uuid,
    details jsonb,
    ip_address inet,
    created_at timestamptz DEFAULT now()
);

ALTER TABLE public.admin_audit_log ADD CONSTRAINT admin_audit_log_admin_id_fkey FOREIGN KEY (admin_id) REFERENCES admin_users(id);
ALTER TABLE public.admin_audit_log ADD CONSTRAINT admin_audit_log_pkey PRIMARY KEY (id);

-- ── public.admin_users ──
CREATE TABLE public.admin_users (
    id uuid NOT NULL DEFAULT gen_random_uuid(),
    user_id uuid,
    email text NOT NULL,
    full_name text NOT NULL,
    role text NOT NULL DEFAULT 'viewer'::text,
    avatar_url text,
    is_active bool DEFAULT true,
    last_login timestamptz,
    created_at timestamptz DEFAULT now(),
    updated_at timestamptz DEFAULT now()
);

ALTER TABLE public.admin_users ADD CONSTRAINT admin_users_email_key UNIQUE (email);
ALTER TABLE public.admin_users ADD CONSTRAINT admin_users_pkey PRIMARY KEY (id);
ALTER TABLE public.admin_users ADD CONSTRAINT admin_users_role_check CHECK ((role = ANY (ARRAY['super_admin'::text, 'admin'::text, 'support'::text, 'viewer'::text])));
ALTER TABLE public.admin_users ADD CONSTRAINT admin_users_user_id_fkey FOREIGN KEY (user_id) REFERENCES auth.users(id) ON DELETE CASCADE;

-- ── public.affordability_checks ──
CREATE TABLE public.affordability_checks (
    id uuid NOT NULL DEFAULT uuid_generate_v4(),
    user_id uuid NOT NULL,
    circle_id uuid,
    check_type varchar(50) DEFAULT 'circle_join'::character varying,
    monthly_income_used numeric NOT NULL,
    income_was_verified bool DEFAULT false,
    current_obligations numeric NOT NULL,
    proposed_obligation numeric NOT NULL,
    current_ratio numeric,
    proposed_ratio numeric,
    max_allowed_ratio numeric,
    result varchar(20) NOT NULL,
    score int4,
    risk_level varchar(20),
    reasons _text,
    warnings _text,
    recommendations _text,
    was_overridden bool DEFAULT false,
    override_by uuid,
    override_reason text,
    created_at timestamptz DEFAULT now()
);

ALTER TABLE public.affordability_checks ADD CONSTRAINT affordability_checks_check_type_check CHECK (((check_type)::text = ANY ((ARRAY['circle_join'::character varying, 'circle_increase'::character varying, 'manual_review'::character varying, 'periodic_review'::character varying])::text[])));
ALTER TABLE public.affordability_checks ADD CONSTRAINT affordability_checks_circle_id_fkey FOREIGN KEY (circle_id) REFERENCES circles(id) ON DELETE SET NULL;
ALTER TABLE public.affordability_checks ADD CONSTRAINT affordability_checks_override_by_fkey FOREIGN KEY (override_by) REFERENCES auth.users(id);
ALTER TABLE public.affordability_checks ADD CONSTRAINT affordability_checks_pkey PRIMARY KEY (id);
ALTER TABLE public.affordability_checks ADD CONSTRAINT affordability_checks_result_check CHECK (((result)::text = ANY ((ARRAY['approved'::character varying, 'denied'::character varying, 'warning'::character varying])::text[])));
ALTER TABLE public.affordability_checks ADD CONSTRAINT affordability_checks_risk_level_check CHECK (((risk_level)::text = ANY ((ARRAY['low'::character varying, 'medium'::character varying, 'high'::character varying, 'critical'::character varying])::text[])));
ALTER TABLE public.affordability_checks ADD CONSTRAINT affordability_checks_score_check CHECK (((score >= 0) AND (score <= 100)));
ALTER TABLE public.affordability_checks ADD CONSTRAINT affordability_checks_user_id_fkey FOREIGN KEY (user_id) REFERENCES auth.users(id) ON DELETE CASCADE;

-- ── public.ai_decisions ──
CREATE TABLE public.ai_decisions (
    id uuid NOT NULL DEFAULT gen_random_uuid(),
    member_id uuid NOT NULL,
    decision_type text NOT NULL,
    decision_value text,
    explanation_key text NOT NULL,
    explanation_data jsonb NOT NULL DEFAULT '{}'::jsonb,
    rendered_explanation text,
    language text NOT NULL DEFAULT 'en'::text,
    source_event_id text,
    source_event_type text,
    notification_sent bool NOT NULL DEFAULT false,
    created_at timestamptz NOT NULL DEFAULT now()
);

ALTER TABLE public.ai_decisions ADD CONSTRAINT ai_decisions_decision_type_check CHECK ((decision_type = ANY (ARRAY['xnscore_increase'::text, 'xnscore_decrease'::text, 'circle_join_rejection'::text, 'liquidity_denial'::text, 'tier_advancement'::text, 'tier_demotion'::text, 'payout_position'::text, 'intervention_message'::text])));
ALTER TABLE public.ai_decisions ADD CONSTRAINT ai_decisions_member_id_fkey FOREIGN KEY (member_id) REFERENCES profiles(id) ON DELETE CASCADE;
ALTER TABLE public.ai_decisions ADD CONSTRAINT ai_decisions_pkey PRIMARY KEY (id);

-- ── public.ai_recommendation_feedback ──
CREATE TABLE public.ai_recommendation_feedback (
    id uuid NOT NULL DEFAULT gen_random_uuid(),
    user_id uuid NOT NULL,
    recommendation_type text NOT NULL,
    recommendation_id uuid,
    recommendation_data jsonb NOT NULL DEFAULT '{}'::jsonb,
    model_version text NOT NULL DEFAULT 'rule-v1'::text,
    feedback text,
    feedback_text text,
    feedback_category text,
    outcome text,
    outcome_details jsonb DEFAULT '{}'::jsonb,
    shown_at timestamptz NOT NULL DEFAULT now(),
    feedback_given_at timestamptz,
    outcome_recorded_at timestamptz,
    prompt_dismissed_at timestamptz,
    prompt_expires_at timestamptz NOT NULL DEFAULT (now() + '48:00:00'::interval),
    feedback_prompted bool NOT NULL DEFAULT false,
    feedback_prompt_eligible bool NOT NULL DEFAULT true,
    human_review_requested bool NOT NULL DEFAULT false,
    human_review_resolved_at timestamptz,
    created_at timestamptz NOT NULL DEFAULT now(),
    updated_at timestamptz NOT NULL DEFAULT now()
