CREATE OR REPLACE FUNCTION public.activate_user(p_user_id uuid)
 RETURNS void
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
BEGIN
    UPDATE users
    SET is_suspended = false,
        updated_at = NOW()
    WHERE id = p_user_id;

    INSERT INTO admin_audit_log (admin_id, action, entity_type, entity_id, details)
    VALUES (auth.uid(), 'activate_user', 'user', p_user_id, '{}'::jsonb);
END;
$function$
;

CREATE OR REPLACE FUNCTION public.add_community_creator_as_owner()
 RETURNS trigger
 LANGUAGE plpgsql
AS $function$
BEGIN
    INSERT INTO public.community_memberships (
        user_id, community_id, role, status, joined_at
    )
    VALUES (NEW.created_by, NEW.id, 'owner', 'active', NOW());
    RETURN NEW;
END;
$function$
;

CREATE OR REPLACE FUNCTION public.admin_adjust_xnscore(p_user_id uuid, p_adjustment numeric, p_reason text)
 RETURNS void
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
    v_current_score DECIMAL;
    v_new_score DECIMAL;
BEGIN
    SELECT COALESCE(xn_score, 30) INTO v_current_score FROM users WHERE id = p_user_id;
    v_new_score := GREATEST(0, LEAST(100, v_current_score + p_adjustment));

    UPDATE users SET xn_score = v_new_score, updated_at = NOW() WHERE id = p_user_id;

    -- Log in xn_score_history
    INSERT INTO xn_score_history (user_id, previous_score, new_score, change_amount, event_type, reason)
    VALUES (p_user_id, v_current_score, v_new_score, p_adjustment, 'admin_adjustment', p_reason);

    INSERT INTO admin_audit_log (admin_id, action, entity_type, entity_id, details)
    VALUES (auth.uid(), 'adjust_xnscore', 'user', p_user_id,
            jsonb_build_object('previous', v_current_score, 'new', v_new_score, 'reason', p_reason));
END;
$function$
;

CREATE OR REPLACE FUNCTION public.admin_approve_loan(p_loan_id uuid, p_adjusted_amount numeric DEFAULT NULL::numeric, p_adjusted_rate numeric DEFAULT NULL::numeric, p_adjusted_term integer DEFAULT NULL::integer)
 RETURNS void
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
    v_loan loans%ROWTYPE;
BEGIN
    SELECT * INTO v_loan FROM loans WHERE id = p_loan_id;

    IF v_loan.status != 'pending' THEN
        RAISE EXCEPTION 'Loan is not in pending status';
    END IF;

    -- Update loan with adjustments if provided
    UPDATE loans SET
        status = 'approved',
        amount = COALESCE(p_adjusted_amount, amount),
        interest_rate = COALESCE(p_adjusted_rate, interest_rate),
        term_weeks = COALESCE(p_adjusted_term, term_weeks),
        approved_by = auth.uid(),
        updated_at = NOW()
    WHERE id = p_loan_id;

    INSERT INTO admin_audit_log (admin_id, action, entity_type, entity_id, details)
    VALUES (auth.uid(), 'approve_loan', 'loan', p_loan_id, jsonb_build_object(
        'original_amount', v_loan.amount,
        'adjusted_amount', p_adjusted_amount,
        'original_rate', v_loan.interest_rate,
        'adjusted_rate', p_adjusted_rate
    ));
END;
$function$
;

CREATE OR REPLACE FUNCTION public.admin_close_group(p_group_id uuid, p_reason text)
 RETURNS void
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
BEGIN
    UPDATE groups SET status = 'cancelled', updated_at = NOW() WHERE id = p_group_id;

    -- TODO: Handle refunds for pending contributions

    INSERT INTO admin_audit_log (admin_id, action, entity_type, entity_id, details)
    VALUES (auth.uid(), 'close_group', 'group', p_group_id, jsonb_build_object('reason', p_reason));
END;
$function$
;

CREATE OR REPLACE FUNCTION public.admin_reject_loan(p_loan_id uuid, p_reason text)
 RETURNS void
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
BEGIN
    UPDATE loans SET
        status = 'rejected',
        rejection_reason = p_reason,
        updated_at = NOW()
    WHERE id = p_loan_id AND status = 'pending';

    INSERT INTO admin_audit_log (admin_id, action, entity_type, entity_id, details)
    VALUES (auth.uid(), 'reject_loan', 'loan', p_loan_id, jsonb_build_object('reason', p_reason));
END;
$function$
;

CREATE OR REPLACE FUNCTION public.apply_for_loan(p_user_id uuid, p_group_id uuid, p_amount numeric, p_purpose text, p_term_months integer DEFAULT 6)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
    v_group RECORD;
    v_user RECORD;
    v_membership RECORD;
    v_xn_score DECIMAL(5,2);
    v_tier JSONB;
    v_loan_limit DECIMAL(10,2);
    v_interest_rate DECIMAL(5,2);
    v_monthly_payment DECIMAL(10,2);
    v_total_repayment DECIMAL(10,2);
    v_existing_loans INTEGER;
    v_loan_id UUID;
BEGIN
    -- Get user info
    SELECT * INTO v_user FROM users WHERE id = p_user_id;

    IF v_user IS NULL THEN
        RETURN jsonb_build_object('error', 'User not found', 'code', 'USER_NOT_FOUND');
    END IF;

    -- Get group info
    SELECT * INTO v_group FROM groups WHERE id = p_group_id;

    IF v_group IS NULL THEN
        RETURN jsonb_build_object('error', 'Circle not found', 'code', 'GROUP_NOT_FOUND');
    END IF;

    -- Check if loans are enabled for this group
    IF COALESCE(v_group.loans_enabled, FALSE) = FALSE THEN
        RETURN jsonb_build_object('error', 'Loans are not enabled for this circle', 'code', 'LOANS_DISABLED');
    END IF;

    -- Check membership
    SELECT * INTO v_membership
    FROM group_members
    WHERE group_id = p_group_id
    AND user_id = p_user_id
    AND status = 'active';

    IF v_membership IS NULL THEN
        RETURN jsonb_build_object('error', 'You must be an active member to apply for a loan', 'code', 'NOT_MEMBER');
    END IF;

    -- Check XnScore and loan eligibility
    v_xn_score := COALESCE(v_user.xn_score, 30);
    v_tier := get_xn_tier(v_xn_score);
    v_loan_limit := COALESCE((v_tier->>'benefits'->>'loan_limit')::DECIMAL, 0);

    IF v_loan_limit = 0 THEN
        RETURN jsonb_build_object(
            'error', 'Your XnScore tier does not qualify for loans',
            'code', 'NOT_ELIGIBLE',
            'xn_score', v_xn_score,
            'tier', v_tier->>'name',
            'action_required', 'Improve your XnScore to unlock loan access'
        );
    END IF;

    IF p_amount > v_loan_limit THEN
        RETURN jsonb_build_object(
            'error', 'Requested amount exceeds your loan limit',
            'code', 'EXCEEDS_LIMIT',
            'requested', p_amount,
            'max_allowed', v_loan_limit,
            'tier', v_tier->>'name'
        );
    END IF;

    -- Check for existing active loans
    SELECT COUNT(*) INTO v_existing_loans
    FROM loans
    WHERE borrower_id = p_user_id
    AND status IN ('active', 'pending', 'approved');

    IF v_existing_loans > 0 THEN
        RETURN jsonb_build_object(
            'error', 'You have an existing active loan',
            'code', 'EXISTING_LOAN',
            'action_required', 'Repay your current loan before applying for a new one'
        );
    END IF;

    -- Validate term
    IF p_term_months < 1 OR p_term_months > 12 THEN
        RETURN jsonb_build_object('error', 'Loan term must be between 1 and 12 months', 'code', 'INVALID_TERM');
    END IF;

    -- Calculate interest rate based on XnScore tier
    v_interest_rate := CASE
        WHEN v_xn_score >= 90 THEN 5.0   -- Elite: 5%
        WHEN v_xn_score >= 75 THEN 8.0   -- Excellent: 8%
        WHEN v_xn_score >= 60 THEN 12.0  -- Good: 12%
        WHEN v_xn_score >= 45 THEN 18.0  -- Fair: 18%
        ELSE 0 -- Not eligible
    END;

    -- Calculate repayment amounts
    v_total_repayment := p_amount * (1 + (v_interest_rate / 100) * (p_term_months / 12.0));
    v_monthly_payment := ROUND(v_total_repayment / p_term_months, 2);

    -- Create loan application
    INSERT INTO loans (
        borrower_id,
        group_id,
        amount,
        amount_due,
        interest_rate,
        term_months,
        monthly_payment,
        purpose,
        status,
        applied_at
    ) VALUES (
        p_user_id,
        p_group_id,
        p_amount,
        v_total_repayment,
        v_interest_rate,
        p_term_months,
        v_monthly_payment,
        p_purpose,
        'pending',
        NOW()
    )
    RETURNING id INTO v_loan_id;

    -- Notify user
    PERFORM create_notification(
        p_user_id,
        'loan',
        'loan',
        'Loan Application Submitted',
        'Your loan application for $' || p_amount || ' has been submitted and is pending review.',
        jsonb_build_object(
            'loan_id', v_loan_id,
            'amount', p_amount,
            'interest_rate', v_interest_rate,
            'term_months', p_term_months,
            'monthly_payment', v_monthly_payment
        ),
        'normal',
        NULL,
        'loan',
        v_loan_id::TEXT,
        '/loans/' || v_loan_id
    );

    -- Notify group admin
    PERFORM create_notification(
        v_group.admin_id,
        'loan',
        'loan',
        'New Loan Application',
        v_user.full_name || ' has applied for a $' || p_amount || ' loan from ' || v_group.name || '.',
        jsonb_build_object(
            'loan_id', v_loan_id,
            'user_id', p_user_id,
            'user_name', v_user.full_name,
            'amount', p_amount,
            'xn_score', v_xn_score
        ),
        'high',
        NULL,
        'loan',
        v_loan_id::TEXT,
        '/loans/' || v_loan_id || '/review'
    );

    RETURN jsonb_build_object(
        'success', true,
        'loan_id', v_loan_id,
        'amount', p_amount,
        'interest_rate', v_interest_rate,
        'term_months', p_term_months,
        'monthly_payment', v_monthly_payment,
        'total_repayment', v_total_repayment,
        'status', 'pending',
        'message', 'Loan application submitted successfully. Waiting for approval.'
    );
END;
$function$
;

CREATE OR REPLACE FUNCTION public.apply_inactivity_decay(p_user_id uuid)
 RETURNS TABLE(success boolean, decay_applied numeric, previous_score numeric, new_score numeric, inactive_days integer, decay_reason text)
 LANGUAGE plpgsql
AS $function$
DECLARE
    v_score RECORD;
    v_last_activity TIMESTAMPTZ;
    v_days_inactive INTEGER;
    v_decay_amount DECIMAL;
    v_new_score DECIMAL;
    v_score_floor DECIMAL := 15.00; -- Minimum score floor
    v_threshold_crossed TEXT;
    v_previous_threshold INTEGER;
BEGIN
    -- Get current score
    SELECT * INTO v_score FROM xn_scores WHERE xn_scores.user_id = p_user_id;

    IF NOT FOUND THEN
        RETURN QUERY SELECT FALSE, 0::DECIMAL, 0::DECIMAL, 0::DECIMAL, 0, 'User not found'::TEXT;
        RETURN;
    END IF;

    -- Skip if score is frozen
    IF v_score.score_frozen THEN
        RETURN QUERY SELECT FALSE, 0::DECIMAL, v_score.total_score, v_score.total_score, 0, 'Score frozen'::TEXT;
        RETURN;
    END IF;

    -- Skip if in recovery period (no decay during recovery)
    IF v_score.in_recovery_period AND v_score.recovery_ends_at > now() THEN
        RETURN QUERY SELECT FALSE, 0::DECIMAL, v_score.total_score, v_score.total_score, 0, 'In recovery period'::TEXT;
        RETURN;
    END IF;

    -- Get last financial activity
    v_last_activity := COALESCE(
        v_score.last_financial_activity_at,
        get_last_financial_activity(p_user_id)
    );

    -- If no activity ever, use account creation date
    IF v_last_activity IS NULL THEN
        SELECT created_at INTO v_last_activity FROM profiles WHERE id = p_user_id;
    END IF;

    -- Calculate days inactive
    v_days_inactive := EXTRACT(DAY FROM (now() - v_last_activity))::INTEGER;

    -- Get the previous threshold that was already applied
    v_previous_threshold := CASE
        WHEN v_score.financial_inactive_days >= 365 THEN 365
        WHEN v_score.financial_inactive_days >= 240 THEN 240
        WHEN v_score.financial_inactive_days >= 180 THEN 180
        WHEN v_score.financial_inactive_days >= 120 THEN 120
        WHEN v_score.financial_inactive_days >= 90 THEN 90
        WHEN v_score.financial_inactive_days >= 60 THEN 60
        WHEN v_score.financial_inactive_days >= 30 THEN 30
        ELSE 0
    END;

    -- Determine if we've crossed a NEW threshold
    v_threshold_crossed := CASE
        WHEN v_days_inactive >= 365 AND v_previous_threshold < 365 THEN 'inactivity_365d'
        WHEN v_days_inactive >= 240 AND v_previous_threshold < 240 THEN 'inactivity_240d'
        WHEN v_days_inactive >= 180 AND v_previous_threshold < 180 THEN 'inactivity_180d'
        WHEN v_days_inactive >= 120 AND v_previous_threshold < 120 THEN 'inactivity_120d'
        WHEN v_days_inactive >= 90 AND v_previous_threshold < 90 THEN 'inactivity_90d'
        WHEN v_days_inactive >= 60 AND v_previous_threshold < 60 THEN 'inactivity_60d'
        WHEN v_days_inactive >= 30 AND v_previous_threshold < 30 THEN 'inactivity_30d'
        ELSE NULL
    END;

    -- If no new threshold crossed, no decay needed
    IF v_threshold_crossed IS NULL THEN
        -- Just update the inactive days counter
        UPDATE xn_scores SET
            financial_inactive_days = v_days_inactive,
            last_financial_activity_at = v_last_activity,
            updated_at = now()
        WHERE xn_scores.user_id = p_user_id;

        RETURN QUERY SELECT TRUE, 0::DECIMAL, v_score.total_score, v_score.total_score, v_days_inactive, 'No new threshold'::TEXT;
        RETURN;
    END IF;

    -- Get decay amount for this threshold
    v_decay_amount := CASE v_threshold_crossed
        WHEN 'inactivity_30d' THEN -3.00
        WHEN 'inactivity_60d' THEN -6.00
        WHEN 'inactivity_90d' THEN -10.00
        WHEN 'inactivity_120d' THEN -15.00
        WHEN 'inactivity_180d' THEN -20.00
        WHEN 'inactivity_240d' THEN -25.00
        WHEN 'inactivity_365d' THEN -30.00
        ELSE 0.00
    END;

    -- Calculate new score (with floor protection)
    v_new_score := GREATEST(v_score_floor, v_score.total_score + v_decay_amount);

    -- Record decay event
    PERFORM record_decay_event(
        p_user_id,
        v_decay_amount,
        v_threshold_crossed,
        jsonb_build_object(
            'days_inactive', v_days_inactive,
            'previous_threshold', v_previous_threshold,
            'last_activity', v_last_activity
        )
    );

    -- Apply the decay using existing adjustment function
    PERFORM apply_xnscore_adjustment(
        p_user_id,
        v_decay_amount,
        v_threshold_crossed,
        NULL
    );

    -- Update tracking fields
    UPDATE xn_scores SET
        financial_inactive_days = v_days_inactive,
        last_financial_activity_at = v_last_activity,
        total_inactivity_penalty = COALESCE(total_inactivity_penalty, 0) + ABS(v_decay_amount),
        decay_floor_reached = (v_new_score <= v_score_floor),
        updated_at = now()
    WHERE xn_scores.user_id = p_user_id;

    RETURN QUERY SELECT TRUE, ABS(v_decay_amount), v_score.total_score, v_new_score, v_days_inactive, v_threshold_crossed;
END;
$function$
;

CREATE OR REPLACE FUNCTION public.apply_late_fee_to_loan(p_loan_id uuid, p_scheduled_payment_id uuid, p_days_past_due integer)
 RETURNS TABLE(applied boolean, fee_id uuid, fee_cents integer, reason text)
 LANGUAGE plpgsql
 SECURITY DEFINER
AS $function$
DECLARE
    v_schedule RECORD;
    v_loan RECORD;
    v_existing_fee RECORD;
    v_fee_result RECORD;
    v_fee_id UUID;
BEGIN
    SELECT * INTO v_schedule FROM loan_payment_schedule WHERE id = p_scheduled_payment_id;
    IF NOT FOUND THEN
        RETURN QUERY SELECT FALSE, NULL::UUID, 0, 'Scheduled payment not found';
        RETURN;
    END IF;

    SELECT * INTO v_loan FROM loans WHERE id = p_loan_id;

    SELECT * INTO v_existing_fee FROM loan_late_fees
    WHERE scheduled_payment_id = p_scheduled_payment_id;

    IF FOUND THEN
        RETURN QUERY SELECT FALSE, v_existing_fee.id, v_existing_fee.calculated_fee_cents, 'Fee already applied';
        RETURN;
    END IF;

    SELECT * INTO v_fee_result
    FROM calculate_loan_late_fee(v_schedule.total_due_cents, p_days_past_due, v_loan.loan_product_id);

    IF v_fee_result.within_grace_period THEN
        RETURN QUERY SELECT FALSE, NULL::UUID, 0, 'Within grace period';
        RETURN;
    END IF;

    INSERT INTO loan_late_fees (
        loan_id, scheduled_payment_id, fee_type, flat_fee_cents, percentage,
        calculated_fee_cents, payment_due_date, grace_period_days, days_past_due, fee_applied_date
    ) VALUES (
        p_loan_id, p_scheduled_payment_id, v_fee_result.fee_type, v_fee_result.flat_fee_cents,
        5.0, v_fee_result.fee_cents, v_schedule.due_date, v_fee_result.grace_period_days,
        p_days_past_due, CURRENT_DATE
    ) RETURNING id INTO v_fee_id;

    UPDATE loans SET
        outstanding_fees_cents = COALESCE(outstanding_fees_cents, 0) + v_fee_result.fee_cents,
        total_outstanding_cents = total_outstanding_cents + v_fee_result.fee_cents,
        updated_at = now()
    WHERE id = p_loan_id;

    RETURN QUERY SELECT TRUE, v_fee_id, v_fee_result.fee_cents, 'Late fee applied';
END;
$function$
;

CREATE OR REPLACE FUNCTION public.apply_payment_to_loan(p_loan_id uuid, p_payment_amount_cents integer, p_payment_method text, p_payment_source_id text DEFAULT NULL::text, p_wallet_transaction_id uuid DEFAULT NULL::uuid)
 RETURNS TABLE(payment_id uuid, total_paid_cents integer, fees_paid_cents integer, interest_paid_cents integer, principal_paid_cents integer, remaining_principal_cents integer, remaining_interest_cents integer, remaining_fees_cents integer, total_remaining_cents integer, loan_status loan_status, is_paid_off boolean, overpayment_cents integer)
 LANGUAGE plpgsql
 SECURITY DEFINER
AS $function$
DECLARE
    v_loan RECORD;
    v_interest RECORD;
    v_schedule RECORD;
    v_payment_id UUID;
    v_remaining INTEGER;
    v_fees_paid INTEGER := 0;
    v_interest_paid INTEGER := 0;
    v_principal_paid INTEGER := 0;
    v_total_accrued_interest INTEGER;
    v_pending_fees INTEGER;
    v_new_status loan_status;
    v_is_on_time BOOLEAN;
    v_days_late INTEGER := 0;
    v_new_principal INTEGER;
    v_new_accrued_interest INTEGER;
    v_new_fees INTEGER;
    v_new_total INTEGER;
BEGIN
    SELECT * INTO v_loan FROM loans WHERE id = p_loan_id;
    IF NOT FOUND THEN RAISE EXCEPTION 'Loan % not found', p_loan_id; END IF;
    IF v_loan.status != 'active' THEN RAISE EXCEPTION 'Cannot apply payment to % loan', v_loan.status; END IF;

    SELECT * INTO v_interest FROM calculate_accrued_interest(p_loan_id);
    v_total_accrued_interest := v_interest.accrued_interest_cents + COALESCE(v_loan.accrued_interest_cents, 0);

    SELECT COALESCE(SUM(calculated_fee_cents - COALESCE(paid_amount_cents, 0)), 0)
    INTO v_pending_fees FROM loan_late_fees WHERE loan_late_fees.loan_id = p_loan_id AND status = 'pending';

    SELECT * INTO v_schedule FROM loan_payment_schedule
    WHERE loan_payment_schedule.loan_id = p_loan_id AND status IN ('scheduled', 'partial', 'late')
    ORDER BY payment_number ASC LIMIT 1;

    IF v_schedule IS NOT NULL THEN
        v_is_on_time := CURRENT_DATE <= v_schedule.due_date + 5;
        v_days_late := GREATEST(0, CURRENT_DATE - v_schedule.due_date - 5);
    ELSE
        v_is_on_time := TRUE;
    END IF;

    v_remaining := p_payment_amount_cents;

    -- Pay fees first
    IF v_remaining > 0 AND v_pending_fees > 0 THEN
        v_fees_paid := LEAST(v_remaining, v_pending_fees);
        v_remaining := v_remaining - v_fees_paid;
        PERFORM mark_late_fees_paid(p_loan_id, v_fees_paid);
    END IF;

    -- Pay interest
    IF v_remaining > 0 AND v_total_accrued_interest > 0 THEN
        v_interest_paid := LEAST(v_remaining, v_total_accrued_interest);
        v_remaining := v_remaining - v_interest_paid;
    END IF;

    -- Pay principal
    IF v_remaining > 0 AND v_loan.outstanding_principal_cents > 0 THEN
        v_principal_paid := LEAST(v_remaining, v_loan.outstanding_principal_cents);
        v_remaining := v_remaining - v_principal_paid;
    END IF;

    v_new_principal := v_loan.outstanding_principal_cents - v_principal_paid;
    v_new_accrued_interest := v_total_accrued_interest - v_interest_paid;
    v_new_fees := v_pending_fees - v_fees_paid;
    v_new_total := v_new_principal + v_new_accrued_interest + v_new_fees;

    IF v_new_principal <= 0 AND v_new_accrued_interest <= 0 AND v_new_fees <= 0 THEN
        v_new_status := 'paid_off';
    ELSE
        v_new_status := 'active';
    END IF;

    -- Record interest accrual
    INSERT INTO loan_interest_accruals (
        loan_id, accrual_date, period_start_date, period_end_date, days_in_period,
        principal_balance_cents, previous_accrued_interest_cents,
        rate_type, annual_rate, daily_rate,
        interest_accrued_cents, cumulative_interest_cents, triggered_by
    ) VALUES (
        p_loan_id, CURRENT_DATE, v_interest.period_start_date, v_interest.period_end_date,
        v_interest.days_in_period, v_loan.outstanding_principal_cents,
        COALESCE(v_loan.accrued_interest_cents, 0), v_interest.rate_type,
        v_interest.effective_rate, v_interest.effective_rate / 365,
        v_interest.accrued_interest_cents,
        COALESCE(v_loan.total_interest_accrued_cents, 0) + v_interest.accrued_interest_cents,
        'payment'::accrual_trigger
    );

    -- Update loan
    UPDATE loans SET
        outstanding_principal_cents = v_new_principal,
        outstanding_interest_cents = v_new_accrued_interest,
        outstanding_fees_cents = v_new_fees,
        total_outstanding_cents = v_new_total,
        accrued_interest_cents = v_new_accrued_interest,
        last_interest_accrual_date = now(),
        total_interest_paid_cents = COALESCE(total_interest_paid_cents, 0) + v_interest_paid,
        total_interest_accrued_cents = COALESCE(total_interest_accrued_cents, 0) + v_interest.accrued_interest_cents,
        total_fees_paid_cents = COALESCE(total_fees_paid_cents, 0) + v_fees_paid,
        payments_made = payments_made + 1,
        last_payment_date = CURRENT_DATE,
        last_payment_amount_cents = p_payment_amount_cents,
        days_past_due = CASE WHEN v_is_on_time THEN 0 ELSE v_days_late END,
        is_delinquent = NOT v_is_on_time,
        status = v_new_status,
        closed_at = CASE WHEN v_new_status = 'paid_off' THEN now() ELSE NULL END,
        closed_reason = CASE WHEN v_new_status = 'paid_off' THEN 'fully_repaid' ELSE NULL END,
        updated_at = now()
    WHERE id = p_loan_id;

    -- Create payment record
    INSERT INTO loan_payments (
        loan_id, user_id, schedule_id, amount_cents, principal_cents, interest_cents, fees_cents,
        payment_method, payment_source_id, wallet_transaction_id,
        was_on_time, days_late, status, processed_at
    ) VALUES (
        p_loan_id, v_loan.user_id, v_schedule.id, p_payment_amount_cents,
        v_principal_paid, v_interest_paid, v_fees_paid,
        p_payment_method, p_payment_source_id, p_wallet_transaction_id,
        v_is_on_time, v_days_late, 'completed'::loan_payment_status, now()
    ) RETURNING id INTO v_payment_id;

    -- Update schedule if applicable
    IF v_schedule IS NOT NULL THEN
        UPDATE loan_payment_schedule SET
            principal_paid_cents = principal_paid_cents + v_principal_paid,
            interest_paid_cents = interest_paid_cents + v_interest_paid,
            fees_paid_cents = fees_paid_cents + v_fees_paid,
            total_paid_cents = total_paid_cents + p_payment_amount_cents,
            status = CASE
                WHEN principal_paid_cents + v_principal_paid >= principal_due_cents
                     AND interest_paid_cents + v_interest_paid >= interest_due_cents
                THEN 'paid'::payment_schedule_status
                ELSE 'partial'::payment_schedule_status
            END,
            updated_at = now()
        WHERE id = v_schedule.id;
    END IF;

    -- Release guarantees if paid off
    IF v_new_status = 'paid_off' THEN
        UPDATE loan_guarantees SET status = 'released', released_at = now(),
            release_reason = 'loan_paid_off', updated_at = now()
        WHERE loan_guarantees.loan_id = p_loan_id AND status = 'active';

        UPDATE loan_co_signers SET status = 'released', released_at = now(),
            release_reason = 'loan_paid_off', updated_at = now()
        WHERE loan_co_signers.loan_id = p_loan_id AND status = 'active';
    END IF;

    RETURN QUERY SELECT v_payment_id, p_payment_amount_cents,
        v_fees_paid, v_interest_paid, v_principal_paid,
        v_new_principal, v_new_accrued_interest, v_new_fees, v_new_total,
        v_new_status, v_new_status = 'paid_off', v_remaining;
END;
$function$
;

CREATE OR REPLACE FUNCTION public.apply_tenure_bonus(p_user_id uuid)
 RETURNS TABLE(success boolean, bonus_applied numeric, previous_score numeric, new_score numeric, tenure_month integer, reason text)
 LANGUAGE plpgsql
AS $function$
DECLARE
    v_score RECORD;
    v_profile RECORD;
    v_months_since_creation INTEGER;
    v_eligible_month INTEGER;
    v_bonus_amount DECIMAL := 1.00; -- +1 per month
    v_max_tenure_bonus DECIMAL := 25.00; -- Cap at +25
    v_already_earned INTEGER;
    v_new_score DECIMAL;
BEGIN
    -- Get current score
    SELECT * INTO v_score FROM xn_scores WHERE xn_scores.user_id = p_user_id;

    IF NOT FOUND THEN
        RETURN QUERY SELECT FALSE, 0::DECIMAL, 0::DECIMAL, 0::DECIMAL, 0, 'User not found'::TEXT;
        RETURN;
    END IF;

    -- Get profile for account age
    SELECT * INTO v_profile FROM profiles WHERE id = p_user_id;

    -- Calculate months since account creation
    v_months_since_creation := EXTRACT(MONTH FROM age(now(), v_profile.created_at))::INTEGER +
                               (EXTRACT(YEAR FROM age(now(), v_profile.created_at))::INTEGER * 12);

    -- Check if already maxed out
    IF COALESCE(v_score.tenure_bonus, 0) >= v_max_tenure_bonus THEN
        RETURN QUERY SELECT FALSE, 0::DECIMAL, v_score.total_score, v_score.total_score,
            v_score.tenure_months_earned, 'Max tenure bonus reached'::TEXT;
        RETURN;
    END IF;

    -- Check if active this month (must have made at least 1 contribution)
    IF NOT is_user_financially_active(p_user_id, 30) THEN
        RETURN QUERY SELECT FALSE, 0::DECIMAL, v_score.total_score, v_score.total_score,
            v_score.tenure_months_earned, 'Not active this month'::TEXT;
        RETURN;
    END IF;

    -- Calculate which month they're eligible for
    v_already_earned := COALESCE(v_score.tenure_months_earned, 0);
    v_eligible_month := v_already_earned + 1;

    -- Check if enough time has passed
    IF v_months_since_creation < v_eligible_month THEN
        RETURN QUERY SELECT FALSE, 0::DECIMAL, v_score.total_score, v_score.total_score,
            v_already_earned, 'Not enough tenure yet'::TEXT;
        RETURN;
    END IF;

    -- Check if this month already granted
    IF EXISTS (
        SELECT 1 FROM xnscore_tenure_history
        WHERE user_id = p_user_id AND tenure_month = v_eligible_month
    ) THEN
        RETURN QUERY SELECT FALSE, 0::DECIMAL, v_score.total_score, v_score.total_score,
            v_eligible_month, 'Already earned this month'::TEXT;
        RETURN;
    END IF;

    -- Apply recovery multiplier if active
    IF v_score.in_recovery_period AND v_score.recovery_ends_at > now() THEN
        v_bonus_amount := v_bonus_amount * COALESCE(v_score.recovery_multiplier, 1.5);
    END IF;

    -- Cap the bonus if it would exceed max
    IF (COALESCE(v_score.tenure_bonus, 0) + v_bonus_amount) > v_max_tenure_bonus THEN
        v_bonus_amount := v_max_tenure_bonus - COALESCE(v_score.tenure_bonus, 0);
    END IF;

    -- Record tenure event
    PERFORM record_tenure_event(p_user_id, v_bonus_amount, v_eligible_month);

    -- Apply the bonus using existing adjustment function
    PERFORM apply_xnscore_adjustment(
        p_user_id,
        v_bonus_amount,
        format('tenure_bonus_month_%s', v_eligible_month),
        NULL
    );

    -- Update tracking fields
    UPDATE xn_scores SET
        tenure_bonus = COALESCE(tenure_bonus, 0) + v_bonus_amount,
        tenure_months_earned = v_eligible_month,
        next_tenure_check_date = (now() + INTERVAL '1 month')::DATE,
        updated_at = now()
    WHERE xn_scores.user_id = p_user_id;

    v_new_score := v_score.total_score + v_bonus_amount;

    RETURN QUERY SELECT TRUE, v_bonus_amount, v_score.total_score, v_new_score,
        v_eligible_month, 'Tenure bonus applied'::TEXT;
END;
$function$
;

CREATE OR REPLACE FUNCTION public.apply_xnscore_adjustment(p_user_id uuid, p_adjustment numeric, p_trigger_event text, p_trigger_id uuid DEFAULT NULL::uuid)
 RETURNS TABLE(success boolean, previous_score numeric, new_score numeric, actual_adjustment numeric, velocity_capped boolean, queued_amount numeric)
 LANGUAGE plpgsql
 SECURITY DEFINER
AS $function$
DECLARE
    v_score RECORD;
    v_profile RECORD;
    v_account_age_days INTEGER;
    v_age_cap INTEGER;
    v_velocity_check RECORD;
    v_actual_adjustment DECIMAL;
    v_new_raw DECIMAL;
    v_new_capped DECIMAL;
    v_queued DECIMAL := 0;
BEGIN
    -- Get current score
    SELECT * INTO v_score FROM xn_scores WHERE xn_scores.user_id = p_user_id;

    IF NOT FOUND THEN
        -- Calculate initial score first
        PERFORM calculate_initial_xnscore(p_user_id);
        SELECT * INTO v_score FROM xn_scores WHERE xn_scores.user_id = p_user_id;
    END IF;

    -- Check if score is frozen
    IF v_score.score_frozen THEN
        RETURN QUERY SELECT FALSE, v_score.total_score, v_score.total_score, 0::DECIMAL, FALSE, 0::DECIMAL;
        RETURN;
    END IF;

    -- Get age cap
    SELECT * INTO v_profile FROM profiles WHERE id = p_user_id;
    v_account_age_days := EXTRACT(DAY FROM (now() - v_profile.created_at))::INTEGER;
    v_age_cap := get_xnscore_age_cap(v_account_age_days);

    -- For positive adjustments, check velocity cap
    IF p_adjustment > 0 THEN
        SELECT * INTO v_velocity_check FROM check_velocity_cap(p_user_id, p_adjustment);

        IF NOT v_velocity_check.allowed THEN
            v_actual_adjustment := v_velocity_check.allowed_increase;
            v_queued := p_adjustment - v_actual_adjustment;

            -- Queue the overflow
            IF v_queued > 0 THEN
                INSERT INTO xnscore_queued_increases (
                    user_id, amount, reason, source_event, source_id, process_after
                ) VALUES (
                    p_user_id, v_queued, 'velocity_cap_overflow', p_trigger_event, p_trigger_id,
                    date_trunc('week', now() + INTERVAL '1 week')::DATE
                );
            END IF;
        ELSE
            v_actual_adjustment := p_adjustment;
        END IF;
    ELSE
        -- Negative adjustments bypass velocity (immediate)
        v_actual_adjustment := p_adjustment;
    END IF;

    -- Calculate new scores
    v_new_raw := v_score.raw_score + v_actual_adjustment;
    v_new_capped := LEAST(GREATEST(0, v_new_raw), v_age_cap);

    -- Update score
    UPDATE xn_scores SET
        previous_score = total_score,
        total_score = v_new_capped,
        raw_score = v_new_raw,
        score_tier = get_xnscore_tier(v_new_capped),
        age_cap_applied = v_new_capped < v_new_raw,
        max_allowed_score = v_age_cap,
        account_age_days = v_account_age_days,
        points_gained_this_week = CASE
            WHEN v_actual_adjustment > 0 THEN points_gained_this_week + v_actual_adjustment
            ELSE points_gained_this_week
        END,
        last_calculated_at = now(),
        calculation_trigger = p_trigger_event,
        updated_at = now()
    WHERE xn_scores.user_id = p_user_id;

    -- Log to history
    INSERT INTO xnscore_history (
        user_id, score, previous_score, score_change,
        trigger_event, trigger_id,
        raw_score_before_cap, age_cap_applied, age_cap_value,
        weekly_points_before, weekly_points_after,
        velocity_capped
    ) VALUES (
        p_user_id, v_new_capped, v_score.total_score, v_new_capped - v_score.total_score,
        p_trigger_event, p_trigger_id,
        v_new_raw, v_new_capped < v_new_raw, v_age_cap,
        v_score.points_gained_this_week,
        CASE WHEN v_actual_adjustment > 0 THEN v_score.points_gained_this_week + v_actual_adjustment ELSE v_score.points_gained_this_week END,
        v_queued > 0
    );

    RETURN QUERY SELECT
        TRUE,
        v_score.total_score,
        v_new_capped,
        v_actual_adjustment,
        v_queued > 0,
        v_queued;
END;
$function$
;

CREATE OR REPLACE FUNCTION public.approve_kyc(p_user_id uuid)
 RETURNS void
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
BEGIN
    UPDATE users SET kyc_status = 'verified', updated_at = NOW() WHERE id = p_user_id;

    INSERT INTO admin_audit_log (admin_id, action, entity_type, entity_id, details)
    VALUES (auth.uid(), 'approve_kyc', 'user', p_user_id, '{}'::jsonb);
END;
$function$
;

CREATE OR REPLACE FUNCTION public.archive_completed_group(p_group_id uuid)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
    v_group RECORD;
    v_archived_id UUID;
    v_total_circulated DECIMAL(12,2);
    v_member_count INTEGER;
BEGIN
    -- Get group details
    SELECT * INTO v_group FROM groups WHERE id = p_group_id;

    IF v_group IS NULL THEN
        RETURN jsonb_build_object('error', 'Group not found');
    END IF;

    IF v_group.status NOT IN ('completed', 'cancelled') THEN
        RETURN jsonb_build_object('error', 'Group must be completed or cancelled to archive');
    END IF;

    -- Calculate total amount circulated
    SELECT COALESCE(SUM(amount), 0) INTO v_total_circulated
    FROM contributions
    WHERE group_id = p_group_id AND status = 'completed';

    -- Generate archive ID
    v_archived_id := gen_random_uuid();

    -- Insert into archived_groups
    INSERT INTO archived_groups (
        id,
        original_id,
        name,
        description,
        admin_id,
        contribution_amount,
        contribution_frequency,
        max_members,
        total_cycles_completed,
        total_amount_circulated,
        status,
        started_at,
        completed_at,
        archive_reason,
        metadata,
        created_at,
        updated_at
    ) VALUES (
        v_archived_id,
        v_group.id,
        v_group.name,
        v_group.description,
        v_group.admin_id,
        v_group.contribution_amount,
        v_group.contribution_frequency,
        v_group.max_members,
        v_group.current_cycle,
        v_total_circulated,
        v_group.status,
        v_group.created_at,
        NOW(),
        CASE WHEN v_group.status = 'completed' THEN 'completed' ELSE 'cancelled' END,
        jsonb_build_object(
            'late_fee_percentage', v_group.late_fee_percentage,
            'total_contributions', (SELECT COUNT(*) FROM contributions WHERE group_id = p_group_id),
            'total_payouts', (SELECT COUNT(*) FROM payouts WHERE group_id = p_group_id)
        ),
        v_group.created_at,
        v_group.updated_at
    );

    -- Archive member data
    INSERT INTO archived_group_members (
        archived_group_id,
        user_id,
        user_name,
        payout_position,
        total_contributed,
        total_received,
        on_time_payments,
        late_payments,
        joined_at,
        left_at,
        final_status
    )
    SELECT
        v_archived_id,
        gm.user_id,
        u.full_name,
        gm.payout_position,
        COALESCE((SELECT SUM(c.amount) FROM contributions c WHERE c.group_id = p_group_id AND c.user_id = gm.user_id AND c.status = 'completed'), 0),
        COALESCE((SELECT SUM(p.amount) FROM payouts p WHERE p.group_id = p_group_id AND p.user_id = gm.user_id AND p.status = 'completed'), 0),
        (SELECT COUNT(*) FROM contributions c WHERE c.group_id = p_group_id AND c.user_id = gm.user_id AND c.status = 'completed' AND (c.late_fee IS NULL OR c.late_fee = 0)),
        (SELECT COUNT(*) FROM contributions c WHERE c.group_id = p_group_id AND c.user_id = gm.user_id AND c.late_fee > 0),
        gm.joined_at,
        CASE WHEN gm.status = 'left' THEN gm.updated_at ELSE NULL END,
        gm.status
    FROM group_members gm
    LEFT JOIN users u ON u.id = gm.user_id
    WHERE gm.group_id = p_group_id;

    GET DIAGNOSTICS v_member_count = ROW_COUNT;

    -- Update group status to archived
    UPDATE groups
    SET status = 'archived', updated_at = NOW()
    WHERE id = p_group_id;

    -- Delete detail records (keep contributions/payouts for audit but could be cleaned later)
    -- For now, we'll keep the original data and just mark as archived

    RETURN jsonb_build_object(
        'success', true,
        'archived_id', v_archived_id,
        'group_name', v_group.name,
        'members_archived', v_member_count,
        'total_circulated', v_total_circulated,
        'archived_at', NOW()
    );
END;
$function$
;

CREATE OR REPLACE FUNCTION public.assess_creditworthiness(p_user_id uuid, p_requested_amount_cents integer, p_requested_term_months integer, p_loan_purpose loan_product_purpose, p_loan_product_code text DEFAULT NULL::text, p_elder_guarantee_user_id uuid DEFAULT NULL::uuid, p_cosigner_user_id uuid DEFAULT NULL::uuid)
 RETURNS uuid
 LANGUAGE plpgsql
 SECURITY DEFINER
AS $function$
DECLARE
    v_product RECORD;
    v_xnscore RECORD;

    -- Pillar 1
    v_xnscore_value DECIMAL;
    v_base_credit_score INTEGER;

    -- Pillar 2
    v_circle_health RECORD;

    -- Pillar 3
    v_loan_history RECORD;

    -- Final score
    v_raw_credit_score INTEGER;
    v_final_credit_score INTEGER;
    v_risk_grade risk_grade;

    -- Pillar 4
    v_capacity RECORD;
    v_score_based_limit INTEGER;
    v_product_limit INTEGER;
    v_final_max_amount INTEGER;
    v_approved_amount INTEGER;

    -- Pillar 5
    v_community RECORD;

    -- APR
    v_base_apr DECIMAL;
    v_final_apr DECIMAL;
    v_apr_floor DECIMAL := 5.0;

    -- Repayment
    v_repayment RECORD;

    -- Decision
    v_is_eligible BOOLEAN;
    v_rejection_reasons TEXT[];
    v_recommendation credit_recommendation;
    v_conditions TEXT[] := '{}';

    -- Preflight
    v_preflight RECORD;

    -- Result
    v_assessment_id UUID;
BEGIN
    -- Get loan product
    IF p_loan_product_code IS NOT NULL THEN
        SELECT * INTO v_product FROM loan_products WHERE code = p_loan_product_code AND is_active = TRUE;
    END IF;

    -- Get XnScore
    SELECT * INTO v_xnscore FROM xn_scores WHERE user_id = p_user_id;

    IF v_xnscore IS NULL THEN
        -- Cannot assess without XnScore
        INSERT INTO creditworthiness_assessments (
            user_id, loan_product_id, requested_amount_cents, requested_term_months, loan_purpose,
            xnscore_at_assessment, xnscore_base_credit_score,
            raw_credit_score, final_credit_score, risk_grade,
            score_based_limit_cents, final_max_amount_cents,
            base_apr, final_apr,
            is_eligible, rejection_reasons, system_recommendation,
            expires_at, factor_breakdown
        ) VALUES (
            p_user_id, v_product.id, p_requested_amount_cents, p_requested_term_months, p_loan_purpose,
            0, 300,
            300, 300, 'E'::risk_grade,
            0, 0,
            0, 0,
            FALSE, ARRAY['No XnScore calculated'], 'reject'::credit_recommendation,
            now() + INTERVAL '48 hours', '{}'::JSONB
        )
        RETURNING id INTO v_assessment_id;

        RETURN v_assessment_id;
    END IF;

    -- ═══════════════════════════════════════════════════════════════════
    -- PREFLIGHT CHECKS
    -- ═══════════════════════════════════════════════════════════════════

    SELECT * INTO v_preflight FROM check_preflight_eligibility(
        p_user_id, v_product.id, p_requested_amount_cents, p_requested_term_months
    );

    IF NOT v_preflight.eligible THEN
        INSERT INTO creditworthiness_assessments (
            user_id, loan_product_id, requested_amount_cents, requested_term_months, loan_purpose,
            xnscore_at_assessment, xnscore_base_credit_score,
            raw_credit_score, final_credit_score, risk_grade,
            score_based_limit_cents, final_max_amount_cents,
            base_apr, final_apr,
            is_eligible, rejection_reasons, system_recommendation,
            expires_at, factor_breakdown
        ) VALUES (
            p_user_id, v_product.id, p_requested_amount_cents, p_requested_term_months, p_loan_purpose,
            v_xnscore.total_score, calculate_xnscore_credit_score(v_xnscore.total_score),
            calculate_xnscore_credit_score(v_xnscore.total_score),
            calculate_xnscore_credit_score(v_xnscore.total_score),
            get_risk_grade(calculate_xnscore_credit_score(v_xnscore.total_score)),
            0, 0,
            0, 0,
            FALSE, v_preflight.reasons, 'reject'::credit_recommendation,
            now() + INTERVAL '48 hours',
            jsonb_build_object('preflight_failed', TRUE, 'reasons', v_preflight.reasons)
        )
        RETURNING id INTO v_assessment_id;

        RETURN v_assessment_id;
    END IF;

    -- ═══════════════════════════════════════════════════════════════════
    -- PILLAR 1: XNSCORE → CREDIT SCORE
    -- ═══════════════════════════════════════════════════════════════════

    v_xnscore_value := v_xnscore.total_score;
    v_base_credit_score := calculate_xnscore_credit_score(v_xnscore_value);

    -- ═══════════════════════════════════════════════════════════════════
    -- PILLAR 2: CIRCLE HEALTH
    -- ═══════════════════════════════════════════════════════════════════

    SELECT * INTO v_circle_health FROM calculate_circle_health_adjustment(p_user_id);

    -- ═══════════════════════════════════════════════════════════════════
    -- PILLAR 3: LOAN HISTORY
    -- ═══════════════════════════════════════════════════════════════════

    SELECT * INTO v_loan_history FROM calculate_loan_history_adjustment(p_user_id);

    -- ═══════════════════════════════════════════════════════════════════
    -- CALCULATE FINAL CREDIT SCORE
    -- ═══════════════════════════════════════════════════════════════════

    v_raw_credit_score := v_base_credit_score + v_circle_health.adjustment + v_loan_history.adjustment;
    v_final_credit_score := GREATEST(300, LEAST(850, v_raw_credit_score));
    v_risk_grade := get_risk_grade(v_final_credit_score);

    -- Check if eligible based on final score
    IF v_risk_grade = 'E' THEN
        v_is_eligible := FALSE;
        v_rejection_reasons := ARRAY['Credit score below minimum threshold'];
        v_recommendation := 'reject'::credit_recommendation;
    ELSE
        v_is_eligible := TRUE;
        v_rejection_reasons := NULL;
    END IF;

    -- ═══════════════════════════════════════════════════════════════════
    -- PILLAR 4: CAPACITY
    -- ═══════════════════════════════════════════════════════════════════

    SELECT * INTO v_capacity FROM calculate_capacity(p_user_id);

    v_score_based_limit := get_score_based_limit(v_final_credit_score);
    v_product_limit := COALESCE(v_product.max_amount_cents, 1000000);

    v_final_max_amount := LEAST(
        v_capacity.net_capacity_cents,
        v_score_based_limit,
        v_product_limit
    );

    v_approved_amount := LEAST(p_requested_amount_cents, v_final_max_amount);

    -- Check if approved amount meets minimum
    IF v_is_eligible AND v_approved_amount < COALESCE(v_product.min_amount_cents, 10000) THEN
        v_is_eligible := FALSE;
        v_rejection_reasons := ARRAY['Approved amount below minimum threshold'];
        v_recommendation := 'reject'::credit_recommendation;
    END IF;

    -- ═══════════════════════════════════════════════════════════════════
    -- PILLAR 5: COMMUNITY COLLATERAL
    -- ═══════════════════════════════════════════════════════════════════

    SELECT * INTO v_community FROM calculate_community_collateral(
        p_user_id, p_elder_guarantee_user_id, p_cosigner_user_id, v_approved_amount
    );

    -- ═══════════════════════════════════════════════════════════════════
    -- CALCULATE FINAL APR
    -- ═══════════════════════════════════════════════════════════════════

    v_base_apr := get_base_apr(v_final_credit_score, v_risk_grade, v_product.id);

    IF v_base_apr IS NOT NULL THEN
        v_final_apr := GREATEST(v_apr_floor, v_base_apr - v_community.total_discount);
    ELSE
        v_final_apr := 0;
    END IF;

    -- ═══════════════════════════════════════════════════════════════════
    -- CALCULATE REPAYMENT
    -- ═══════════════════════════════════════════════════════════════════

    IF v_is_eligible THEN
        SELECT * INTO v_repayment FROM calculate_repayment(
            v_approved_amount, v_final_apr, p_requested_term_months
        );
    END IF;

    -- ═══════════════════════════════════════════════════════════════════
    -- GENERATE RECOMMENDATION
    -- ═══════════════════════════════════════════════════════════════════

    IF v_is_eligible THEN
        IF v_risk_grade = 'D' THEN
            v_recommendation := 'approve_with_conditions'::credit_recommendation;
            v_conditions := array_append(v_conditions, 'Require Elder guarantee or co-signer');
        ELSIF v_loan_history.defaulted_count > 0 THEN
            v_recommendation := 'approve_with_conditions'::credit_recommendation;
            v_conditions := array_append(v_conditions, 'Previous default on record - monitor closely');
        ELSIF v_final_credit_score < 500 THEN
            v_recommendation := 'manual_review'::credit_recommendation;
            v_conditions := array_append(v_conditions, 'Borderline score - manual review required');
        ELSE
            v_recommendation := 'approve'::credit_recommendation;
        END IF;

        IF v_approved_amount < p_requested_amount_cents THEN
            v_conditions := array_append(v_conditions,
                format('Approved amount ($%s) less than requested ($%s)',
                    v_approved_amount / 100, p_requested_amount_cents / 100));
        END IF;
    END IF;

    -- ═══════════════════════════════════════════════════════════════════
    -- CREATE ASSESSMENT RECORD
    -- ═══════════════════════════════════════════════════════════════════

    INSERT INTO creditworthiness_assessments (
        user_id, loan_product_id, requested_amount_cents, requested_term_months, loan_purpose,

        -- Pillar 1
        xnscore_at_assessment, xnscore_base_credit_score,

        -- Pillar 2
        circle_health_score, circle_health_adjustment, avg_circle_risk_score, circles_assessed,

        -- Pillar 3
        loan_history_score, loan_history_adjustment, loans_repaid_count, loans_defaulted_count,
        total_late_payments, has_active_delinquency,

        -- Final score
        raw_credit_score, final_credit_score, risk_grade,

        -- Pillar 4
        contribution_capacity_cents, wallet_capacity_cents, savings_capacity_cents,
        total_capacity_cents, existing_obligations_cents, score_based_limit_cents, final_max_amount_cents,

        -- Pillar 5
        vouch_count, vouch_discount_percent,
        elder_guarantee_user_id, elder_guarantee_coverage_percent, elder_guarantee_discount_percent,
        co_signer_user_id, co_signer_xnscore, co_signer_discount_percent,
        total_community_discount_percent,

        -- APR
        base_apr, final_apr,

        -- Decision
        is_eligible, rejection_reasons, approved_amount_cents,
        monthly_payment_cents, total_interest_cents, total_repayment_cents,
        system_recommendation, recommended_conditions,

        -- Metadata
        expires_at, factor_breakdown
    ) VALUES (
        p_user_id, v_product.id, p_requested_amount_cents, p_requested_term_months, p_loan_purpose,

        v_xnscore_value, v_base_credit_score,

        v_circle_health.score, v_circle_health.adjustment, v_circle_health.avg_risk_score, v_circle_health.circle_count,

        v_loan_history.score, v_loan_history.adjustment, v_loan_history.repaid_count, v_loan_history.defaulted_count,
        v_loan_history.late_payments, v_loan_history.has_active_delinquency,

        v_raw_credit_score, v_final_credit_score, v_risk_grade,

        v_capacity.contribution_capacity_cents, v_capacity.wallet_capacity_cents, v_capacity.savings_capacity_cents,
        v_capacity.total_capacity_cents, v_capacity.existing_obligations_cents, v_score_based_limit, v_final_max_amount,

        v_community.vouch_count, v_community.vouch_discount,
        p_elder_guarantee_user_id, v_community.elder_coverage_percent, v_community.elder_discount,
        p_cosigner_user_id, v_community.cosigner_xnscore, v_community.cosigner_discount,
        v_community.total_discount,

        COALESCE(v_base_apr, 0), COALESCE(v_final_apr, 0),

        v_is_eligible, v_rejection_reasons, CASE WHEN v_is_eligible THEN v_approved_amount ELSE NULL END,
        v_repayment.monthly_payment_cents, v_repayment.total_interest_cents, v_repayment.total_repayment_cents,
        v_recommendation, NULLIF(v_conditions, '{}'),

        now() + INTERVAL '48 hours',
        jsonb_build_object(
            'pillar1', jsonb_build_object('xnscore', v_xnscore_value, 'base_credit_score', v_base_credit_score),
            'pillar2', v_circle_health.details,
            'pillar3', v_loan_history.details,
            'pillar4', v_capacity.details,
            'pillar5', v_community.details,
            'final_score', jsonb_build_object('raw', v_raw_credit_score, 'capped', v_final_credit_score),
            'apr', jsonb_build_object('base', v_base_apr, 'discount', v_community.total_discount, 'final', v_final_apr)
        )
    )
    RETURNING id INTO v_assessment_id;

    RETURN v_assessment_id;
END;
$function$
;

CREATE OR REPLACE FUNCTION public.auto_archive_completed_groups()
 RETURNS integer
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
    v_group RECORD;
    v_archived_count INTEGER := 0;
    v_archive_threshold INTERVAL := '90 days'; -- Archive groups completed more than 90 days ago
BEGIN
    FOR v_group IN
        SELECT id
        FROM groups
        WHERE status = 'completed'
        AND updated_at < NOW() - v_archive_threshold
        AND id NOT IN (SELECT original_id FROM archived_groups)
    LOOP
        PERFORM archive_completed_group(v_group.id);
        v_archived_count := v_archived_count + 1;
    END LOOP;

    RAISE NOTICE 'Auto-archived % completed groups', v_archived_count;
    RETURN v_archived_count;
END;
$function$
;

CREATE OR REPLACE FUNCTION public.auto_calculate_initial_xnscore()
 RETURNS trigger
 LANGUAGE plpgsql
AS $function$
BEGIN
    -- Queue initial score calculation (don't block insert)
    PERFORM pg_notify('xnscore_calculate', NEW.id::TEXT);
    RETURN NEW;
END;
$function$
;

CREATE OR REPLACE FUNCTION public.auto_create_connection_from_circle()
 RETURNS trigger
 LANGUAGE plpgsql
AS $function$
BEGIN
    IF NEW.status = 'completed' AND OLD.status != 'completed' THEN
        -- Create connections between all members who don't already have one
        INSERT INTO user_connections (user_id, connected_user_id, connection_type, source, circles_together, successful_circles)
        SELECT cm1.user_id, cm2.user_id, 'acquaintance', 'circle_history', 1,
            CASE WHEN (SELECT COUNT(*) FROM defaults WHERE circle_id = NEW.id AND status = 'unresolved') = 0 THEN 1 ELSE 0 END
        FROM circle_members cm1
        JOIN circle_members cm2 ON cm1.circle_id = cm2.circle_id
        WHERE cm1.circle_id = NEW.id
          AND cm1.user_id != cm2.user_id
          AND cm1.status = 'completed'
          AND cm2.status = 'completed'
        ON CONFLICT (user_id, connected_user_id) DO NOTHING;
    END IF;

    RETURN NEW;
END;
$function$
;

CREATE OR REPLACE FUNCTION public.auto_escalate_defaults()
 RETURNS integer
 LANGUAGE plpgsql
AS $function$
DECLARE
    v_escalated INTEGER := 0;
    v_default RECORD;
    v_current_level INTEGER;
    v_days_since_default INTEGER;
BEGIN
    FOR v_default IN
        SELECT d.*, gp.expires_at as grace_expires
        FROM defaults d
        LEFT JOIN default_grace_periods gp ON gp.default_id = d.id AND gp.status = 'active'
        WHERE d.status IN ('unresolved', 'grace_period')
    LOOP
        -- Calculate days since default
        v_days_since_default := EXTRACT(DAY FROM NOW() - v_default.created_at);

        -- Get current escalation level
        SELECT COALESCE(MAX(escalation_level), 0) INTO v_current_level
        FROM default_escalations
        WHERE default_id = v_default.id AND status = 'active';

        -- Determine if escalation is needed
        IF v_days_since_default >= 7 AND v_current_level < 1 THEN
            INSERT INTO default_escalations (default_id, escalation_level, escalation_type)
            VALUES (v_default.id, 1, 'warning');
            v_escalated := v_escalated + 1;
        ELSIF v_days_since_default >= 14 AND v_current_level < 2 THEN
            UPDATE default_escalations SET status = 'superseded' WHERE default_id = v_default.id AND status = 'active';
            INSERT INTO default_escalations (default_id, escalation_level, escalation_type)
            VALUES (v_default.id, 2, 'final_notice');
            v_escalated := v_escalated + 1;
        ELSIF v_days_since_default >= 30 AND v_current_level < 3 THEN
            UPDATE default_escalations SET status = 'superseded' WHERE default_id = v_default.id AND status = 'active';
            INSERT INTO default_escalations (default_id, escalation_level, escalation_type)
            VALUES (v_default.id, 3, 'account_restriction');
            v_escalated := v_escalated + 1;
        END IF;
    END LOOP;

    RETURN v_escalated;
END;
$function$
;

CREATE OR REPLACE FUNCTION public.auto_execute_approved_dissolutions()
 RETURNS integer
 LANGUAGE plpgsql
AS $function$
DECLARE
    v_executed INTEGER := 0;
    v_dissolution RECORD;
BEGIN
    FOR v_dissolution IN
        SELECT id FROM dissolution_requests
        WHERE status = 'approved'
    LOOP
        PERFORM execute_dissolution(v_dissolution.id);
        v_executed := v_executed + 1;
    END LOOP;

    RETURN v_executed;
END;
$function$
;

CREATE OR REPLACE FUNCTION public.auto_set_escrow()
 RETURNS trigger
 LANGUAGE plpgsql
AS $function$ BEGIN IF NEW.final_amount_cents >= 20000 THEN NEW.is_escrow = true; END IF; RETURN NEW; END; $function$
;

CREATE OR REPLACE FUNCTION public.award_expertise_points(p_user_id uuid, p_domain_id text, p_points integer, p_source text, p_cap integer DEFAULT 999)
 RETURNS integer
 LANGUAGE plpgsql
 SECURITY DEFINER
AS $function$
DECLARE
  current_points INT;
  new_points INT;
BEGIN
  -- Upsert user_expertise
  INSERT INTO user_expertise (user_id, domain_id, points, last_updated)
  VALUES (p_user_id, p_domain_id, p_points, NOW())
  ON CONFLICT (user_id, domain_id)
  DO UPDATE SET
    points = user_expertise.points + p_points,
    last_updated = NOW();

  -- Return new total
  SELECT points INTO new_points FROM user_expertise
  WHERE user_id = p_user_id AND domain_id = p_domain_id;

  RETURN new_points;
END;
$function$
;

CREATE OR REPLACE FUNCTION public.calculate_accrued_interest(p_loan_id uuid, p_as_of_date timestamp with time zone DEFAULT now())
 RETURNS TABLE(loan_id uuid, principal_balance_cents integer, accrued_interest_cents integer, days_in_period integer, period_start_date date, period_end_date date, daily_interest_cents integer, effective_rate numeric, annual_rate_percent numeric, rate_type interest_rate_type, tier_breakdown jsonb, note text)
 LANGUAGE plpgsql
 STABLE
AS $function$
DECLARE
    v_loan RECORD;
    v_period_start DATE;
    v_period_end DATE;
    v_days INTEGER;
    v_effective_rate DECIMAL;
    v_interest_result RECORD;
BEGIN
    SELECT * INTO v_loan FROM loans WHERE id = p_loan_id;
    IF NOT FOUND THEN
        RAISE EXCEPTION 'Loan % not found', p_loan_id;
    END IF;

    IF v_loan.status IN ('paid_off', 'defaulted', 'written_off') THEN
        RETURN QUERY SELECT p_loan_id, 0::INTEGER, 0::INTEGER, 0::INTEGER,
            CURRENT_DATE, CURRENT_DATE, 0::INTEGER, 0::DECIMAL, 0::DECIMAL,
            v_loan.interest_rate_type, NULL::JSONB, 'Loan is closed'::TEXT;
        RETURN;
    END IF;

    v_period_start := COALESCE(v_loan.last_interest_accrual_date::DATE, v_loan.created_at::DATE);
    v_period_end := p_as_of_date::DATE;
    v_days := v_period_end - v_period_start;

    IF v_days <= 0 THEN
        v_effective_rate := get_effective_rate(p_loan_id, v_period_end);
        RETURN QUERY SELECT p_loan_id, v_loan.outstanding_principal_cents,
            0::INTEGER, 0::INTEGER, v_period_start, v_period_end, 0::INTEGER,
            v_effective_rate, v_effective_rate * 100,
            v_loan.interest_rate_type, NULL::JSONB, 'No days since last accrual'::TEXT;
        RETURN;
    END IF;

    IF v_loan.outstanding_principal_cents <= 0 THEN
        RETURN QUERY SELECT p_loan_id, 0::INTEGER, 0::INTEGER, v_days,
            v_period_start, v_period_end, 0::INTEGER, 0::DECIMAL, 0::DECIMAL,
            v_loan.interest_rate_type, NULL::JSONB, 'No outstanding principal'::TEXT;
        RETURN;
    END IF;

    v_effective_rate := get_effective_rate(p_loan_id, v_period_end);

    SELECT * INTO v_interest_result
    FROM calculate_daily_interest(v_loan.outstanding_principal_cents, v_effective_rate, v_days);

    RETURN QUERY SELECT p_loan_id, v_loan.outstanding_principal_cents,
        v_interest_result.interest_cents, v_days, v_period_start, v_period_end,
        ROUND(v_interest_result.interest_cents::DECIMAL / GREATEST(v_days, 1))::INTEGER,
        v_effective_rate, v_effective_rate * 100,
        v_loan.interest_rate_type, NULL::JSONB, NULL::TEXT;
END;
$function$
;

CREATE OR REPLACE FUNCTION public.calculate_advance_fee()
 RETURNS trigger
 LANGUAGE plpgsql
AS $function$
BEGIN
  IF NEW.status = 'approved' AND (OLD.status IS NULL OR OLD.status = 'requested') THEN
    -- Calculate fee based on tier
    NEW.fee_amount_cents = ROUND(NEW.approved_amount_cents * (NEW.fee_pct / 100));
    NEW.disbursed_amount_cents = NEW.approved_amount_cents;
    NEW.total_repayment_cents = NEW.approved_amount_cents + NEW.fee_amount_cents;
    NEW.advance_pct_of_payout = ROUND((NEW.approved_amount_cents::NUMERIC / NULLIF(NEW.expected_payout_cents, 0)) * 100, 2);
  END IF;
  RETURN NEW;
END;
$function$
;

CREATE OR REPLACE FUNCTION public.calculate_all_member_positions(p_dissolution_id uuid)
 RETURNS void
 LANGUAGE plpgsql
AS $function$
DECLARE
    v_dissolution dissolution_requests%ROWTYPE;
    v_member RECORD;
    v_position RECORD;
    v_total_positive_positions DECIMAL(15,2) := 0;
    v_refund_priority TEXT;
BEGIN
    -- Get dissolution details
    SELECT * INTO v_dissolution FROM dissolution_requests WHERE id = p_dissolution_id;

    -- Get refund priority from config
    SELECT refund_priority INTO v_refund_priority
    FROM dissolution_trigger_config
    WHERE trigger_type = v_dissolution.trigger_type;

    -- Calculate positions for each member
    FOR v_member IN
        SELECT cm.user_id
        FROM circle_members cm
        WHERE cm.circle_id = v_dissolution.circle_id
        AND cm.status = 'active'
    LOOP
        SELECT * INTO v_position FROM calculate_member_net_position(v_dissolution.circle_id, v_member.user_id);

        INSERT INTO dissolution_member_positions (
            dissolution_request_id,
            user_id,
            total_contributed,
            total_received,
            net_position
        ) VALUES (
            p_dissolution_id,
            v_member.user_id,
            v_position.total_contributed,
            v_position.total_received,
            v_position.net_position
        );

        -- Sum positive positions for refund calculation
        IF v_position.net_position > 0 THEN
            v_total_positive_positions := v_total_positive_positions + v_position.net_position;
        END IF;
    END LOOP;

    -- Calculate refund shares based on priority method
    IF v_refund_priority = 'net_position' THEN
        -- Refund based on net position (those who contributed more than received)
        UPDATE dissolution_member_positions dmp
        SET
            refund_share_percentage = CASE
                WHEN v_total_positive_positions > 0 AND dmp.net_position > 0
                THEN (dmp.net_position / v_total_positive_positions * 100)
                ELSE 0
            END,
            calculated_refund = CASE
                WHEN v_total_positive_positions > 0 AND dmp.net_position > 0
                THEN LEAST(dmp.net_position, v_dissolution.total_pool_amount * (dmp.net_position / v_total_positive_positions))
                ELSE 0
            END
        WHERE dmp.dissolution_request_id = p_dissolution_id;
    ELSE
        -- Pro-rata based on total contributions
        UPDATE dissolution_member_positions dmp
        SET
            refund_share_percentage = CASE
                WHEN (SELECT SUM(total_contributed) FROM dissolution_member_positions WHERE dissolution_request_id = p_dissolution_id) > 0
                THEN (dmp.total_contributed / (SELECT SUM(total_contributed) FROM dissolution_member_positions WHERE dissolution_request_id = p_dissolution_id) * 100)
                ELSE 0
            END,
            calculated_refund = CASE
                WHEN (SELECT SUM(total_contributed) FROM dissolution_member_positions WHERE dissolution_request_id = p_dissolution_id) > 0
                THEN v_dissolution.total_pool_amount * (dmp.total_contributed / (SELECT SUM(total_contributed) FROM dissolution_member_positions WHERE dissolution_request_id = p_dissolution_id))
                ELSE 0
            END
        WHERE dmp.dissolution_request_id = p_dissolution_id;
    END IF;

    -- Set adjusted refund (before fees are applied)
    UPDATE dissolution_member_positions
    SET adjusted_refund = calculated_refund
    WHERE dissolution_request_id = p_dissolution_id;

END;
$function$
;

CREATE OR REPLACE FUNCTION public.calculate_capacity(p_user_id uuid)
 RETURNS TABLE(contribution_capacity_cents integer, wallet_capacity_cents integer, savings_capacity_cents integer, total_capacity_cents integer, existing_obligations_cents integer, net_capacity_cents integer, details jsonb)
 LANGUAGE plpgsql
 STABLE
AS $function$
DECLARE
    v_avg_contribution DECIMAL;
    v_contribution_count INTEGER;
    v_wallet_balance INTEGER;
    v_flexible_savings INTEGER;
    v_locked_savings INTEGER;
    v_active_loan_obligations INTEGER;

    v_contribution_cap INTEGER;
    v_wallet_cap INTEGER;
    v_savings_cap INTEGER;
    v_total_cap INTEGER;
    v_net_cap INTEGER;
BEGIN
    -- A. Contribution history (last 6 months)
    SELECT
        COALESCE(AVG(amount), 0),
        COUNT(*)
    INTO v_avg_contribution, v_contribution_count
    FROM contributions
    WHERE user_id = p_user_id
    AND status IN ('completed', 'late')
    AND paid_at >= now() - INTERVAL '6 months';

    -- Contribution capacity = avg × 3 months runway
    v_contribution_cap := ROUND(v_avg_contribution * 3);

    -- B. Wallet balance
    SELECT COALESCE(available_balance, 0)
    INTO v_wallet_balance
    FROM wallets
    WHERE user_id = p_user_id;

    -- Wallet capacity = 50% of balance
    v_wallet_cap := ROUND(v_wallet_balance * 0.5);

    -- C. Savings goals
    SELECT
        COALESCE(SUM(CASE WHEN goal_type != 'locked' THEN current_balance ELSE 0 END), 0),
        COALESCE(SUM(CASE WHEN goal_type = 'locked' THEN current_balance ELSE 0 END), 0)
    INTO v_flexible_savings, v_locked_savings
    FROM savings_goals
    WHERE user_id = p_user_id AND is_active = TRUE;

    -- Savings capacity = flexible × 50% + locked × 25%
    v_savings_cap := ROUND((v_flexible_savings * 0.5) + (v_locked_savings * 0.25));

    -- Total capacity
    v_total_cap := v_contribution_cap + v_wallet_cap + v_savings_cap;

    -- Existing obligations
    SELECT COALESCE(SUM(outstanding_principal_cents), 0)
    INTO v_active_loan_obligations
    FROM loans
    WHERE user_id = p_user_id AND status = 'active';

    -- Net capacity (reduce by 50% of existing obligations)
    v_net_cap := GREATEST(0, v_total_cap - ROUND(v_active_loan_obligations * 0.5));

    RETURN QUERY SELECT
        v_contribution_cap,
        v_wallet_cap,
        v_savings_cap,
        v_total_cap,
        v_active_loan_obligations,
        v_net_cap,
        jsonb_build_object(
            'avg_monthly_contribution', ROUND(v_avg_contribution / 100, 2),
            'contribution_months_analyzed', v_contribution_count,
            'wallet_balance', ROUND(v_wallet_balance::DECIMAL / 100, 2),
            'flexible_savings', ROUND(v_flexible_savings::DECIMAL / 100, 2),
            'locked_savings', ROUND(v_locked_savings::DECIMAL / 100, 2),
            'active_loan_debt', ROUND(v_active_loan_obligations::DECIMAL / 100, 2)
        )::JSONB;
END;
$function$
;

CREATE OR REPLACE FUNCTION public.calculate_circle_completion_factor(p_user_id uuid)
 RETURNS TABLE(total_score numeric, completion_rate_score numeric, full_cycle_score numeric, no_abandonment_score numeric, component_details jsonb)
 LANGUAGE plpgsql
 STABLE
AS $function$
DECLARE
    v_score_record RECORD;
    v_circles_joined INTEGER;
    v_circles_completed INTEGER;
    v_circles_abandoned INTEGER;
    v_full_cycles INTEGER;
    v_completion_pct DECIMAL;

    v_completion_rate DECIMAL := 0;
    v_cycle_bonus DECIMAL := 0;
    v_no_abandon DECIMAL := 0;
    v_details JSONB;
BEGIN
    -- Get score record
    SELECT * INTO v_score_record FROM xn_scores WHERE user_id = p_user_id;

    IF v_score_record IS NULL THEN
        RETURN QUERY SELECT 0::DECIMAL, 0::DECIMAL, 0::DECIMAL, 0::DECIMAL, '{}'::JSONB;
        RETURN;
    END IF;

    v_circles_joined := COALESCE(v_score_record.circles_participated, 0);
    v_circles_abandoned := COALESCE(v_score_record.circles_abandoned, 0);
    v_full_cycles := COALESCE(v_score_record.full_cycles_completed, 0);
    v_circles_completed := v_circles_joined - v_circles_abandoned;

    -- Calculate completion rate (12 pts max)
    IF v_circles_joined > 0 THEN
        v_completion_pct := v_circles_completed::DECIMAL / v_circles_joined;
        v_completion_rate := LEAST(12, v_completion_pct * 12);
    END IF;

    -- Full cycle bonus (5 pts max)
    v_cycle_bonus := LEAST(5, (LEAST(v_full_cycles, 10)::DECIMAL / 10) * 5);

    -- No abandonment bonus (3 pts)
    IF v_circles_abandoned = 0 AND v_circles_joined > 0 THEN
        v_no_abandon := 3;
    END IF;

    v_details := jsonb_build_object(
        'circles_joined', v_circles_joined,
        'circles_completed', v_circles_completed,
        'circles_abandoned', v_circles_abandoned,
        'completion_percentage', ROUND(COALESCE(v_completion_pct * 100, 0), 1),
        'full_cycles_completed', v_full_cycles,
        'completion_rate', ROUND(COALESCE(v_score_record.completion_rate, 0), 1)
    );

    RETURN QUERY SELECT
        ROUND(v_completion_rate + v_cycle_bonus + v_no_abandon, 2),
        ROUND(v_completion_rate, 2),
        ROUND(v_cycle_bonus, 2),
        ROUND(v_no_abandon, 2),
        v_details;
END;
$function$
;

CREATE OR REPLACE FUNCTION public.calculate_circle_health_adjustment(p_user_id uuid)
 RETURNS TABLE(score numeric, adjustment integer, avg_risk_score numeric, circle_count integer, details jsonb)
 LANGUAGE plpgsql
 STABLE
AS $function$
DECLARE
    v_memberships RECORD;
    v_total_risk DECIMAL := 0;
    v_circle_count INTEGER := 0;
    v_avg_risk DECIMAL;
    v_health_score DECIMAL;
    v_adjustment INTEGER;
BEGIN
    -- Get active circle memberships with their risk scores
    FOR v_memberships IN
        SELECT
            cm.circle_id,
            c.name as circle_name,
            COALESCE(
                (SELECT risk_score FROM circle_risk_assessments
                 WHERE circle_id = cm.circle_id
                 ORDER BY calculated_at DESC LIMIT 1),
                50 -- Default to 50 if no assessment
            ) as risk_score
        FROM circle_members cm
        JOIN circles c ON c.id = cm.circle_id
        WHERE cm.user_id = p_user_id
        AND cm.status = 'active'
    LOOP
        v_total_risk := v_total_risk + v_memberships.risk_score;
        v_circle_count := v_circle_count + 1;
    END LOOP;

    IF v_circle_count = 0 THEN
        -- No active circles - neutral
        RETURN QUERY SELECT
            50::DECIMAL,
            0,
            NULL::DECIMAL,
            0,
            jsonb_build_object('note', 'No active circle memberships')::JSONB;
        RETURN;
    END IF;

    v_avg_risk := v_total_risk / v_circle_count;
    v_health_score := 100 - v_avg_risk; -- Lower risk = higher health

    -- Adjustment: (health - 50) capped at ±50
    v_adjustment := GREATEST(-50, LEAST(50, ROUND(v_health_score - 50)));

    RETURN QUERY SELECT
        ROUND(v_health_score, 2),
        v_adjustment,
        ROUND(v_avg_risk, 2),
        v_circle_count,
        jsonb_build_object(
            'avg_circle_risk', ROUND(v_avg_risk, 2),
            'circle_count', v_circle_count,
            'health_interpretation', CASE
                WHEN v_avg_risk < 30 THEN 'healthy'
                WHEN v_avg_risk < 50 THEN 'average'
                ELSE 'elevated_risk'
            END
        )::JSONB;
END;
$function$
;

CREATE OR REPLACE FUNCTION public.calculate_community_collateral(p_user_id uuid, p_elder_guarantee_user_id uuid, p_cosigner_user_id uuid, p_approved_amount_cents integer)
 RETURNS TABLE(vouch_count integer, vouch_discount numeric, elder_xnscore numeric, elder_coverage_percent numeric, elder_discount numeric, cosigner_xnscore numeric, cosigner_discount numeric, total_discount numeric, details jsonb)
 LANGUAGE plpgsql
 STABLE
AS $function$
DECLARE
    v_vouches INTEGER;
    v_vouch_discount DECIMAL := 0;
    v_elder_score DECIMAL;
    v_elder_coverage DECIMAL := 0;
    v_elder_discount DECIMAL := 0;
    v_elder_capacity RECORD;
    v_cosigner_score DECIMAL;
    v_cosigner_discount DECIMAL := 0;
    v_cosigner_capacity RECORD;
    v_shared_circle UUID;
    v_total_discount DECIMAL;
    v_max_discount DECIMAL := 7.0; -- Maximum 7% APR discount
BEGIN
    -- A. Vouch discount (max -2% APR)
    SELECT COUNT(DISTINCT voucher_user_id) INTO v_vouches
    FROM vouches
    WHERE vouchee_user_id = p_user_id AND vouch_status = 'active';

    IF v_vouches >= 10 THEN v_vouch_discount := 2.0;
    ELSIF v_vouches >= 6 THEN v_vouch_discount := 1.0;
    ELSIF v_vouches >= 3 THEN v_vouch_discount := 0.5;
    END IF;

    -- B. Elder guarantee discount (max -3% APR)
    IF p_elder_guarantee_user_id IS NOT NULL THEN
        SELECT total_score INTO v_elder_score
        FROM xn_scores WHERE user_id = p_elder_guarantee_user_id;

        -- Elder must have XnScore >= 80
        IF v_elder_score IS NOT NULL AND v_elder_score >= 80 THEN
            SELECT * INTO v_elder_capacity FROM check_elder_guarantee_capacity(p_elder_guarantee_user_id);

            IF v_elder_capacity.can_guarantee THEN
                -- Default 50% coverage
                v_elder_coverage := 50;

                IF v_elder_coverage >= 100 THEN v_elder_discount := 3.0;
                ELSIF v_elder_coverage >= 50 THEN v_elder_discount := 2.0;
                ELSIF v_elder_coverage >= 25 THEN v_elder_discount := 1.0;
                END IF;
            END IF;
        END IF;
    END IF;

    -- C. Co-signer discount (max -1.5% APR)
    IF p_cosigner_user_id IS NOT NULL THEN
        SELECT total_score INTO v_cosigner_score
        FROM xn_scores WHERE user_id = p_cosigner_user_id;

        -- Co-signer must have XnScore >= 60
        IF v_cosigner_score IS NOT NULL AND v_cosigner_score >= 60 THEN
            -- Must share a circle
            v_shared_circle := check_shared_circle(p_user_id, p_cosigner_user_id);

            IF v_shared_circle IS NOT NULL THEN
                SELECT * INTO v_cosigner_capacity FROM check_cosigner_capacity(p_cosigner_user_id);

                IF v_cosigner_capacity.can_cosign THEN
                    v_cosigner_discount := 1.5;
                END IF;
            END IF;
        END IF;
    END IF;

    -- Total discount (capped)
    v_total_discount := LEAST(v_max_discount, v_vouch_discount + v_elder_discount + v_cosigner_discount);

    RETURN QUERY SELECT
        v_vouches,
        v_vouch_discount,
        v_elder_score,
        v_elder_coverage,
        v_elder_discount,
        v_cosigner_score,
        v_cosigner_discount,
        v_total_discount,
        jsonb_build_object(
            'vouch_count', v_vouches,
            'vouch_discount_applied', v_vouch_discount > 0,
            'elder_eligible', v_elder_score >= 80,
            'elder_coverage', v_elder_coverage,
            'cosigner_eligible', v_cosigner_score >= 60,
            'shared_circle_id', v_shared_circle,
            'max_discount', v_max_discount
        )::JSONB;
END;
$function$
;

CREATE OR REPLACE FUNCTION public.calculate_community_standing_factor(p_user_id uuid)
 RETURNS TABLE(total_score numeric, vouches_received_score numeric, member_diversity_score numeric, elder_connections_score numeric, vouching_reliability_score numeric, component_details jsonb)
 LANGUAGE plpgsql
 STABLE
AS $function$
DECLARE
    v_score_record RECORD;
    v_total_vouch_value DECIMAL := 0;
    v_vouch_count INTEGER := 0;
    v_unique_members INTEGER;
    v_unique_elders INTEGER;
    v_voucher_reliability DECIMAL;

    v_vouch_score DECIMAL := 0;
    v_diversity_score DECIMAL := 0;
    v_elder_score DECIMAL := 0;
    v_reliability_score DECIMAL := 0;
    v_details JSONB;
BEGIN
    -- Get score record
    SELECT * INTO v_score_record FROM xn_scores WHERE user_id = p_user_id;

    IF v_score_record IS NULL THEN
        RETURN QUERY SELECT 0::DECIMAL, 0::DECIMAL, 0::DECIMAL, 0::DECIMAL, 0::DECIMAL, '{}'::JSONB;
        RETURN;
    END IF;

    -- Calculate vouch value received
    SELECT COUNT(*), COALESCE(SUM(diluted_vouch_value), 0)
    INTO v_vouch_count, v_total_vouch_value
    FROM vouches
    WHERE vouchee_user_id = p_user_id AND vouch_status = 'active';

    v_unique_members := COALESCE(v_score_record.unique_circle_members_count, 0);
    v_unique_elders := COALESCE(v_score_record.unique_elders_count, 0);

    -- Voucher reliability (1.0 = good, 0.0 = restricted)
    v_voucher_reliability := CASE v_score_record.voucher_reliability
        WHEN 'good' THEN 1.0
        WHEN 'warning' THEN 0.7
        WHEN 'poor' THEN 0.4
        WHEN 'restricted' THEN 0.0
        ELSE 1.0
    END;

    -- Vouches received score (5 pts max)
    v_vouch_score := LEAST(5, (LEAST(v_total_vouch_value, 10) / 10) * 5);

    -- Member diversity score (4 pts max)
    v_diversity_score := LEAST(4, (LEAST(v_unique_members, 20)::DECIMAL / 20) * 4);

    -- Elder connections score (3 pts max)
    v_elder_score := LEAST(3, (LEAST(v_unique_elders, 5)::DECIMAL / 5) * 3);

    -- Vouching reliability score (3 pts max)
    v_reliability_score := v_voucher_reliability * 3;

    v_details := jsonb_build_object(
        'vouches_received', v_vouch_count,
        'total_vouch_value', ROUND(v_total_vouch_value, 2),
        'unique_circle_members', v_unique_members,
        'unique_elders', v_unique_elders,
        'unique_communities', COALESCE(v_score_record.unique_communities_count, 0),
        'voucher_reliability', v_score_record.voucher_reliability,
        'total_vouchee_defaults', COALESCE(v_score_record.total_vouchee_defaults, 0)
    );

    RETURN QUERY SELECT
        ROUND(v_vouch_score + v_diversity_score + v_elder_score + v_reliability_score, 2),
        ROUND(v_vouch_score, 2),
        ROUND(v_diversity_score, 2),
        ROUND(v_elder_score, 2),
        ROUND(v_reliability_score, 2),
        v_details;
END;
$function$
;

CREATE OR REPLACE FUNCTION public.calculate_cycle_dates(p_start date, p_freq text, p_num integer)
 RETURNS TABLE(start_date date, contribution_deadline date, expected_payout_date date)
 LANGUAGE plpgsql
 IMMUTABLE
AS $function$
DECLARE v_s DATE; v_d DATE; v_p DATE;
BEGIN
    CASE p_freq
        WHEN 'weekly' THEN v_s := p_start + ((p_num-1) * 7); v_d := v_s + 5; v_p := v_s + 7;
        WHEN 'biweekly' THEN v_s := p_start + ((p_num-1) * 14); v_d := v_s + 10; v_p := v_s + 14;
        WHEN 'monthly' THEN v_s := p_start + ((p_num-1) * INTERVAL '1 month'); v_d := v_s + 25; v_p := (DATE_TRUNC('month', v_s) + INTERVAL '1 month' - INTERVAL '1 day')::DATE;
        WHEN 'quarterly' THEN v_s := p_start + ((p_num-1) * INTERVAL '3 months'); v_d := v_s + 80; v_p := (DATE_TRUNC('month', v_s + INTERVAL '3 months') - INTERVAL '1 day')::DATE;
        ELSE v_s := p_start + ((p_num-1) * INTERVAL '1 month'); v_d := v_s + 25; v_p := (DATE_TRUNC('month', v_s) + INTERVAL '1 month' - INTERVAL '1 day')::DATE;
    END CASE;
    RETURN QUERY SELECT v_s, v_d, v_p;
END; $function$
;

CREATE OR REPLACE FUNCTION public.calculate_daily_interest(p_principal_cents integer, p_annual_rate numeric, p_days integer)
 RETURNS TABLE(interest_cents integer, daily_rate numeric, daily_interest_cents numeric)
 LANGUAGE plpgsql
 STABLE
AS $function$
DECLARE
    v_days_per_year INTEGER := 365;
    v_daily_rate DECIMAL;
    v_interest DECIMAL;
BEGIN
    v_daily_rate := p_annual_rate / v_days_per_year;
    v_interest := p_principal_cents * v_daily_rate * p_days;
    interest_cents := ROUND(v_interest)::INTEGER;
    IF p_days > 0 AND interest_cents < p_days THEN
        interest_cents := p_days;
    END IF;
    daily_rate := v_daily_rate;
    daily_interest_cents := v_interest / GREATEST(p_days, 1);
    RETURN NEXT;
END;
$function$
;

CREATE OR REPLACE FUNCTION public.calculate_estimated_monthly_payment(p_principal_cents integer, p_annual_rate numeric, p_term_months integer)
 RETURNS TABLE(monthly_payment_cents integer, total_payments_cents integer, total_interest_cents integer, monthly_rate numeric, effective_rate numeric)
 LANGUAGE plpgsql
 STABLE
AS $function$
DECLARE
    v_monthly_rate DECIMAL;
    v_payment DECIMAL;
BEGIN
    IF p_term_months <= 0 THEN RAISE EXCEPTION 'Term months must be positive'; END IF;
    IF p_principal_cents <= 0 THEN
        RETURN QUERY SELECT 0::INTEGER, 0::INTEGER, 0::INTEGER, 0::DECIMAL, 0::DECIMAL;
        RETURN;
    END IF;

    v_monthly_rate := p_annual_rate / 12;

    IF p_annual_rate = 0 OR p_annual_rate IS NULL THEN
        v_payment := p_principal_cents::DECIMAL / p_term_months;
        RETURN QUERY SELECT CEIL(v_payment)::INTEGER, ROUND(v_payment * p_term_months)::INTEGER, 0::INTEGER, 0::DECIMAL, 0::DECIMAL;
        RETURN;
    END IF;

    v_payment := p_principal_cents * (
        (v_monthly_rate * POWER(1 + v_monthly_rate, p_term_months)) /
        (POWER(1 + v_monthly_rate, p_term_months) - 1)
    );

    RETURN QUERY SELECT CEIL(v_payment)::INTEGER, ROUND(v_payment * p_term_months)::INTEGER,
        (ROUND(v_payment * p_term_months) - p_principal_cents)::INTEGER, v_monthly_rate, p_annual_rate;
END;
$function$
;

CREATE OR REPLACE FUNCTION public.calculate_financial_behavior_factor(p_user_id uuid)
 RETURNS TABLE(total_score numeric, wallet_usage_score numeric, payout_retention_score numeric, savings_engagement_score numeric, component_details jsonb)
 LANGUAGE plpgsql
 STABLE
AS $function$
DECLARE
    v_score_record RECORD;
    v_wallet RECORD;
    v_wallet_deposits INTEGER := 0;
    v_total_deposited DECIMAL := 0;
    v_retention_rate DECIMAL := 0;
    v_has_savings BOOLEAN := FALSE;

    v_wallet_score DECIMAL := 0;
    v_retention_score DECIMAL := 0;
    v_savings_score DECIMAL := 0;
    v_details JSONB;
BEGIN
    -- Get score record
    SELECT * INTO v_score_record FROM xn_scores WHERE user_id = p_user_id;

    -- Get wallet info
    SELECT * INTO v_wallet FROM wallets WHERE user_id = p_user_id;

    IF v_score_record IS NULL THEN
        RETURN QUERY SELECT 0::DECIMAL, 0::DECIMAL, 0::DECIMAL, 0::DECIMAL, '{}'::JSONB;
        RETURN;
    END IF;

    -- Count wallet deposits
    SELECT COUNT(*), COALESCE(SUM(amount), 0)
    INTO v_wallet_deposits, v_total_deposited
    FROM wallet_transactions
    WHERE user_id = p_user_id
    AND transaction_type = 'deposit'
    AND transaction_status = 'completed';

    -- Calculate retention rate from payout preferences
    SELECT COALESCE(pp.wallet_percentage, 0)::DECIMAL / 100
    INTO v_retention_rate
    FROM payout_preferences pp
    WHERE pp.user_id = p_user_id;

    v_retention_rate := COALESCE(v_retention_rate, 0);

    -- Check for savings goals
    SELECT EXISTS(
        SELECT 1 FROM savings_goals WHERE user_id = p_user_id AND is_active = TRUE
    ) INTO v_has_savings;

    -- Wallet usage score (6 pts max)
    -- Based on deposit frequency and total deposited
    IF v_wallet_deposits > 0 THEN
        v_wallet_score := LEAST(6, (LEAST(v_wallet_deposits, 12)::DECIMAL / 12) * 6);
    END IF;

    -- Payout retention score (5 pts max)
    v_retention_score := v_retention_rate * 5;

    -- Savings engagement score (4 pts)
    IF v_has_savings THEN
        v_savings_score := 4;
    END IF;

    v_details := jsonb_build_object(
        'wallet_balance', COALESCE(v_wallet.available_balance, 0),
        'total_deposited', ROUND(v_total_deposited, 2),
        'deposit_count', v_wallet_deposits,
        'payout_retention_rate', ROUND(v_retention_rate * 100, 1),
        'has_savings_goals', v_has_savings,
        'last_wallet_deposit', v_score_record.last_wallet_deposit_at
    );

    RETURN QUERY SELECT
        ROUND(v_wallet_score + v_retention_score + v_savings_score, 2),
        ROUND(v_wallet_score, 2),
        ROUND(v_retention_score, 2),
        ROUND(v_savings_score, 2),
        v_details;
END;
$function$
;

CREATE OR REPLACE FUNCTION public.calculate_full_xnscore(p_user_id uuid)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
    v_user RECORD;
    v_payment_history_score DECIMAL(5,2) := 0;
    v_circle_completion_score DECIMAL(5,2) := 0;
    v_time_reliability_score DECIMAL(5,2) := 0;
    v_security_deposit_score DECIMAL(5,2) := 0;
    v_diversity_social_score DECIMAL(5,2) := 0;
    v_engagement_score DECIMAL(5,2) := 0;
    v_total_score DECIMAL(5,2);
    v_age_cap DECIMAL(5,2);
    v_final_score DECIMAL(5,2);
    v_account_age_days INTEGER;
    v_account_age_months DECIMAL;

    -- Payment history variables
    v_total_payments INTEGER;
    v_on_time_payments INTEGER;
    v_on_time_rate DECIMAL;
    v_payment_streak INTEGER;
    v_has_default BOOLEAN;

    -- Circle completion variables
    v_circles_joined INTEGER;
    v_circles_completed INTEGER;
    v_completion_rate DECIMAL;
    v_full_cycles INTEGER;
    v_early_exits INTEGER;

    -- Diversity & Social variables
    v_unique_circles INTEGER;
    v_vouchers_received INTEGER;

    -- Engagement variables
    v_profile_complete BOOLEAN;
    v_kyc_verified BOOLEAN;
    v_longevity BOOLEAN;
BEGIN
    -- Get user info
    SELECT * INTO v_user FROM users WHERE id = p_user_id;
    IF v_user IS NULL THEN
        RETURN jsonb_build_object('error', 'User not found');
    END IF;

    -- Calculate account age
    v_account_age_days := EXTRACT(DAY FROM (NOW() - v_user.created_at));
    v_account_age_months := v_account_age_days / 30.0;

    -- ============================================
    -- FACTOR 1: Payment History (35 pts max)
    -- ============================================
    -- On-time rate: 20 pts, Streak: 10 pts, No defaults: 5 pts

    -- Get payment stats
    SELECT
        COUNT(*),
        COUNT(*) FILTER (WHERE status = 'completed' AND (late_fee IS NULL OR late_fee = 0))
    INTO v_total_payments, v_on_time_payments
    FROM contributions
    WHERE user_id = p_user_id;

    -- Add loan payments to stats
    SELECT
        v_total_payments + COUNT(*),
        v_on_time_payments + COUNT(*) FILTER (WHERE status = 'completed')
    INTO v_total_payments, v_on_time_payments
    FROM loan_payments lp
    JOIN loans l ON l.id = lp.loan_id
    WHERE l.borrower_id = p_user_id;

    -- Calculate on-time rate (20 pts max)
    IF v_total_payments > 0 THEN
        v_on_time_rate := v_on_time_payments::DECIMAL / v_total_payments;
        v_payment_history_score := v_payment_history_score + (v_on_time_rate * 20);
    END IF;

    -- Calculate payment streak (10 pts max) - consecutive on-time payments / 5
    SELECT COALESCE(
        (SELECT COUNT(*)
         FROM (
             SELECT created_at,
                    ROW_NUMBER() OVER (ORDER BY created_at DESC) -
                    ROW_NUMBER() OVER (PARTITION BY (status = 'completed' AND (late_fee IS NULL OR late_fee = 0))
                                       ORDER BY created_at DESC) AS grp
             FROM contributions
             WHERE user_id = p_user_id
         ) sub
         WHERE grp = (
             SELECT MIN(grp) FROM (
                 SELECT ROW_NUMBER() OVER (ORDER BY created_at DESC) -
                        ROW_NUMBER() OVER (PARTITION BY (status = 'completed' AND (late_fee IS NULL OR late_fee = 0))
                                           ORDER BY created_at DESC) AS grp
                 FROM contributions
                 WHERE user_id = p_user_id
                 AND status = 'completed' AND (late_fee IS NULL OR late_fee = 0)
             ) first_group
         )
        ), 0
    ) INTO v_payment_streak;

    v_payment_history_score := v_payment_history_score + LEAST(v_payment_streak / 5.0, 10);

    -- Check for defaults (5 pts if never defaulted, -5 if any)
    SELECT EXISTS(
        SELECT 1 FROM loans WHERE borrower_id = p_user_id AND status = 'defaulted'
    ) INTO v_has_default;

    IF v_has_default THEN
        v_payment_history_score := v_payment_history_score - 5;
    ELSE
        v_payment_history_score := v_payment_history_score + 5;
    END IF;

    v_payment_history_score := GREATEST(0, LEAST(35, v_payment_history_score));

    -- ============================================
    -- FACTOR 2: Circle Completion (25 pts max)
    -- ============================================
    -- Completion rate: 15 pts, Full cycles: 10 pts

    SELECT
        COUNT(*),
        COUNT(*) FILTER (WHERE gm.status = 'completed' OR g.status = 'completed')
    INTO v_circles_joined, v_circles_completed
    FROM group_members gm
    JOIN groups g ON g.id = gm.group_id
    WHERE gm.user_id = p_user_id;

    -- Completion rate (15 pts)
    IF v_circles_joined > 0 THEN
        v_completion_rate := v_circles_completed::DECIMAL / v_circles_joined;
        v_circle_completion_score := v_completion_rate * 15;
    END IF;

    -- Full cycles completed (10 pts max)
    -- 1 cycle=2pts, 2=4pts, 3=6pts, 4=8pts, 5+=10pts
    v_full_cycles := v_circles_completed;
    v_circle_completion_score := v_circle_completion_score +
        CASE
            WHEN v_full_cycles >= 5 THEN 10
            WHEN v_full_cycles >= 4 THEN 8
            WHEN v_full_cycles >= 3 THEN 6
            WHEN v_full_cycles >= 2 THEN 4
            WHEN v_full_cycles >= 1 THEN 2
            ELSE 0
        END;

    -- Early exit penalty (-3 each in last 12 months)
    SELECT COUNT(*) INTO v_early_exits
    FROM group_members gm
    JOIN groups g ON g.id = gm.group_id
    WHERE gm.user_id = p_user_id
    AND gm.status = 'left'
    AND g.status = 'active'
    AND gm.updated_at >= NOW() - INTERVAL '12 months';

    v_circle_completion_score := v_circle_completion_score - (v_early_exits * 3);
    v_circle_completion_score := GREATEST(0, LEAST(25, v_circle_completion_score));

    -- ============================================
    -- FACTOR 3: Time & Reliability (20 pts max)
    -- ============================================
    -- Account age: 10 pts (max at 24 months), Sustained activity: 10 pts

    -- Account age (10 pts, capped at 730 days / 24 months)
    v_time_reliability_score := LEAST(v_account_age_days / 730.0, 1) * 10;

    -- Sustained activity (10 pts) - based on active months ratio
    -- For simplicity, we'll use a rough calculation based on payments per month
    IF v_account_age_months > 0 THEN
        DECLARE
            v_active_months INTEGER;
        BEGIN
            SELECT COUNT(DISTINCT DATE_TRUNC('month', created_at))
            INTO v_active_months
            FROM contributions
            WHERE user_id = p_user_id
            AND created_at >= NOW() - INTERVAL '24 months';

            v_time_reliability_score := v_time_reliability_score +
                LEAST(v_active_months / GREATEST(v_account_age_months, 1), 1) * 10;
        END;
    END IF;

    v_time_reliability_score := GREATEST(0, LEAST(20, v_time_reliability_score));

    -- ============================================
    -- FACTOR 4: Security Deposit (10 pts max)
    -- ============================================
    -- Based on deposit amount relative to contribution
    -- 3x contribution = 10pts, 2x = 7pts, 1.5x = 5pts, 1x = 3pts

    DECLARE
        v_deposit_amount DECIMAL;
        v_avg_contribution DECIMAL;
        v_deposit_ratio DECIMAL;
    BEGIN
        -- Get user's security deposit (if any)
        SELECT COALESCE(SUM(amount), 0) INTO v_deposit_amount
        FROM security_deposits
        WHERE user_id = p_user_id
        AND status = 'locked'
        AND locked_until > NOW();

        -- Get average contribution amount
        SELECT COALESCE(AVG(contribution_amount), 100) INTO v_avg_contribution
        FROM groups g
        JOIN group_members gm ON gm.group_id = g.id
        WHERE gm.user_id = p_user_id
        AND g.status = 'active';

        IF v_avg_contribution > 0 AND v_deposit_amount > 0 THEN
            v_deposit_ratio := v_deposit_amount / v_avg_contribution;
            v_security_deposit_score := CASE
                WHEN v_deposit_ratio >= 3 THEN 10
                WHEN v_deposit_ratio >= 2 THEN 7
                WHEN v_deposit_ratio >= 1.5 THEN 5
                WHEN v_deposit_ratio >= 1 THEN 3
                ELSE 0
            END;
        END IF;
    EXCEPTION
        WHEN undefined_table THEN
            -- security_deposits table doesn't exist yet
            v_security_deposit_score := 0;
    END;

    -- ============================================
    -- FACTOR 5: Diversity & Social (7 pts max)
    -- ============================================
    -- Circle diversity: 5 pts (1 pt per unique circle, 90+ days, 3+ payments)
    -- Social validation (vouchers): 2 pts

    SELECT COUNT(DISTINCT gm.group_id) INTO v_unique_circles
    FROM group_members gm
    JOIN groups g ON g.id = gm.group_id
    WHERE gm.user_id = p_user_id
    AND gm.joined_at <= NOW() - INTERVAL '90 days'
    AND (SELECT COUNT(*) FROM contributions c WHERE c.group_id = gm.group_id AND c.user_id = p_user_id AND c.status = 'completed') >= 3;

    v_diversity_social_score := LEAST(v_unique_circles, 5);

    -- Vouchers (2 pts max)
    BEGIN
        SELECT COUNT(*) INTO v_vouchers_received
        FROM vouches
        WHERE vouchee_id = p_user_id
        AND status = 'active';

        v_diversity_social_score := v_diversity_social_score + LEAST(v_vouchers_received, 2);
    EXCEPTION
        WHEN undefined_table THEN
            -- vouches table doesn't exist yet
            NULL;
    END;

    v_diversity_social_score := LEAST(7, v_diversity_social_score);

    -- ============================================
    -- FACTOR 6: Engagement (3 pts max)
    -- ============================================
    -- Profile complete: 1 pt, KYC verified: 1 pt, Longevity (12+ months): 1 pt

    v_profile_complete := (v_user.full_name IS NOT NULL AND v_user.phone IS NOT NULL AND v_user.avatar_url IS NOT NULL);
    v_kyc_verified := COALESCE(v_user.kyc_verified, FALSE);
    v_longevity := (v_account_age_months >= 12);

    IF v_profile_complete THEN v_engagement_score := v_engagement_score + 1; END IF;
    IF v_kyc_verified THEN v_engagement_score := v_engagement_score + 1; END IF;
    IF v_longevity THEN v_engagement_score := v_engagement_score + 1; END IF;

    -- ============================================
    -- CALCULATE TOTAL AND APPLY AGE CAP
    -- ============================================

    v_total_score := v_payment_history_score + v_circle_completion_score +
                     v_time_reliability_score + v_security_deposit_score +
                     v_diversity_social_score + v_engagement_score;

    -- Apply age-based caps
    IF v_account_age_months < 6 THEN
        v_age_cap := 75;
    ELSIF v_account_age_months < 12 THEN
        v_age_cap := 85;
    ELSIF v_account_age_months < 18 THEN
        v_age_cap := 90;
    ELSE
        v_age_cap := 100;
    END IF;

    v_final_score := LEAST(v_total_score, v_age_cap);

    -- Update user's score
    UPDATE users
    SET xn_score = v_final_score, updated_at = NOW()
    WHERE id = p_user_id;

    -- Return detailed breakdown
    RETURN jsonb_build_object(
        'user_id', p_user_id,
        'final_score', v_final_score,
        'raw_score', v_total_score,
        'age_cap_applied', v_total_score > v_age_cap,
        'age_cap', v_age_cap,
        'account_age_months', ROUND(v_account_age_months, 1),
        'tier', get_xn_tier(v_final_score),
        'breakdown', jsonb_build_object(
            'payment_history', jsonb_build_object(
                'score', v_payment_history_score,
                'max', 35,
                'percentage', ROUND(v_payment_history_score / 35 * 100, 1)
            ),
            'circle_completion', jsonb_build_object(
                'score', v_circle_completion_score,
                'max', 25,
                'percentage', ROUND(v_circle_completion_score / 25 * 100, 1)
            ),
            'time_reliability', jsonb_build_object(
                'score', v_time_reliability_score,
                'max', 20,
                'percentage', ROUND(v_time_reliability_score / 20 * 100, 1)
            ),
            'security_deposit', jsonb_build_object(
                'score', v_security_deposit_score,
                'max', 10,
                'percentage', ROUND(v_security_deposit_score / 10 * 100, 1)
            ),
            'diversity_social', jsonb_build_object(
                'score', v_diversity_social_score,
                'max', 7,
                'percentage', ROUND(v_diversity_social_score / 7 * 100, 1)
            ),
            'engagement', jsonb_build_object(
                'score', v_engagement_score,
                'max', 3,
                'percentage', ROUND(v_engagement_score / 3 * 100, 1)
            )
        ),
        'calculated_at', NOW()
    );
END;
$function$
;

CREATE OR REPLACE FUNCTION public.calculate_initial_xnscore(p_user_id uuid)
 RETURNS TABLE(user_id uuid, score numeric, raw_score numeric, tier xnscore_tier, age_cap integer, age_cap_applied boolean, breakdown jsonb)
 LANGUAGE plpgsql
 SECURITY DEFINER
AS $function$
DECLARE
    v_profile RECORD;
    v_existing_score RECORD;
    v_account_age_days INTEGER;
    v_age_cap INTEGER;

    -- Signal values
    v_base INTEGER := 20;
    v_email_points INTEGER := 0;
    v_phone_points INTEGER := 0;
    v_id_points INTEGER := 0;
    v_profile_points INTEGER := 0;
    v_inviter_points INTEGER := 0;
    v_quick_join_points INTEGER := 0;
    v_bank_points INTEGER := 0;

    v_profile_completion INTEGER;
    v_inviter_id UUID;
    v_inviter_score DECIMAL;
    v_has_circle BOOLEAN;
    v_hours_to_circle INTEGER;

    v_raw_total DECIMAL;
    v_capped_total DECIMAL;
    v_tier xnscore_tier;
    v_breakdown JSONB;
BEGIN
    -- Get profile
    SELECT * INTO v_profile FROM profiles WHERE id = p_user_id;

    IF NOT FOUND THEN
        RAISE EXCEPTION 'User not found: %', p_user_id;
    END IF;

    -- Check for existing score
    SELECT * INTO v_existing_score FROM xn_scores WHERE xn_scores.user_id = p_user_id;

    IF FOUND AND v_existing_score.initial_calculated_at IS NOT NULL THEN
        -- Return existing score
        RETURN QUERY SELECT
            p_user_id,
            v_existing_score.total_score,
            v_existing_score.raw_score,
            v_existing_score.score_tier,
            v_existing_score.max_allowed_score::INTEGER,
            v_existing_score.age_cap_applied,
            v_existing_score.initial_score_breakdown;
        RETURN;
    END IF;

    -- Calculate account age
    v_account_age_days := EXTRACT(DAY FROM (now() - v_profile.created_at))::INTEGER;
    v_age_cap := get_xnscore_age_cap(v_account_age_days);

    -- ═══════════════════════════════════════════════════════════════════
    -- GATHER SIGNALS
    -- ═══════════════════════════════════════════════════════════════════

    -- Email verification (+5)
    IF v_profile.email_verified = TRUE THEN
        v_email_points := 5;
    END IF;

    -- Phone verification (+5)
    IF v_profile.phone_verified = TRUE THEN
        v_phone_points := 5;
    END IF;

    -- ID verification (+10)
    IF v_profile.identity_verified = TRUE THEN
        v_id_points := 10;
    END IF;

    -- Profile completion (+2 if 100%)
    v_profile_completion := calculate_profile_completion(p_user_id);
    IF v_profile_completion >= 100 THEN
        v_profile_points := 2;
    END IF;

    -- Inviter bonus (+1 to +5)
    IF v_profile.invited_by IS NOT NULL THEN
        v_inviter_id := v_profile.invited_by;
        SELECT total_score INTO v_inviter_score
        FROM xn_scores WHERE xn_scores.user_id = v_inviter_id;

        IF v_inviter_score IS NOT NULL THEN
            IF v_inviter_score >= 80 THEN
                v_inviter_points := 5;
            ELSIF v_inviter_score >= 60 THEN
                v_inviter_points := 3;
            ELSE
                v_inviter_points := 1;
            END IF;
        ELSE
            v_inviter_points := 1; -- Any inviter is better than none
        END IF;
    END IF;

    -- Quick circle join (+2 if joined within 1 hour)
    SELECT EXISTS(
        SELECT 1 FROM circle_members
        WHERE circle_members.user_id = p_user_id
    ) INTO v_has_circle;

    IF v_has_circle THEN
        SELECT EXTRACT(EPOCH FROM (MIN(cm.joined_at) - v_profile.created_at))/3600
        INTO v_hours_to_circle
        FROM circle_members cm
        WHERE cm.user_id = p_user_id;

        IF v_hours_to_circle IS NOT NULL AND v_hours_to_circle <= 1 THEN
            v_quick_join_points := 2;
        END IF;
    END IF;

    -- Bank account (+1 to +3) - check if linked
    IF EXISTS(SELECT 1 FROM user_bank_accounts WHERE user_bank_accounts.user_id = p_user_id AND status = 'active') THEN
        v_bank_points := 1;
        -- Could add more points based on Plaid data if available
    END IF;

    -- ═══════════════════════════════════════════════════════════════════
    -- CALCULATE TOTALS
    -- ═══════════════════════════════════════════════════════════════════

    v_raw_total := v_base + v_email_points + v_phone_points + v_id_points +
                   v_profile_points + v_inviter_points + v_quick_join_points + v_bank_points;

    v_capped_total := LEAST(v_raw_total, v_age_cap);
    v_tier := get_xnscore_tier(v_capped_total);

    v_breakdown := jsonb_build_object(
        'base', v_base,
        'email_verified', v_email_points,
        'phone_verified', v_phone_points,
        'id_verified', v_id_points,
        'profile_complete', v_profile_points,
        'inviter_bonus', v_inviter_points,
        'quick_join', v_quick_join_points,
        'bank_linked', v_bank_points,
        'raw_total', v_raw_total,
        'age_cap', v_age_cap,
        'capped_total', v_capped_total
    );

    -- ═══════════════════════════════════════════════════════════════════
    -- STORE INITIAL SIGNALS
    -- ═══════════════════════════════════════════════════════════════════

    INSERT INTO xnscore_initial_signals (
        user_id, base_score,
        email_verified, email_verified_points,
        phone_verified, phone_verified_points,
        id_verified, id_verified_points,
        profile_complete, profile_complete_points, profile_completion_pct,
        has_inviter, inviter_user_id, inviter_xnscore_at_invite, inviter_points,
        joined_circle_quickly, joined_circle_quickly_points, hours_to_first_circle,
        bank_account_linked, bank_account_points,
        raw_initial_score, capped_initial_score, age_cap_at_creation
    ) VALUES (
        p_user_id, v_base,
        v_profile.email_verified, v_email_points,
        v_profile.phone_verified, v_phone_points,
        v_profile.identity_verified, v_id_points,
        v_profile_completion >= 100, v_profile_points, v_profile_completion,
        v_inviter_id IS NOT NULL, v_inviter_id, v_inviter_score, v_inviter_points,
        v_quick_join_points > 0, v_quick_join_points, v_hours_to_circle,
        v_bank_points > 0, v_bank_points,
        v_raw_total::INTEGER, v_capped_total::INTEGER, v_age_cap
    )
    ON CONFLICT (user_id) DO UPDATE SET
        email_verified = EXCLUDED.email_verified,
        email_verified_points = EXCLUDED.email_verified_points,
        phone_verified = EXCLUDED.phone_verified,
        phone_verified_points = EXCLUDED.phone_verified_points,
        id_verified = EXCLUDED.id_verified,
        id_verified_points = EXCLUDED.id_verified_points,
        profile_complete = EXCLUDED.profile_complete,
        profile_complete_points = EXCLUDED.profile_complete_points,
        raw_initial_score = EXCLUDED.raw_initial_score,
        capped_initial_score = EXCLUDED.capped_initial_score,
        recalculated_count = xnscore_initial_signals.recalculated_count + 1,
        last_recalculated_at = now();

    -- ═══════════════════════════════════════════════════════════════════
    -- CREATE OR UPDATE MAIN SCORE RECORD
    -- ═══════════════════════════════════════════════════════════════════

    INSERT INTO xn_scores (
        user_id,
        total_score, raw_score, previous_score,
        score_tier,
        time_reliability_score, diversity_social_score, engagement_score,
        initial_score, initial_score_breakdown, initial_calculated_at,
        age_cap_applied, max_allowed_score, account_age_days,
        points_gained_this_week, week_start_date,
        last_calculated_at, calculation_trigger
    ) VALUES (
        p_user_id,
        v_capped_total, v_raw_total, NULL,
        v_tier,
        0, v_inviter_points, v_profile_points + v_quick_join_points,
        v_capped_total, v_breakdown, now(),
        v_capped_total < v_raw_total, v_age_cap, v_account_age_days,
        0, date_trunc('week', now())::DATE,
        now(), 'initial_calculation'
    )
    ON CONFLICT (user_id) DO UPDATE SET
        total_score = EXCLUDED.total_score,
        raw_score = EXCLUDED.raw_score,
        score_tier = EXCLUDED.score_tier,
        initial_score = EXCLUDED.initial_score,
        initial_score_breakdown = EXCLUDED.initial_score_breakdown,
        initial_calculated_at = EXCLUDED.initial_calculated_at,
        age_cap_applied = EXCLUDED.age_cap_applied,
        max_allowed_score = EXCLUDED.max_allowed_score,
        account_age_days = EXCLUDED.account_age_days,
        last_calculated_at = now(),
        calculation_trigger = 'initial_recalculation',
        updated_at = now();

    -- ═══════════════════════════════════════════════════════════════════
    -- LOG TO HISTORY
    -- ═══════════════════════════════════════════════════════════════════

    INSERT INTO xnscore_history (
        user_id, score, previous_score, score_change,
        trigger_event, factor_breakdown,
        raw_score_before_cap, age_cap_applied, age_cap_value,
        weekly_points_before, weekly_points_after, velocity_capped
    ) VALUES (
        p_user_id, v_capped_total, NULL, v_capped_total,
        'initial_calculation', v_breakdown,
        v_raw_total, v_capped_total < v_raw_total, v_age_cap,
        0, 0, FALSE
    );

    -- Return result
    RETURN QUERY SELECT
        p_user_id,
        v_capped_total,
        v_raw_total,
        v_tier,
        v_age_cap,
        v_capped_total < v_raw_total,
        v_breakdown;
END;
$function$
;

CREATE OR REPLACE FUNCTION public.calculate_late_fee(p_circle_id uuid, p_outstanding_amount numeric, p_days_late integer)
 RETURNS numeric
 LANGUAGE plpgsql
AS $function$
DECLARE
    v_config RECORD;
    v_fee DECIMAL := 0;
    v_tier RECORD;
BEGIN
    SELECT * INTO v_config FROM late_fee_config WHERE circle_id = p_circle_id;

    IF v_config IS NULL THEN
        SELECT * INTO v_config FROM late_fee_config WHERE circle_id IS NULL LIMIT 1;
    END IF;

    IF v_config IS NULL THEN
        RETURN 0;
    END IF;

    IF NOT COALESCE(v_config.enabled, true) THEN
        RETURN 0;
    END IF;

    IF p_days_late <= COALESCE(v_config.grace_period_days, 2) THEN
        RETURN 0;
    END IF;

    CASE COALESCE(v_config.fee_type, 'percentage')
        WHEN 'flat' THEN
            v_fee := COALESCE(v_config.flat_fee, 500);

        WHEN 'percentage' THEN
            v_fee := p_outstanding_amount * COALESCE(v_config.late_fee_percentage, 0.05);

        WHEN 'tiered' THEN
            IF v_config.tiered_fees IS NOT NULL THEN
                FOR v_tier IN SELECT * FROM jsonb_to_recordset(v_config.tiered_fees) AS x(days_late INTEGER, fee DECIMAL)
                    ORDER BY days_late DESC
                LOOP
                    IF p_days_late >= v_tier.days_late THEN
                        v_fee := v_tier.fee;
                        EXIT;
                    END IF;
                END LOOP;
            END IF;
        ELSE
            v_fee := p_outstanding_amount * 0.05;
    END CASE;

    IF v_config.max_fee IS NOT NULL THEN
        v_fee := LEAST(v_fee, v_config.max_fee);
    END IF;

    RETURN ROUND(v_fee, 2);
END;
$function$
;

CREATE OR REPLACE FUNCTION public.calculate_loan_history_adjustment(p_user_id uuid)
 RETURNS TABLE(score numeric, adjustment integer, repaid_count integer, defaulted_count integer, late_payments integer, has_active_delinquency boolean, details jsonb)
 LANGUAGE plpgsql
 STABLE
AS $function$
DECLARE
    v_loans RECORD;
    v_adjustment INTEGER := 0;
    v_score DECIMAL := 50;
    v_repaid INTEGER := 0;
    v_defaulted INTEGER := 0;
    v_late INTEGER := 0;
    v_early_payoffs INTEGER := 0;
    v_has_delinquency BOOLEAN := FALSE;
    v_total_loans INTEGER := 0;
BEGIN
    -- Aggregate loan history
    SELECT
        COUNT(*) FILTER (WHERE status = 'paid_off'),
        COUNT(*) FILTER (WHERE status = 'defaulted'),
        COUNT(*) FILTER (WHERE closed_reason = 'early_payoff'),
        COUNT(*),
        COALESCE(SUM(
            (SELECT COUNT(*) FROM loan_payments lp
             WHERE lp.loan_id = l.id AND lp.was_on_time = FALSE)
        ), 0),
        EXISTS(SELECT 1 FROM loans WHERE user_id = p_user_id AND status = 'active' AND days_past_due > 0)
    INTO v_repaid, v_defaulted, v_early_payoffs, v_total_loans, v_late, v_has_delinquency
    FROM loans l
    WHERE l.user_id = p_user_id;

    IF v_total_loans = 0 THEN
        -- No loan history - neutral
        RETURN QUERY SELECT
            50::DECIMAL,
            0,
            0,
            0,
            0,
            FALSE,
            jsonb_build_object('note', 'No prior loan history')::JSONB;
        RETURN;
    END IF;

    -- Positive: Loans repaid (+25 each, max +75)
    v_adjustment := v_adjustment + LEAST(75, v_repaid * 25);

    -- Positive: Perfect payment record (+25)
    IF v_late = 0 AND v_repaid > 0 THEN
        v_adjustment := v_adjustment + 25;
    END IF;

    -- Positive: Early payoffs (+10 each, max +30)
    v_adjustment := v_adjustment + LEAST(30, v_early_payoffs * 10);

    -- Negative: Late payments (-15 each)
    v_adjustment := v_adjustment - (v_late * 15);

    -- Negative: Defaults (-50 each)
    v_adjustment := v_adjustment - (v_defaulted * 50);

    -- Cap at ±100
    v_adjustment := GREATEST(-100, LEAST(100, v_adjustment));

    -- Score (0-100)
    v_score := GREATEST(0, LEAST(100, 50 + v_adjustment));

    RETURN QUERY SELECT
        ROUND(v_score, 2),
        v_adjustment,
        v_repaid,
        v_defaulted,
        v_late::INTEGER,
        v_has_delinquency,
        jsonb_build_object(
            'total_loans', v_total_loans,
            'early_payoffs', v_early_payoffs,
            'interpretation', CASE
                WHEN v_adjustment > 50 THEN 'excellent'
                WHEN v_adjustment > 0 THEN 'good'
                WHEN v_adjustment = 0 THEN 'neutral'
                WHEN v_adjustment > -50 THEN 'concerning'
                ELSE 'poor'
            END
        )::JSONB;
END;
$function$
;

CREATE OR REPLACE FUNCTION public.calculate_loan_late_fee(p_scheduled_payment_cents integer, p_days_past_due integer, p_loan_product_id uuid DEFAULT NULL::uuid)
 RETURNS TABLE(fee_cents integer, fee_type late_fee_type, flat_fee_cents integer, percentage_fee_cents integer, grace_period_days integer, within_grace_period boolean)
 LANGUAGE plpgsql
 STABLE
AS $function$
DECLARE
    v_grace_period INTEGER := 5;
    v_flat_fee INTEGER := 500;
    v_percentage DECIMAL := 5.0;
    v_percentage_fee INTEGER;
    v_product RECORD;
BEGIN
    IF p_loan_product_id IS NOT NULL THEN
        SELECT * INTO v_product FROM loan_products WHERE id = p_loan_product_id;
        IF FOUND THEN
            v_grace_period := COALESCE(v_product.grace_period_days, 5);
            v_flat_fee := COALESCE(v_product.late_fee_flat_cents, 500);
            v_percentage := COALESCE(v_product.late_fee_percent, 5.0);
        END IF;
    END IF;

    IF p_days_past_due <= v_grace_period THEN
        RETURN QUERY SELECT 0::INTEGER, 'flat'::late_fee_type,
            v_flat_fee, 0::INTEGER, v_grace_period, TRUE;
        RETURN;
    END IF;

    v_percentage_fee := ROUND(p_scheduled_payment_cents * (v_percentage / 100))::INTEGER;

    IF v_flat_fee >= v_percentage_fee THEN
        RETURN QUERY SELECT v_flat_fee, 'flat'::late_fee_type,
            v_flat_fee, v_percentage_fee, v_grace_period, FALSE;
    ELSE
        RETURN QUERY SELECT v_percentage_fee, 'percentage'::late_fee_type,
            v_flat_fee, v_percentage_fee, v_grace_period, FALSE;
    END IF;
END;
$function$
;

CREATE OR REPLACE FUNCTION public.calculate_member_net_position(p_circle_id uuid, p_user_id uuid)
 RETURNS TABLE(total_contributed numeric, total_received numeric, net_position numeric)
 LANGUAGE plpgsql
 STABLE
AS $function$
BEGIN
    RETURN QUERY
    SELECT
        COALESCE(SUM(CASE WHEN ct.type = 'contribution' THEN ct.amount ELSE 0 END), 0)::DECIMAL(15,2) as total_contributed,
        COALESCE(SUM(CASE WHEN ct.type = 'payout' THEN ct.amount ELSE 0 END), 0)::DECIMAL(15,2) as total_received,
        (COALESCE(SUM(CASE WHEN ct.type = 'contribution' THEN ct.amount ELSE 0 END), 0) -
         COALESCE(SUM(CASE WHEN ct.type = 'payout' THEN ct.amount ELSE 0 END), 0))::DECIMAL(15,2) as net_position
    FROM circle_transactions ct
    WHERE ct.circle_id = p_circle_id
    AND ct.user_id = p_user_id
    AND ct.status = 'completed';
END;
$function$
;

CREATE OR REPLACE FUNCTION public.calculate_payment_reliability_factor(p_user_id uuid)
 RETURNS TABLE(total_score numeric, on_time_rate_score numeric, payment_streak_score numeric, no_defaults_score numeric, late_recovery_score numeric, component_details jsonb)
 LANGUAGE plpgsql
 STABLE
AS $function$
DECLARE
    v_total_contributions INTEGER;
    v_on_time_contributions INTEGER;
    v_late_contributions INTEGER;
    v_late_recovered INTEGER;
    v_on_time_pct DECIMAL;
    v_score_record RECORD;

    v_on_time_rate DECIMAL := 0;
    v_streak_bonus DECIMAL := 0;
    v_no_defaults DECIMAL := 0;
    v_late_recovery DECIMAL := 0;
    v_details JSONB;
BEGIN
    -- Get score record
    SELECT * INTO v_score_record FROM xn_scores WHERE user_id = p_user_id;

    -- Count contributions
    SELECT
        COUNT(*) FILTER (WHERE status IN ('completed', 'late')),
        COUNT(*) FILTER (WHERE status = 'completed' AND (paid_at <= due_date OR paid_at IS NULL)),
        COUNT(*) FILTER (WHERE status = 'late'),
        COUNT(*) FILTER (WHERE status = 'late' AND paid_at IS NOT NULL)
    INTO v_total_contributions, v_on_time_contributions, v_late_contributions, v_late_recovered
    FROM contributions
    WHERE user_id = p_user_id;

    -- Calculate on-time rate (20 pts max)
    IF v_total_contributions > 0 THEN
        v_on_time_pct := v_on_time_contributions::DECIMAL / v_total_contributions;
        v_on_time_rate := LEAST(20, v_on_time_pct * 20);
    END IF;

    -- Calculate streak bonus (8 pts max)
    IF v_score_record IS NOT NULL THEN
        v_streak_bonus := LEAST(8, (LEAST(v_score_record.payment_streak, 20)::DECIMAL / 20) * 8);
    END IF;

    -- No defaults bonus (5 pts)
    IF v_score_record IS NOT NULL AND NOT COALESCE(v_score_record.has_defaults, FALSE) THEN
        v_no_defaults := 5;
    END IF;

    -- Late recovery bonus (2 pts max)
    IF v_late_contributions > 0 AND v_late_recovered > 0 THEN
        v_late_recovery := LEAST(2, (v_late_recovered::DECIMAL / v_late_contributions) * 2);
    END IF;

    v_details := jsonb_build_object(
        'total_contributions', v_total_contributions,
        'on_time_contributions', v_on_time_contributions,
        'on_time_percentage', ROUND(COALESCE(v_on_time_pct * 100, 0), 1),
        'current_streak', COALESCE(v_score_record.payment_streak, 0),
        'best_streak', COALESCE(v_score_record.best_payment_streak, 0),
        'has_defaults', COALESCE(v_score_record.has_defaults, FALSE),
        'default_count', COALESCE(v_score_record.default_count, 0),
        'late_payments', v_late_contributions,
        'late_recovered', v_late_recovered
    );

    RETURN QUERY SELECT
        ROUND(v_on_time_rate + v_streak_bonus + v_no_defaults + v_late_recovery, 2),
        ROUND(v_on_time_rate, 2),
        ROUND(v_streak_bonus, 2),
        ROUND(v_no_defaults, 2),
        ROUND(v_late_recovery, 2),
        v_details;
END;
$function$
;

CREATE OR REPLACE FUNCTION public.calculate_payoff_amount(p_loan_id uuid, p_payoff_date date DEFAULT CURRENT_DATE)
 RETURNS TABLE(loan_id uuid, payoff_date date, outstanding_principal_cents integer, accrued_interest_cents integer, previous_accrued_interest_cents integer, outstanding_fees_cents integer, total_payoff_cents integer, per_diem_cents integer, current_rate numeric, current_rate_percent numeric, rate_type interest_rate_type, valid_until date, note text)
 LANGUAGE plpgsql
 STABLE
AS $function$
DECLARE
    v_loan RECORD;
    v_interest RECORD;
    v_fees_total INTEGER;
BEGIN
    SELECT * INTO v_loan FROM loans WHERE id = p_loan_id;
    IF NOT FOUND THEN RAISE EXCEPTION 'Loan % not found', p_loan_id; END IF;

    SELECT * INTO v_interest FROM calculate_accrued_interest(p_loan_id, p_payoff_date::TIMESTAMPTZ);

    SELECT COALESCE(SUM(calculated_fee_cents - COALESCE(paid_amount_cents, 0)), 0)
    INTO v_fees_total FROM loan_late_fees
    WHERE loan_late_fees.loan_id = p_loan_id AND status = 'pending';

    RETURN QUERY SELECT p_loan_id, p_payoff_date,
        v_loan.outstanding_principal_cents,
        v_interest.accrued_interest_cents,
        COALESCE(v_loan.accrued_interest_cents, 0),
        v_fees_total,
        v_loan.outstanding_principal_cents + v_interest.accrued_interest_cents +
            COALESCE(v_loan.accrued_interest_cents, 0) + v_fees_total,
        v_interest.daily_interest_cents,
        v_interest.effective_rate,
        v_interest.annual_rate_percent,
        v_interest.rate_type,
        p_payoff_date + 10,
        format('Add $%s/day after %s',
            ROUND(v_interest.daily_interest_cents::DECIMAL / 100, 2),
            to_char(p_payoff_date, 'MM/DD/YYYY'));
END;
$function$
;

CREATE OR REPLACE FUNCTION public.calculate_payout_net_amount()
 RETURNS trigger
 LANGUAGE plpgsql
AS $function$
BEGIN
    NEW.net_amount = NEW.amount - COALESCE(NEW.fee_amount, 0);
    RETURN NEW;
END;
$function$
;

CREATE OR REPLACE FUNCTION public.calculate_pool_rate(p_circle_id uuid)
 RETURNS numeric
 LANGUAGE plpgsql
 SECURITY DEFINER
AS $function$
DECLARE
  v_pool RECORD;
  v_avg_score DECIMAL(6,2);
  v_min_score DECIMAL(6,2);
  v_members_below_fair INTEGER;
  v_total_defaults INTEGER;
  v_member_count INTEGER;
  v_rate DECIMAL(5,4);
  v_previous_rate DECIMAL(5,4);
BEGIN
  SELECT * INTO v_pool
  FROM circle_insurance_pools
  WHERE circle_id = p_circle_id;

  IF v_pool IS NULL THEN
    RETURN 0.0200;
  END IF;

  v_previous_rate := v_pool.current_rate;

  SELECT
    COALESCE(AVG(xs.total_score), 0),
    COALESCE(MIN(xs.total_score), 0),
    COUNT(*) FILTER (WHERE xs.score_tier IN ('critical', 'poor')),
    COUNT(*)
  INTO v_avg_score, v_min_score, v_members_below_fair, v_member_count
  FROM circle_members cm
  LEFT JOIN xn_scores xs ON xs.user_id = cm.user_id
  WHERE cm.circle_id = p_circle_id
    AND cm.status = 'active';

  SELECT COALESCE(SUM(mbp.default_count), 0)
  INTO v_total_defaults
  FROM circle_members cm
  JOIN member_behavioral_profiles mbp ON mbp.user_id = cm.user_id
  WHERE cm.circle_id = p_circle_id
    AND cm.status = 'active';

  v_rate := 0.0200;

  IF v_avg_score >= 75 THEN
    v_rate := v_rate - 0.0050;
  ELSIF v_avg_score >= 60 THEN
    v_rate := v_rate - 0.0030;
  ELSIF v_avg_score < 45 THEN
    v_rate := v_rate + 0.0030;
  END IF;

  IF v_members_below_fair > 0 AND v_member_count > 0 THEN
    v_rate := v_rate + LEAST(v_members_below_fair * 0.0020, 0.0080);
  END IF;

  IF v_total_defaults > 0 THEN
    v_rate := v_rate + LEAST(v_total_defaults * 0.0015, 0.0060);
  END IF;

  v_rate := GREATEST(v_pool.rate_floor, LEAST(v_pool.rate_ceiling, v_rate));

  UPDATE circle_insurance_pools
  SET current_rate = v_rate, updated_at = NOW()
  WHERE id = v_pool.id;

  INSERT INTO insurance_pool_rate_history (
    pool_id, circle_id, effective_rate, previous_rate, reason,
    avg_member_score, min_member_score, members_below_fair,
    default_history_factor
  ) VALUES (
    v_pool.id, p_circle_id, v_rate, v_previous_rate,
    'Dynamic rate recalculation',
    v_avg_score, v_min_score, v_members_below_fair,
    LEAST(v_total_defaults * 0.0015, 0.0060)
  );

  RETURN v_rate;
END;
$function$
;

CREATE OR REPLACE FUNCTION public.calculate_position_percentile(p_position integer, p_total_positions integer)
 RETURNS numeric
 LANGUAGE plpgsql
 IMMUTABLE
AS $function$
BEGIN
    IF p_total_positions = 0 THEN
        RETURN 0.50;
    END IF;
    RETURN p_position::DECIMAL / p_total_positions::DECIMAL;
END;
$function$
;

CREATE OR REPLACE FUNCTION public.calculate_profile_completion(p_user_id uuid)
 RETURNS integer
 LANGUAGE plpgsql
 STABLE
AS $function$
DECLARE
    v_profile RECORD;
    v_completed INTEGER := 0;
    v_total INTEGER := 10;
BEGIN
    SELECT * INTO v_profile FROM profiles WHERE id = p_user_id;

    IF NOT FOUND THEN
        RETURN 0;
    END IF;

    IF v_profile.full_name IS NOT NULL AND LENGTH(v_profile.full_name) > 0 THEN v_completed := v_completed + 1; END IF;
    IF v_profile.email IS NOT NULL THEN v_completed := v_completed + 1; END IF;
    IF v_profile.phone IS NOT NULL THEN v_completed := v_completed + 1; END IF;
    IF v_profile.date_of_birth IS NOT NULL THEN v_completed := v_completed + 1; END IF;
    IF v_profile.address IS NOT NULL THEN v_completed := v_completed + 1; END IF;
    IF v_profile.city IS NOT NULL THEN v_completed := v_completed + 1; END IF;
    IF v_profile.country IS NOT NULL THEN v_completed := v_completed + 1; END IF;
    IF v_profile.avatar_url IS NOT NULL THEN v_completed := v_completed + 1; END IF;
    IF v_profile.bio IS NOT NULL AND LENGTH(v_profile.bio) >= 20 THEN v_completed := v_completed + 1; END IF;
    IF v_profile.occupation IS NOT NULL THEN v_completed := v_completed + 1; END IF;

    RETURN ROUND((v_completed::DECIMAL / v_total) * 100);
END;
$function$
;

CREATE OR REPLACE FUNCTION public.calculate_removal_settlement(p_circle_id uuid, p_user_id uuid, p_reason removal_reason)
 RETURNS TABLE(settlement_type settlement_type, refund_amount numeric, exit_fee_amount numeric, debt_amount numeric, xn_score_impact integer)
 LANGUAGE plpgsql
 STABLE
AS $function$
DECLARE
    v_position RECORD;
    v_settings circle_removal_settings%ROWTYPE;
    v_circle circles%ROWTYPE;
    v_settlement settlement_type;
    v_refund DECIMAL(15,2) := 0;
    v_fee DECIMAL(15,2) := 0;
    v_debt DECIMAL(15,2) := 0;
    v_xn_impact INTEGER := 0;
BEGIN
    SELECT * INTO v_position FROM get_member_circle_position(p_circle_id, p_user_id);
    SELECT * INTO v_circle FROM circles WHERE id = p_circle_id;
    SELECT * INTO v_settings FROM circle_removal_settings WHERE circle_id = p_circle_id;

    IF v_settings IS NULL THEN
        v_settings.early_exit_fee_percentage := 0.05;
        v_settings.forfeit_on_default := true;
        v_settings.forfeit_on_fraud := true;
    END IF;

    IF v_position.has_received_payout THEN
        v_settlement := 'debt_created';
        v_debt := v_position.remaining_cycles_to_pay * COALESCE(v_circle.amount, 0);
        v_xn_impact := -75;
    ELSE
        CASE p_reason
            WHEN 'voluntary' THEN
                v_settlement := 'partial_refund';
                v_fee := v_position.total_contributed * v_settings.early_exit_fee_percentage;
                v_refund := v_position.total_contributed - v_fee;
                v_xn_impact := -15;
            WHEN 'default', 'fraud' THEN
                IF (p_reason = 'default' AND v_settings.forfeit_on_default) OR (p_reason = 'fraud' AND v_settings.forfeit_on_fraud) THEN
                    v_settlement := 'forfeiture'; v_refund := 0;
                ELSE
                    v_settlement := 'partial_refund';
                    v_fee := v_position.total_contributed * v_settings.early_exit_fee_percentage;
                    v_refund := v_position.total_contributed - v_fee;
                END IF;
                v_xn_impact := CASE p_reason WHEN 'fraud' THEN -100 ELSE -50 END;
            WHEN 'admin', 'emergency' THEN
                v_settlement := 'full_refund'; v_refund := v_position.total_contributed; v_xn_impact := 0;
            WHEN 'rule_violation' THEN
                v_settlement := 'forfeiture'; v_refund := 0; v_xn_impact := -40;
            WHEN 'inactivity' THEN
                v_settlement := 'partial_refund';
                v_fee := v_position.total_contributed * v_settings.early_exit_fee_percentage;
                v_refund := v_position.total_contributed - v_fee;
                v_xn_impact := -20;
            WHEN 'membership_collapse' THEN
                v_settlement := 'full_refund'; v_refund := v_position.total_contributed; v_xn_impact := 0;
            ELSE
                v_settlement := 'no_settlement'; v_xn_impact := 0;
        END CASE;
    END IF;

    RETURN QUERY SELECT v_settlement, v_refund, v_fee, v_debt, v_xn_impact;
END;
$function$
;

CREATE OR REPLACE FUNCTION public.calculate_repayment(p_principal_cents integer, p_apr numeric, p_term_months integer)
 RETURNS TABLE(monthly_payment_cents integer, total_interest_cents integer, total_repayment_cents integer)
 LANGUAGE plpgsql
 IMMUTABLE
AS $function$
DECLARE
    v_monthly_rate DECIMAL;
    v_monthly_payment DECIMAL;
BEGIN
    v_monthly_rate := p_apr / 100 / 12;

    IF v_monthly_rate = 0 THEN
        monthly_payment_cents := ROUND(p_principal_cents::DECIMAL / p_term_months);
        total_interest_cents := 0;
        total_repayment_cents := p_principal_cents;
    ELSE
        -- Standard amortization formula
        v_monthly_payment := p_principal_cents *
            (v_monthly_rate * POWER(1 + v_monthly_rate, p_term_months)) /
            (POWER(1 + v_monthly_rate, p_term_months) - 1);

        monthly_payment_cents := ROUND(v_monthly_payment);
        total_repayment_cents := monthly_payment_cents * p_term_months;
        total_interest_cents := total_repayment_cents - p_principal_cents;
    END IF;

    RETURN NEXT;
END;
$function$
;

CREATE OR REPLACE FUNCTION public.calculate_round_due_date(p_start_date date, p_frequency text, p_round_number integer)
 RETURNS date
 LANGUAGE plpgsql
 IMMUTABLE
AS $function$
DECLARE
    v_due_date DATE;
    v_original_day INTEGER;
    v_last_day_of_month INTEGER;
BEGIN
    v_due_date := p_start_date;
    v_original_day := EXTRACT(DAY FROM p_start_date);

    CASE p_frequency
        WHEN 'daily' THEN
            v_due_date := p_start_date + (p_round_number * INTERVAL '1 day');
        WHEN 'weekly' THEN
            v_due_date := p_start_date + (p_round_number * INTERVAL '7 days');
        WHEN 'biweekly' THEN
            v_due_date := p_start_date + (p_round_number * INTERVAL '14 days');
        WHEN 'monthly' THEN
            v_due_date := p_start_date + (p_round_number * INTERVAL '1 month');
            -- Clamp to valid day if needed (e.g., Jan 31 -> Feb 28)
            v_last_day_of_month := EXTRACT(DAY FROM (DATE_TRUNC('month', v_due_date) + INTERVAL '1 month' - INTERVAL '1 day'));
            IF v_original_day > v_last_day_of_month THEN
                v_due_date := DATE_TRUNC('month', v_due_date) + (v_last_day_of_month - 1) * INTERVAL '1 day';
            END IF;
        WHEN 'quarterly' THEN
            v_due_date := p_start_date + (p_round_number * INTERVAL '3 months');
            v_last_day_of_month := EXTRACT(DAY FROM (DATE_TRUNC('month', v_due_date) + INTERVAL '1 month' - INTERVAL '1 day'));
            IF v_original_day > v_last_day_of_month THEN
                v_due_date := DATE_TRUNC('month', v_due_date) + (v_last_day_of_month - 1) * INTERVAL '1 day';
            END IF;
        ELSE
            v_due_date := p_start_date + (p_round_number * INTERVAL '1 month');
    END CASE;

    RETURN v_due_date;
END;
$function$
;

CREATE OR REPLACE FUNCTION public.calculate_score_breakdown(p_user_id uuid)
 RETURNS jsonb
 LANGUAGE plpgsql
 STABLE
AS $function$
DECLARE
    v_score_record RECORD;
    v_payment RECORD;
    v_completion RECORD;
    v_tenure RECORD;
    v_community RECORD;
    v_financial RECORD;
    v_previous_cache RECORD;

    v_total_calculated DECIMAL;
    v_breakdown JSONB;
    v_components JSONB;
    v_tips JSONB;
BEGIN
    -- Get current score
    SELECT * INTO v_score_record FROM xn_scores WHERE user_id = p_user_id;

    IF NOT FOUND THEN
        RETURN jsonb_build_object('error', 'User score not found');
    END IF;

    -- Get previous cache for trend calculation
    SELECT * INTO v_previous_cache FROM xn_score_breakdown_cache WHERE user_id = p_user_id;

    -- Calculate each factor
    SELECT * INTO v_payment FROM calculate_payment_reliability_factor(p_user_id);
    SELECT * INTO v_completion FROM calculate_circle_completion_factor(p_user_id);
    SELECT * INTO v_tenure FROM calculate_tenure_activity_factor(p_user_id);
    SELECT * INTO v_community FROM calculate_community_standing_factor(p_user_id);
    SELECT * INTO v_financial FROM calculate_financial_behavior_factor(p_user_id);

    -- Sum calculated total
    v_total_calculated := COALESCE(v_payment.total_score, 0) +
                          COALESCE(v_completion.total_score, 0) +
                          COALESCE(v_tenure.total_score, 0) +
                          COALESCE(v_community.total_score, 0) +
                          COALESCE(v_financial.total_score, 0);

    -- Build factor breakdown
    v_breakdown := jsonb_build_object(
        'payment_reliability', jsonb_build_object(
            'score', COALESCE(v_payment.total_score, 0),
            'max_score', 35,
            'weight', 35,
            'status', get_factor_status(COALESCE(v_payment.total_score, 0), 35)::TEXT,
            'trend', get_factor_trend(COALESCE(v_payment.total_score, 0), v_previous_cache.payment_reliability_score)::TEXT,
            'components', jsonb_build_object(
                'on_time_rate', jsonb_build_object('score', v_payment.on_time_rate_score, 'max', 20),
                'payment_streak', jsonb_build_object('score', v_payment.payment_streak_score, 'max', 8),
                'no_defaults', jsonb_build_object('score', v_payment.no_defaults_score, 'max', 5),
                'late_recovery', jsonb_build_object('score', v_payment.late_recovery_score, 'max', 2)
            ),
            'details', v_payment.component_details
        ),
        'circle_completion', jsonb_build_object(
            'score', COALESCE(v_completion.total_score, 0),
            'max_score', 20,
            'weight', 20,
            'status', get_factor_status(COALESCE(v_completion.total_score, 0), 20)::TEXT,
            'trend', get_factor_trend(COALESCE(v_completion.total_score, 0), v_previous_cache.circle_completion_score)::TEXT,
            'components', jsonb_build_object(
                'completion_rate', jsonb_build_object('score', v_completion.completion_rate_score, 'max', 12),
                'full_cycle', jsonb_build_object('score', v_completion.full_cycle_score, 'max', 5),
                'no_abandonment', jsonb_build_object('score', v_completion.no_abandonment_score, 'max', 3)
            ),
            'details', v_completion.component_details
        ),
        'tenure_activity', jsonb_build_object(
            'score', COALESCE(v_tenure.total_score, 0),
            'max_score', 15,
            'weight', 15,
            'status', get_factor_status(COALESCE(v_tenure.total_score, 0), 15)::TEXT,
            'trend', get_factor_trend(COALESCE(v_tenure.total_score, 0), v_previous_cache.tenure_activity_score)::TEXT,
            'components', jsonb_build_object(
                'account_age', jsonb_build_object('score', v_tenure.account_age_score, 'max', 5),
                'tenure_bonus', jsonb_build_object('score', v_tenure.tenure_bonus_score, 'max', 7),
                'recent_activity', jsonb_build_object('score', v_tenure.recent_activity_score, 'max', 3)
            ),
            'details', v_tenure.component_details
        ),
        'community_standing', jsonb_build_object(
            'score', COALESCE(v_community.total_score, 0),
            'max_score', 15,
            'weight', 15,
            'status', get_factor_status(COALESCE(v_community.total_score, 0), 15)::TEXT,
            'trend', get_factor_trend(COALESCE(v_community.total_score, 0), v_previous_cache.community_standing_score)::TEXT,
            'components', jsonb_build_object(
                'vouches_received', jsonb_build_object('score', v_community.vouches_received_score, 'max', 5),
                'member_diversity', jsonb_build_object('score', v_community.member_diversity_score, 'max', 4),
                'elder_connections', jsonb_build_object('score', v_community.elder_connections_score, 'max', 3),
                'vouching_reliability', jsonb_build_object('score', v_community.vouching_reliability_score, 'max', 3)
            ),
            'details', v_community.component_details
        ),
        'financial_behavior', jsonb_build_object(
            'score', COALESCE(v_financial.total_score, 0),
            'max_score', 15,
            'weight', 15,
            'status', get_factor_status(COALESCE(v_financial.total_score, 0), 15)::TEXT,
            'trend', get_factor_trend(COALESCE(v_financial.total_score, 0), v_previous_cache.financial_behavior_score)::TEXT,
            'components', jsonb_build_object(
                'wallet_usage', jsonb_build_object('score', v_financial.wallet_usage_score, 'max', 6),
                'payout_retention', jsonb_build_object('score', v_financial.payout_retention_score, 'max', 5),
                'savings_engagement', jsonb_build_object('score', v_financial.savings_engagement_score, 'max', 4)
            ),
            'details', v_financial.component_details
        )
    );

    -- Get improvement tips
    SELECT get_improvement_tips(p_user_id, 5) INTO v_tips;

    RETURN jsonb_build_object(
        'user_id', p_user_id,
        'total_score', v_score_record.total_score,
        'calculated_total', ROUND(v_total_calculated, 2),
        'tier', v_score_record.score_tier,
        'factors', v_breakdown,
        'improvement_tips', v_tips,
        'calculated_at', now()
    );
END;
$function$
;

CREATE OR REPLACE FUNCTION public.calculate_tenure_activity_factor(p_user_id uuid)
 RETURNS TABLE(total_score numeric, account_age_score numeric, tenure_bonus_score numeric, recent_activity_score numeric, component_details jsonb)
 LANGUAGE plpgsql
 STABLE
AS $function$
DECLARE
    v_score_record RECORD;
    v_profile RECORD;
    v_account_months INTEGER;
    v_tenure_bonus DECIMAL;
    v_is_active BOOLEAN;

    v_age_score DECIMAL := 0;
    v_tenure_score DECIMAL := 0;
    v_activity_score DECIMAL := 0;
    v_details JSONB;
BEGIN
    -- Get score and profile records
    SELECT * INTO v_score_record FROM xn_scores WHERE user_id = p_user_id;
    SELECT * INTO v_profile FROM profiles WHERE id = p_user_id;

    IF v_score_record IS NULL OR v_profile IS NULL THEN
        RETURN QUERY SELECT 0::DECIMAL, 0::DECIMAL, 0::DECIMAL, 0::DECIMAL, '{}'::JSONB;
        RETURN;
    END IF;

    -- Calculate account age in months
    v_account_months := EXTRACT(MONTH FROM age(now(), v_profile.created_at))::INTEGER +
                        (EXTRACT(YEAR FROM age(now(), v_profile.created_at))::INTEGER * 12);

    v_tenure_bonus := COALESCE(v_score_record.tenure_bonus, 0);
    v_is_active := is_user_financially_active(p_user_id, 30);

    -- Account age score (5 pts max) - based on 18 month cap
    v_age_score := LEAST(5, (LEAST(v_account_months, 18)::DECIMAL / 18) * 5);

    -- Tenure bonus score (7 pts max) - based on max 25 tenure bonus
    v_tenure_score := LEAST(7, (v_tenure_bonus / 25) * 7);

    -- Recent activity score (3 pts)
    IF v_is_active THEN
        v_activity_score := 3;
    END IF;

    v_details := jsonb_build_object(
        'account_age_months', v_account_months,
        'account_age_days', COALESCE(v_score_record.account_age_days, 0),
        'tenure_bonus_earned', v_tenure_bonus,
        'tenure_months_earned', COALESCE(v_score_record.tenure_months_earned, 0),
        'max_tenure_bonus', 25,
        'is_recently_active', v_is_active,
        'last_activity_at', v_score_record.last_financial_activity_at,
        'financial_inactive_days', COALESCE(v_score_record.financial_inactive_days, 0),
        'in_recovery_period', COALESCE(v_score_record.in_recovery_period, FALSE)
    );

    RETURN QUERY SELECT
        ROUND(v_age_score + v_tenure_score + v_activity_score, 2),
        ROUND(v_age_score, 2),
        ROUND(v_tenure_score, 2),
        ROUND(v_activity_score, 2),
        v_details;
END;
$function$
;

CREATE OR REPLACE FUNCTION public.calculate_total_decay_penalty(p_inactive_days integer)
 RETURNS numeric
 LANGUAGE plpgsql
 IMMUTABLE
AS $function$
DECLARE
    v_total DECIMAL(5,2) := 0;
BEGIN
    -- Cumulative decay based on thresholds passed
    IF p_inactive_days >= 30 THEN v_total := v_total + 3; END IF;
    IF p_inactive_days >= 60 THEN v_total := v_total + 6; END IF;
    IF p_inactive_days >= 90 THEN v_total := v_total + 10; END IF;
    IF p_inactive_days >= 120 THEN v_total := v_total + 15; END IF;
    IF p_inactive_days >= 180 THEN v_total := v_total + 20; END IF;
    IF p_inactive_days >= 240 THEN v_total := v_total + 25; END IF;
    IF p_inactive_days >= 365 THEN v_total := v_total + 30; END IF;

    RETURN v_total;
END;
$function$
;

CREATE OR REPLACE FUNCTION public.calculate_trust_score(p_user_id uuid, p_other_user_id uuid)
 RETURNS integer
 LANGUAGE plpgsql
AS $function$
DECLARE
    v_connection_type VARCHAR(50);
    v_circles_together INTEGER;
    v_successful_circles INTEGER;
    v_base_score INTEGER;
BEGIN
    -- Get connection info
    SELECT connection_type, circles_together, successful_circles
    INTO v_connection_type, v_circles_together, v_successful_circles
    FROM user_connections
    WHERE user_id = p_user_id AND connected_user_id = p_other_user_id AND status = 'active';

    IF v_connection_type IS NULL THEN
        -- Check for indirect connection
        v_connection_type := get_connection_type(p_user_id, p_other_user_id);
        v_circles_together := 0;
        v_successful_circles := 0;
    END IF;

    -- Base score by connection type
    v_base_score := CASE v_connection_type
        WHEN 'family' THEN 90
        WHEN 'close_friend' THEN 85
        WHEN 'friend' THEN 70
        WHEN 'colleague' THEN 65
        WHEN 'acquaintance' THEN 40
        ELSE 20
    END;

    -- Bonus for successful circles together
    IF v_circles_together > 0 THEN
        v_base_score := v_base_score + LEAST(20, v_successful_circles * 5);
    END IF;

    RETURN LEAST(100, v_base_score);
END;
$function$
;

CREATE OR REPLACE FUNCTION public.calculate_user_obligations(p_user_id uuid)
 RETURNS numeric
 LANGUAGE plpgsql
AS $function$
DECLARE
    total_obligations DECIMAL(12,2) := 0;
BEGIN
    SELECT COALESCE(SUM(
        CASE c.frequency
            WHEN 'weekly' THEN c.amount * 4.33
            WHEN 'biweekly' THEN c.amount * 2.17
            WHEN 'monthly' THEN c.amount
            ELSE c.amount
        END
    ), 0)
    INTO total_obligations
    FROM circle_members cm
    JOIN circles c ON c.id = cm.circle_id
    WHERE cm.user_id = p_user_id
      AND cm.status IN ('active', 'pending')
      AND c.status IN ('active', 'pending', 'forming');

    RETURN total_obligations;
END;
$function$
;

CREATE OR REPLACE FUNCTION public.calculate_vouch_value(p_voucher_id uuid, p_vouchee_id uuid)
 RETURNS TABLE(raw_value numeric, diluted_value numeric, dilution_factor numeric, voucher_score numeric, sequence_number integer)
 LANGUAGE plpgsql
 STABLE
AS $function$
DECLARE
    v_voucher_score DECIMAL;
    v_existing_vouches INTEGER;
    v_base_value DECIMAL;
    v_dilution DECIMAL;
BEGIN
    -- Get voucher's score
    SELECT total_score INTO v_voucher_score
    FROM xn_scores WHERE user_id = p_voucher_id;

    IF v_voucher_score IS NULL THEN
        RETURN QUERY SELECT 0::DECIMAL, 0::DECIMAL, 1::DECIMAL, 0::DECIMAL, 0;
        RETURN;
    END IF;

    -- Count existing vouches for this vouchee
    SELECT COUNT(*) INTO v_existing_vouches
    FROM vouches
    WHERE vouchee_user_id = p_vouchee_id AND vouch_status = 'active';

    -- Base value based on voucher's score
    IF v_voucher_score >= 90 THEN
        v_base_value := 2.0;
    ELSIF v_voucher_score >= 80 THEN
        v_base_value := 1.5;
    ELSIF v_voucher_score >= 70 THEN
        v_base_value := 1.0;
    ELSE
        v_base_value := 0.5;
    END IF;

    -- Dilution: each additional vouch is worth less
    -- 1st vouch: 100%, 2nd: 50%, 3rd: 25%, etc.
    v_dilution := POWER(0.5, v_existing_vouches);

    RETURN QUERY SELECT
        v_base_value,
        v_base_value * v_dilution,
        v_dilution,
        v_voucher_score,
        v_existing_vouches + 1;
END;
$function$
;

CREATE OR REPLACE FUNCTION public.calculate_voucher_reliability(p_user_id uuid)
 RETURNS text
 LANGUAGE plpgsql
AS $function$
DECLARE
    v_total_vouchee_defaults INTEGER;
BEGIN
    SELECT COUNT(*) INTO v_total_vouchee_defaults
    FROM voucher_default_impacts
    WHERE voucher_user_id = p_user_id;

    IF v_total_vouchee_defaults >= 5 THEN
        RETURN 'restricted';
    ELSIF v_total_vouchee_defaults >= 3 THEN
        RETURN 'poor';
    ELSIF v_total_vouchee_defaults >= 2 THEN
        RETURN 'warning';
    ELSE
        RETURN 'good';
    END IF;
END;
$function$
;

CREATE OR REPLACE FUNCTION public.calculate_xnscore_credit_score(p_xnscore numeric)
 RETURNS integer
 LANGUAGE plpgsql
 IMMUTABLE
AS $function$
BEGIN
    -- Formula: CreditScore = 300 + (XnScore × 5.5)
    RETURN LEAST(850, GREATEST(300, ROUND(300 + (p_xnscore * 5.5))::INTEGER));
END;
$function$
;

CREATE OR REPLACE FUNCTION public.can_claim_urgent_need(p_user_id uuid)
 RETURNS boolean
 LANGUAGE plpgsql
AS $function$
DECLARE
    last_claim_date DATE;
BEGIN
    SELECT MAX(next_eligible_date) INTO last_claim_date
    FROM urgent_need_claims
    WHERE user_id = p_user_id AND verified = true;

    IF last_claim_date IS NULL THEN
        RETURN true;
    END IF;

    RETURN CURRENT_DATE >= last_claim_date;
END;
$function$
;

CREATE OR REPLACE FUNCTION public.can_request_swap(p_circle_id uuid, p_requester_id uuid, p_target_id uuid, p_requester_position integer, p_target_position integer)
 RETURNS TABLE(allowed boolean, reason text)
 LANGUAGE plpgsql
 STABLE
AS $function$
DECLARE
    v_config JSONB;
    v_circle RECORD;
    v_requester_member RECORD;
    v_target_member RECORD;
    v_requester_xn INTEGER;
    v_target_xn INTEGER;
    v_requester_swaps INTEGER;
    v_target_swaps INTEGER;
    v_circle_swaps INTEGER;
    v_cycles_to_payout INTEGER;
BEGIN
    -- Get config
    v_config := get_circle_swap_config(p_circle_id);

    -- Check if swaps are enabled
    IF NOT (v_config->>'swaps_enabled')::BOOLEAN THEN
        RETURN QUERY SELECT false, 'Position swaps are disabled for this circle';
        RETURN;
    END IF;

    -- Get circle details
    SELECT * INTO v_circle FROM circles WHERE id = p_circle_id;
    IF NOT FOUND THEN
        RETURN QUERY SELECT false, 'Circle not found';
        RETURN;
    END IF;

    -- Check circle status
    IF v_circle.status NOT IN ('active', 'in_progress') THEN
        RETURN QUERY SELECT false, 'Circle must be active to swap positions';
        RETURN;
    END IF;

    -- Verify both users are active members
    SELECT * INTO v_requester_member
    FROM circle_members
    WHERE circle_id = p_circle_id AND user_id = p_requester_id AND status = 'active';

    IF NOT FOUND THEN
        RETURN QUERY SELECT false, 'Requester is not an active member';
        RETURN;
    END IF;

    SELECT * INTO v_target_member
    FROM circle_members
    WHERE circle_id = p_circle_id AND user_id = p_target_id AND status = 'active';

    IF NOT FOUND THEN
        RETURN QUERY SELECT false, 'Target is not an active member';
        RETURN;
    END IF;

    -- Check for existing pending swap involving either user
    IF EXISTS (
        SELECT 1 FROM position_swap_requests
        WHERE circle_id = p_circle_id
        AND swap_status IN ('pending_target', 'pending_confirmation', 'pending_elder_approval', 'approved')
        AND (requester_user_id IN (p_requester_id, p_target_id) OR target_user_id IN (p_requester_id, p_target_id))
    ) THEN
        RETURN QUERY SELECT false, 'There is already a pending swap request involving one of these members';
        RETURN;
    END IF;

    -- Get XnScores
    SELECT COALESCE(xn_score, 50) INTO v_requester_xn FROM profiles WHERE id = p_requester_id;
    SELECT COALESCE(xn_score, 50) INTO v_target_xn FROM profiles WHERE id = p_target_id;

    -- Check XnScore for early positions
    IF p_target_position <= (v_config->>'early_position_threshold')::INTEGER THEN
        IF v_requester_xn < (v_config->>'min_xn_score_for_early_position')::INTEGER THEN
            RETURN QUERY SELECT false,
                format('XnScore of %s required for early positions (you have %s)',
                    (v_config->>'min_xn_score_for_early_position')::INTEGER, v_requester_xn);
            RETURN;
        END IF;
    END IF;

    -- Check max swaps per member per cycle
    SELECT COUNT(*) INTO v_requester_swaps
    FROM member_swap_history
    WHERE user_id = p_requester_id
    AND circle_id = p_circle_id
    AND cycle_number = COALESCE(v_circle.current_cycle, 1);

    IF v_requester_swaps >= (v_config->>'max_swaps_per_member_per_cycle')::INTEGER THEN
        RETURN QUERY SELECT false, 'You have reached your swap limit for this cycle';
        RETURN;
    END IF;

    SELECT COUNT(*) INTO v_target_swaps
    FROM member_swap_history
    WHERE user_id = p_target_id
    AND circle_id = p_circle_id
    AND cycle_number = COALESCE(v_circle.current_cycle, 1);

    IF v_target_swaps >= (v_config->>'max_swaps_per_member_per_cycle')::INTEGER THEN
        RETURN QUERY SELECT false, 'Target member has reached their swap limit for this cycle';
        RETURN;
    END IF;

    -- Check max swaps per cycle for circle
    SELECT COUNT(*) INTO v_circle_swaps
    FROM position_swap_requests
    WHERE circle_id = p_circle_id
    AND cycle_number = COALESCE(v_circle.current_cycle, 1)
    AND swap_status = 'completed';

    IF v_circle_swaps >= (v_config->>'max_swaps_per_cycle')::INTEGER THEN
        RETURN QUERY SELECT false, 'Maximum swaps for this cycle have been reached';
        RETURN;
    END IF;

    -- Check blackout period (if either position is close to payout)
    v_cycles_to_payout := LEAST(
        p_requester_position - COALESCE(v_circle.current_cycle, 1),
        p_target_position - COALESCE(v_circle.current_cycle, 1)
    );

    IF v_cycles_to_payout >= 0 AND v_cycles_to_payout < (v_config->>'blackout_cycles_before_payout')::INTEGER THEN
        RETURN QUERY SELECT false, 'Cannot swap - too close to payout cycle (blackout period)';
        RETURN;
    END IF;

    -- All checks passed
    RETURN QUERY SELECT true, 'Swap request allowed';
END;
$function$
;

CREATE OR REPLACE FUNCTION public.cancel_deletion_request(p_user_id uuid)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
BEGIN
    UPDATE user_deletion_requests
    SET status = 'cancelled', processed_at = NOW()
    WHERE user_id = p_user_id
    AND status = 'pending';

    IF NOT FOUND THEN
        RETURN jsonb_build_object('error', 'No pending deletion request found');
    END IF;

    RETURN jsonb_build_object(
        'success', true,
        'message', 'Your account deletion request has been cancelled'
    );
END;
$function$
;

CREATE OR REPLACE FUNCTION public.cancel_dissolution(p_dissolution_id uuid, p_cancelled_by uuid, p_reason text)
 RETURNS boolean
 LANGUAGE plpgsql
 SECURITY DEFINER
AS $function$
DECLARE
    v_dissolution dissolution_requests%ROWTYPE;
BEGIN
    -- Get dissolution request
    SELECT * INTO v_dissolution FROM dissolution_requests WHERE id = p_dissolution_id;

    IF NOT FOUND THEN
        RAISE EXCEPTION 'Dissolution request not found';
    END IF;

    -- Can only cancel if in early stages
    IF v_dissolution.status NOT IN ('proposed', 'voting') THEN
        RAISE EXCEPTION 'Dissolution cannot be cancelled at this stage';
    END IF;

    -- Only initiator or admin can cancel
    IF v_dissolution.initiated_by != p_cancelled_by THEN
        -- Check if admin (would need admin check here)
        RAISE EXCEPTION 'Only the initiator can cancel this dissolution request';
    END IF;

    -- Update status
    UPDATE dissolution_requests
    SET
        status = 'cancelled',
        resolved_at = now(),
        resolved_by = p_cancelled_by,
        resolution_notes = p_reason,
        updated_at = now()
    WHERE id = p_dissolution_id;

    -- Record event
    INSERT INTO dissolution_events (
        dissolution_request_id,
        event_type,
        event_description,
        actor_id,
        new_state
    ) VALUES (
        p_dissolution_id,
        'dissolution_cancelled',
        'Dissolution cancelled: ' || p_reason,
        p_cancelled_by,
        jsonb_build_object('reason', p_reason)
    );

    RETURN true;
END;
$function$
;

CREATE OR REPLACE FUNCTION public.cancel_removal_request(p_removal_request_id uuid, p_cancelled_by uuid, p_reason text)
 RETURNS boolean
 LANGUAGE plpgsql
 SECURITY DEFINER
AS $function$
DECLARE v_request member_removal_requests%ROWTYPE;
BEGIN
    SELECT * INTO v_request FROM member_removal_requests WHERE id = p_removal_request_id;
    IF NOT FOUND THEN RAISE EXCEPTION 'Not found'; END IF;
    IF v_request.status != 'pending_approval' THEN RAISE EXCEPTION 'Only pending can be cancelled'; END IF;
    IF v_request.can_be_cancelled_until IS NOT NULL AND v_request.can_be_cancelled_until < now() THEN RAISE EXCEPTION 'Window passed'; END IF;
    IF v_request.initiated_by != p_cancelled_by AND NOT EXISTS (SELECT 1 FROM circle_members WHERE circle_id = v_request.circle_id AND user_id = p_cancelled_by AND role IN ('elder', 'admin', 'creator')) THEN
        RAISE EXCEPTION 'Only initiator or Elder can cancel';
    END IF;
    UPDATE member_removal_requests SET status = 'cancelled', resolved_at = now(), resolved_by = p_cancelled_by, resolution_notes = p_reason, updated_at = now() WHERE id = p_removal_request_id;
    RETURN true;
END;
$function$
;

CREATE OR REPLACE FUNCTION public.cancel_swap_request(p_request_id uuid, p_user_id uuid, p_reason text DEFAULT NULL::text)
 RETURNS boolean
 LANGUAGE plpgsql
 SECURITY DEFINER
AS $function$
DECLARE
    v_request position_swap_requests%ROWTYPE;
    v_xn_penalty INTEGER := 0;
BEGIN
    -- Get the request
    SELECT * INTO v_request FROM position_swap_requests WHERE id = p_request_id;

    IF NOT FOUND THEN
        RAISE EXCEPTION 'Swap request not found';
    END IF;

    -- Only requester can cancel, or elder can cancel at any time
    IF v_request.requester_user_id != p_user_id THEN
        IF NOT EXISTS (
            SELECT 1 FROM circle_members
            WHERE circle_id = v_request.circle_id
            AND user_id = p_user_id
            AND role IN ('elder', 'admin', 'creator')
        ) THEN
            RAISE EXCEPTION 'Only the requester or an Elder can cancel this request';
        END IF;
    END IF;

    -- Check status - cannot cancel completed or already cancelled
    IF v_request.swap_status IN ('completed', 'cancelled', 'expired', 'rejected', 'elder_denied') THEN
        RAISE EXCEPTION 'Cannot cancel a request that is already %', v_request.swap_status;
    END IF;

    -- XnScore penalty if cancelling after target accepted
    IF v_request.swap_status IN ('pending_confirmation', 'pending_elder_approval', 'approved') THEN
        v_xn_penalty := -2;
        UPDATE profiles SET xn_score = GREATEST(0, xn_score + v_xn_penalty) WHERE id = v_request.requester_user_id;
    END IF;

    -- Update status
    UPDATE position_swap_requests SET
        swap_status = 'cancelled',
        updated_at = now()
    WHERE id = p_request_id;

    INSERT INTO position_swap_events (
        swap_request_id, event_type, actor_user_id, actor_role, event_details, xn_score_change
    ) VALUES (
        p_request_id, 'requester_cancelled', p_user_id,
        CASE WHEN v_request.requester_user_id = p_user_id THEN 'requester' ELSE 'elder' END,
        COALESCE(p_reason, 'Cancelled swap request'),
        v_xn_penalty
    );

    RETURN true;
END;
$function$
;

CREATE OR REPLACE FUNCTION public.cast_dissolution_vote(p_dissolution_id uuid, p_user_id uuid, p_vote dissolution_vote_type, p_reason text DEFAULT NULL::text)
 RETURNS boolean
 LANGUAGE plpgsql
 SECURITY DEFINER
AS $function$
DECLARE
    v_dissolution dissolution_requests%ROWTYPE;
    v_existing_vote dissolution_vote_type;
BEGIN
    -- Get dissolution request
    SELECT * INTO v_dissolution FROM dissolution_requests WHERE id = p_dissolution_id;

    IF NOT FOUND THEN
        RAISE EXCEPTION 'Dissolution request not found';
    END IF;

    -- Check if voting is open
    IF v_dissolution.status != 'voting' THEN
        RAISE EXCEPTION 'Voting is not open for this dissolution request';
    END IF;

    -- Check if voting period has ended
    IF v_dissolution.voting_ends_at < now() THEN
        RAISE EXCEPTION 'Voting period has ended';
    END IF;

    -- Check if user is a member of the circle
    IF NOT EXISTS (
        SELECT 1 FROM circle_members
        WHERE circle_id = v_dissolution.circle_id
        AND user_id = p_user_id
        AND status = 'active'
    ) THEN
        RAISE EXCEPTION 'User is not an active member of this circle';
    END IF;

    -- Check for existing vote
    SELECT vote INTO v_existing_vote
    FROM dissolution_votes
    WHERE dissolution_request_id = p_dissolution_id
    AND user_id = p_user_id;

    IF FOUND THEN
        -- Update existing vote
        UPDATE dissolution_votes
        SET vote = p_vote, reason = p_reason, updated_at = now()
        WHERE dissolution_request_id = p_dissolution_id
        AND user_id = p_user_id;

        -- Update vote counts
        UPDATE dissolution_requests
        SET
            votes_for = votes_for + CASE WHEN p_vote = 'approve' THEN 1 ELSE 0 END - CASE WHEN v_existing_vote = 'approve' THEN 1 ELSE 0 END,
            votes_against = votes_against + CASE WHEN p_vote = 'reject' THEN 1 ELSE 0 END - CASE WHEN v_existing_vote = 'reject' THEN 1 ELSE 0 END,
            votes_abstain = votes_abstain + CASE WHEN p_vote = 'abstain' THEN 1 ELSE 0 END - CASE WHEN v_existing_vote = 'abstain' THEN 1 ELSE 0 END
        WHERE id = p_dissolution_id;
    ELSE
        -- Insert new vote
        INSERT INTO dissolution_votes (dissolution_request_id, user_id, vote, reason)
        VALUES (p_dissolution_id, p_user_id, p_vote, p_reason);

        -- Update vote counts
        UPDATE dissolution_requests
        SET
            votes_for = votes_for + CASE WHEN p_vote = 'approve' THEN 1 ELSE 0 END,
            votes_against = votes_against + CASE WHEN p_vote = 'reject' THEN 1 ELSE 0 END,
            votes_abstain = votes_abstain + CASE WHEN p_vote = 'abstain' THEN 1 ELSE 0 END
        WHERE id = p_dissolution_id;
    END IF;

    -- Record event
    INSERT INTO dissolution_events (
        dissolution_request_id,
        event_type,
        event_description,
        actor_id,
        new_state
    ) VALUES (
        p_dissolution_id,
        'vote_cast',
        'Member cast vote: ' || p_vote::TEXT,
        p_user_id,
        jsonb_build_object('vote', p_vote, 'reason', p_reason)
    );

    RETURN true;
END;
$function$
;

CREATE OR REPLACE FUNCTION public.cast_proposal_vote(p_proposal_id uuid, p_voter_id uuid, p_vote text, p_reasoning text DEFAULT NULL::text)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
AS $function$
DECLARE
  v_proposal RECORD;
  v_settings RECORD;
  v_member RECORD;
  v_existing_vote RECORD;
  v_vote_weight DECIMAL(3,2) := 1.00;
  v_total_voted INTEGER;
  v_result TEXT;
BEGIN
  IF p_vote NOT IN ('yes', 'no', 'abstain') THEN
    RAISE EXCEPTION 'Invalid vote: %. Must be yes, no, or abstain.', p_vote;
  END IF;

  SELECT * INTO v_proposal FROM circle_proposals WHERE id = p_proposal_id;
  IF v_proposal IS NULL THEN
    RAISE EXCEPTION 'Proposal not found';
  END IF;
  IF v_proposal.status != 'open' THEN
    RAISE EXCEPTION 'Proposal is not open for voting (status: %)', v_proposal.status;
  END IF;
  IF v_proposal.voting_ends_at IS NOT NULL AND v_proposal.voting_ends_at <= NOW() THEN
    RAISE EXCEPTION 'Voting period has ended';
  END IF;

  SELECT * INTO v_member FROM circle_members
  WHERE circle_id = v_proposal.circle_id AND user_id = p_voter_id AND status = 'active';
  IF v_member IS NULL THEN
    RAISE EXCEPTION 'Voter is not an active circle member';
  END IF;

  SELECT * INTO v_settings FROM circle_governance_settings
  WHERE circle_id = v_proposal.circle_id;

  IF v_settings IS NOT NULL AND v_settings.enable_weighted_voting THEN
    IF v_member.role = 'creator' THEN
      v_vote_weight := v_settings.creator_vote_weight;
    ELSIF v_member.role = 'admin' THEN
      v_vote_weight := v_settings.admin_vote_weight;
    END IF;
  END IF;

  SELECT * INTO v_existing_vote FROM circle_proposal_votes
  WHERE proposal_id = p_proposal_id AND voter_id = p_voter_id;

  IF v_existing_vote IS NOT NULL THEN
    IF v_settings IS NOT NULL AND NOT v_settings.allow_vote_change THEN
      RAISE EXCEPTION 'Vote changes are not allowed for this circle';
    END IF;

    UPDATE circle_proposals SET
      votes_for = votes_for - CASE WHEN v_existing_vote.vote = 'yes' THEN 1 ELSE 0 END,
      votes_against = votes_against - CASE WHEN v_existing_vote.vote = 'no' THEN 1 ELSE 0 END,
      votes_abstain = votes_abstain - CASE WHEN v_existing_vote.vote = 'abstain' THEN 1 ELSE 0 END,
      total_vote_weight = total_vote_weight - v_existing_vote.vote_weight,
      weight_for = weight_for - CASE WHEN v_existing_vote.vote = 'yes' THEN v_existing_vote.vote_weight ELSE 0 END,
      weight_against = weight_against - CASE WHEN v_existing_vote.vote = 'no' THEN v_existing_vote.vote_weight ELSE 0 END
    WHERE id = p_proposal_id;

    UPDATE circle_proposal_votes SET
      vote = p_vote,
      vote_weight = v_vote_weight,
      reasoning = COALESCE(p_reasoning, reasoning),
      updated_at = NOW()
    WHERE id = v_existing_vote.id;
  ELSE
    INSERT INTO circle_proposal_votes (proposal_id, voter_id, vote, vote_weight, reasoning)
    VALUES (p_proposal_id, p_voter_id, p_vote, v_vote_weight, p_reasoning);
  END IF;

  UPDATE circle_proposals SET
    votes_for = votes_for + CASE WHEN p_vote = 'yes' THEN 1 ELSE 0 END,
    votes_against = votes_against + CASE WHEN p_vote = 'no' THEN 1 ELSE 0 END,
    votes_abstain = votes_abstain + CASE WHEN p_vote = 'abstain' THEN 1 ELSE 0 END,
    total_vote_weight = total_vote_weight + v_vote_weight,
    weight_for = weight_for + CASE WHEN p_vote = 'yes' THEN v_vote_weight ELSE 0 END,
    weight_against = weight_against + CASE WHEN p_vote = 'no' THEN v_vote_weight ELSE 0 END,
    updated_at = NOW()
  WHERE id = p_proposal_id;

  IF v_settings IS NOT NULL AND v_settings.close_on_all_voted THEN
    SELECT COUNT(*) INTO v_total_voted FROM circle_proposal_votes
    WHERE proposal_id = p_proposal_id;

    SELECT * INTO v_proposal FROM circle_proposals WHERE id = p_proposal_id;

    IF v_total_voted >= v_proposal.eligible_voters THEN
      v_result := tally_proposal(p_proposal_id);
      RETURN jsonb_build_object(
        'success', true, 'vote', p_vote, 'weight', v_vote_weight,
        'early_close', true, 'result', v_result
      );
    END IF;
  END IF;

  RETURN jsonb_build_object(
    'success', true, 'vote', p_vote, 'weight', v_vote_weight,
    'early_close', false
  );
END;
$function$
;

CREATE OR REPLACE FUNCTION public.cast_removal_vote(p_removal_request_id uuid, p_user_id uuid, p_vote text, p_reason text DEFAULT NULL::text)
 RETURNS boolean
 LANGUAGE plpgsql
 SECURITY DEFINER
AS $function$
DECLARE
    v_request member_removal_requests%ROWTYPE;
    v_existing_vote TEXT;
BEGIN
    SELECT * INTO v_request FROM member_removal_requests WHERE id = p_removal_request_id;
    IF NOT FOUND THEN RAISE EXCEPTION 'Removal request not found'; END IF;
    IF v_request.status != 'pending_approval' OR NOT v_request.requires_vote THEN RAISE EXCEPTION 'Voting is not open'; END IF;
    IF v_request.voting_ends_at < now() THEN RAISE EXCEPTION 'Voting period has ended'; END IF;
    IF p_user_id = v_request.member_user_id THEN RAISE EXCEPTION 'Cannot vote on own removal'; END IF;
    IF NOT EXISTS (SELECT 1 FROM circle_members WHERE circle_id = v_request.circle_id AND user_id = p_user_id) THEN
        RAISE EXCEPTION 'User is not a member of this circle';
    END IF;

    SELECT vote INTO v_existing_vote FROM removal_votes WHERE removal_request_id = p_removal_request_id AND user_id = p_user_id;

    IF FOUND THEN
        UPDATE removal_votes SET vote = p_vote, reason = p_reason, updated_at = now() WHERE removal_request_id = p_removal_request_id AND user_id = p_user_id;
        UPDATE member_removal_requests SET
            votes_for = votes_for + CASE WHEN p_vote = 'approve' THEN 1 ELSE 0 END - CASE WHEN v_existing_vote = 'approve' THEN 1 ELSE 0 END,
            votes_against = votes_against + CASE WHEN p_vote = 'reject' THEN 1 ELSE 0 END - CASE WHEN v_existing_vote = 'reject' THEN 1 ELSE 0 END,
            votes_abstain = votes_abstain + CASE WHEN p_vote = 'abstain' THEN 1 ELSE 0 END - CASE WHEN v_existing_vote = 'abstain' THEN 1 ELSE 0 END
        WHERE id = p_removal_request_id;
    ELSE
        INSERT INTO removal_votes (removal_request_id, user_id, vote, reason) VALUES (p_removal_request_id, p_user_id, p_vote, p_reason);
        UPDATE member_removal_requests SET
            votes_for = votes_for + CASE WHEN p_vote = 'approve' THEN 1 ELSE 0 END,
            votes_against = votes_against + CASE WHEN p_vote = 'reject' THEN 1 ELSE 0 END,
            votes_abstain = votes_abstain + CASE WHEN p_vote = 'abstain' THEN 1 ELSE 0 END
        WHERE id = p_removal_request_id;
    END IF;

    RETURN true;
END;
$function$
;

CREATE OR REPLACE FUNCTION public.check_affordability_quick(p_user_id uuid, p_circle_amount numeric, p_frequency character varying DEFAULT 'monthly'::character varying)
 RETURNS TABLE(can_afford boolean, score integer, risk_level character varying, current_ratio numeric, proposed_ratio numeric, max_affordable numeric, reason text)
 LANGUAGE plpgsql
AS $function$
DECLARE
    v_monthly_income DECIMAL(12,2);
    v_income_source VARCHAR(50);
    v_adjusted_income DECIMAL(12,2);
    v_current_obligations DECIMAL(12,2);
    v_new_obligation DECIMAL(12,2);
    v_total_obligations DECIMAL(12,2);
    v_current_ratio DECIMAL(5,4);
    v_proposed_ratio DECIMAL(5,4);
    v_max_ratio DECIMAL(5,4) := 0.30; -- Default max ratio
    v_can_afford BOOLEAN;
    v_score INTEGER;
    v_risk_level VARCHAR(20);
    v_max_affordable DECIMAL(12,2);
    v_reason TEXT;
BEGIN
    -- Get user's income
    SELECT COALESCE(fp.monthly_income, p.monthly_income, 0),
           COALESCE(fp.income_source, p.income_source, 'self_reported')
    INTO v_monthly_income, v_income_source
    FROM profiles p
    LEFT JOIN financial_profiles fp ON fp.user_id = p.id
    WHERE p.id = p_user_id;

    -- Check if income is available
    IF v_monthly_income IS NULL OR v_monthly_income = 0 THEN
        RETURN QUERY SELECT
            false::BOOLEAN,
            0::INTEGER,
            'critical'::VARCHAR(20),
            0::DECIMAL(5,4),
            0::DECIMAL(5,4),
            0::DECIMAL(12,2),
            'No income information available. Please complete your financial profile.'::TEXT;
        RETURN;
    END IF;

    -- Adjust income for unverified sources
    v_adjusted_income := CASE
        WHEN v_income_source = 'self_reported' THEN v_monthly_income * 0.80
        ELSE v_monthly_income
    END;

    -- Get current obligations
    v_current_obligations := calculate_user_obligations(p_user_id);

    -- Calculate new obligation in monthly terms
    v_new_obligation := CASE p_frequency
        WHEN 'weekly' THEN p_circle_amount * 4.33
        WHEN 'biweekly' THEN p_circle_amount * 2.17
        WHEN 'monthly' THEN p_circle_amount
        ELSE p_circle_amount
    END;

    v_total_obligations := v_current_obligations + v_new_obligation;

    -- Calculate ratios
    v_current_ratio := v_current_obligations / v_adjusted_income;
    v_proposed_ratio := v_total_obligations / v_adjusted_income;

    -- Calculate max affordable
    v_max_affordable := GREATEST(0, (v_adjusted_income * v_max_ratio) - v_current_obligations);

    -- Determine result
    IF v_proposed_ratio <= 0.15 THEN
        v_can_afford := true;
        v_risk_level := 'low';
        v_score := 90;
        v_reason := 'Comfortably affordable';
    ELSIF v_proposed_ratio <= 0.20 THEN
        v_can_afford := true;
        v_risk_level := 'medium';
        v_score := 75;
        v_reason := 'Affordable with moderate commitment';
    ELSIF v_proposed_ratio <= v_max_ratio THEN
        v_can_afford := true;
        v_risk_level := 'high';
        v_score := 55;
        v_reason := 'Near maximum recommended obligations';
    ELSE
        v_can_afford := false;
        v_risk_level := 'critical';
        v_score := 30;
        v_reason := 'Exceeds maximum recommended obligations (' || ROUND(v_max_ratio * 100) || '% of income)';
    END IF;

    RETURN QUERY SELECT
        v_can_afford,
        v_score,
        v_risk_level,
        v_current_ratio,
        v_proposed_ratio,
        v_max_affordable,
        v_reason;
END;
$function$
;

CREATE OR REPLACE FUNCTION public.check_and_apply_recovery_multiplier(p_user_id uuid, p_base_amount numeric)
 RETURNS numeric
 LANGUAGE plpgsql
AS $function$
DECLARE
    v_score RECORD;
    v_multiplied DECIMAL;
BEGIN
    SELECT * INTO v_score FROM xn_scores WHERE user_id = p_user_id;

    IF NOT FOUND THEN
        RETURN p_base_amount;
    END IF;

    -- Check if in active recovery period
    IF v_score.in_recovery_period AND v_score.recovery_ends_at > now() THEN
        v_multiplied := p_base_amount * COALESCE(v_score.recovery_multiplier, 1.5);

        -- Track usage
        UPDATE xnscore_recovery_periods SET
            bonus_events_during_recovery = bonus_events_during_recovery + 1,
            total_bonus_earned_during = total_bonus_earned_during + (v_multiplied - p_base_amount),
            updated_at = now()
        WHERE id = v_score.recovery_period_id;

        RETURN v_multiplied;
    END IF;

    RETURN p_base_amount;
END;
$function$
;

CREATE OR REPLACE FUNCTION public.check_circle_eligibility(p_user_id uuid, p_circle_id uuid)
 RETURNS TABLE(eligible boolean, reason text, code text, current_score numeric, required_score integer, position_restrictions jsonb)
 LANGUAGE plpgsql
 STABLE
AS $function$
DECLARE
    v_score RECORD;
    v_circle RECORD;
    v_contribution_amount DECIMAL;
    v_min_required INTEGER;
    v_active_defaults INTEGER;
    v_fraud_frozen BOOLEAN;
    v_position_restrictions JSONB;
BEGIN
    -- Get XnScore
    SELECT * INTO v_score FROM xn_scores WHERE xn_scores.user_id = p_user_id;

    IF NOT FOUND THEN
        RETURN QUERY SELECT
            FALSE, 'No XnScore calculated'::TEXT, 'NO_SCORE'::TEXT,
            0::DECIMAL, 0, '{}'::JSONB;
        RETURN;
    END IF;

    -- Get circle
    SELECT * INTO v_circle FROM circles WHERE id = p_circle_id;

    IF NOT FOUND THEN
        RETURN QUERY SELECT
            FALSE, 'Circle not found'::TEXT, 'CIRCLE_NOT_FOUND'::TEXT,
            v_score.total_score, 0, '{}'::JSONB;
        RETURN;
    END IF;

    v_contribution_amount := v_circle.contribution_amount;

    -- Determine minimum score based on contribution amount
    IF v_contribution_amount >= 1000 THEN
        v_min_required := 75;
    ELSIF v_contribution_amount >= 500 THEN
        v_min_required := 60;
    ELSIF v_contribution_amount >= 200 THEN
        v_min_required := 45;
    ELSE
        v_min_required := 25;
    END IF;

    -- Check minimum score
    IF v_score.total_score < v_min_required THEN
        RETURN QUERY SELECT
            FALSE,
            format('XnScore %s below minimum %s for this circle', v_score.total_score, v_min_required),
            'SCORE_TOO_LOW'::TEXT,
            v_score.total_score, v_min_required, '{}'::JSONB;
        RETURN;
    END IF;

    -- Check account age for high-value circles
    IF v_contribution_amount >= 500 AND v_score.account_age_days < 90 THEN
        RETURN QUERY SELECT
            FALSE,
            'Account must be at least 90 days old for circles >= $500'::TEXT,
            'ACCOUNT_TOO_NEW'::TEXT,
            v_score.total_score, v_min_required, '{}'::JSONB;
        RETURN;
    END IF;

    IF v_contribution_amount >= 1000 AND v_score.account_age_days < 180 THEN
        RETURN QUERY SELECT
            FALSE,
            'Account must be at least 180 days old for circles >= $1000'::TEXT,
            'ACCOUNT_TOO_NEW'::TEXT,
            v_score.total_score, v_min_required, '{}'::JSONB;
        RETURN;
    END IF;

    -- Check for active defaults
    SELECT COUNT(*) INTO v_active_defaults
    FROM member_debts
    WHERE member_debts.user_id = p_user_id AND debt_status IN ('pending', 'repaying');

    IF v_active_defaults > 0 THEN
        RETURN QUERY SELECT
            FALSE,
            'Cannot join circles with unresolved debts'::TEXT,
            'HAS_ACTIVE_DEBTS'::TEXT,
            v_score.total_score, v_min_required, '{}'::JSONB;
        RETURN;
    END IF;

    -- Check if flagged for fraud
    SELECT score_frozen INTO v_fraud_frozen
    FROM xnscore_fraud_signals
    WHERE xnscore_fraud_signals.user_id = p_user_id;

    IF v_fraud_frozen = TRUE THEN
        RETURN QUERY SELECT
            FALSE,
            'Account under review'::TEXT,
            'FRAUD_REVIEW'::TEXT,
            v_score.total_score, v_min_required, '{}'::JSONB;
        RETURN;
    END IF;

    -- Calculate position restrictions
    v_position_restrictions := jsonb_build_object(
        'can_take_early_position', v_score.total_score >= 70,
        'can_take_first_position', v_score.total_score >= 80,
        'max_early_position', CASE
            WHEN v_score.total_score >= 80 THEN 1
            WHEN v_score.total_score >= 70 THEN 3
            ELSE CEIL(v_circle.member_count::DECIMAL / 2)
        END
    );

    -- Eligible!
    RETURN QUERY SELECT
        TRUE,
        'Eligible to join'::TEXT,
        'ELIGIBLE'::TEXT,
        v_score.total_score,
        v_min_required,
        v_position_restrictions;
END;
$function$
;

CREATE OR REPLACE FUNCTION public.check_cosigner_capacity(p_cosigner_user_id uuid)
 RETURNS TABLE(can_cosign boolean, active_cosigns integer, reason text)
 LANGUAGE plpgsql
 STABLE
AS $function$
DECLARE
    v_active INTEGER;
    v_max_cosigns INTEGER := 2;
BEGIN
    SELECT COUNT(*)
    INTO v_active
    FROM loan_co_signers
    WHERE co_signer_user_id = p_cosigner_user_id
    AND status = 'active';

    IF v_active >= v_max_cosigns THEN
        RETURN QUERY SELECT FALSE, v_active, 'Maximum of 2 active co-signs reached';
        RETURN;
    END IF;

    RETURN QUERY SELECT TRUE, v_active, 'Eligible to co-sign';
END;
$function$
;

CREATE OR REPLACE FUNCTION public.check_elder_guarantee_capacity(p_elder_user_id uuid)
 RETURNS TABLE(can_guarantee boolean, active_guarantees integer, total_guaranteed_cents integer, remaining_capacity_cents integer, reason text)
 LANGUAGE plpgsql
 STABLE
AS $function$
DECLARE
    v_active INTEGER;
    v_total_guaranteed INTEGER;
    v_max_guarantees INTEGER := 3;
    v_max_guaranteed INTEGER := 500000; -- $5,000
BEGIN
    SELECT COUNT(*), COALESCE(SUM(max_liability_cents), 0)
    INTO v_active, v_total_guaranteed
    FROM loan_guarantees
    WHERE guarantor_user_id = p_elder_user_id
    AND status = 'active';

    IF v_active >= v_max_guarantees THEN
        RETURN QUERY SELECT
            FALSE, v_active, v_total_guaranteed,
            0,
            'Maximum of 3 active guarantees reached';
        RETURN;
    END IF;

    IF v_total_guaranteed >= v_max_guaranteed THEN
        RETURN QUERY SELECT
            FALSE, v_active, v_total_guaranteed,
            0,
            'Maximum guarantee amount ($5,000) reached';
        RETURN;
    END IF;

    RETURN QUERY SELECT
        TRUE, v_active, v_total_guaranteed,
        v_max_guaranteed - v_total_guaranteed,
        'Eligible to guarantee';
END;
$function$
;

CREATE OR REPLACE FUNCTION public.check_overdue_contributions()
 RETURNS integer
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
    v_processed INTEGER := 0;
    v_member RECORD;
    v_late_fee DECIMAL(10,2);
    v_grace_period_days INTEGER := 3; -- Days after due date before marking overdue
BEGIN
    -- Find members who haven't contributed and are past grace period
    FOR v_member IN
        SELECT
            gm.user_id,
            gm.group_id,
            g.name AS group_name,
            g.contribution_amount,
            g.current_cycle,
            g.next_payout_date,
            g.late_fee_percentage,
            u.full_name,
            EXTRACT(DAY FROM (CURRENT_DATE - g.next_payout_date)) AS days_overdue
        FROM group_members gm
        JOIN groups g ON g.id = gm.group_id
        JOIN users u ON u.id = gm.user_id
        WHERE g.status = 'active'
        AND gm.status = 'active'
        AND g.next_payout_date IS NOT NULL
        AND g.next_payout_date < CURRENT_DATE - v_grace_period_days
        -- No completed contribution for current cycle
        AND NOT EXISTS (
            SELECT 1 FROM contributions c
            WHERE c.group_id = gm.group_id
            AND c.user_id = gm.user_id
            AND c.cycle_number = g.current_cycle
            AND c.status = 'completed'
        )
        -- Not already marked as overdue for this cycle
        AND NOT EXISTS (
            SELECT 1 FROM contributions c
            WHERE c.group_id = gm.group_id
            AND c.user_id = gm.user_id
            AND c.cycle_number = g.current_cycle
            AND c.status = 'overdue'
        )
    LOOP
        -- Calculate late fee
        v_late_fee := ROUND(v_member.contribution_amount * COALESCE(v_member.late_fee_percentage, 5) / 100, 2);

        -- Create overdue contribution record
        INSERT INTO contributions (
            group_id,
            user_id,
            amount,
            late_fee,
            cycle_number,
            status,
            due_date
        ) VALUES (
            v_member.group_id,
            v_member.user_id,
            v_member.contribution_amount,
            v_late_fee,
            v_member.current_cycle,
            'overdue',
            v_member.next_payout_date
        );

        -- Update member penalty count
        UPDATE group_members
        SET
            penalty_count = COALESCE(penalty_count, 0) + 1,
            updated_at = NOW()
        WHERE group_id = v_member.group_id
        AND user_id = v_member.user_id;

        -- Create notification for overdue
        INSERT INTO notifications (
            user_id,
            type,
            category,
            priority,
            title,
            body,
            data,
            related_entity_type,
            related_entity_id,
            action_url
        ) VALUES (
            v_member.user_id,
            'circle',
            'alert',
            'urgent',
            'Contribution Overdue!',
            'Your contribution of $' || v_member.contribution_amount || ' for ' || v_member.group_name ||
            ' is overdue. A late fee of $' || v_late_fee || ' has been applied. Total due: $' ||
            (v_member.contribution_amount + v_late_fee),
            jsonb_build_object(
                'group_id', v_member.group_id,
                'group_name', v_member.group_name,
                'amount', v_member.contribution_amount,
                'late_fee', v_late_fee,
                'total_due', v_member.contribution_amount + v_late_fee,
                'days_overdue', v_member.days_overdue
            ),
            'circle',
            v_member.group_id::TEXT,
            '/circles/' || v_member.group_id
        );

        -- Queue push notification
        INSERT INTO notification_queue (
            notification_id,
            user_id,
            channel,
            payload,
            priority
        )
        SELECT
            currval('notifications_id_seq'),
            v_member.user_id,
            'push',
            jsonb_build_object(
                'title', 'Contribution Overdue!',
                'body', 'Your contribution for ' || v_member.group_name || ' is overdue. A late fee has been applied.',
                'data', jsonb_build_object('circleId', v_member.group_id)
            ),
            'urgent';

        -- Update XnScore for missed payment
        PERFORM update_xnscore_for_event(v_member.user_id, 'missed_contribution', v_member.group_id);

        v_processed := v_processed + 1;
    END LOOP;

    RAISE NOTICE 'Processed % overdue contributions', v_processed;
    RETURN v_processed;
END;
$function$
;

CREATE OR REPLACE FUNCTION public.check_overdue_loans()
 RETURNS integer
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
    v_processed INTEGER := 0;
    v_loan RECORD;
    v_late_fee DECIMAL(10,2);
    v_grace_period_days INTEGER := 5; -- Days after due date before marking overdue
    v_penalty_rate DECIMAL(5,2) := 2.0; -- 2% late fee
BEGIN
    -- Find loans with overdue payments
    FOR v_loan IN
        SELECT
            l.id AS loan_id,
            l.borrower_id,
            l.amount,
            l.amount_due,
            l.monthly_payment,
            l.next_payment_date,
            l.group_id,
            l.missed_payments,
            g.name AS group_name,
            u.full_name,
            EXTRACT(DAY FROM (CURRENT_DATE - l.next_payment_date)) AS days_overdue
        FROM loans l
        JOIN groups g ON g.id = l.group_id
        JOIN users u ON u.id = l.borrower_id
        WHERE l.status = 'active'
        AND l.next_payment_date IS NOT NULL
        AND l.next_payment_date < CURRENT_DATE - v_grace_period_days
    LOOP
        -- Calculate late fee (percentage of monthly payment)
        v_late_fee := ROUND(v_loan.monthly_payment * v_penalty_rate / 100, 2);

        -- Update loan with late fee and missed payment count
        UPDATE loans
        SET
            amount_due = amount_due + v_late_fee,
            missed_payments = COALESCE(missed_payments, 0) + 1,
            status = CASE
                WHEN COALESCE(missed_payments, 0) >= 2 THEN 'defaulted'
                ELSE 'active'
            END,
            updated_at = NOW()
        WHERE id = v_loan.loan_id;

        -- Create loan payment record for tracking
        INSERT INTO loan_payments (
            loan_id,
            amount,
            payment_type,
            status,
            notes
        ) VALUES (
            v_loan.loan_id,
            0,
            'penalty',
            'overdue',
            'Late fee of $' || v_late_fee || ' applied. Payment was ' || v_loan.days_overdue || ' days overdue.'
        );

        -- Create notification for overdue loan
        INSERT INTO notifications (
            user_id,
            type,
            category,
            priority,
            title,
            body,
            data,
            related_entity_type,
            related_entity_id,
            action_url
        ) VALUES (
            v_loan.borrower_id,
            'loan',
            'alert',
            'urgent',
            CASE
                WHEN COALESCE(v_loan.missed_payments, 0) >= 2 THEN 'Loan Defaulted!'
                ELSE 'Loan Payment Overdue!'
            END,
            CASE
                WHEN COALESCE(v_loan.missed_payments, 0) >= 2 THEN
                    'Your loan has been marked as defaulted due to multiple missed payments. Please contact support immediately.'
                ELSE
                    'Your loan payment of $' || v_loan.monthly_payment || ' is overdue. A late fee of $' || v_late_fee ||
                    ' has been applied. Total now due: $' || (v_loan.amount_due + v_late_fee)
            END,
            jsonb_build_object(
                'loan_id', v_loan.loan_id,
                'group_id', v_loan.group_id,
                'group_name', v_loan.group_name,
                'monthly_payment', v_loan.monthly_payment,
                'late_fee', v_late_fee,
                'amount_due', v_loan.amount_due + v_late_fee,
                'days_overdue', v_loan.days_overdue,
                'missed_payments', COALESCE(v_loan.missed_payments, 0) + 1
            ),
            'loan',
            v_loan.loan_id::TEXT,
            '/loans/' || v_loan.loan_id
        );

        -- Queue push notification
        INSERT INTO notification_queue (
            notification_id,
            user_id,
            channel,
            payload,
            priority
        )
        SELECT
            currval('notifications_id_seq'),
            v_loan.borrower_id,
            'push',
            jsonb_build_object(
                'title', CASE
                    WHEN COALESCE(v_loan.missed_payments, 0) >= 2 THEN 'Loan Defaulted!'
                    ELSE 'Loan Payment Overdue!'
                END,
                'body', 'Your loan payment is overdue. A late fee has been applied.',
                'data', jsonb_build_object('loanId', v_loan.loan_id)
            ),
            'urgent';

        -- Notify group admin about overdue/defaulted loan
        INSERT INTO notifications (
            user_id,
            type,
            category,
            priority,
            title,
            body,
            data,
            related_entity_type,
            related_entity_id
        )
        SELECT
            g.admin_id,
            'loan',
            'alert',
            'high',
            CASE
                WHEN COALESCE(v_loan.missed_payments, 0) >= 2 THEN 'Member Loan Defaulted'
                ELSE 'Member Loan Payment Overdue'
            END,
            v_loan.full_name || '''s loan payment is ' ||
            CASE
                WHEN COALESCE(v_loan.missed_payments, 0) >= 2 THEN 'now in default status'
                ELSE 'overdue by ' || v_loan.days_overdue || ' days'
            END,
            jsonb_build_object(
                'loan_id', v_loan.loan_id,
                'borrower_id', v_loan.borrower_id,
                'borrower_name', v_loan.full_name,
                'amount_due', v_loan.amount_due + v_late_fee
            ),
            'loan',
            v_loan.loan_id::TEXT
        FROM groups g
        WHERE g.id = v_loan.group_id;

        -- Update XnScore for missed loan payment
        PERFORM update_xnscore_for_event(v_loan.borrower_id, 'missed_loan_payment', v_loan.loan_id);

        v_processed := v_processed + 1;
    END LOOP;

    RAISE NOTICE 'Processed % overdue loans', v_processed;
    RETURN v_processed;
END;
$function$
;

CREATE OR REPLACE FUNCTION public.check_preflight_eligibility(p_user_id uuid, p_loan_product_id uuid, p_requested_amount_cents integer, p_requested_term_months integer)
 RETURNS TABLE(eligible boolean, reasons text[])
 LANGUAGE plpgsql
 STABLE
AS $function$
DECLARE
    v_reasons TEXT[] := '{}';
    v_profile RECORD;
    v_xnscore RECORD;
    v_product RECORD;
    v_account_age_days INTEGER;
    v_active_loans INTEGER;
    v_recent_default BOOLEAN;
    v_active_delinquency BOOLEAN;
BEGIN
    -- Get user data
    SELECT * INTO v_profile FROM profiles WHERE id = p_user_id;
    SELECT * INTO v_xnscore FROM xn_scores WHERE user_id = p_user_id;

    IF p_loan_product_id IS NOT NULL THEN
        SELECT * INTO v_product FROM loan_products WHERE id = p_loan_product_id;
    END IF;

    -- Check if user exists and has XnScore
    IF v_xnscore IS NULL THEN
        v_reasons := array_append(v_reasons, 'No credit history - XnScore not yet calculated');
        RETURN QUERY SELECT FALSE, v_reasons;
        RETURN;
    END IF;

    -- Check minimum XnScore
    IF v_product IS NOT NULL AND v_xnscore.total_score < v_product.min_xnscore THEN
        v_reasons := array_append(v_reasons,
            format('XnScore %s below minimum %s for this product', v_xnscore.total_score, v_product.min_xnscore));
    ELSIF v_xnscore.total_score < 40 THEN
        v_reasons := array_append(v_reasons,
            format('XnScore %s below minimum 40 for any loan', v_xnscore.total_score));
    END IF;

    -- Check account age
    v_account_age_days := EXTRACT(DAY FROM (now() - v_profile.created_at))::INTEGER;

    IF v_product IS NOT NULL AND v_account_age_days < v_product.min_account_age_days THEN
        v_reasons := array_append(v_reasons,
            format('Account age %s days below minimum %s days', v_account_age_days, v_product.min_account_age_days));
    ELSIF v_account_age_days < 90 THEN
        v_reasons := array_append(v_reasons, 'Account must be at least 90 days old');
    END IF;

    -- Check for active delinquency
    SELECT EXISTS(
        SELECT 1 FROM loans
        WHERE user_id = p_user_id AND status = 'active' AND days_past_due > 30
    ) INTO v_active_delinquency;

    IF v_active_delinquency THEN
        v_reasons := array_append(v_reasons, 'Currently delinquent on existing loan');
    END IF;

    -- Check for recent default
    SELECT EXISTS(
        SELECT 1 FROM loans
        WHERE user_id = p_user_id
        AND status = 'defaulted'
        AND closed_at > now() - INTERVAL '6 months'
    ) INTO v_recent_default;

    IF v_recent_default THEN
        v_reasons := array_append(v_reasons, 'Default within last 6 months');
    END IF;

    -- Check loan stacking
    SELECT COUNT(*) INTO v_active_loans
    FROM loans WHERE user_id = p_user_id AND status = 'active';

    IF v_active_loans >= 2 THEN
        v_reasons := array_append(v_reasons, 'Maximum of 2 active loans allowed');
    END IF;

    -- Check product-specific requirements
    IF v_product IS NOT NULL THEN
        IF p_requested_amount_cents < v_product.min_amount_cents THEN
            v_reasons := array_append(v_reasons,
                format('Amount below product minimum of $%s', v_product.min_amount_cents / 100));
        END IF;

        IF p_requested_amount_cents > v_product.max_amount_cents THEN
            v_reasons := array_append(v_reasons,
                format('Amount exceeds product maximum of $%s', v_product.max_amount_cents / 100));
        END IF;

        IF NOT (p_requested_term_months = ANY(v_product.allowed_terms)) THEN
            v_reasons := array_append(v_reasons,
                format('Term %s months not available for this product', p_requested_term_months));
        END IF;
    END IF;

    -- Check KYC verification
    IF NOT COALESCE(v_profile.identity_verified, FALSE) THEN
        v_reasons := array_append(v_reasons, 'Identity verification required');
    END IF;

    RETURN QUERY SELECT array_length(v_reasons, 1) IS NULL OR array_length(v_reasons, 1) = 0, v_reasons;
END;
$function$
;

CREATE OR REPLACE FUNCTION public.check_repeat_offender(p_user_id uuid)
 RETURNS TABLE(is_repeat_offender boolean, total_defaults integer, defaults_last_12_months integer, unresolved_defaults integer, requires_suspension_review boolean)
 LANGUAGE plpgsql
AS $function$
BEGIN
    RETURN QUERY
    SELECT
        (SELECT COUNT(*) >= 2 FROM defaults WHERE user_id = p_user_id),
        (SELECT COUNT(*)::INTEGER FROM defaults WHERE user_id = p_user_id),
        (SELECT COUNT(*)::INTEGER FROM defaults WHERE user_id = p_user_id AND created_at >= NOW() - INTERVAL '12 months'),
        (SELECT COUNT(*)::INTEGER FROM defaults WHERE user_id = p_user_id AND default_status = 'unresolved'),
        (
            (SELECT COUNT(*) >= 3 FROM defaults WHERE user_id = p_user_id AND created_at >= NOW() - INTERVAL '12 months') OR
            (SELECT COUNT(*) >= 2 FROM defaults WHERE user_id = p_user_id AND default_status = 'unresolved') OR
            (SELECT COUNT(*) >= 5 FROM defaults WHERE user_id = p_user_id)
        );
END;
$function$
;

CREATE OR REPLACE FUNCTION public.check_shared_circle(p_user1 uuid, p_user2 uuid)
 RETURNS uuid
 LANGUAGE plpgsql
 STABLE
AS $function$
DECLARE
    v_circle_id UUID;
BEGIN
    SELECT cm1.circle_id INTO v_circle_id
    FROM circle_members cm1
    JOIN circle_members cm2 ON cm1.circle_id = cm2.circle_id
    WHERE cm1.user_id = p_user1
    AND cm2.user_id = p_user2
    AND cm1.status = 'active'
    AND cm2.status = 'active'
    LIMIT 1;

    RETURN v_circle_id;
END;
$function$
;

CREATE OR REPLACE FUNCTION public.check_user_exists_by_email(p_email text)
 RETURNS json
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
  v_user_id UUID;
  v_full_name TEXT;
  v_password_set BOOLEAN;
BEGIN
  -- Look up user by email (case-insensitive)
  SELECT id INTO v_user_id
  FROM auth.users
  WHERE LOWER(email) = LOWER(TRIM(p_email))
  LIMIT 1;

  IF v_user_id IS NULL THEN
    RETURN jsonb_build_object('exists', false);
  END IF;

  -- Get profile info
  SELECT full_name, COALESCE(password_set, false) INTO v_full_name, v_password_set
  FROM public.profiles
  WHERE id = v_user_id;

  RETURN jsonb_build_object(
    'exists', true,
    'user_id', v_user_id,
    'full_name', COALESCE(v_full_name, p_email),
    'password_set', v_password_set
  );

EXCEPTION WHEN OTHERS THEN
  -- Don't leak errors to client; just say doesn't exist
  RETURN jsonb_build_object('exists', false);
END;
$function$
;

CREATE OR REPLACE FUNCTION public.check_user_restriction(p_user_id uuid, p_restriction_type text)
 RETURNS boolean
 LANGUAGE plpgsql
AS $function$
BEGIN
    RETURN EXISTS (
        SELECT 1 FROM user_restrictions
        WHERE user_id = p_user_id
        AND restriction_type = p_restriction_type
        AND lifted_at IS NULL
        AND (active_until IS NULL OR active_until > NOW())
    );
END;
$function$
;

CREATE OR REPLACE FUNCTION public.check_velocity_cap(p_user_id uuid, p_requested_increase numeric)
 RETURNS TABLE(allowed boolean, allowed_increase numeric, remaining_this_week numeric, velocity_warning boolean)
 LANGUAGE plpgsql
AS $function$
DECLARE
    v_score RECORD;
    v_weekly_limit DECIMAL := 5.00; -- Max +5 points per week
    v_current_week_start DATE;
    v_remaining DECIMAL;
BEGIN
    v_current_week_start := date_trunc('week', now())::DATE;

    SELECT * INTO v_score FROM xn_scores WHERE xn_scores.user_id = p_user_id;

    IF NOT FOUND THEN
        RETURN QUERY SELECT TRUE, p_requested_increase, v_weekly_limit, FALSE;
        RETURN;
    END IF;

    -- Check if we're in a new week
    IF v_score.week_start_date < v_current_week_start THEN
        -- Reset for new week
        UPDATE xn_scores SET
            week_start_date = v_current_week_start,
            points_gained_this_week = 0
        WHERE xn_scores.user_id = p_user_id;

        v_remaining := v_weekly_limit;
    ELSE
        v_remaining := v_weekly_limit - v_score.points_gained_this_week;
    END IF;

    IF p_requested_increase <= v_remaining THEN
        RETURN QUERY SELECT
            TRUE,
            p_requested_increase,
            v_remaining - p_requested_increase,
            FALSE;
    ELSE
        RETURN QUERY SELECT
            FALSE,
            GREATEST(0, v_remaining),
            0::DECIMAL,
            TRUE;
    END IF;
END;
$function$
;

CREATE OR REPLACE FUNCTION public.check_vouch_requirements()
 RETURNS trigger
 LANGUAGE plpgsql
AS $function$
DECLARE
    required_vouches INTEGER;
    current_vouches INTEGER;
BEGIN
    SELECT c.required_vouches INTO required_vouches
    FROM public.communities c WHERE c.id = NEW.community_id;

    IF required_vouches > 0 THEN
        SELECT COUNT(*) INTO current_vouches
        FROM public.member_vouches mv
        WHERE mv.vouched_user_id = NEW.vouched_user_id
        AND mv.community_id = NEW.community_id
        AND mv.status = 'active';

        IF current_vouches >= required_vouches THEN
            UPDATE public.community_memberships
            SET status = 'active', joined_at = NOW(), updated_at = NOW()
            WHERE user_id = NEW.vouched_user_id
            AND community_id = NEW.community_id
            AND status = 'pending';
        END IF;
    END IF;
    RETURN NEW;
END;
$function$
;

CREATE OR REPLACE FUNCTION public.cleanup_old_data()
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
    v_old_notifications INTEGER;
    v_old_queue_items INTEGER;
    v_old_score_history INTEGER;
BEGIN
    -- Delete read notifications older than 90 days
    DELETE FROM notifications
    WHERE read = TRUE
    AND read_at < NOW() - INTERVAL '90 days';
    GET DIAGNOSTICS v_old_notifications = ROW_COUNT;

    -- Delete old notification queue items (already processed)
    DELETE FROM notification_queue
    WHERE status = 'sent'
    AND processed_at < NOW() - INTERVAL '30 days';
    GET DIAGNOSTICS v_old_queue_items = ROW_COUNT;

    -- Trim XnScore history (keep last 1 year per user)
    WITH ranked_history AS (
        SELECT id, ROW_NUMBER() OVER (PARTITION BY user_id ORDER BY created_at DESC) as rn
        FROM xn_score_history
    )
    DELETE FROM xn_score_history
    WHERE id IN (SELECT id FROM ranked_history WHERE rn > 365);
    GET DIAGNOSTICS v_old_score_history = ROW_COUNT;

    RETURN jsonb_build_object(
        'notifications_deleted', v_old_notifications,
        'queue_items_deleted', v_old_queue_items,
        'score_history_trimmed', v_old_score_history,
        'cleaned_at', NOW()
    );
END;
$function$
;

CREATE OR REPLACE FUNCTION public.cleanup_old_events()
 RETURNS integer
 LANGUAGE plpgsql
 SECURITY DEFINER
AS $function$
DECLARE
  deleted_count INTEGER;
BEGIN
  DELETE FROM user_events
  WHERE created_at < NOW() - INTERVAL '90 days';
  GET DIAGNOSTICS deleted_count = ROW_COUNT;
  RETURN deleted_count;
END;
$function$
;

CREATE OR REPLACE FUNCTION public.cleanup_old_notifications()
 RETURNS integer
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
    v_deleted INTEGER := 0;
    v_queue_deleted INTEGER;
    v_notif_deleted INTEGER;
BEGIN
    -- Delete processed queue items older than 7 days
    DELETE FROM notification_queue
    WHERE status = 'sent'
    AND processed_at < NOW() - INTERVAL '7 days';

    GET DIAGNOSTICS v_queue_deleted = ROW_COUNT;

    -- Delete cancelled queue items older than 1 day
    DELETE FROM notification_queue
    WHERE status = 'cancelled'
    AND created_at < NOW() - INTERVAL '1 day';

    -- Delete read notifications older than 30 days
    DELETE FROM notifications
    WHERE read = TRUE
    AND read_at < NOW() - INTERVAL '30 days';

    GET DIAGNOSTICS v_notif_deleted = ROW_COUNT;

    -- Delete expired notifications
    DELETE FROM notifications
    WHERE expires_at IS NOT NULL
    AND expires_at < NOW();

    v_deleted := v_queue_deleted + v_notif_deleted;

    RAISE NOTICE 'Cleaned up % old notification records', v_deleted;
    RETURN v_deleted;
END;
$function$
;

CREATE OR REPLACE FUNCTION public.close_expired_proposals()
 RETURNS integer
 LANGUAGE plpgsql
 SECURITY DEFINER
AS $function$
DECLARE
  v_count INTEGER := 0;
  v_proposal RECORD;
BEGIN
  FOR v_proposal IN
    SELECT id FROM circle_proposals
    WHERE status = 'open'
      AND voting_ends_at IS NOT NULL
      AND voting_ends_at <= NOW()
  LOOP
    BEGIN
      PERFORM tally_proposal(v_proposal.id);
      v_count := v_count + 1;
    EXCEPTION WHEN OTHERS THEN
      RAISE WARNING 'tally_proposal failed for %: %', v_proposal.id, SQLERRM;
    END;
  END LOOP;
  RETURN v_count;
END;
$function$
;

CREATE OR REPLACE FUNCTION public.complete_circle_join(p_pending_id uuid)
 RETURNS json
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
  v_pending RECORD;
  v_user_id UUID;
  v_user_email TEXT;
  v_circle_name TEXT;
  v_circle_amount NUMERIC;
  v_amount_cents BIGINT;
  v_existing_member UUID;
  v_member_id UUID;
  v_user_display_name TEXT;
  v_email_local_part TEXT;
  v_amount_dollars TEXT;
BEGIN
  v_user_id := auth.uid();
  IF v_user_id IS NULL THEN
    RETURN jsonb_build_object('success', false, 'error', 'not_authenticated');
  END IF;

  SELECT email INTO v_user_email FROM auth.users WHERE id = v_user_id;
  IF v_user_email IS NULL THEN
    RETURN jsonb_build_object('success', false, 'error', 'user_not_found');
  END IF;

  SELECT * INTO v_pending FROM pending_joins WHERE id = p_pending_id;
  IF v_pending IS NULL THEN
    RETURN jsonb_build_object('success', false, 'error', 'pending_not_found');
  END IF;

  IF LOWER(v_pending.email) <> LOWER(v_user_email) THEN
    RETURN jsonb_build_object('success', false, 'error', 'email_mismatch');
  END IF;

  SELECT name, amount INTO v_circle_name, v_circle_amount
  FROM circles WHERE id = v_pending.circle_id;

  v_amount_cents := (v_circle_amount * 100)::bigint;

  IF v_pending.status = 'completed' THEN
    RETURN jsonb_build_object(
      'success', true,
      'already_completed', true,
      'circle_name', v_circle_name,
      'amount', v_circle_amount
    );
  END IF;

  SELECT id INTO v_existing_member FROM circle_members
  WHERE circle_id = v_pending.circle_id AND user_id = v_user_id;

  IF v_existing_member IS NULL THEN
    INSERT INTO circle_members (circle_id, user_id, status, joined_at, role)
    VALUES (v_pending.circle_id, v_user_id, 'active', NOW(), 'member')
    RETURNING id INTO v_member_id;
  ELSE
    v_member_id := v_existing_member;
  END IF;

  INSERT INTO user_wallets (user_id, main_balance_cents, reserved_balance_cents, committed_balance_cents, wallet_status, created_at, updated_at)
  VALUES (v_user_id, 0, 0, 0, 'active', NOW(), NOW())
  ON CONFLICT (user_id) DO NOTHING;

  INSERT INTO circle_contributions (
    circle_id, user_id, member_id, cycle_number, amount, currency,
    due_date, paid_date, status, is_on_time, payment_method, created_at
  )
  VALUES (
    v_pending.circle_id, v_user_id, v_member_id, 1, v_circle_amount, 'USD',
    CURRENT_DATE, NOW(), 'paid', true, 'demo_quickjoin', NOW()
  );

  UPDATE user_wallets
  SET main_balance_cents = main_balance_cents + v_amount_cents,
      updated_at = NOW(),
      last_activity_at = NOW()
  WHERE user_id = v_user_id;

  UPDATE pending_joins
  SET status = 'completed', completed_at = NOW()
  WHERE id = p_pending_id;

  -- Phase 2: post system messages to circle chat (best-effort, non-blocking)
  BEGIN
    -- Resolve display name with fallback chain
    SELECT full_name INTO v_user_display_name
    FROM profiles WHERE id = v_user_id;

    IF v_user_display_name IS NULL OR TRIM(v_user_display_name) = '' THEN
      v_email_local_part := split_part(v_user_email, '@', 1);
      IF v_email_local_part IS NOT NULL AND v_email_local_part <> '' THEN
        v_user_display_name := v_email_local_part;
      ELSE
        v_user_display_name := 'A new member';
      END IF;
    END IF;

    -- Format amount as a clean dollar string (no trailing zeros for whole amounts)
    IF v_circle_amount = v_circle_amount::int THEN
      v_amount_dollars := v_circle_amount::int::text;
    ELSE
      v_amount_dollars := trim(trailing '0' from v_circle_amount::text);
      v_amount_dollars := trim(trailing '.' from v_amount_dollars);
    END IF;

    -- Join event
    INSERT INTO circle_messages (circle_id, user_id, message_type, body)
    VALUES (
      v_pending.circle_id,
      v_user_id,
      'system',
      v_user_display_name || ' joined the circle'
    );

    -- Contribution event
    INSERT INTO circle_messages (circle_id, user_id, message_type, body)
    VALUES (
      v_pending.circle_id,
      v_user_id,
      'system',
      v_user_display_name || ' contributed $' || v_amount_dollars || ' for Cycle 1'
    );

  EXCEPTION WHEN OTHERS THEN
    RAISE WARNING 'Phase 2 system message insert failed for pending_id=%, user_id=%, circle_id=%, error=%',
      p_pending_id, v_user_id, v_pending.circle_id, SQLERRM;
  END;

  RETURN jsonb_build_object(
    'success', true,
    'circle_name', v_circle_name,
    'amount', v_circle_amount,
    'circle_id', v_pending.circle_id,
    'wallet_credited_cents', v_amount_cents
  );

EXCEPTION WHEN OTHERS THEN
  RETURN jsonb_build_object(
    'success', false,
    'error', 'exception',
    'message', SQLERRM
  );
END;
$function$
;

CREATE OR REPLACE FUNCTION public.complete_referral(p_referred_user_id uuid)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
    v_referral RECORD;
    v_referrer RECORD;
BEGIN
    -- Find pending referral for this user
    SELECT * INTO v_referral
    FROM referrals
    WHERE referred_id = p_referred_user_id
    AND status = 'signed_up'
    AND reward_paid = FALSE;

    IF v_referral IS NULL THEN
        RETURN jsonb_build_object('message', 'No pending referral found');
    END IF;

    -- Get referrer info
    SELECT * INTO v_referrer FROM users WHERE id = v_referral.referrer_id;

    -- Mark referral as completed
    UPDATE referrals
    SET
        status = 'completed',
        completed_at = NOW(),
        reward_paid = TRUE,
        updated_at = NOW()
    WHERE id = v_referral.id;

    -- Pay referrer reward
    UPDATE wallets
    SET balance = balance + v_referral.reward_amount, updated_at = NOW()
    WHERE user_id = v_referral.referrer_id;

    -- Create transaction record
    INSERT INTO wallet_transactions (
        wallet_id,
        type,
        amount,
        description,
        reference_type,
        reference_id,
        status
    )
    SELECT
        id,
        'referral_reward',
        v_referral.reward_amount,
        'Referral reward',
        'referral',
        v_referral.id,
        'completed'
    FROM wallets
    WHERE user_id = v_referral.referrer_id;

    -- Update referrer's XnScore
    PERFORM update_xnscore_for_event(v_referral.referrer_id, 'referral_success', v_referral.id);

    -- Notify referrer
    PERFORM create_notification(
        v_referral.referrer_id,
        'payment',
        'referral',
        'Referral Reward Earned! 💰',
        'You earned $' || v_referral.reward_amount || ' because your referral completed their first circle!',
        jsonb_build_object(
            'referral_id', v_referral.id,
            'reward_amount', v_referral.reward_amount
        ),
        'high',
        NULL,
        'referral',
        v_referral.id::TEXT,
        '/wallet'
    );

    RETURN jsonb_build_object(
        'success', true,
        'referral_id', v_referral.id,
        'referrer_id', v_referral.referrer_id,
        'reward_paid', v_referral.reward_amount,
        'message', 'Referral completed and reward paid'
    );
END;
$function$
;

CREATE OR REPLACE FUNCTION public.compute_all_circle_health_scores()
 RETURNS integer
 LANGUAGE plpgsql
 SECURITY DEFINER
AS $function$
DECLARE v_count INTEGER := 0; v_circle RECORD;
BEGIN
  FOR v_circle IN SELECT id FROM circles WHERE status IN ('active', 'in_progress', 'pending')
  LOOP
    BEGIN
      PERFORM compute_circle_health_score(v_circle.id);
      v_count := v_count + 1;
    EXCEPTION WHEN OTHERS THEN
      RAISE WARNING 'compute_circle_health_score failed for circle %: %', v_circle.id, SQLERRM;
    END;
  END LOOP;
  RETURN v_count;
END;
$function$
;

CREATE OR REPLACE FUNCTION public.compute_all_default_probabilities()
 RETURNS integer
 LANGUAGE plpgsql
 SECURITY DEFINER
AS $function$
DECLARE
  v_count INTEGER := 0;
  v_user RECORD;
BEGIN
  FOR v_user IN
    SELECT DISTINCT p.id FROM profiles p
    WHERE EXISTS (SELECT 1 FROM member_behavioral_profiles mbp WHERE mbp.user_id = p.id)
  LOOP
    BEGIN
      PERFORM compute_default_probability(v_user.id);
      v_count := v_count + 1;
    EXCEPTION WHEN OTHERS THEN
      RAISE WARNING 'compute_default_probability failed for user %: %', v_user.id, SQLERRM;
    END;
  END LOOP;
  RETURN v_count;
END;
$function$
;

CREATE OR REPLACE FUNCTION public.compute_all_honor_scores()
 RETURNS integer
 LANGUAGE plpgsql
 SECURITY DEFINER
AS $function$
DECLARE v_count INTEGER := 0; v_user RECORD;
BEGIN
  FOR v_user IN SELECT DISTINCT user_id FROM community_memberships WHERE status = 'active'
  LOOP
    BEGIN
      PERFORM compute_honor_score(v_user.user_id);
      v_count := v_count + 1;
    EXCEPTION WHEN OTHERS THEN
      RAISE WARNING 'compute_honor_score failed for user %: %', v_user.user_id, SQLERRM;
    END;
  END LOOP;
  RETURN v_count;
END;
$function$
;

CREATE OR REPLACE FUNCTION public.compute_all_member_profiles()
 RETURNS integer
 LANGUAGE plpgsql
 SECURITY DEFINER
AS $function$
DECLARE
  v_user_id UUID;
  v_count INTEGER := 0;
BEGIN
  FOR v_user_id IN
    SELECT id FROM profiles
    WHERE id IN (
      SELECT DISTINCT user_id FROM user_events
      WHERE created_at > NOW() - INTERVAL '90 days'
    )
  LOOP
    PERFORM compute_member_profile(v_user_id);
    v_count := v_count + 1;
  END LOOP;
  RETURN v_count;
END;
$function$
;

CREATE OR REPLACE FUNCTION public.compute_circle_health_score(p_circle_id uuid)
 RETURNS numeric
 LANGUAGE plpgsql
 SECURITY DEFINER
AS $function$
DECLARE
  v_contribution_score DECIMAL(5,2) := 50;
  v_member_quality DECIMAL(5,2) := 50;
  v_financial_stability DECIMAL(5,2) := 50;
  v_social_cohesion DECIMAL(5,2) := 50;
  v_health_score DECIMAL(5,2);
  v_health_status TEXT;
  v_on_time_pct DECIMAL(5,2) := 0;
  v_avg_xnscore DECIMAL(5,2) := 0;
  v_members_with_defaults INTEGER := 0;
  v_total_members INTEGER := 0;
  v_avg_default_prob DECIMAL(5,4) := 0;
  v_previous_score DECIMAL(5,2);
  v_trend TEXT := 'stable';
  v_total_contributions INTEGER := 0;
  v_on_time_contributions INTEGER := 0;
  v_defaulted_contributions INTEGER := 0;
  v_shared_circles_avg DECIMAL := 0;
BEGIN
  -- Get total active members
  SELECT COUNT(*) INTO v_total_members
  FROM circle_members WHERE circle_id = p_circle_id AND status = 'active';
  IF v_total_members = 0 THEN RETURN 0; END IF;

  -- CONTRIBUTION RELIABILITY (40%)
  SELECT COUNT(*),
    COUNT(*) FILTER (WHERE status = 'completed' AND is_late = false),
    COUNT(*) FILTER (WHERE status = 'defaulted')
  INTO v_total_contributions, v_on_time_contributions, v_defaulted_contributions
  FROM contributions WHERE circle_id = p_circle_id;

  IF v_total_contributions > 0 THEN
    v_on_time_pct := (v_on_time_contributions::DECIMAL / v_total_contributions) * 100;
    v_contribution_score := LEAST(100, GREATEST(0, ((v_on_time_pct - 50) / 45) * 100));
    IF v_defaulted_contributions > 0 THEN
      v_contribution_score := GREATEST(0, v_contribution_score - (v_defaulted_contributions * 15));
    END IF;
  END IF;

  -- MEMBER QUALITY (25%)
  SELECT COALESCE(AVG(xs.total_score), 0) INTO v_avg_xnscore
  FROM circle_members cm JOIN xn_scores xs ON xs.user_id = cm.user_id
  WHERE cm.circle_id = p_circle_id AND cm.status = 'active';
  v_member_quality := v_avg_xnscore;

  SELECT COUNT(*) INTO v_members_with_defaults
  FROM circle_members
  WHERE circle_id = p_circle_id AND status = 'active' AND has_active_default = true;
  IF v_members_with_defaults > 0 THEN
    v_member_quality := GREATEST(0, v_member_quality - (v_members_with_defaults * 20));
  END IF;

  -- Avg default probability
  SELECT COALESCE(AVG(dps.predicted_probability), 0) INTO v_avg_default_prob
  FROM circle_members cm JOIN default_probability_scores dps ON dps.user_id = cm.user_id
  WHERE cm.circle_id = p_circle_id AND cm.status = 'active';

  -- FINANCIAL STABILITY (20%)
  v_financial_stability := GREATEST(0, 100 - (v_avg_default_prob * 200));
  IF EXISTS (SELECT 1 FROM defaults WHERE circle_id = p_circle_id AND default_status = 'unresolved') THEN
    v_financial_stability := GREATEST(0, v_financial_stability - 30);
  END IF;

  -- SOCIAL COHESION (15%)
  SELECT COALESCE(AVG(shared_count), 0) INTO v_shared_circles_avg
  FROM (
    SELECT cm1.user_id, COUNT(DISTINCT cm2.circle_id) as shared_count
    FROM circle_members cm1
    JOIN circle_members cm2 ON cm2.user_id = cm1.user_id
      AND cm2.circle_id != p_circle_id AND cm2.status = 'active'
    WHERE cm1.circle_id = p_circle_id AND cm1.status = 'active'
    GROUP BY cm1.user_id
  ) sub;
  v_social_cohesion := LEAST(100, v_shared_circles_avg * 20 + 30);

  -- COMPOSITE
  v_health_score := ROUND(
    v_contribution_score * 0.40 + v_member_quality * 0.25 +
    v_financial_stability * 0.20 + v_social_cohesion * 0.15, 2);

  v_health_status := CASE
    WHEN v_health_score >= 80 THEN 'thriving'
    WHEN v_health_score >= 60 THEN 'healthy'
    WHEN v_health_score >= 40 THEN 'at_risk'
    ELSE 'critical'
  END;

  -- TREND
  SELECT health_score INTO v_previous_score FROM circle_health_scores WHERE circle_id = p_circle_id;
  IF v_previous_score IS NOT NULL THEN
    IF v_health_score > v_previous_score + 3 THEN v_trend := 'improving';
    ELSIF v_health_score < v_previous_score - 3 THEN v_trend := 'declining';
    ELSE v_trend := 'stable';
    END IF;
  END IF;

  -- UPSERT
  INSERT INTO circle_health_scores (
    circle_id, health_score, health_status,
    contribution_reliability_score, member_quality_score,
    financial_stability_score, social_cohesion_score,
    on_time_contribution_pct, avg_member_xnscore,
    members_with_defaults, total_members,
    avg_default_probability, previous_score, trend,
    last_computed_at, updated_at
  ) VALUES (
    p_circle_id, v_health_score, v_health_status,
    v_contribution_score, v_member_quality,
    v_financial_stability, v_social_cohesion,
    v_on_time_pct, v_avg_xnscore,
    v_members_with_defaults, v_total_members,
    v_avg_default_prob, v_previous_score, v_trend,
    NOW(), NOW()
  )
  ON CONFLICT (circle_id) DO UPDATE SET
    health_score = EXCLUDED.health_score,
    health_status = EXCLUDED.health_status,
    contribution_reliability_score = EXCLUDED.contribution_reliability_score,
    member_quality_score = EXCLUDED.member_quality_score,
    financial_stability_score = EXCLUDED.financial_stability_score,
    social_cohesion_score = EXCLUDED.social_cohesion_score,
    on_time_contribution_pct = EXCLUDED.on_time_contribution_pct,
    avg_member_xnscore = EXCLUDED.avg_member_xnscore,
    members_with_defaults = EXCLUDED.members_with_defaults,
    total_members = EXCLUDED.total_members,
    avg_default_probability = EXCLUDED.avg_default_probability,
    previous_score = circle_health_scores.health_score,
    trend = EXCLUDED.trend,
    last_computed_at = NOW(), updated_at = NOW();

  -- HISTORY
  INSERT INTO circle_health_history (circle_id, health_score, health_status, component_scores, computed_at)
  VALUES (p_circle_id, v_health_score, v_health_status,
    jsonb_build_object('contribution_reliability', v_contribution_score,
      'member_quality', v_member_quality, 'financial_stability', v_financial_stability,
      'social_cohesion', v_social_cohesion), NOW());

  RETURN v_health_score;
END;
$function$
;

CREATE OR REPLACE FUNCTION public.compute_default_probability(p_user_id uuid)
 RETURNS numeric
 LANGUAGE plpgsql
 SECURITY DEFINER
AS $function$
DECLARE
  v_payment DECIMAL(5,4) := 0;
  v_financial DECIMAL(5,4) := 0;
  v_behavioral DECIMAL(5,4) := 0;
  v_social DECIMAL(5,4) := 0;
  v_tenure DECIMAL(5,4) := 0;
  v_probability DECIMAL(5,4);
  v_bucket TEXT;
  v_confidence DECIMAL(3,2) := 0;
  v_data_points INTEGER := 0;
  r_profile RECORD;
  r_risk RECORD;
  r_network RECORD;
  r_score RECORD;
BEGIN
  SELECT * INTO r_profile FROM member_behavioral_profiles WHERE user_id = p_user_id;
  SELECT * INTO r_risk FROM member_risk_indicators WHERE user_id = p_user_id;
  SELECT * INTO r_network FROM member_network_metrics WHERE user_id = p_user_id;
  SELECT * INTO r_score FROM xn_scores WHERE user_id = p_user_id;

  -- PAYMENT SIGNAL (35%)
  IF r_profile IS NOT NULL THEN
    v_data_points := v_data_points + 1;
    IF COALESCE(r_profile.missed_pct, 0) > 20 THEN v_payment := v_payment + 0.35;
    ELSIF COALESCE(r_profile.missed_pct, 0) > 10 THEN v_payment := v_payment + 0.20;
    ELSIF COALESCE(r_profile.missed_pct, 0) > 5 THEN v_payment := v_payment + 0.10;
    END IF;
    IF COALESCE(r_profile.late_pct, 0) > 30 THEN v_payment := v_payment + 0.25;
    ELSIF COALESCE(r_profile.late_pct, 0) > 15 THEN v_payment := v_payment + 0.15;
    END IF;
    IF r_profile.payment_trend = 'declining' THEN v_payment := v_payment + 0.15; END IF;
    IF COALESCE(r_profile.total_contributions, 0) > 5
       AND COALESCE(r_profile.current_on_time_streak, 0) = 0 THEN
      v_payment := v_payment + 0.15;
    END IF;
    v_payment := LEAST(1.0000, v_payment);
  END IF;

  -- FINANCIAL SIGNAL (20%)
  IF r_profile IS NOT NULL THEN
    v_data_points := v_data_points + 1;
    IF COALESCE(r_profile.balance_volatility, 0) > 80 THEN v_financial := v_financial + 0.30;
    ELSIF COALESCE(r_profile.balance_volatility, 0) > 50 THEN v_financial := v_financial + 0.15;
    END IF;
    IF COALESCE(r_profile.avg_contribution_amount, 0) > 0
       AND COALESCE(r_profile.avg_wallet_balance, 0) < r_profile.avg_contribution_amount THEN
      v_financial := v_financial + 0.35;
    END IF;
    IF COALESCE(r_profile.loan_utilization_rate, 0) > 80 THEN v_financial := v_financial + 0.15;
    ELSIF COALESCE(r_profile.loan_utilization_rate, 0) > 60 THEN v_financial := v_financial + 0.08;
    END IF;
    IF COALESCE(r_profile.loans_defaulted, 0) > 0 THEN v_financial := v_financial + 0.30; END IF;
    v_financial := LEAST(1.0000, v_financial);
  END IF;

  -- BEHAVIORAL SIGNAL (20%)
  IF r_profile IS NOT NULL THEN
    v_data_points := v_data_points + 1;
    IF COALESCE(r_profile.days_since_last_activity, 0) > 30 THEN v_behavioral := v_behavioral + 0.40;
    ELSIF COALESCE(r_profile.days_since_last_activity, 0) > 14 THEN v_behavioral := v_behavioral + 0.20;
    END IF;
    IF r_risk IS NOT NULL AND COALESCE(r_risk.device_fingerprint_changes_30d, 0) > 2 THEN
      v_behavioral := v_behavioral + 0.20;
    END IF;
    IF r_risk IS NOT NULL AND COALESCE(r_risk.velocity_anomaly_score, 0) > 50 THEN
      v_behavioral := v_behavioral + 0.25;
    ELSIF r_risk IS NOT NULL AND COALESCE(r_risk.velocity_anomaly_score, 0) > 30 THEN
      v_behavioral := v_behavioral + 0.12;
    END IF;
    IF r_risk IS NOT NULL AND COALESCE(r_risk.login_anomaly_score, 0) > 50 THEN
      v_behavioral := v_behavioral + 0.15;
    END IF;
    v_behavioral := LEAST(1.0000, v_behavioral);
  END IF;

  -- SOCIAL SIGNAL (15%)
  IF r_risk IS NOT NULL OR r_network IS NOT NULL THEN
    v_data_points := v_data_points + 1;
    IF r_risk IS NOT NULL AND COALESCE(r_risk.social_isolation_score, 0) > 70 THEN
      v_social := v_social + 0.30;
    ELSIF r_risk IS NOT NULL AND COALESCE(r_risk.social_isolation_score, 0) > 50 THEN
      v_social := v_social + 0.15;
    END IF;
    IF r_risk IS NOT NULL AND COALESCE(r_risk.default_contagion_risk, 0) > 50 THEN
      v_social := v_social + 0.35;
    ELSIF r_risk IS NOT NULL AND COALESCE(r_risk.default_contagion_risk, 0) > 25 THEN
      v_social := v_social + 0.18;
    END IF;
    IF r_network IS NOT NULL AND COALESCE(r_network.network_default_rate, 0) > 10 THEN
      v_social := v_social + 0.30;
    ELSIF r_network IS NOT NULL AND COALESCE(r_network.network_default_rate, 0) > 5 THEN
      v_social := v_social + 0.15;
    END IF;
    v_social := LEAST(1.0000, v_social);
  END IF;

  -- TENURE SIGNAL (10%)
  IF r_profile IS NOT NULL THEN
    v_data_points := v_data_points + 1;
    IF COALESCE(r_profile.account_age_days, 0) < 30 THEN v_tenure := 0.5000;
    ELSIF COALESCE(r_profile.account_age_days, 0) < 90 THEN v_tenure := 0.3000;
    ELSIF COALESCE(r_profile.account_age_days, 0) < 180 THEN v_tenure := 0.1500;
    ELSE v_tenure := 0.0000;
    END IF;
  ELSIF r_score IS NOT NULL THEN
    v_data_points := v_data_points + 1;
    IF COALESCE(r_score.account_age_days, 0) < 30 THEN v_tenure := 0.5000;
    ELSIF COALESCE(r_score.account_age_days, 0) < 90 THEN v_tenure := 0.3000;
    ELSIF COALESCE(r_score.account_age_days, 0) < 180 THEN v_tenure := 0.1500;
    ELSE v_tenure := 0.0000;
    END IF;
  END IF;

  -- COMPOSITE
  v_probability := LEAST(1.0000, GREATEST(0.0000,
    0.35 * v_payment + 0.20 * v_financial + 0.20 * v_behavioral + 0.15 * v_social + 0.10 * v_tenure
  ));

  v_bucket := CASE
    WHEN v_probability < 0.05 THEN 'very_low'
    WHEN v_probability < 0.15 THEN 'low'
    WHEN v_probability < 0.30 THEN 'moderate'
    WHEN v_probability < 0.50 THEN 'high'
    ELSE 'very_high'
  END;

  v_confidence := LEAST(1.00, v_data_points::DECIMAL / 5.0);

  -- UPSERT
  INSERT INTO default_probability_scores (
    user_id, predicted_probability, risk_bucket,
    payment_signal, financial_signal, behavioral_signal, social_signal, tenure_signal,
    model_version, confidence_score,
    input_signals, last_computed_at, updated_at
  ) VALUES (
    p_user_id, v_probability, v_bucket,
    v_payment, v_financial, v_behavioral, v_social, v_tenure,
    'v1_heuristic', v_confidence,
    jsonb_build_object(
      'missed_pct', COALESCE(r_profile.missed_pct, 0),
      'late_pct', COALESCE(r_profile.late_pct, 0),
      'payment_trend', COALESCE(r_profile.payment_trend, 'unknown'),
      'balance_volatility', COALESCE(r_profile.balance_volatility, 0),
      'days_since_last_activity', COALESCE(r_profile.days_since_last_activity, 0),
      'account_age_days', COALESCE(r_profile.account_age_days, COALESCE(r_score.account_age_days, 0)),
      'social_isolation', COALESCE(r_risk.social_isolation_score, 0),
      'network_default_rate', COALESCE(r_network.network_default_rate, 0),
      'xn_score', COALESCE(r_score.total_score, 0)
    ),
    NOW(), NOW()
  )
  ON CONFLICT (user_id) DO UPDATE SET
    predicted_probability = EXCLUDED.predicted_probability,
    risk_bucket = EXCLUDED.risk_bucket,
    payment_signal = EXCLUDED.payment_signal,
    financial_signal = EXCLUDED.financial_signal,
    behavioral_signal = EXCLUDED.behavioral_signal,
    social_signal = EXCLUDED.social_signal,
    tenure_signal = EXCLUDED.tenure_signal,
    confidence_score = EXCLUDED.confidence_score,
    input_signals = EXCLUDED.input_signals,
    last_computed_at = NOW(),
    updated_at = NOW();

  -- HISTORY
  INSERT INTO default_probability_history (user_id, probability, risk_bucket, model_version, computed_at)
  VALUES (p_user_id, v_probability, v_bucket, 'v1_heuristic', NOW());

  -- UPDATE member_risk_indicators
  UPDATE member_risk_indicators
  SET predicted_default_probability = v_probability, updated_at = NOW()
  WHERE user_id = p_user_id;

  RETURN v_probability;
END;
$function$
;

CREATE OR REPLACE FUNCTION public.compute_honor_score(p_user_id uuid)
 RETURNS numeric
 LANGUAGE plpgsql
 SECURITY DEFINER
AS $function$
DECLARE
  v_circles_participation DECIMAL(5,2) := 0;
  v_community_engagement DECIMAL(5,2) := 0;
  v_community_score DECIMAL(5,2) := 0;
  v_vouch_given DECIMAL(5,2) := 0;
  v_vouch_received DECIMAL(5,2) := 0;
  v_dispute_involvement DECIMAL(5,2) := 0;
  v_character_score DECIMAL(5,2) := 0;
  v_expertise_top3 DECIMAL(5,2) := 0;
  v_expertise_domains INTEGER := 0;
  v_expertise_score DECIMAL(5,2) := 0;
  v_total_score DECIMAL(5,2) := 0;
  v_previous_score DECIMAL(5,2);
  v_score_tier TEXT;
  v_input_snapshot JSONB := '{}';
  v_circles_completed INTEGER := 0;
  v_training_completed INTEGER := 0;
  v_council_votes INTEGER := 0;
  v_elder_months INTEGER := 0;
  v_vouches_given_total INTEGER := 0;
  v_vouches_given_success INTEGER := 0;
  v_vouches_given_failed INTEGER := 0;
  v_vouches_given_active INTEGER := 0;
  v_vouches_received_total INTEGER := 0;
  v_vouches_received_active INTEGER := 0;
  v_vouches_received_failed INTEGER := 0;
  v_cases_resolved INTEGER := 0;
  v_disputes_against INTEGER := 0;
BEGIN
  -- ══════════════════════════════════════════════════
  -- COMMUNITY PILLAR (30 pts max)
  -- ══════════════════════════════════════════════════

  -- A. Circles Participation (max 15)
  SELECT COALESCE(circles_completed, 0) INTO v_circles_completed
  FROM community_memberships WHERE user_id = p_user_id AND status = 'active' LIMIT 1;

  IF COALESCE(v_circles_completed, 0) > 0 THEN
    v_circles_participation := LEAST(15, ROUND(v_circles_completed * 1.5, 2));
  ELSE
    v_circles_participation := 5;
  END IF;

  -- B. Community Engagement (max 15)
  SELECT COALESCE(
    (SELECT COUNT(*) FROM jsonb_each(COALESCE(cm.training_progress, '{}'::jsonb)) kv
     WHERE (kv.value->>'completed')::boolean = true), 0)
  INTO v_training_completed
  FROM community_memberships cm WHERE cm.user_id = p_user_id AND cm.status = 'active' LIMIT 1;

  SELECT COUNT(*) INTO v_council_votes FROM elder_vote_records WHERE elder_user_id = p_user_id;

  SELECT COALESCE(EXTRACT(MONTH FROM AGE(NOW(), elder_approved_at))::INTEGER, 0)
  INTO v_elder_months
  FROM community_memberships WHERE user_id = p_user_id AND status = 'active' AND role = 'elder' LIMIT 1;

  v_community_engagement := LEAST(8, COALESCE(v_training_completed, 0))
    + LEAST(4, ROUND(COALESCE(v_council_votes, 0) * 0.5, 2))
    + LEAST(3, ROUND(COALESCE(v_elder_months, 0) * 0.5, 2));
  v_community_engagement := LEAST(15, v_community_engagement);

  v_community_score := LEAST(30, v_circles_participation + v_community_engagement);

  -- ══════════════════════════════════════════════════
  -- CHARACTER PILLAR (40 pts max) -- THE HEART
  -- ══════════════════════════════════════════════════

  -- A. Vouch Given (max 20)
  SELECT COUNT(*),
    COUNT(*) FILTER (WHERE status IN ('active', 'expired')),
    COUNT(*) FILTER (WHERE status = 'invalidated_by_default'),
    COUNT(*) FILTER (WHERE status = 'active')
  INTO v_vouches_given_total, v_vouches_given_success, v_vouches_given_failed, v_vouches_given_active
  FROM member_vouches WHERE voucher_user_id = p_user_id;

  IF v_vouches_given_total > 0 THEN
    v_vouch_given := GREATEST(0, LEAST(20,
      10 + (v_vouches_given_success * 5) - (v_vouches_given_failed * 10) - (v_vouches_given_active * 5)
    ));
  ELSE
    v_vouch_given := 10;
  END IF;

  -- B. Vouch Received (max 10)
  SELECT COUNT(*),
    COUNT(*) FILTER (WHERE status IN ('active', 'expired')),
    COUNT(*) FILTER (WHERE status = 'invalidated_by_default')
  INTO v_vouches_received_total, v_vouches_received_active, v_vouches_received_failed
  FROM member_vouches WHERE vouched_user_id = p_user_id;

  IF v_vouches_received_total > 0 THEN
    v_vouch_received := GREATEST(0, LEAST(10,
      2 + (v_vouches_received_active * 3) - (v_vouches_received_failed * 5)
    ));
  ELSE
    v_vouch_received := 2;
  END IF;

  -- C. Dispute Involvement (max 10)
  SELECT COUNT(*) INTO v_cases_resolved
  FROM disputes WHERE assigned_to = p_user_id AND status = 'resolved';

  SELECT COUNT(*) INTO v_disputes_against
  FROM disputes WHERE against_user_id = p_user_id AND status NOT IN ('dismissed');

  v_dispute_involvement := GREATEST(0, LEAST(10,
    3 + LEAST(7, COALESCE(v_cases_resolved, 0)) - (COALESCE(v_disputes_against, 0) * 2)
  ));

  v_character_score := LEAST(40, v_vouch_given + v_vouch_received + v_dispute_involvement);

  -- ══════════════════════════════════════════════════
  -- EXPERTISE PILLAR (30 pts max)
  -- ══════════════════════════════════════════════════

  SELECT COUNT(*) INTO v_expertise_domains
  FROM user_expertise WHERE user_id = p_user_id AND total_domain_score > 0;

  SELECT COALESCE(AVG(top_scores.total_domain_score), 0) INTO v_expertise_top3
  FROM (SELECT total_domain_score FROM user_expertise
    WHERE user_id = p_user_id AND total_domain_score > 0
    ORDER BY total_domain_score DESC LIMIT 3) top_scores;

  v_expertise_score := LEAST(30, ROUND(v_expertise_top3, 2));

  -- ══════════════════════════════════════════════════
  -- TOTAL + TIER
  -- ══════════════════════════════════════════════════

  v_total_score := LEAST(100, v_community_score + v_character_score + v_expertise_score);

  v_score_tier := CASE
    WHEN v_total_score >= 90 THEN 'Grand Elder'
    WHEN v_total_score >= 75 THEN 'Elder'
    WHEN v_total_score >= 50 THEN 'Respected'
    WHEN v_total_score >= 25 THEN 'Trusted'
    ELSE 'Novice'
  END;

  v_input_snapshot := jsonb_build_object(
    'circles_completed', v_circles_completed, 'training_completed', v_training_completed,
    'council_votes', v_council_votes, 'elder_months', v_elder_months,
    'vouches_given_total', v_vouches_given_total, 'vouches_given_success', v_vouches_given_success,
    'vouches_given_failed', v_vouches_given_failed, 'vouches_given_active', v_vouches_given_active,
    'vouches_received_total', v_vouches_received_total, 'vouches_received_active', v_vouches_received_active,
    'vouches_received_failed', v_vouches_received_failed,
    'cases_resolved', v_cases_resolved, 'disputes_against', v_disputes_against,
    'expertise_domains_active', v_expertise_domains, 'expertise_top3_avg', v_expertise_top3);

  SELECT total_score INTO v_previous_score FROM honor_scores WHERE user_id = p_user_id;

  INSERT INTO honor_scores (
    user_id, total_score, previous_score, score_tier,
    community_score, character_score, expertise_score,
    circles_participation_score, community_engagement_score,
    vouch_given_score, vouch_received_score, dispute_involvement_score,
    expertise_top3_avg, expertise_domains_active,
    input_snapshot, computation_trigger, last_computed_at
  ) VALUES (
    p_user_id, v_total_score, v_previous_score, v_score_tier,
    v_community_score, v_character_score, v_expertise_score,
    v_circles_participation, v_community_engagement,
    v_vouch_given, v_vouch_received, v_dispute_involvement,
    v_expertise_top3, v_expertise_domains,
    v_input_snapshot, 'pipeline', NOW()
  )
  ON CONFLICT (user_id) DO UPDATE SET
    total_score = EXCLUDED.total_score, previous_score = honor_scores.total_score,
    score_tier = EXCLUDED.score_tier,
    community_score = EXCLUDED.community_score, character_score = EXCLUDED.character_score,
    expertise_score = EXCLUDED.expertise_score,
    circles_participation_score = EXCLUDED.circles_participation_score,
    community_engagement_score = EXCLUDED.community_engagement_score,
    vouch_given_score = EXCLUDED.vouch_given_score,
    vouch_received_score = EXCLUDED.vouch_received_score,
    dispute_involvement_score = EXCLUDED.dispute_involvement_score,
    expertise_top3_avg = EXCLUDED.expertise_top3_avg,
    expertise_domains_active = EXCLUDED.expertise_domains_active,
    input_snapshot = EXCLUDED.input_snapshot,
    computation_trigger = EXCLUDED.computation_trigger,
    last_computed_at = NOW(), updated_at = NOW();

  IF v_previous_score IS NULL OR v_previous_score != v_total_score THEN
    INSERT INTO honor_score_history (
      user_id, score, previous_score, score_change,
      trigger_event, trigger_details, pillar_breakdown
    ) VALUES (
      p_user_id, v_total_score, COALESCE(v_previous_score, 0),
      v_total_score - COALESCE(v_previous_score, 0),
      'pipeline_recompute', 'Daily pipeline computation',
      jsonb_build_object('community', v_community_score, 'character', v_character_score, 'expertise', v_expertise_score)
    );
  END IF;

  UPDATE community_memberships SET honor_score = ROUND(v_total_score)::INTEGER, updated_at = NOW()
  WHERE user_id = p_user_id AND status = 'active';

  RETURN v_total_score;
END;
$function$
;

CREATE OR REPLACE FUNCTION public.compute_member_profile(p_user_id uuid)
 RETURNS void
 LANGUAGE plpgsql
 SECURITY DEFINER
AS $function$
DECLARE
  v_account_created TIMESTAMPTZ;
  v_account_age INTEGER;
  v_total_contributions INTEGER := 0;
  v_total_amount DECIMAL(15,2) := 0;
  v_on_time INTEGER := 0;
  v_late INTEGER := 0;
  v_missed INTEGER := 0;
  v_avg_late_days DECIMAL(5,2) := 0;
  v_last_contribution TIMESTAMPTZ;
  v_circles_joined INTEGER := 0;
  v_circles_completed INTEGER := 0;
  v_circles_active INTEGER := 0;
  v_wallet_balance DECIMAL(12,2) := 0;
  v_deposits_3m DECIMAL(12,2) := 0;
  v_withdrawals_3m DECIMAL(12,2) := 0;
  v_largest_tx DECIMAL(12,2) := 0;
  v_loans_applied INTEGER := 0;
  v_loans_approved INTEGER := 0;
  v_loans_repaid INTEGER := 0;
  v_loans_defaulted INTEGER := 0;
  v_total_borrowed DECIMAL(15,2) := 0;
  v_total_repaid_loans DECIMAL(15,2) := 0;
  v_vouches_given INTEGER := 0;
  v_vouches_received INTEGER := 0;
  v_disputes_filed INTEGER := 0;
  v_disputes_received INTEGER := 0;
  v_connections INTEGER := 0;
  v_avg_conn_score DECIMAL(5,2) := 0;
  v_sessions_week DECIMAL(5,2) := 0;
  v_last_login TIMESTAMPTZ;
  v_active_30 INTEGER := 0;
  v_active_90 INTEGER := 0;
  v_primary_device TEXT := 'web';
  v_default_count INTEGER := 0;
  v_default_amount DECIMAL(15,2) := 0;
  v_start_time TIMESTAMPTZ := clock_timestamp();
  v_duration_ms INTEGER;
BEGIN
  SELECT created_at INTO v_account_created FROM profiles WHERE id = p_user_id;
  IF v_account_created IS NULL THEN RETURN; END IF;
  v_account_age := EXTRACT(DAY FROM (NOW() - v_account_created))::INTEGER;

  BEGIN
    SELECT COUNT(*), COALESCE(SUM(contributed_amount), 0), MAX(contributed_at)
    INTO v_total_contributions, v_total_amount, v_last_contribution
    FROM cycle_contributions WHERE user_id = p_user_id AND status = 'paid';
  EXCEPTION WHEN OTHERS THEN NULL;
  END;

  BEGIN
    SELECT COALESCE(SUM(on_time_count), 0), COALESCE(SUM(late_count), 0), COALESCE(SUM(missed_count), 0)
    INTO v_on_time, v_late, v_missed
    FROM member_contribution_stats WHERE user_id = p_user_id;
  EXCEPTION WHEN OTHERS THEN NULL;
  END;

  BEGIN
    SELECT COALESCE(AVG(days_late), 0) INTO v_avg_late_days
    FROM cycle_contributions WHERE user_id = p_user_id AND days_late > 0;
  EXCEPTION WHEN OTHERS THEN NULL;
  END;

  BEGIN
    SELECT COUNT(*) INTO v_circles_joined FROM circle_members WHERE user_id = p_user_id;
    SELECT COUNT(*) INTO v_circles_active
    FROM circle_members cm JOIN circles c ON c.id = cm.circle_id
    WHERE cm.user_id = p_user_id AND cm.status = 'active' AND c.status = 'active';
  EXCEPTION WHEN OTHERS THEN NULL;
  END;

  BEGIN
    SELECT COALESCE(balance, 0) INTO v_wallet_balance FROM wallets WHERE user_id = p_user_id;
  EXCEPTION WHEN OTHERS THEN NULL;
  END;

  BEGIN
    SELECT COUNT(DISTINCT DATE(created_at)) INTO v_active_30
    FROM user_events WHERE user_id = p_user_id AND created_at > NOW() - INTERVAL '30 days';
    SELECT COUNT(DISTINCT DATE(created_at)) INTO v_active_90
    FROM user_events WHERE user_id = p_user_id AND created_at > NOW() - INTERVAL '90 days';
    SELECT MAX(created_at) INTO v_last_login
    FROM user_events WHERE user_id = p_user_id AND event_type IN ('login', 'app_open');
    SELECT COALESCE(COUNT(DISTINCT session_id)::DECIMAL / 4.0, 0) INTO v_sessions_week
    FROM user_events WHERE user_id = p_user_id AND created_at > NOW() - INTERVAL '28 days';
  EXCEPTION WHEN OTHERS THEN NULL;
  END;

  v_duration_ms := EXTRACT(MILLISECONDS FROM (clock_timestamp() - v_start_time))::INTEGER;

  INSERT INTO member_behavioral_profiles (
    user_id,
    total_contributions, total_contribution_amount, avg_contribution_amount,
    on_time_pct, late_pct, missed_pct, avg_late_days, last_contribution_at,
    circles_joined, circles_completed, circles_active, circle_completion_rate,
    avg_wallet_balance, avg_monthly_deposits, avg_monthly_withdrawals,
    largest_single_transaction, wallet_activity_score,
    loans_applied, loans_approved, loans_repaid, loans_defaulted,
    total_borrowed, total_repaid,
    vouches_given, vouches_received, disputes_filed, disputes_received,
    network_quality_score,
    account_age_days, last_login_at, avg_sessions_per_week,
    days_since_last_activity, active_days_last_30, active_days_last_90,
    primary_device,
    default_count, default_total_amount, risk_score,
    last_computed_at, computation_duration_ms, data_sources
  ) VALUES (
    p_user_id,
    v_total_contributions, v_total_amount,
    CASE WHEN v_total_contributions > 0 THEN v_total_amount / v_total_contributions ELSE 0 END,
    CASE WHEN v_total_contributions > 0 THEN (v_on_time::DECIMAL / v_total_contributions * 100) ELSE 0 END,
    CASE WHEN v_total_contributions > 0 THEN (v_late::DECIMAL / v_total_contributions * 100) ELSE 0 END,
    CASE WHEN v_total_contributions > 0 THEN (v_missed::DECIMAL / v_total_contributions * 100) ELSE 0 END,
    v_avg_late_days, v_last_contribution,
    v_circles_joined, v_circles_completed, v_circles_active,
    CASE WHEN v_circles_joined > 0 THEN (v_circles_completed::DECIMAL / v_circles_joined * 100) ELSE 0 END,
    v_wallet_balance, v_deposits_3m / 3.0, v_withdrawals_3m / 3.0,
    v_largest_tx, LEAST(v_deposits_3m + v_withdrawals_3m, 100),
    v_loans_applied, v_loans_approved, v_loans_repaid, v_loans_defaulted,
    v_total_borrowed, v_total_repaid_loans,
    v_vouches_given, v_vouches_received, v_disputes_filed, v_disputes_received,
    CASE WHEN v_connections > 0 THEN v_avg_conn_score ELSE 50 END,
    v_account_age, v_last_login, v_sessions_week,
    CASE WHEN v_last_login IS NOT NULL THEN EXTRACT(DAY FROM (NOW() - v_last_login))::INTEGER ELSE v_account_age END,
    v_active_30, v_active_90, v_primary_device,
    v_default_count, v_default_amount,
    CASE WHEN v_default_count > 0 THEN LEAST(v_default_count * 20, 100) ELSE 0 END,
    NOW(), v_duration_ms,
    '["cycle_contributions","member_contribution_stats","circle_members","wallets","user_events"]'::jsonb
  )
  ON CONFLICT (user_id) DO UPDATE SET
    total_contributions = EXCLUDED.total_contributions,
    total_contribution_amount = EXCLUDED.total_contribution_amount,
    avg_contribution_amount = EXCLUDED.avg_contribution_amount,
    on_time_pct = EXCLUDED.on_time_pct,
    late_pct = EXCLUDED.late_pct,
    missed_pct = EXCLUDED.missed_pct,
    avg_late_days = EXCLUDED.avg_late_days,
    last_contribution_at = EXCLUDED.last_contribution_at,
    circles_joined = EXCLUDED.circles_joined,
    circles_completed = EXCLUDED.circles_completed,
    circles_active = EXCLUDED.circles_active,
    circle_completion_rate = EXCLUDED.circle_completion_rate,
    avg_wallet_balance = EXCLUDED.avg_wallet_balance,
    avg_monthly_deposits = EXCLUDED.avg_monthly_deposits,
    avg_monthly_withdrawals = EXCLUDED.avg_monthly_withdrawals,
    largest_single_transaction = EXCLUDED.largest_single_transaction,
    wallet_activity_score = EXCLUDED.wallet_activity_score,
    loans_applied = EXCLUDED.loans_applied,
    loans_approved = EXCLUDED.loans_approved,
    loans_repaid = EXCLUDED.loans_repaid,
    loans_defaulted = EXCLUDED.loans_defaulted,
    total_borrowed = EXCLUDED.total_borrowed,
    total_repaid = EXCLUDED.total_repaid,
    vouches_given = EXCLUDED.vouches_given,
    vouches_received = EXCLUDED.vouches_received,
    disputes_filed = EXCLUDED.disputes_filed,
    disputes_received = EXCLUDED.disputes_received,
    network_quality_score = EXCLUDED.network_quality_score,
    account_age_days = EXCLUDED.account_age_days,
    last_login_at = EXCLUDED.last_login_at,
    avg_sessions_per_week = EXCLUDED.avg_sessions_per_week,
    days_since_last_activity = EXCLUDED.days_since_last_activity,
    active_days_last_30 = EXCLUDED.active_days_last_30,
    active_days_last_90 = EXCLUDED.active_days_last_90,
    primary_device = EXCLUDED.primary_device,
    default_count = EXCLUDED.default_count,
    default_total_amount = EXCLUDED.default_total_amount,
    risk_score = EXCLUDED.risk_score,
    last_computed_at = EXCLUDED.last_computed_at,
    computation_duration_ms = EXCLUDED.computation_duration_ms,
    data_sources = EXCLUDED.data_sources;
END;
$function$
;

CREATE OR REPLACE FUNCTION public.compute_session_analytics(p_user_id uuid, p_date date DEFAULT (CURRENT_DATE - '1 day'::interval))
 RETURNS void
 LANGUAGE plpgsql
 SECURITY DEFINER
AS $function$
DECLARE
  v_session_count INTEGER := 0;
  v_screens INTEGER := 0;
  v_unique_screens INTEGER := 0;
  v_auth_events INTEGER := 0;
  v_tx_events INTEGER := 0;
  v_circle_events INTEGER := 0;
  v_errors INTEGER := 0;
  v_peak_hour INTEGER := 0;
  v_devices JSONB := '[]';
  v_cities JSONB := '[]';
  v_features JSONB := '[]';
BEGIN
  SELECT COUNT(DISTINCT session_id) INTO v_session_count
  FROM user_events WHERE user_id = p_user_id AND DATE(created_at) = p_date;

  IF v_session_count = 0 THEN RETURN; END IF;

  SELECT COUNT(*), COUNT(DISTINCT event_label)
  INTO v_screens, v_unique_screens
  FROM user_events
  WHERE user_id = p_user_id AND DATE(created_at) = p_date AND event_type = 'screen_view';

  SELECT
    COUNT(CASE WHEN event_category = 'auth' THEN 1 END),
    COUNT(CASE WHEN event_category IN ('wallet', 'loan') THEN 1 END),
    COUNT(CASE WHEN event_category = 'circle' THEN 1 END),
    COUNT(CASE WHEN outcome = 'failure' THEN 1 END)
  INTO v_auth_events, v_tx_events, v_circle_events, v_errors
  FROM user_events WHERE user_id = p_user_id AND DATE(created_at) = p_date;

  SELECT EXTRACT(HOUR FROM created_at)::INTEGER INTO v_peak_hour
  FROM user_events WHERE user_id = p_user_id AND DATE(created_at) = p_date
  GROUP BY EXTRACT(HOUR FROM created_at) ORDER BY COUNT(*) DESC LIMIT 1;

  SELECT COALESCE(jsonb_agg(DISTINCT device_type), '[]') INTO v_devices
  FROM user_events
  WHERE user_id = p_user_id AND DATE(created_at) = p_date AND device_type IS NOT NULL;

  SELECT COALESCE(jsonb_agg(DISTINCT geo_city), '[]') INTO v_cities
  FROM user_events
  WHERE user_id = p_user_id AND DATE(created_at) = p_date AND geo_city IS NOT NULL;

  SELECT COALESCE(jsonb_agg(jsonb_build_object('feature', cat, 'count', cnt)), '[]')
  INTO v_features
  FROM (
    SELECT event_category AS cat, COUNT(*) AS cnt
    FROM user_events WHERE user_id = p_user_id AND DATE(created_at) = p_date
    GROUP BY event_category ORDER BY cnt DESC LIMIT 5
  ) sub;

  INSERT INTO member_session_analytics (
    user_id, analytics_date,
    session_count, screens_viewed, unique_screens,
    most_used_features, auth_events, transaction_events, circle_events, errors_encountered,
    device_types, peak_hour, geo_cities
  ) VALUES (
    p_user_id, p_date,
    v_session_count, v_screens, v_unique_screens,
    v_features, v_auth_events, v_tx_events, v_circle_events, v_errors,
    v_devices, v_peak_hour, v_cities
  )
  ON CONFLICT (user_id, analytics_date) DO UPDATE SET
    session_count = EXCLUDED.session_count,
    screens_viewed = EXCLUDED.screens_viewed,
    unique_screens = EXCLUDED.unique_screens,
    most_used_features = EXCLUDED.most_used_features,
    auth_events = EXCLUDED.auth_events,
    transaction_events = EXCLUDED.transaction_events,
    circle_events = EXCLUDED.circle_events,
    errors_encountered = EXCLUDED.errors_encountered,
    device_types = EXCLUDED.device_types,
    peak_hour = EXCLUDED.peak_hour,
    geo_cities = EXCLUDED.geo_cities;
END;
$function$
;

CREATE OR REPLACE FUNCTION public.confirm_swap_request(p_request_id uuid, p_requester_id uuid, p_reason text DEFAULT NULL::text)
 RETURNS boolean
 LANGUAGE plpgsql
 SECURITY DEFINER
AS $function$
DECLARE
    v_request position_swap_requests%ROWTYPE;
    v_config JSONB;
    v_requires_elder BOOLEAN;
BEGIN
    -- Get the request
    SELECT * INTO v_request FROM position_swap_requests WHERE id = p_request_id;

    IF NOT FOUND THEN
        RAISE EXCEPTION 'Swap request not found';
    END IF;

    -- Verify caller is the requester
    IF v_request.requester_user_id != p_requester_id THEN
        RAISE EXCEPTION 'Only the requester can confirm';
    END IF;

    -- Check status
    IF v_request.swap_status != 'pending_confirmation' THEN
        RAISE EXCEPTION 'Request is not pending confirmation';
    END IF;

    -- Check cooling off period
    IF v_request.cooling_off_ends_at IS NOT NULL AND v_request.cooling_off_ends_at > now() THEN
        RAISE EXCEPTION 'Cooling off period has not ended yet. Please wait until %', v_request.cooling_off_ends_at;
    END IF;

    -- Check expiry
    IF v_request.expires_at < now() THEN
        UPDATE position_swap_requests SET swap_status = 'expired', updated_at = now() WHERE id = p_request_id;
        INSERT INTO position_swap_events (swap_request_id, event_type, actor_role, event_details)
        VALUES (p_request_id, 'swap_expired', 'system', 'Request expired before requester confirmed');
        RAISE EXCEPTION 'Request has expired';
    END IF;

    -- Check if elder approval required
    v_config := get_circle_swap_config(v_request.circle_id);
    v_requires_elder := (v_config->>'require_elder_approval')::BOOLEAN;

    -- Update status
    UPDATE position_swap_requests SET
        requester_confirmed_at = now(),
        requester_confirmation_reason = p_reason,
        swap_status = CASE WHEN v_requires_elder THEN 'pending_elder_approval' ELSE 'approved' END,
        updated_at = now()
    WHERE id = p_request_id;

    INSERT INTO position_swap_events (
        swap_request_id, event_type, actor_user_id, actor_role, event_details
    ) VALUES (
        p_request_id, 'requester_confirmed', p_requester_id, 'requester',
        COALESCE(p_reason, 'Confirmed swap request')
    );

    -- If no elder approval needed, execute immediately
    IF NOT v_requires_elder THEN
        PERFORM execute_position_swap(p_request_id);
    END IF;

    RETURN true;
END;
$function$
;

CREATE OR REPLACE FUNCTION public.contribute_to_reserve_fund()
 RETURNS trigger
 LANGUAGE plpgsql
AS $function$
DECLARE
    v_community_id UUID;
    v_contribution_percent DECIMAL(4,2);
    v_contribution_amount DECIMAL(12,2);
    v_current_balance DECIMAL(15,2);
BEGIN
    -- Only process for successful payments
    IF NEW.status = 'completed' AND (OLD.status IS NULL OR OLD.status != 'completed') THEN
        -- Get community ID and contribution percent
        SELECT c.community_id, com.reserve_contribution_percent
        INTO v_community_id, v_contribution_percent
        FROM circles c
        LEFT JOIN communities com ON com.id = c.community_id
        WHERE c.id = NEW.circle_id;

        IF v_community_id IS NOT NULL AND v_contribution_percent > 0 THEN
            v_contribution_amount := NEW.amount * (v_contribution_percent / 100);

            -- Update community reserve
            UPDATE communities
            SET reserve_fund_balance = COALESCE(reserve_fund_balance, 0) + v_contribution_amount
            WHERE id = v_community_id
            RETURNING reserve_fund_balance INTO v_current_balance;

            -- Log transaction
            INSERT INTO reserve_fund_transactions (
                community_id, transaction_type, amount, balance_after, circle_id, description
            ) VALUES (
                v_community_id, 'contribution', v_contribution_amount, v_current_balance,
                NEW.circle_id, 'Auto-contribution from circle payment'
            );
        END IF;
    END IF;

    RETURN NEW;
END;
$function$
;

CREATE OR REPLACE FUNCTION public.create_financial_profile_for_user()
 RETURNS trigger
 LANGUAGE plpgsql
AS $function$
BEGIN
    INSERT INTO financial_profiles (user_id)
    VALUES (NEW.id)
    ON CONFLICT (user_id) DO NOTHING;
    RETURN NEW;
END;
$function$
;

CREATE OR REPLACE FUNCTION public.create_insurance_pool_for_circle()
 RETURNS trigger
 LANGUAGE plpgsql
 SECURITY DEFINER
AS $function$
BEGIN
  INSERT INTO circle_insurance_pools (circle_id)
  VALUES (NEW.id)
  ON CONFLICT (circle_id) DO NOTHING;
  RETURN NEW;
END;
$function$
;

CREATE OR REPLACE FUNCTION public.create_loan_application(p_assessment_id uuid, p_user_id uuid, p_purpose_description text DEFAULT NULL::text)
 RETURNS uuid
 LANGUAGE plpgsql
 SECURITY DEFINER
AS $function$
DECLARE
    v_assessment RECORD;
    v_application_id UUID;
BEGIN
    -- Get assessment
    SELECT * INTO v_assessment FROM creditworthiness_assessments WHERE id = p_assessment_id;

    IF NOT FOUND THEN
        RAISE EXCEPTION 'Assessment not found';
    END IF;

    IF v_assessment.user_id != p_user_id THEN
        RAISE EXCEPTION 'Assessment does not belong to user';
    END IF;

    IF NOT v_assessment.is_eligible THEN
        RAISE EXCEPTION 'Assessment shows user is not eligible';
    END IF;

    IF v_assessment.expires_at < now() THEN
        RAISE EXCEPTION 'Assessment has expired';
    END IF;

    -- Create application
    INSERT INTO loan_applications (
        user_id, assessment_id, loan_product_id,
        requested_amount_cents, approved_amount_cents, term_months,
        purpose, purpose_description,
        apr, origination_fee_cents,
        monthly_payment_cents, total_interest_cents, total_repayment_cents,
        status, expires_at
    ) VALUES (
        p_user_id, p_assessment_id, v_assessment.loan_product_id,
        v_assessment.requested_amount_cents, v_assessment.approved_amount_cents, v_assessment.requested_term_months,
        v_assessment.loan_purpose, p_purpose_description,
        v_assessment.final_apr, 0,
        v_assessment.monthly_payment_cents, v_assessment.total_interest_cents, v_assessment.total_repayment_cents,
        CASE
            WHEN v_assessment.system_recommendation = 'approve' THEN 'approved'::loan_application_status
            ELSE 'pending'::loan_application_status
        END,
        now() + INTERVAL '7 days'
    )
    RETURNING id INTO v_application_id;

    RETURN v_application_id;
END;
$function$
;

CREATE OR REPLACE FUNCTION public.create_notification(p_user_id uuid, p_type character varying, p_title text, p_body text, p_data jsonb DEFAULT '{}'::jsonb, p_category character varying DEFAULT NULL::character varying, p_priority character varying DEFAULT 'normal'::character varying, p_related_entity_type character varying DEFAULT NULL::character varying, p_related_entity_id uuid DEFAULT NULL::uuid, p_action_url text DEFAULT NULL::text, p_image_url text DEFAULT NULL::text, p_scheduled_for timestamp with time zone DEFAULT NULL::timestamp with time zone, p_expires_at timestamp with time zone DEFAULT NULL::timestamp with time zone)
 RETURNS uuid
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
    v_notification_id UUID;
    v_prefs RECORD;
    v_push_enabled BOOLEAN;
    v_email_enabled BOOLEAN;
    v_category_key VARCHAR;
BEGIN
    -- Insert notification
    INSERT INTO notifications (
        user_id, type, title, body, data, category, priority,
        related_entity_type, related_entity_id, action_url, image_url,
        scheduled_for, expires_at
    ) VALUES (
        p_user_id, p_type, p_title, p_body, p_data, p_category, p_priority,
        p_related_entity_type, p_related_entity_id, p_action_url, p_image_url,
        p_scheduled_for, p_expires_at
    )
    RETURNING id INTO v_notification_id;

    -- Get user preferences
    SELECT * INTO v_prefs
    FROM notification_preferences
    WHERE user_id = p_user_id;

    -- If no preferences exist, create defaults
    IF NOT FOUND THEN
        INSERT INTO notification_preferences (user_id)
        VALUES (p_user_id)
        RETURNING * INTO v_prefs;
    END IF;

    -- Determine category preference key
    v_category_key := COALESCE(p_category, 'system');

    -- Check push preference for category
    v_push_enabled := v_prefs.push_enabled AND (
        CASE v_category_key
            WHEN 'payment' THEN v_prefs.push_payments
            WHEN 'payout' THEN v_prefs.push_payouts
            WHEN 'circle' THEN v_prefs.push_circles
            WHEN 'loan' THEN v_prefs.push_loans
            WHEN 'reminder' THEN v_prefs.push_reminders
            WHEN 'security' THEN v_prefs.push_security
            WHEN 'marketing' THEN v_prefs.push_marketing
            ELSE v_prefs.push_system
        END
    );

    -- Check email preference for category
    v_email_enabled := v_prefs.email_enabled AND (
        CASE v_category_key
            WHEN 'payment' THEN v_prefs.email_payments
            WHEN 'payout' THEN v_prefs.email_payouts
            WHEN 'circle' THEN v_prefs.email_circles
            WHEN 'loan' THEN v_prefs.email_loans
            WHEN 'reminder' THEN v_prefs.email_reminders
            WHEN 'security' THEN v_prefs.email_security
            WHEN 'marketing' THEN v_prefs.email_marketing
            ELSE TRUE
        END
    );

    -- Queue push notification if enabled
    IF v_push_enabled THEN
        INSERT INTO notification_queue (
            notification_id, user_id, channel, status, payload, next_attempt_at
        ) VALUES (
            v_notification_id, p_user_id, 'push', 'pending',
            jsonb_build_object(
                'notification_id', v_notification_id,
                'title', p_title,
                'body', p_body,
                'data', p_data,
                'category', p_category,
                'priority', p_priority
            ),
            COALESCE(p_scheduled_for, NOW())
        );
    END IF;

    -- Queue email notification if enabled (for important categories)
    IF v_email_enabled AND (p_category IS NOT NULL AND p_category IN ('payment', 'payout', 'security', 'loan')) THEN
        INSERT INTO notification_queue (
            notification_id, user_id, channel, status, payload, next_attempt_at
        ) VALUES (
            v_notification_id, p_user_id, 'email', 'pending',
            jsonb_build_object(
                'notification_id', v_notification_id,
                'title', p_title,
                'body', p_body,
                'data', p_data,
                'category', p_category
            ),
            COALESCE(p_scheduled_for, NOW())
        );
    END IF;

    RETURN v_notification_id;
END;
$function$
;

CREATE OR REPLACE FUNCTION public.create_pending_join(p_email text, p_invite_code text, p_payment_method text, p_payment_details_encrypted text)
 RETURNS uuid
 LANGUAGE plpgsql
 SECURITY DEFINER
AS $function$DECLARE
  v_circle_id UUID;
  v_pending_id UUID;
BEGIN
  IF p_email IS NULL OR p_email = '' THEN
    RAISE EXCEPTION 'email is required';
  END IF;

  IF p_invite_code IS NULL OR p_invite_code = '' THEN
    RAISE EXCEPTION 'invite_code is required';
  END IF;

  SELECT id INTO v_circle_id
  FROM circles
  WHERE invite_code = p_invite_code;

  IF v_circle_id IS NULL THEN
    RAISE EXCEPTION 'Invalid invite code: %', p_invite_code;
  END IF;

  INSERT INTO pending_joins (
    email,
    invite_code,
    circle_id,
    payment_method,
    payment_details_encrypted,
    consented_to_rules
  )
  VALUES (
    LOWER(TRIM(p_email)),
    p_invite_code,
    v_circle_id,
    COALESCE(p_payment_method, 'debit_card'),
    p_payment_details_encrypted,
    true
  )
  RETURNING id INTO v_pending_id;

  RETURN v_pending_id;
END;$function$
;

CREATE OR REPLACE FUNCTION public.create_referral(p_user_id uuid)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
    v_code TEXT;
    v_referral_id UUID;
BEGIN
    -- Generate unique code
    v_code := generate_referral_code(p_user_id);

    IF v_code IS NULL THEN
        RETURN jsonb_build_object('error', 'User not found', 'code', 'USER_NOT_FOUND');
    END IF;

    -- Create referral record
    INSERT INTO referrals (referrer_id, referral_code, status)
    VALUES (p_user_id, v_code, 'pending')
    RETURNING id INTO v_referral_id;

    RETURN jsonb_build_object(
        'success', true,
        'referral_id', v_referral_id,
        'referral_code', v_code,
        'referral_link', 'https://tandaxn.app/join?ref=' || v_code,
        'reward_amount', 10.00,
        'expires_at', NOW() + INTERVAL '90 days'
    );
END;
$function$
;

CREATE OR REPLACE FUNCTION public.create_swap_request(p_circle_id uuid, p_requester_id uuid, p_target_id uuid, p_reason text DEFAULT NULL::text)
 RETURNS uuid
 LANGUAGE plpgsql
 SECURITY DEFINER
AS $function$
DECLARE
    v_request_id UUID;
    v_config JSONB;
    v_circle RECORD;
    v_requester_position INTEGER;
    v_target_position INTEGER;
    v_requester_xn INTEGER;
    v_target_xn INTEGER;
    v_can_swap RECORD;
    v_expiry_hours INTEGER;
BEGIN
    -- Get positions
    SELECT position INTO v_requester_position
    FROM circle_members
    WHERE circle_id = p_circle_id AND user_id = p_requester_id AND status = 'active';

    SELECT position INTO v_target_position
    FROM circle_members
    WHERE circle_id = p_circle_id AND user_id = p_target_id AND status = 'active';

    IF v_requester_position IS NULL OR v_target_position IS NULL THEN
        RAISE EXCEPTION 'Could not find positions for members';
    END IF;

    -- Check if swap is allowed
    SELECT * INTO v_can_swap FROM can_request_swap(
        p_circle_id, p_requester_id, p_target_id,
        v_requester_position, v_target_position
    );

    IF NOT v_can_swap.allowed THEN
        RAISE EXCEPTION '%', v_can_swap.reason;
    END IF;

    -- Get config and circle
    v_config := get_circle_swap_config(p_circle_id);
    SELECT * INTO v_circle FROM circles WHERE id = p_circle_id;
    v_expiry_hours := (v_config->>'request_expiry_hours')::INTEGER;

    -- Get XnScores
    SELECT COALESCE(xn_score, 50) INTO v_requester_xn FROM profiles WHERE id = p_requester_id;
    SELECT COALESCE(xn_score, 50) INTO v_target_xn FROM profiles WHERE id = p_target_id;

    -- Create the request
    INSERT INTO position_swap_requests (
        circle_id,
        requester_user_id, requester_position, requester_xn_score,
        target_user_id, target_position, target_xn_score,
        request_reason,
        swap_status,
        expires_at,
        cycle_number
    ) VALUES (
        p_circle_id,
        p_requester_id, v_requester_position, v_requester_xn,
        p_target_id, v_target_position, v_target_xn,
        p_reason,
        'pending_target',
        now() + (v_expiry_hours || ' hours')::INTERVAL,
        COALESCE(v_circle.current_cycle, 1)
    ) RETURNING id INTO v_request_id;

    -- Log the event
    INSERT INTO position_swap_events (
        swap_request_id, event_type, actor_user_id, actor_role, event_details
    ) VALUES (
        v_request_id, 'request_created', p_requester_id, 'requester',
        format('Requested swap: Position %s → Position %s', v_requester_position, v_target_position)
    );

    RETURN v_request_id;
END;
$function$
;

CREATE OR REPLACE FUNCTION public.create_vouch(p_voucher_id uuid, p_vouchee_id uuid, p_reason text DEFAULT NULL::text, p_relationship text DEFAULT NULL::text)
 RETURNS uuid
 LANGUAGE plpgsql
 SECURITY DEFINER
AS $function$
DECLARE
    v_limits RECORD;
    v_value RECORD;
    v_vouch_id UUID;
BEGIN
    -- Check if can vouch
    SELECT * INTO v_limits FROM get_vouch_limits(p_voucher_id);

    IF NOT v_limits.can_vouch THEN
        RAISE EXCEPTION 'Cannot vouch: %', v_limits.reason;
    END IF;

    -- Cannot vouch for self
    IF p_voucher_id = p_vouchee_id THEN
        RAISE EXCEPTION 'Cannot vouch for yourself';
    END IF;

    -- Check for existing active vouch
    IF EXISTS (
        SELECT 1 FROM vouches
        WHERE voucher_user_id = p_voucher_id
        AND vouchee_user_id = p_vouchee_id
        AND vouch_status = 'active'
    ) THEN
        RAISE EXCEPTION 'Already have an active vouch for this user';
    END IF;

    -- Calculate vouch value
    SELECT * INTO v_value FROM calculate_vouch_value(p_voucher_id, p_vouchee_id);

    -- Create vouch
    INSERT INTO vouches (
        voucher_user_id, vouchee_user_id,
        voucher_xnscore_at_vouch,
        vouch_sequence,
        raw_vouch_value, diluted_vouch_value,
        vouch_reason, relationship_type,
        expires_at
    ) VALUES (
        p_voucher_id, p_vouchee_id,
        v_value.voucher_score,
        v_value.sequence_number,
        v_value.raw_value, v_value.diluted_value,
        p_reason, p_relationship,
        now() + INTERVAL '1 year' -- Vouches expire after 1 year
    )
    RETURNING id INTO v_vouch_id;

    -- Apply score increase to vouchee
    PERFORM apply_xnscore_adjustment(
        p_vouchee_id,
        v_value.diluted_value,
        'vouch_received',
        v_vouch_id
    );

    -- Small bonus to voucher
    PERFORM apply_xnscore_adjustment(
        p_voucher_id,
        0.5,
        'vouch_given',
        v_vouch_id
    );

    RETURN v_vouch_id;
END;
$function$
;

CREATE OR REPLACE FUNCTION public.deactivate_push_token(p_token text)
 RETURNS boolean
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
BEGIN
    UPDATE push_tokens
    SET
        active = FALSE,
        updated_at = NOW()
    WHERE token = p_token
    AND user_id = auth.uid();

    RETURN FOUND;
END;
$function$
;

