BEGIN
    SELECT requires_vote INTO v_requires_vote
    FROM dissolution_trigger_config
    WHERE trigger_type = p_trigger_type;

    RETURN COALESCE(v_requires_vote, true);
END;
$function$
;

CREATE OR REPLACE FUNCTION public.distribute_pool_balance(p_circle_id uuid, p_action text)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
AS $function$
DECLARE
  v_pool RECORD;
  v_member RECORD;
  v_member_count INTEGER;
  v_per_member_cents BIGINT;
  v_remainder_cents BIGINT;
  v_distributed_total BIGINT := 0;
  v_distributions JSONB := '[]'::JSONB;
  v_cycle_id UUID;
BEGIN
  SELECT * INTO v_pool
  FROM circle_insurance_pools
  WHERE circle_id = p_circle_id;

  IF v_pool IS NULL OR v_pool.balance_cents <= 0 THEN
    RETURN jsonb_build_object(
      'action', p_action,
      'amount_cents', 0,
      'reason', 'No pool balance to process'
    );
  END IF;

  SELECT id INTO v_cycle_id
  FROM circle_cycles
  WHERE circle_id = p_circle_id
  ORDER BY cycle_number DESC
  LIMIT 1;

  IF p_action = 'rollover' THEN
    UPDATE circle_insurance_pools
    SET
      total_rolled_over_cents = total_rolled_over_cents + v_pool.balance_cents,
      updated_at = NOW()
    WHERE id = v_pool.id;

    INSERT INTO insurance_pool_transactions (
      pool_id, circle_id, transaction_type, amount_cents,
      running_balance_cents, cycle_id, description
    ) VALUES (
      v_pool.id, p_circle_id, 'rollover', v_pool.balance_cents,
      v_pool.balance_cents, v_cycle_id,
      'Pool balance rolled over to next cycle'
    );

    RETURN jsonb_build_object(
      'action', 'rollover',
      'amount_cents', v_pool.balance_cents,
      'pool_balance_cents', v_pool.balance_cents,
      'message', 'Balance rolled over successfully'
    );
  END IF;

  IF p_action = 'distribute' THEN
    UPDATE circle_insurance_pools
    SET status = 'distributing', updated_at = NOW()
    WHERE id = v_pool.id;

    SELECT COUNT(*) INTO v_member_count
    FROM circle_members
    WHERE circle_id = p_circle_id AND status = 'active';

    IF v_member_count = 0 THEN
      RETURN jsonb_build_object(
        'action', 'distribute',
        'error', 'No active members to distribute to'
      );
    END IF;

    v_per_member_cents := FLOOR(v_pool.balance_cents / v_member_count);
    v_remainder_cents := v_pool.balance_cents - (v_per_member_cents * v_member_count);

    FOR v_member IN
      SELECT cm.user_id
      FROM circle_members cm
      WHERE cm.circle_id = p_circle_id AND cm.status = 'active'
      ORDER BY cm.position ASC
    LOOP
      v_distributed_total := v_distributed_total + v_per_member_cents;

      INSERT INTO insurance_pool_transactions (
        pool_id, circle_id, transaction_type, amount_cents,
        running_balance_cents, cycle_id, user_id, description
      ) VALUES (
        v_pool.id, p_circle_id, 'distribution',
        -v_per_member_cents,
        v_pool.balance_cents - v_distributed_total,
        v_cycle_id, v_member.user_id,
        'Insurance pool distribution: $' ||
          ROUND(v_per_member_cents / 100.0, 2)::TEXT || ' per member'
      );

      v_distributions := v_distributions || jsonb_build_object(
        'user_id', v_member.user_id,
        'amount_cents', v_per_member_cents
      );
    END LOOP;

    UPDATE circle_insurance_pools
    SET
      balance_cents = v_remainder_cents,
      total_distributed_cents = total_distributed_cents + v_distributed_total,
      status = CASE WHEN v_remainder_cents <= 0 THEN 'closed' ELSE 'active' END,
      updated_at = NOW()
    WHERE id = v_pool.id;

    RETURN jsonb_build_object(
      'action', 'distribute',
      'total_distributed_cents', v_distributed_total,
      'per_member_cents', v_per_member_cents,
      'member_count', v_member_count,
      'remainder_cents', v_remainder_cents,
      'distributions', v_distributions
    );
  END IF;

  RETURN jsonb_build_object('error', 'Invalid action: ' || p_action);
END;
$function$
;

CREATE OR REPLACE FUNCTION public.elder_decide_swap(p_request_id uuid, p_elder_id uuid, p_approve boolean, p_reason text DEFAULT NULL::text)
 RETURNS boolean
 LANGUAGE plpgsql
 SECURITY DEFINER
AS $function$
DECLARE
    v_request position_swap_requests%ROWTYPE;
BEGIN
    -- Get the request
    SELECT * INTO v_request FROM position_swap_requests WHERE id = p_request_id;

    IF NOT FOUND THEN
        RAISE EXCEPTION 'Swap request not found';
    END IF;

    -- Verify caller is an elder/admin/creator
    IF NOT EXISTS (
        SELECT 1 FROM circle_members
        WHERE circle_id = v_request.circle_id
        AND user_id = p_elder_id
        AND role IN ('elder', 'admin', 'creator')
    ) THEN
        RAISE EXCEPTION 'Only circle Elders can approve/deny swaps';
    END IF;

    -- Check status
    IF v_request.swap_status != 'pending_elder_approval' THEN
        RAISE EXCEPTION 'Request is not pending Elder approval';
    END IF;

    IF p_approve THEN
        UPDATE position_swap_requests SET
            swap_status = 'approved',
            elder_approved_by = p_elder_id,
            elder_decision_at = now(),
            elder_decision_reason = p_reason,
            updated_at = now()
        WHERE id = p_request_id;

        INSERT INTO position_swap_events (
            swap_request_id, event_type, actor_user_id, actor_role, event_details
        ) VALUES (
            p_request_id, 'elder_approved', p_elder_id, 'elder',
            COALESCE(p_reason, 'Elder approved the swap')
        );

        -- Execute the swap
        PERFORM execute_position_swap(p_request_id);
    ELSE
        UPDATE position_swap_requests SET
            swap_status = 'elder_denied',
            elder_approved_by = p_elder_id,
            elder_decision_at = now(),
            elder_decision_reason = p_reason,
            updated_at = now()
        WHERE id = p_request_id;

        INSERT INTO position_swap_events (
            swap_request_id, event_type, actor_user_id, actor_role, event_details
        ) VALUES (
            p_request_id, 'elder_denied', p_elder_id, 'elder',
            COALESCE(p_reason, 'Elder denied the swap')
        );
    END IF;

    RETURN true;
END;
$function$
;

CREATE OR REPLACE FUNCTION public.end_recovery_period(p_user_id uuid)
 RETURNS boolean
 LANGUAGE plpgsql
AS $function$
DECLARE
    v_score RECORD;
    v_recovery RECORD;
BEGIN
    SELECT * INTO v_score FROM xn_scores WHERE user_id = p_user_id;

    IF NOT FOUND OR NOT v_score.in_recovery_period THEN
        RETURN FALSE;
    END IF;

    -- Update recovery period record
    UPDATE xnscore_recovery_periods SET
        is_active = FALSE,
        ended_at = now(),
        ended_reason = CASE
            WHEN ends_at <= now() THEN 'completed'
            ELSE 'manual_end'
        END,
        score_at_end = v_score.total_score,
        updated_at = now()
    WHERE id = v_score.recovery_period_id;

    -- Update xn_scores
    UPDATE xn_scores SET
        in_recovery_period = FALSE,
        recovery_period_id = NULL,
        recovery_ends_at = NULL,
        recovery_multiplier = 1.00,
        updated_at = now()
    WHERE xn_scores.user_id = p_user_id;

    -- Log to history
    INSERT INTO xnscore_history (
        user_id, score, previous_score, score_change,
        trigger_event, trigger_details
    ) VALUES (
        p_user_id, v_score.total_score, v_score.total_score, 0,
        'recovery_period_ended', 'Recovery period completed'
    );

    RETURN TRUE;
END;
$function$
;

CREATE OR REPLACE FUNCTION public.ensure_single_default_payout_method()
 RETURNS trigger
 LANGUAGE plpgsql
AS $function$
BEGIN
    IF NEW.is_default = true THEN
        UPDATE payout_methods
        SET is_default = false
        WHERE user_id = NEW.user_id
        AND id != NEW.id
        AND is_default = true;
    END IF;
    RETURN NEW;
END;
$function$
;

CREATE OR REPLACE FUNCTION public.ensure_user_profile()
 RETURNS void
 LANGUAGE plpgsql
 SECURITY DEFINER
AS $function$
BEGIN
  INSERT INTO profiles (id, email, full_name)
  VALUES (
    auth.uid(),
    (SELECT email FROM auth.users WHERE id = auth.uid()),
    (SELECT COALESCE(raw_user_meta_data->>'full_name', raw_user_meta_data->>'name', email)
     FROM auth.users WHERE id = auth.uid())
  )
  ON CONFLICT (id) DO NOTHING;
END;
$function$
;

CREATE OR REPLACE FUNCTION public.evaluate_all_member_tiers()
 RETURNS integer
 LANGUAGE plpgsql
 SECURITY DEFINER
AS $function$
DECLARE
  v_count INTEGER := 0;
  v_user RECORD;
BEGIN
  FOR v_user IN SELECT DISTINCT user_id FROM xn_scores
  LOOP
    BEGIN
      PERFORM evaluate_member_tier(v_user.user_id);
      v_count := v_count + 1;
    EXCEPTION WHEN OTHERS THEN
      RAISE WARNING 'evaluate_member_tier failed for user %: %', v_user.user_id, SQLERRM;
    END;
  END LOOP;
  RETURN v_count;
END;
$function$
;

CREATE OR REPLACE FUNCTION public.evaluate_member_tier(p_user_id uuid)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
AS $function$
DECLARE
  v_xn RECORD;
  v_profile RECORD;
  v_current RECORD;
  v_tier RECORD;
  v_new_tier_key TEXT;
  v_new_tier_number INTEGER;
  v_previous_tier TEXT;
  v_changed BOOLEAN := false;
  v_change_type TEXT;
  v_reason TEXT;
  v_next_tier RECORD;
  v_progress_pct INTEGER := 0;
  v_action_items JSONB := '[]';
  v_score INTEGER;
  v_age INTEGER;
  v_completed INTEGER;
  v_defaults INTEGER;
BEGIN
  -- Read XnScore
  SELECT total_score, account_age_days INTO v_xn FROM xn_scores WHERE user_id = p_user_id;
  IF v_xn IS NULL THEN
    v_score := 0; v_age := 0;
  ELSE
    v_score := COALESCE(ROUND(v_xn.total_score), 0);
    v_age := COALESCE(v_xn.account_age_days, 0);
  END IF;

  -- Read behavioral profile
  SELECT circles_completed, default_count INTO v_profile FROM member_behavioral_profiles WHERE user_id = p_user_id;
  v_completed := COALESCE(v_profile.circles_completed, 0);
  v_defaults := COALESCE(v_profile.default_count, 0);

  -- Determine tier from score
  SELECT * INTO v_tier FROM graduated_entry_tiers
  WHERE v_score >= xn_score_min AND v_score <= xn_score_max
  ORDER BY tier_number DESC LIMIT 1;

  IF v_tier IS NULL THEN
    SELECT * INTO v_tier FROM graduated_entry_tiers WHERE tier_key = 'critical';
  END IF;

  v_new_tier_key := v_tier.tier_key;
  v_new_tier_number := v_tier.tier_number;

  -- Get current status
  SELECT * INTO v_current FROM member_tier_status WHERE user_id = p_user_id;

  -- Determine if tier changed
  IF v_current IS NULL THEN
    v_changed := true;
    v_change_type := 'initial';
    v_previous_tier := NULL;
    v_reason := format('Initial tier assignment: %s (XnScore %s)', v_tier.label, v_score);
  ELSIF v_current.current_tier != v_new_tier_key THEN
    v_changed := true;
    v_previous_tier := v_current.current_tier;
    IF v_new_tier_number > v_current.tier_number THEN
      v_change_type := 'advancement';
      v_reason := format('Advanced from %s to %s (XnScore %s)', v_current.current_tier, v_new_tier_key, v_score);
    ELSE
      v_change_type := 'demotion';
      v_reason := format('Demoted from %s to %s (XnScore dropped to %s)', v_current.current_tier, v_new_tier_key, v_score);
    END IF;
  ELSE
    v_previous_tier := v_current.previous_tier;
  END IF;

  -- Compute progress to next tier
  SELECT * INTO v_next_tier FROM graduated_entry_tiers WHERE tier_number = v_new_tier_number + 1;

  IF v_next_tier IS NOT NULL THEN
    IF (v_next_tier.xn_score_min - v_tier.xn_score_min) > 0 THEN
      v_progress_pct := LEAST(100, GREATEST(0,
        ROUND(((v_score - v_tier.xn_score_min)::DECIMAL / (v_next_tier.xn_score_min - v_tier.xn_score_min)) * 100)
      ));
    END IF;

    IF v_score < v_next_tier.xn_score_min THEN
      v_action_items := v_action_items || jsonb_build_object(
        'type', 'xn_score',
        'message', format('Earn %s more XnScore points to reach %s', v_next_tier.xn_score_min - v_score, v_next_tier.label),
        'current', v_score, 'required', v_next_tier.xn_score_min
      );
    END IF;

    IF v_age < v_next_tier.min_account_age_days THEN
      v_action_items := v_action_items || jsonb_build_object(
        'type', 'account_age',
        'message', format('%s more days on platform needed for %s', v_next_tier.min_account_age_days - v_age, v_next_tier.label),
        'current', v_age, 'required', v_next_tier.min_account_age_days
      );
    END IF;
  ELSE
    v_progress_pct := 100;
  END IF;

  -- UPSERT member_tier_status
  INSERT INTO member_tier_status (
    user_id, current_tier, tier_number, previous_tier, tier_achieved_at,
    is_demoted, demotion_reason, demotion_path_back,
    max_circle_size, max_contribution_cents, position_access,
    xn_score_at_eval, account_age_at_eval, circles_completed_at_eval,
    next_tier, progress_pct, action_items
  ) VALUES (
    p_user_id, v_new_tier_key, v_new_tier_number, v_previous_tier,
    CASE WHEN v_changed THEN NOW() ELSE COALESCE(v_current.tier_achieved_at, NOW()) END,
    CASE WHEN v_change_type = 'demotion' THEN true ELSE false END,
    CASE WHEN v_change_type = 'demotion' THEN v_reason ELSE NULL END,
    CASE WHEN v_change_type = 'demotion' THEN
      format('Raise your XnScore back above %s to regain higher tier status', v_tier.xn_score_max + 1)
    ELSE NULL END,
    v_tier.max_circle_size, v_tier.max_contribution_cents, v_tier.position_access,
    v_score, v_age, v_completed,
    CASE WHEN v_next_tier IS NOT NULL THEN v_next_tier.tier_key ELSE NULL END,
    v_progress_pct, v_action_items
  )
  ON CONFLICT (user_id) DO UPDATE SET
    current_tier = EXCLUDED.current_tier,
    tier_number = EXCLUDED.tier_number,
    previous_tier = CASE WHEN v_changed THEN v_previous_tier ELSE member_tier_status.previous_tier END,
    tier_achieved_at = CASE WHEN v_changed THEN NOW() ELSE member_tier_status.tier_achieved_at END,
    is_demoted = EXCLUDED.is_demoted,
    demotion_reason = EXCLUDED.demotion_reason,
    demotion_path_back = EXCLUDED.demotion_path_back,
    max_circle_size = EXCLUDED.max_circle_size,
    max_contribution_cents = EXCLUDED.max_contribution_cents,
    position_access = EXCLUDED.position_access,
    xn_score_at_eval = EXCLUDED.xn_score_at_eval,
    account_age_at_eval = EXCLUDED.account_age_at_eval,
    circles_completed_at_eval = EXCLUDED.circles_completed_at_eval,
    next_tier = EXCLUDED.next_tier,
    progress_pct = EXCLUDED.progress_pct,
    action_items = EXCLUDED.action_items,
    updated_at = NOW();

  -- Record tier change in history
  IF v_changed THEN
    INSERT INTO member_tier_history (user_id, from_tier, to_tier, change_type, reason, xn_score, account_age_days, circles_completed)
    VALUES (p_user_id, v_previous_tier, v_new_tier_key, v_change_type, v_reason, v_score, v_age, v_completed);
  END IF;

  RETURN jsonb_build_object(
    'user_id', p_user_id, 'previous_tier', v_previous_tier,
    'new_tier', v_new_tier_key, 'tier_number', v_new_tier_number,
    'changed', v_changed, 'change_type', COALESCE(v_change_type, 'none'),
    'xn_score', v_score, 'account_age', v_age,
    'circles_completed', v_completed, 'progress_pct', v_progress_pct,
    'max_circle_size', v_tier.max_circle_size,
    'max_contribution_cents', v_tier.max_contribution_cents,
    'position_access', v_tier.position_access
  );
END;
$function$
;

CREATE OR REPLACE FUNCTION public.evaluate_score_alerts()
 RETURNS integer
 LANGUAGE plpgsql
 SECURITY DEFINER
AS $function$
DECLARE
  v_count INTEGER := 0;
  v_rec RECORD;
  v_alert_id UUID;
BEGIN
  -- ALERT 1: High default probability
  FOR v_rec IN
    SELECT dps.user_id, dps.predicted_probability, dps.risk_bucket
    FROM default_probability_scores dps
    WHERE dps.predicted_probability > 0.25
      AND NOT EXISTS (
        SELECT 1 FROM score_alerts sa
        WHERE sa.target_type = 'member' AND sa.target_id = dps.user_id
          AND sa.alert_type = 'member_default_risk'
          AND sa.created_at > NOW() - INTERVAL '7 days'
          AND sa.status IN ('open', 'acknowledged')
      )
  LOOP
    INSERT INTO score_alerts (
      alert_type, target_type, target_id, severity, title, message,
      score_value, threshold_value, context
    ) VALUES (
      'member_default_risk', 'member', v_rec.user_id,
      CASE WHEN v_rec.predicted_probability > 0.50 THEN 'critical' ELSE 'warning' END,
      CASE WHEN v_rec.predicted_probability > 0.50 THEN 'Critical Default Risk' ELSE 'Elevated Default Risk' END,
      'Member default probability is ' || ROUND(v_rec.predicted_probability * 100, 1) || '% (' || v_rec.risk_bucket || ')',
      v_rec.predicted_probability,
      CASE WHEN v_rec.predicted_probability > 0.50 THEN 0.50 ELSE 0.25 END,
      jsonb_build_object('risk_bucket', v_rec.risk_bucket)
    ) RETURNING id INTO v_alert_id;

    INSERT INTO notifications (user_id, type, title, message, data)
    VALUES (v_rec.user_id, 'score_alert',
      'Your payment risk level has increased',
      'Your account shows signs of elevated default risk. Maintain on-time payments to improve your standing.',
      jsonb_build_object('alert_id', v_alert_id, 'risk_bucket', v_rec.risk_bucket));

    INSERT INTO ops_alerts (alert_type, details, priority)
    VALUES ('member_default_risk',
      jsonb_build_object('user_id', v_rec.user_id, 'probability', v_rec.predicted_probability,
        'risk_bucket', v_rec.risk_bucket, 'score_alert_id', v_alert_id),
      CASE WHEN v_rec.predicted_probability > 0.50 THEN 'critical' ELSE 'high' END);
    v_count := v_count + 1;
  END LOOP;

  -- ALERT 2: Circle health decline
  FOR v_rec IN
    SELECT chs.circle_id, chs.health_score, chs.health_status, chs.trend, c.name as circle_name
    FROM circle_health_scores chs JOIN circles c ON c.id = chs.circle_id
    WHERE chs.health_score < 70
      AND NOT EXISTS (
        SELECT 1 FROM score_alerts sa
        WHERE sa.target_type = 'circle' AND sa.target_id = chs.circle_id
          AND sa.alert_type IN ('circle_health_decline', 'circle_critical')
          AND sa.created_at > NOW() - INTERVAL '7 days'
          AND sa.status IN ('open', 'acknowledged')
      )
  LOOP
    INSERT INTO score_alerts (
      alert_type, target_type, target_id, severity, title, message,
      score_value, threshold_value, context
    ) VALUES (
      CASE WHEN v_rec.health_score < 50 THEN 'circle_critical' ELSE 'circle_health_decline' END,
      'circle', v_rec.circle_id,
      CASE WHEN v_rec.health_score < 50 THEN 'critical' ELSE 'warning' END,
      CASE WHEN v_rec.health_score < 50
        THEN 'Critical: Circle health is critical'
        ELSE 'Circle health declining'
      END,
      'Circle health score is ' || ROUND(v_rec.health_score, 1) || '/100 (' || v_rec.health_status || ')',
      v_rec.health_score,
      CASE WHEN v_rec.health_score < 50 THEN 50 ELSE 70 END,
      jsonb_build_object('health_status', v_rec.health_status, 'trend', v_rec.trend)
    ) RETURNING id INTO v_alert_id;

    INSERT INTO notifications (user_id, type, title, message, data)
    SELECT cm.user_id, 'score_alert', 'Your circle needs attention',
      'Circle health is ' || v_rec.health_status || '. Work together to improve on-time contributions.',
      jsonb_build_object('alert_id', v_alert_id, 'circle_id', v_rec.circle_id)
    FROM circle_members cm
    WHERE cm.circle_id = v_rec.circle_id AND cm.status = 'active';

    INSERT INTO ops_alerts (alert_type, details, priority)
    VALUES ('circle_health_decline',
      jsonb_build_object('circle_id', v_rec.circle_id, 'circle_name', v_rec.circle_name,
        'health_score', v_rec.health_score, 'health_status', v_rec.health_status, 'score_alert_id', v_alert_id),
      CASE WHEN v_rec.health_score < 50 THEN 'critical' ELSE 'high' END);
    v_count := v_count + 1;
  END LOOP;

  -- ALERT 3: XnScore significant drop (> 10 points)
  FOR v_rec IN
    SELECT xs.user_id, xs.total_score, xs.previous_score,
           (xs.previous_score - xs.total_score) as drop_amount
    FROM xn_scores xs
    WHERE xs.previous_score IS NOT NULL AND xs.previous_score - xs.total_score > 10
      AND NOT EXISTS (
        SELECT 1 FROM score_alerts sa
        WHERE sa.target_type = 'member' AND sa.target_id = xs.user_id
          AND sa.alert_type = 'xnscore_drop'
          AND sa.created_at > NOW() - INTERVAL '7 days'
          AND sa.status IN ('open', 'acknowledged')
      )
  LOOP
    INSERT INTO score_alerts (
      alert_type, target_type, target_id, severity, title, message,
      score_value, threshold_value, context
    ) VALUES (
      'xnscore_drop', 'member', v_rec.user_id,
      CASE WHEN v_rec.drop_amount > 20 THEN 'critical' ELSE 'warning' END,
      'XnScore dropped significantly',
      'Your XnScore dropped by ' || ROUND(v_rec.drop_amount, 1) || ' points',
      v_rec.total_score, v_rec.previous_score - 10,
      jsonb_build_object('previous_score', v_rec.previous_score,
        'current_score', v_rec.total_score, 'drop_amount', v_rec.drop_amount)
    ) RETURNING id INTO v_alert_id;

    INSERT INTO notifications (user_id, type, title, message, data)
    VALUES (v_rec.user_id, 'score_alert', 'Your XnScore has dropped',
      'Your XnScore dropped by ' || ROUND(v_rec.drop_amount, 1) || ' points. Stay active and make on-time payments to recover.',
      jsonb_build_object('alert_id', v_alert_id, 'drop_amount', v_rec.drop_amount));
    v_count := v_count + 1;
  END LOOP;

  RETURN v_count;
END;
$function$
;

CREATE OR REPLACE FUNCTION public.execute_dissolution(p_dissolution_id uuid, p_executed_by uuid DEFAULT NULL::uuid)
 RETURNS boolean
 LANGUAGE plpgsql
 SECURITY DEFINER
AS $function$
DECLARE
    v_dissolution dissolution_requests%ROWTYPE;
    v_config dissolution_trigger_config%ROWTYPE;
    v_member RECORD;
    v_total_refunded DECIMAL(15,2) := 0;
    v_platform_fee DECIMAL(15,2);
BEGIN
    -- Get dissolution request
    SELECT * INTO v_dissolution FROM dissolution_requests WHERE id = p_dissolution_id;

    IF NOT FOUND THEN
        RAISE EXCEPTION 'Dissolution request not found';
    END IF;

    IF v_dissolution.status != 'approved' THEN
        RAISE EXCEPTION 'Dissolution must be approved before execution';
    END IF;

    -- Update status to executing
    UPDATE dissolution_requests
    SET status = 'executing', updated_at = now()
    WHERE id = p_dissolution_id;

    -- Get config for XnScore impact
    SELECT * INTO v_config FROM dissolution_trigger_config WHERE trigger_type = v_dissolution.trigger_type;

    -- Process each member's refund
    FOR v_member IN
        SELECT * FROM dissolution_member_positions
        WHERE dissolution_request_id = p_dissolution_id
        AND adjusted_refund > 0
    LOOP
        -- Get user's current XnScore
        UPDATE dissolution_member_positions
        SET
            xn_score_before = (SELECT COALESCE(xn_score, 500) FROM profiles WHERE user_id = v_member.user_id),
            xn_score_change = v_config.xn_score_impact
        WHERE id = v_member.id;

        -- Credit refund to user's wallet
        -- Using wallet transaction (assuming wallet infrastructure from migration 015)
        INSERT INTO wallet_transactions (
            user_id,
            type,
            amount,
            balance_type,
            description,
            reference_type,
            reference_id,
            status
        ) VALUES (
            v_member.user_id,
            'credit',
            v_member.adjusted_refund,
            'main',
            'Circle dissolution refund',
            'dissolution',
            p_dissolution_id,
            'completed'
        );

        -- Update user wallet balance
        UPDATE user_wallets
        SET
            main_balance = main_balance + v_member.adjusted_refund,
            updated_at = now()
        WHERE user_id = v_member.user_id;

        -- Update member position status
        UPDATE dissolution_member_positions
        SET
            refund_status = 'completed',
            refund_method = 'wallet',
            refund_executed_at = now(),
            xn_score_after = xn_score_before + v_config.xn_score_impact
        WHERE id = v_member.id;

        -- Update user's XnScore in profiles
        UPDATE profiles
        SET xn_score = GREATEST(0, LEAST(1000, COALESCE(xn_score, 500) + v_config.xn_score_impact))
        WHERE user_id = v_member.user_id;

        v_total_refunded := v_total_refunded + v_member.adjusted_refund;
    END LOOP;

    -- Calculate platform fee (remaining balance)
    v_platform_fee := v_dissolution.total_pool_amount - v_total_refunded;

    -- Update dissolution as completed
    UPDATE dissolution_requests
    SET
        status = 'completed',
        total_refund_amount = v_total_refunded,
        platform_fee_amount = v_platform_fee,
        resolved_at = now(),
        resolved_by = p_executed_by,
        updated_at = now()
    WHERE id = p_dissolution_id;

    -- Update circle status to dissolved
    UPDATE circles
    SET
        status = 'dissolved',
        updated_at = now()
    WHERE id = v_dissolution.circle_id;

    -- Update all circle members to inactive
    UPDATE circle_members
    SET
        status = 'inactive',
        left_at = now(),
        leave_reason = 'circle_dissolved'
    WHERE circle_id = v_dissolution.circle_id;

    -- Record completion event
    INSERT INTO dissolution_events (
        dissolution_request_id,
        event_type,
        event_description,
        actor_id,
        actor_type,
        new_state
    ) VALUES (
        p_dissolution_id,
        'dissolution_completed',
        'Dissolution executed. Total refunded: ' || v_total_refunded || ', Platform fee: ' || v_platform_fee,
        p_executed_by,
        CASE WHEN p_executed_by IS NULL THEN 'system' ELSE 'admin' END,
        jsonb_build_object(
            'total_refunded', v_total_refunded,
            'platform_fee', v_platform_fee,
            'members_refunded', (SELECT COUNT(*) FROM dissolution_member_positions WHERE dissolution_request_id = p_dissolution_id AND refund_status = 'completed')
        )
    );

    RETURN true;
END;
$function$
;

CREATE OR REPLACE FUNCTION public.execute_member_removal(p_removal_request_id uuid, p_executed_by uuid DEFAULT NULL::uuid)
 RETURNS boolean
 LANGUAGE plpgsql
 SECURITY DEFINER
AS $function$
DECLARE
    v_request member_removal_requests%ROWTYPE;
    v_settlement RECORD;
    v_old_positions JSONB;
    v_new_positions JSONB;
    v_circle circles%ROWTYPE;
    v_xn_score_before INTEGER;
    v_xn_score_after INTEGER;
    v_wallet_id UUID;
BEGIN
    SELECT * INTO v_request FROM member_removal_requests WHERE id = p_removal_request_id;
    IF NOT FOUND THEN RAISE EXCEPTION 'Removal request not found'; END IF;
    IF v_request.status NOT IN ('approved', 'pending_approval') THEN RAISE EXCEPTION 'Must be approved first'; END IF;

    UPDATE member_removal_requests SET status = 'executing', updated_at = now() WHERE id = p_removal_request_id;
    SELECT * INTO v_circle FROM circles WHERE id = v_request.circle_id;

    SELECT jsonb_agg(jsonb_build_object('user_id', user_id, 'position', position) ORDER BY position)
    INTO v_old_positions FROM circle_members WHERE circle_id = v_request.circle_id;

    SELECT COALESCE(xn_score, 50) INTO v_xn_score_before FROM profiles WHERE id = v_request.member_user_id;
    SELECT * INTO v_settlement FROM calculate_removal_settlement(v_request.circle_id, v_request.member_user_id, v_request.reason);

    -- Try to get wallet
    BEGIN SELECT id INTO v_wallet_id FROM user_wallets WHERE user_id = v_request.member_user_id;
    EXCEPTION WHEN undefined_table THEN v_wallet_id := NULL; END;

    -- Execute settlement
    CASE v_settlement.settlement_type
        WHEN 'full_refund', 'partial_refund' THEN
            IF v_wallet_id IS NOT NULL AND v_settlement.refund_amount > 0 THEN
                INSERT INTO wallet_transactions (wallet_id, user_id, transaction_type, direction, amount_cents, balance_type, balance_before_cents, balance_after_cents, description, reference_type, reference_id, transaction_status)
                VALUES (v_wallet_id, v_request.member_user_id, 'refund', 'credit', (v_settlement.refund_amount * 100)::BIGINT, 'main', 0, (v_settlement.refund_amount * 100)::BIGINT,
                    CASE v_settlement.settlement_type WHEN 'full_refund' THEN 'Full refund for circle removal' ELSE 'Partial refund (exit fee: ' || v_settlement.exit_fee_amount || ')' END,
                    'removal', p_removal_request_id, 'completed');
                UPDATE user_wallets SET main_balance_cents = main_balance_cents + (v_settlement.refund_amount * 100)::BIGINT, updated_at = now() WHERE user_id = v_request.member_user_id;
            END IF;
        WHEN 'debt_created' THEN
            INSERT INTO member_debts (user_id, circle_id, removal_request_id, original_amount, remaining_amount, reason, debt_status)
            VALUES (v_request.member_user_id, v_request.circle_id, p_removal_request_id, v_settlement.debt_amount, v_settlement.debt_amount, 'early_departure_after_payout', 'pending');
        ELSE NULL;
    END CASE;

    -- Update XnScore
    v_xn_score_after := GREATEST(0, LEAST(100, v_xn_score_before + v_settlement.xn_score_impact));
    UPDATE profiles SET xn_score = v_xn_score_after WHERE id = v_request.member_user_id;

    -- Remove member (update status if column exists, otherwise delete)
    UPDATE circle_members SET status = 'removed' WHERE circle_id = v_request.circle_id AND user_id = v_request.member_user_id;

    -- Update circle member count
    UPDATE circles SET current_members = GREATEST(0, current_members - 1), updated_at = now() WHERE id = v_request.circle_id;

    -- Recalculate positions
    WITH ranked AS (
        SELECT id, ROW_NUMBER() OVER (ORDER BY position) as new_pos
        FROM circle_members WHERE circle_id = v_request.circle_id AND status = 'active'
    )
    UPDATE circle_members cm SET position = r.new_pos::INTEGER FROM ranked r WHERE cm.id = r.id;

    SELECT jsonb_agg(jsonb_build_object('user_id', user_id, 'position', position) ORDER BY position)
    INTO v_new_positions FROM circle_members WHERE circle_id = v_request.circle_id AND status = 'active';

    -- Complete request
    UPDATE member_removal_requests SET
        status = 'completed', resolved_at = now(), resolved_by = p_executed_by,
        settlement_type = v_settlement.settlement_type, settlement_amount = v_settlement.refund_amount,
        exit_fee_amount = v_settlement.exit_fee_amount, debt_amount = v_settlement.debt_amount, updated_at = now()
    WHERE id = p_removal_request_id;

    -- Audit
    INSERT INTO circle_removal_audit (removal_request_id, circle_id, removed_user_id, removed_by_user_id, action_type, reason, reason_details, settlement_type, settlement_amount, exit_fee_amount, debt_amount, old_position, positions_before, positions_after, xn_score_before, xn_score_after, xn_score_delta)
    VALUES (p_removal_request_id, v_request.circle_id, v_request.member_user_id, p_executed_by, 'member_removed', v_request.reason, v_request.reason_details, v_settlement.settlement_type, v_settlement.refund_amount, v_settlement.exit_fee_amount, v_settlement.debt_amount, v_request.member_position, v_old_positions, v_new_positions, v_xn_score_before, v_xn_score_after, v_settlement.xn_score_impact);

    INSERT INTO payout_order_adjustments (circle_id, adjustment_type, affected_user_id, reason, old_order, new_order, old_total_cycles, new_total_cycles, old_beneficiary_id, new_beneficiary_id, cycle_skipped)
    VALUES (v_request.circle_id, 'member_removed', v_request.member_user_id, v_request.reason::TEXT, COALESCE(v_old_positions, '[]'), COALESCE(v_new_positions, '[]'), COALESCE(v_circle.total_cycles, v_circle.member_count), GREATEST(0, COALESCE(v_circle.total_cycles, v_circle.member_count) - 1), CASE WHEN v_request.was_current_beneficiary THEN v_request.member_user_id ELSE NULL END, (v_new_positions->0->>'user_id')::UUID, v_request.was_current_beneficiary);

    RETURN true;
END;
$function$
;

CREATE OR REPLACE FUNCTION public.execute_position_swap(p_request_id uuid)
 RETURNS boolean
 LANGUAGE plpgsql
 SECURITY DEFINER
AS $function$
DECLARE
    v_request position_swap_requests%ROWTYPE;
    v_requester_generous BOOLEAN;
    v_target_generous BOOLEAN;
    v_requester_xn_change INTEGER := 2;
    v_target_xn_change INTEGER := 2;
BEGIN
    -- Get the request
    SELECT * INTO v_request FROM position_swap_requests WHERE id = p_request_id;

    IF NOT FOUND THEN
        RAISE EXCEPTION 'Swap request not found';
    END IF;

    -- Verify status
    IF v_request.swap_status != 'approved' THEN
        RAISE EXCEPTION 'Swap must be approved before execution';
    END IF;

    -- Mark as executing
    UPDATE position_swap_requests SET swap_status = 'executing', updated_at = now() WHERE id = p_request_id;

    -- Perform the swap atomically
    UPDATE circle_members SET position = v_request.target_position, updated_at = now()
    WHERE circle_id = v_request.circle_id AND user_id = v_request.requester_user_id;

    UPDATE circle_members SET position = v_request.requester_position, updated_at = now()
    WHERE circle_id = v_request.circle_id AND user_id = v_request.target_user_id;

    -- Determine generosity (giving up earlier position)
    v_requester_generous := v_request.requester_position < v_request.target_position;
    v_target_generous := v_request.target_position < v_request.requester_position;

    -- Add generosity bonus (+5 for giving up earlier position)
    IF v_requester_generous THEN
        v_requester_xn_change := v_requester_xn_change + 5;
    END IF;
    IF v_target_generous THEN
        v_target_xn_change := v_target_xn_change + 5;
    END IF;

    -- Apply XnScore changes
    UPDATE profiles SET xn_score = LEAST(100, xn_score + v_requester_xn_change) WHERE id = v_request.requester_user_id;
    UPDATE profiles SET xn_score = LEAST(100, xn_score + v_target_xn_change) WHERE id = v_request.target_user_id;

    -- Record history for requester
    INSERT INTO member_swap_history (
        user_id, circle_id, swap_request_id, swap_role,
        old_position, new_position, swap_partner_id,
        was_generous, xn_score_impact, cycle_number
    ) VALUES (
        v_request.requester_user_id, v_request.circle_id, p_request_id, 'requester',
        v_request.requester_position, v_request.target_position, v_request.target_user_id,
        v_requester_generous, v_requester_xn_change, v_request.cycle_number
    );

    -- Record history for target
    INSERT INTO member_swap_history (
        user_id, circle_id, swap_request_id, swap_role,
        old_position, new_position, swap_partner_id,
        was_generous, xn_score_impact, cycle_number
    ) VALUES (
        v_request.target_user_id, v_request.circle_id, p_request_id, 'target',
        v_request.target_position, v_request.requester_position, v_request.requester_user_id,
        v_target_generous, v_target_xn_change, v_request.cycle_number
    );

    -- Mark as completed
    UPDATE position_swap_requests SET
        swap_status = 'completed',
        executed_at = now(),
        executed_by_system = true,
        updated_at = now()
    WHERE id = p_request_id;

    -- Log the event
    INSERT INTO position_swap_events (
        swap_request_id, event_type, actor_role, event_details
    ) VALUES (
        p_request_id, 'swap_executed', 'system',
        format('Positions swapped: %s ↔ %s', v_request.requester_position, v_request.target_position)
    );

    RETURN true;
END;
$function$
;

CREATE OR REPLACE FUNCTION public.expire_old_swap_requests()
 RETURNS void
 LANGUAGE plpgsql
AS $function$
BEGIN
    UPDATE position_swap_requests
    SET status = 'expired', updated_at = NOW()
    WHERE status = 'pending'
    AND expires_at < NOW();
END;
$function$
;

CREATE OR REPLACE FUNCTION public.expire_vouch_grants()
 RETURNS integer
 LANGUAGE plpgsql
 SECURITY DEFINER
AS $function$
DECLARE
  expired_count INT;
BEGIN
  UPDATE vouch_grants
  SET status = 'expired'
  WHERE status = 'active'
    AND expires_at < NOW();

  GET DIAGNOSTICS expired_count = ROW_COUNT;
  RETURN expired_count;
END;
$function$
;

CREATE OR REPLACE FUNCTION public.file_dissolution_objection(p_dissolution_id uuid, p_user_id uuid, p_objection_type objection_type, p_description text, p_evidence_urls text[] DEFAULT NULL::text[])
 RETURNS uuid
 LANGUAGE plpgsql
 SECURITY DEFINER
AS $function$
DECLARE
    v_dissolution dissolution_requests%ROWTYPE;
    v_objection_id UUID;
BEGIN
    -- Get dissolution request
    SELECT * INTO v_dissolution FROM dissolution_requests WHERE id = p_dissolution_id;

    IF NOT FOUND THEN
        RAISE EXCEPTION 'Dissolution request not found';
    END IF;

    -- Check if objection window is open
    IF v_dissolution.status != 'objection_window' THEN
        RAISE EXCEPTION 'Objection window is not open for this dissolution request';
    END IF;

    -- Check if objection period has ended
    IF v_dissolution.objection_window_ends_at < now() THEN
        RAISE EXCEPTION 'Objection window has ended';
    END IF;

    -- Check if user is a member of the circle
    IF NOT EXISTS (
        SELECT 1 FROM circle_members
        WHERE circle_id = v_dissolution.circle_id
        AND user_id = p_user_id
        AND status = 'active'
    ) THEN
        RAISE EXCEPTION 'User is not an active member of this circle';
    END IF;

    -- Create objection
    INSERT INTO dissolution_objections (
        dissolution_request_id,
        user_id,
        objection_type,
        description,
        evidence_urls
    ) VALUES (
        p_dissolution_id,
        p_user_id,
        p_objection_type,
        p_description,
        p_evidence_urls
    ) RETURNING id INTO v_objection_id;

    -- Update objection count
    UPDATE dissolution_requests
    SET objection_count = objection_count + 1
    WHERE id = p_dissolution_id;

    -- Record event
    INSERT INTO dissolution_events (
        dissolution_request_id,
        event_type,
        event_description,
        actor_id,
        new_state
    ) VALUES (
        p_dissolution_id,
        'objection_filed',
        'Objection filed: ' || p_objection_type::TEXT,
        p_user_id,
        jsonb_build_object('objection_type', p_objection_type, 'description', p_description)
    );

    RETURN v_objection_id;
END;
$function$
;

CREATE OR REPLACE FUNCTION public.finalize_objection_window(p_dissolution_id uuid)
 RETURNS text
 LANGUAGE plpgsql
 SECURITY DEFINER
AS $function$
DECLARE
    v_dissolution dissolution_requests%ROWTYPE;
    v_unresolved_objections INTEGER;
    v_new_status dissolution_status;
    v_config dissolution_trigger_config%ROWTYPE;
BEGIN
    -- Get dissolution request
    SELECT * INTO v_dissolution FROM dissolution_requests WHERE id = p_dissolution_id;

    IF NOT FOUND THEN
        RAISE EXCEPTION 'Dissolution request not found';
    END IF;

    IF v_dissolution.status != 'objection_window' THEN
        RAISE EXCEPTION 'Dissolution is not in objection window status';
    END IF;

    -- Get config
    SELECT * INTO v_config FROM dissolution_trigger_config WHERE trigger_type = v_dissolution.trigger_type;

    -- Count unresolved objections
    SELECT COUNT(*) INTO v_unresolved_objections
    FROM dissolution_objections
    WHERE dissolution_request_id = p_dissolution_id
    AND resolved = false;

    IF v_unresolved_objections > 0 AND v_config.can_be_contested THEN
        -- Has unresolved objections, move to contested
        v_new_status := 'contested';
    ELSE
        -- No objections or non-contestable, approve for execution
        v_new_status := 'approved';
    END IF;

    UPDATE dissolution_requests
    SET
        status = v_new_status,
        updated_at = now()
    WHERE id = p_dissolution_id;

    -- Record event
    INSERT INTO dissolution_events (
        dissolution_request_id,
        event_type,
        event_description,
        actor_type,
        new_state
    ) VALUES (
        p_dissolution_id,
        'objection_window_finalized',
        'Objection window closed. Status: ' || v_new_status::TEXT || '. Unresolved objections: ' || v_unresolved_objections,
        'system',
        jsonb_build_object('unresolved_objections', v_unresolved_objections, 'new_status', v_new_status)
    );

    RETURN v_new_status::TEXT;
END;
$function$
;

CREATE OR REPLACE FUNCTION public.generate_all_monthly_obligations()
 RETURNS TABLE(loans_processed integer, obligations_created integer, already_existed integer, errors_count integer)
 LANGUAGE plpgsql
 SECURITY DEFINER
AS $function$
DECLARE
    v_loan RECORD;
    v_result RECORD;
    v_proc INTEGER := 0;
    v_created INTEGER := 0;
    v_existed INTEGER := 0;
    v_errors INTEGER := 0;
BEGIN
    FOR v_loan IN SELECT id FROM loans WHERE status = 'active' AND (last_obligation_generated_date IS NULL OR last_obligation_generated_date < date_trunc('month', CURRENT_DATE)::DATE)
    LOOP
        BEGIN
            SELECT * INTO v_result FROM generate_monthly_obligation(v_loan.id);
            IF v_result.already_exists THEN v_existed := v_existed + 1; ELSE v_created := v_created + 1; END IF;
            v_proc := v_proc + 1;
        EXCEPTION WHEN OTHERS THEN v_errors := v_errors + 1;
        END;
    END LOOP;
    RETURN QUERY SELECT v_proc, v_created, v_existed, v_errors;
END;
$function$
;

CREATE OR REPLACE FUNCTION public.generate_circle_cycles(p_cid uuid)
 RETURNS integer
 LANGUAGE plpgsql
AS $function$
DECLARE v_c RECORD; v_n INTEGER; v_d RECORD; v_cnt INTEGER := 0;
BEGIN
    SELECT * INTO v_c FROM circles WHERE id = p_cid;
    IF v_c IS NULL THEN RAISE EXCEPTION 'Circle not found'; END IF;
    FOR v_n IN 1..v_c.total_cycles LOOP
        SELECT * INTO v_d FROM calculate_cycle_dates(v_c.start_date::DATE, COALESCE(v_c.contribution_frequency,'monthly'), v_n);
        INSERT INTO circle_cycles (circle_id, cycle_number, start_date, contribution_deadline, expected_payout_date, cycle_status, expected_contributions, expected_amount)
        VALUES (p_cid, v_n, v_d.start_date, v_d.contribution_deadline, v_d.expected_payout_date, 'scheduled', v_c.max_members, v_c.contribution_amount * v_c.max_members)
        ON CONFLICT DO NOTHING;
        IF FOUND THEN v_cnt := v_cnt + 1; END IF;
    END LOOP;
    RETURN v_cnt;
END; $function$
;

CREATE OR REPLACE FUNCTION public.generate_gathering_feed_item()
 RETURNS trigger
 LANGUAGE plpgsql
AS $function$
BEGIN
    INSERT INTO community_feed_items (
        community_id, feed_type, title, body,
        attributed_user_id, attributed_name, linked_gathering_id,
        icon_name, is_system_generated
    ) VALUES (
        NEW.community_id,
        'gathering_posted',
        NEW.title,
        NEW.description,
        NEW.organizer_user_id,
        NEW.organizer_first_name,
        NEW.id,
        CASE NEW.event_type
            WHEN 'elder_session' THEN 'school-outline'
            WHEN 'service' THEN 'storefront-outline'
            WHEN 'circle' THEN 'people-outline'
            ELSE 'calendar-outline'
        END,
        true
    );
    RETURN NEW;
END;
$function$
;

CREATE OR REPLACE FUNCTION public.generate_monthly_obligation(p_loan_id uuid, p_for_date date DEFAULT NULL::date)
 RETURNS TABLE(obligation_id uuid, obligation_number integer, due_date date, total_due_cents integer, principal_cents integer, interest_cents integer, already_exists boolean, message text)
 LANGUAGE plpgsql
 SECURITY DEFINER
AS $function$
DECLARE
    v_loan RECORD;
    v_existing RECORD;
    v_num INTEGER;
    v_due DATE;
    v_start DATE;
    v_end DATE;
    v_payment INTEGER;
    v_interest INTEGER;
    v_principal INTEGER;
    v_id UUID;
    v_rate DECIMAL;
    v_target DATE;
BEGIN
    SELECT * INTO v_loan FROM loans WHERE id = p_loan_id;
    IF NOT FOUND THEN RAISE EXCEPTION 'Loan not found'; END IF;
    IF v_loan.status != 'active' THEN
        RETURN QUERY SELECT NULL::UUID, 0, NULL::DATE, 0, 0, 0, FALSE, format('Loan is %s', v_loan.status);
        RETURN;
    END IF;

    v_target := COALESCE(p_for_date,
        CASE WHEN v_loan.last_obligation_generated_date IS NULL THEN
            COALESCE(v_loan.first_payment_date, (v_loan.created_at + INTERVAL '1 month')::DATE)
        ELSE (v_loan.last_obligation_generated_date + INTERVAL '1 month')::DATE END);

    v_due := make_date(EXTRACT(YEAR FROM v_target)::INTEGER, EXTRACT(MONTH FROM v_target)::INTEGER, LEAST(COALESCE(v_loan.payment_day_of_month, 1), 28));

    SELECT * INTO v_existing FROM loan_payment_obligations WHERE loan_id = p_loan_id AND loan_payment_obligations.due_date = v_due;
    IF FOUND THEN
        RETURN QUERY SELECT v_existing.id, v_existing.obligation_number, v_existing.due_date, v_existing.total_due_cents,
            v_existing.principal_due_cents, v_existing.interest_due_cents, TRUE, 'Already exists';
        RETURN;
    END IF;

    SELECT COALESCE(MAX(loan_payment_obligations.obligation_number), 0) + 1 INTO v_num FROM loan_payment_obligations WHERE loan_id = p_loan_id;

    v_start := v_due - INTERVAL '1 month';
    v_end := v_due - INTERVAL '1 day';
    v_payment := COALESCE(v_loan.estimated_monthly_payment_cents, 0);

    IF v_payment = 0 THEN
        SELECT monthly_payment_cents INTO v_payment FROM calculate_estimated_monthly_payment(v_loan.principal_cents, COALESCE(v_loan.apr / 100, 0.10), COALESCE(v_loan.term_months, 12));
    END IF;

    v_rate := get_effective_rate(p_loan_id, v_due);
    SELECT interest_cents INTO v_interest FROM calculate_daily_interest(v_loan.outstanding_principal_cents, v_rate, 30);
    v_principal := GREATEST(0, v_payment - v_interest);

    IF v_principal > v_loan.outstanding_principal_cents THEN
        v_principal := v_loan.outstanding_principal_cents;
        v_payment := v_principal + v_interest;
    END IF;

    INSERT INTO loan_payment_obligations (loan_id, user_id, obligation_number, period_start_date, period_end_date, due_date, estimated_payment_cents, principal_due_cents, interest_due_cents, total_due_cents, status)
    VALUES (p_loan_id, v_loan.user_id, v_num, v_start, v_end, v_due, v_payment, v_principal, v_interest, v_payment,
        CASE WHEN v_due <= CURRENT_DATE THEN 'due'::obligation_status ELSE 'upcoming'::obligation_status END)
    RETURNING id INTO v_id;

    UPDATE loans SET last_obligation_generated_date = v_due, next_payment_date = v_due,
        estimated_monthly_payment_cents = COALESCE(estimated_monthly_payment_cents, v_payment), updated_at = now()
    WHERE id = p_loan_id;

    PERFORM schedule_payment_reminders(v_id);

    RETURN QUERY SELECT v_id, v_num, v_due, v_payment, v_principal, v_interest, FALSE, 'Created';
END;
$function$
;

CREATE OR REPLACE FUNCTION public.generate_payment_schedule(p_loan_id uuid)
 RETURNS integer
 LANGUAGE plpgsql
AS $function$
DECLARE
    v_loan RECORD;
    v_payment_num INTEGER := 1;
    v_remaining_principal INTEGER;
    v_monthly_rate DECIMAL;
    v_payment_date DATE;
    v_principal_portion INTEGER;
    v_interest_portion INTEGER;
BEGIN
    SELECT * INTO v_loan FROM loans WHERE id = p_loan_id;

    IF NOT FOUND THEN
        RAISE EXCEPTION 'Loan not found';
    END IF;

    v_remaining_principal := v_loan.principal_cents;
    v_monthly_rate := v_loan.apr / 100 / 12;
    v_payment_date := v_loan.first_payment_date;

    WHILE v_payment_num <= v_loan.term_months LOOP
        -- Calculate interest for this period
        v_interest_portion := ROUND(v_remaining_principal * v_monthly_rate);

        -- Principal is payment minus interest
        IF v_payment_num < v_loan.term_months THEN
            v_principal_portion := v_loan.monthly_payment_cents - v_interest_portion;
        ELSE
            -- Last payment: remaining principal
            v_principal_portion := v_remaining_principal;
        END IF;

        -- Insert schedule entry
        INSERT INTO loan_payment_schedule (
            loan_id, payment_number, due_date,
            principal_due_cents, interest_due_cents, total_due_cents
        ) VALUES (
            p_loan_id, v_payment_num, v_payment_date,
            v_principal_portion, v_interest_portion, v_principal_portion + v_interest_portion
        );

        v_remaining_principal := v_remaining_principal - v_principal_portion;
        v_payment_date := v_payment_date + INTERVAL '1 month';
        v_payment_num := v_payment_num + 1;
    END LOOP;

    RETURN v_payment_num - 1;
END;
$function$
;

CREATE OR REPLACE FUNCTION public.generate_payoff_quote(p_loan_id uuid, p_payoff_date date DEFAULT CURRENT_DATE)
 RETURNS uuid
 LANGUAGE plpgsql
 SECURITY DEFINER
AS $function$
DECLARE
    v_quote RECORD;
    v_loan RECORD;
    v_quote_id UUID;
BEGIN
    SELECT * INTO v_loan FROM loans WHERE id = p_loan_id;
    SELECT * INTO v_quote FROM calculate_payoff_amount(p_loan_id, p_payoff_date);

    INSERT INTO loan_payoff_quotes (
        loan_id, user_id, quote_date, valid_until,
        outstanding_principal_cents, accrued_interest_cents, outstanding_fees_cents,
        total_payoff_cents, per_diem_cents, current_rate, rate_type
    ) VALUES (
        p_loan_id, v_loan.user_id, p_payoff_date, v_quote.valid_until,
        v_quote.outstanding_principal_cents,
        v_quote.accrued_interest_cents + v_quote.previous_accrued_interest_cents,
        v_quote.outstanding_fees_cents,
        v_quote.total_payoff_cents, v_quote.per_diem_cents,
        v_quote.current_rate, v_quote.rate_type
    ) RETURNING id INTO v_quote_id;

    RETURN v_quote_id;
END;
$function$
;

CREATE OR REPLACE FUNCTION public.generate_post_feed_item()
 RETURNS trigger
 LANGUAGE plpgsql
AS $function$
BEGIN
    INSERT INTO community_feed_items (
        community_id, feed_type, title, body, photo_url,
        attributed_user_id, attributed_name, linked_post_id,
        is_system_generated
    ) VALUES (
        NEW.community_id,
        NEW.post_type,
        COALESCE(NEW.title, NEW.author_first_name || ' shared a ' || NEW.post_type),
        LEFT(NEW.body, 200),
        NEW.photo_url,
        NEW.author_user_id,
        NEW.author_first_name,
        NEW.id,
        false
    );
    RETURN NEW;
END;
$function$
;

CREATE OR REPLACE FUNCTION public.generate_referral_code(p_user_id uuid)
 RETURNS text
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
    v_user RECORD;
    v_code TEXT;
BEGIN
    SELECT * INTO v_user FROM users WHERE id = p_user_id;

    IF v_user IS NULL THEN
        RETURN NULL;
    END IF;

    -- Generate code: first 3 chars of name + random 5 chars
    v_code := UPPER(
        SUBSTRING(REGEXP_REPLACE(v_user.full_name, '[^a-zA-Z]', '', 'g'), 1, 3) ||
        SUBSTRING(MD5(RANDOM()::TEXT), 1, 5)
    );

    -- Ensure uniqueness
    WHILE EXISTS (SELECT 1 FROM referrals WHERE referral_code = v_code) LOOP
        v_code := UPPER(
            SUBSTRING(REGEXP_REPLACE(v_user.full_name, '[^a-zA-Z]', '', 'g'), 1, 3) ||
            SUBSTRING(MD5(RANDOM()::TEXT), 1, 5)
        );
    END LOOP;

    RETURN v_code;
END;
$function$
;

CREATE OR REPLACE FUNCTION public.get_admin_dashboard_stats()
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
    v_result JSONB;
BEGIN
    SELECT jsonb_build_object(
        'total_users', (SELECT COUNT(*) FROM users),
        'active_users', (SELECT COUNT(*) FROM users WHERE updated_at > NOW() - INTERVAL '30 days'),
        'new_users_today', (SELECT COUNT(*) FROM users WHERE created_at::date = CURRENT_DATE),
        'total_groups', (SELECT COUNT(*) FROM groups WHERE deleted_at IS NULL),
        'active_groups', (SELECT COUNT(*) FROM groups WHERE status = 'active' AND deleted_at IS NULL),
        'total_transactions_today', (SELECT COUNT(*) FROM transactions WHERE created_at::date = CURRENT_DATE),
        'transaction_volume_today', COALESCE((SELECT SUM(amount) FROM transactions WHERE created_at::date = CURRENT_DATE AND status = 'completed'), 0),
        'transaction_volume_week', COALESCE((SELECT SUM(amount) FROM transactions WHERE created_at > NOW() - INTERVAL '7 days' AND status = 'completed'), 0),
        'transaction_volume_month', COALESCE((SELECT SUM(amount) FROM transactions WHERE created_at > NOW() - INTERVAL '30 days' AND status = 'completed'), 0),
        'pending_loans', (SELECT COUNT(*) FROM loans WHERE status = 'pending'),
        'active_loans_count', (SELECT COUNT(*) FROM loans WHERE status = 'active'),
        'active_loans_value', COALESCE((SELECT SUM(amount) FROM loans WHERE status = 'active'), 0),
        'default_rate', COALESCE(
            (SELECT
                ROUND(COUNT(*) FILTER (WHERE status = 'defaulted')::DECIMAL /
                NULLIF(COUNT(*)::DECIMAL, 0) * 100, 2)
            FROM loans WHERE status IN ('active', 'completed', 'defaulted')), 0
        ),
        'open_tickets', (SELECT COUNT(*) FROM support_tickets WHERE status IN ('open', 'in_progress')),
        'avg_xn_score', COALESCE((SELECT ROUND(AVG(xn_score)::DECIMAL, 1) FROM users WHERE xn_score IS NOT NULL), 0)
    ) INTO v_result;

    RETURN v_result;
END;
$function$
;

CREATE OR REPLACE FUNCTION public.get_base_apr(p_credit_score integer, p_risk_grade risk_grade, p_loan_product_id uuid DEFAULT NULL::uuid)
 RETURNS numeric
 LANGUAGE plpgsql
 STABLE
AS $function$
DECLARE
    v_product RECORD;
    v_min_apr DECIMAL;
    v_max_apr DECIMAL;
    v_score_ratio DECIMAL;
BEGIN
    -- Get product-specific rates if available
    IF p_loan_product_id IS NOT NULL THEN
        SELECT * INTO v_product FROM loan_products WHERE id = p_loan_product_id;
        IF FOUND THEN
            v_min_apr := v_product.base_apr_min;
            v_max_apr := v_product.base_apr_max;
        END IF;
    END IF;

    -- Default rates by grade if no product
    IF v_min_apr IS NULL THEN
        v_min_apr := CASE p_risk_grade
            WHEN 'A' THEN 5.00
            WHEN 'B' THEN 8.00
            WHEN 'C' THEN 12.00
            WHEN 'D' THEN 18.00
            ELSE NULL
        END;
        v_max_apr := CASE p_risk_grade
            WHEN 'A' THEN 8.00
            WHEN 'B' THEN 12.00
            WHEN 'C' THEN 18.00
            WHEN 'D' THEN 24.00
            ELSE NULL
        END;
    END IF;

    IF v_min_apr IS NULL THEN
        RETURN NULL; -- Ineligible
    END IF;

    -- Linear interpolation within grade (higher score = lower APR)
    -- For grade A (740-850): at 740, get max APR; at 850, get min APR
    v_score_ratio := CASE p_risk_grade
        WHEN 'A' THEN LEAST(1.0, GREATEST(0, (p_credit_score - 740)::DECIMAL / 110))
        WHEN 'B' THEN LEAST(1.0, GREATEST(0, (p_credit_score - 630)::DECIMAL / 110))
        WHEN 'C' THEN LEAST(1.0, GREATEST(0, (p_credit_score - 520)::DECIMAL / 110))
        WHEN 'D' THEN LEAST(1.0, GREATEST(0, (p_credit_score - 410)::DECIMAL / 110))
        ELSE 0
    END;

    RETURN ROUND(v_max_apr - (v_score_ratio * (v_max_apr - v_min_apr)), 2);
END;
$function$
;

CREATE OR REPLACE FUNCTION public.get_circle_dashboard(p_group_id uuid, p_user_id uuid)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
    v_group RECORD;
    v_membership RECORD;
    v_members JSONB;
    v_contributions JSONB;
    v_payouts JSONB;
    v_my_stats JSONB;
BEGIN
    -- Get group info
    SELECT * INTO v_group FROM groups WHERE id = p_group_id;
    IF v_group IS NULL THEN
        RETURN jsonb_build_object('error', 'Circle not found');
    END IF;

    -- Get user's membership
    SELECT * INTO v_membership
    FROM group_members
    WHERE group_id = p_group_id AND user_id = p_user_id;

    IF v_membership IS NULL THEN
        RETURN jsonb_build_object('error', 'Not a member of this circle');
    END IF;

    -- Get members list with XnScore
    SELECT jsonb_agg(jsonb_build_object(
        'user_id', gm.user_id,
        'full_name', u.full_name,
        'avatar_url', u.avatar_url,
        'payout_position', gm.payout_position,
        'status', gm.status,
        'xn_score', COALESCE(u.xn_score, 30),
        'xn_tier', (get_xn_tier(COALESCE(u.xn_score, 30)))->>'name',
        'is_admin', (v_group.admin_id = gm.user_id),
        'contribution_status', (
            SELECT CASE
                WHEN EXISTS (
                    SELECT 1 FROM contributions c
                    WHERE c.group_id = p_group_id
                    AND c.user_id = gm.user_id
                    AND c.cycle_number = v_group.current_cycle
                    AND c.status = 'completed'
                ) THEN 'paid'
                WHEN EXISTS (
                    SELECT 1 FROM contributions c
                    WHERE c.group_id = p_group_id
                    AND c.user_id = gm.user_id
                    AND c.cycle_number = v_group.current_cycle
                    AND c.status = 'overdue'
                ) THEN 'overdue'
                ELSE 'pending'
            END
        )
    ) ORDER BY gm.payout_position) INTO v_members
    FROM group_members gm
    JOIN users u ON u.id = gm.user_id
    WHERE gm.group_id = p_group_id
    AND gm.status = 'active';

    -- Get recent contributions for this cycle
    SELECT jsonb_agg(jsonb_build_object(
        'id', c.id,
        'user_id', c.user_id,
        'user_name', u.full_name,
        'amount', c.amount,
        'late_fee', c.late_fee,
        'status', c.status,
        'created_at', c.created_at
    ) ORDER BY c.created_at DESC) INTO v_contributions
    FROM contributions c
    JOIN users u ON u.id = c.user_id
    WHERE c.group_id = p_group_id
    AND c.cycle_number = v_group.current_cycle;

    -- Get payout history
    SELECT jsonb_agg(jsonb_build_object(
        'id', p.id,
        'user_id', p.user_id,
        'user_name', u.full_name,
        'amount', p.amount,
        'cycle_number', p.cycle_number,
        'status', p.status,
        'payout_date', p.payout_date
    ) ORDER BY p.payout_date DESC) INTO v_payouts
    FROM payouts p
    JOIN users u ON u.id = p.user_id
    WHERE p.group_id = p_group_id
    LIMIT 10;

    -- Get my stats in this circle
    SELECT jsonb_build_object(
        'total_contributed', COALESCE(SUM(c.amount) FILTER (WHERE c.status = 'completed'), 0),
        'total_payouts_received', COALESCE((
            SELECT SUM(p.amount) FROM payouts p
            WHERE p.group_id = p_group_id AND p.user_id = p_user_id AND p.status = 'completed'
        ), 0),
        'on_time_payments', COUNT(*) FILTER (WHERE c.status = 'completed' AND (c.late_fee IS NULL OR c.late_fee = 0)),
        'late_payments', COUNT(*) FILTER (WHERE c.status = 'completed' AND c.late_fee > 0),
        'missed_payments', COUNT(*) FILTER (WHERE c.status = 'overdue')
    ) INTO v_my_stats
    FROM contributions c
    WHERE c.group_id = p_group_id AND c.user_id = p_user_id;

    -- Build result
    RETURN jsonb_build_object(
        'circle', jsonb_build_object(
            'id', v_group.id,
            'name', v_group.name,
            'description', v_group.description,
            'contribution_amount', v_group.contribution_amount,
            'contribution_frequency', v_group.contribution_frequency,
            'max_members', v_group.max_members,
            'current_members', (SELECT COUNT(*) FROM group_members WHERE group_id = p_group_id AND status = 'active'),
            'current_cycle', v_group.current_cycle,
            'total_cycles', v_group.max_members,
            'next_payout_date', v_group.next_payout_date,
            'status', v_group.status,
            'admin_id', v_group.admin_id,
            'late_fee_percentage', v_group.late_fee_percentage,
            'created_at', v_group.created_at
        ),
        'my_membership', jsonb_build_object(
            'payout_position', v_membership.payout_position,
            'status', v_membership.status,
            'joined_at', v_membership.joined_at,
            'is_admin', (v_group.admin_id = p_user_id),
            'has_contributed_this_cycle', EXISTS (
                SELECT 1 FROM contributions c
                WHERE c.group_id = p_group_id
                AND c.user_id = p_user_id
                AND c.cycle_number = v_group.current_cycle
                AND c.status = 'completed'
            ),
            'is_next_recipient', (v_membership.payout_position = v_group.current_cycle + 1)
        ),
        'my_stats', COALESCE(v_my_stats, '{}'::jsonb),
        'members', COALESCE(v_members, '[]'::jsonb),
        'current_cycle_contributions', COALESCE(v_contributions, '[]'::jsonb),
        'payout_history', COALESCE(v_payouts, '[]'::jsonb),
        'pool_balance', (
            SELECT COALESCE(SUM(c.amount), 0)
            FROM contributions c
            WHERE c.group_id = p_group_id
            AND c.cycle_number = v_group.current_cycle
            AND c.status = 'completed'
        ),
        'fetched_at', NOW()
    );
END;
$function$
;

CREATE OR REPLACE FUNCTION public.get_circle_swap_config(p_circle_id uuid)
 RETURNS jsonb
 LANGUAGE plpgsql
 STABLE
AS $function$
DECLARE
    v_config JSONB;
    v_defaults JSONB := '{
        "swaps_enabled": true,
        "require_elder_approval": false,
        "min_xn_score_for_early_position": 70,
        "early_position_threshold": 3,
        "max_swaps_per_cycle": 2,
        "max_swaps_per_member_per_cycle": 1,
        "blackout_cycles_before_payout": 1,
        "request_expiry_hours": 48,
        "cooling_off_hours": 24,
        "swap_fee_percentage": 0
    }';
BEGIN
    SELECT swap_config INTO v_config FROM circles WHERE id = p_circle_id;
    RETURN v_defaults || COALESCE(v_config, '{}');
END;
$function$
;

CREATE OR REPLACE FUNCTION public.get_connection_type(p_user_id uuid, p_other_user_id uuid)
 RETURNS character varying
 LANGUAGE plpgsql
AS $function$
DECLARE
    v_connection_type VARCHAR(50);
BEGIN
    -- Direct connection
    SELECT connection_type INTO v_connection_type
    FROM user_connections
    WHERE user_id = p_user_id
      AND connected_user_id = p_other_user_id
      AND status = 'active';

    IF v_connection_type IS NOT NULL THEN
        RETURN v_connection_type;
    END IF;

    -- Check if friend of friend (Type C)
    IF EXISTS (
        SELECT 1 FROM user_connections uc1
        JOIN user_connections uc2 ON uc1.connected_user_id = uc2.user_id
        WHERE uc1.user_id = p_user_id
          AND uc2.connected_user_id = p_other_user_id
          AND uc1.status = 'active'
          AND uc2.status = 'active'
          AND uc1.connection_type IN ('friend', 'colleague', 'family', 'close_friend')
    ) THEN
        RETURN 'acquaintance';
    END IF;

    RETURN NULL;
END;
$function$
;

CREATE OR REPLACE FUNCTION public.get_current_index_rate(p_index_name text, p_as_of_date date DEFAULT CURRENT_DATE)
 RETURNS numeric
 LANGUAGE sql
 STABLE
AS $function$
    SELECT rate FROM market_index_rates
    WHERE index_name = p_index_name AND effective_date <= p_as_of_date
    ORDER BY effective_date DESC LIMIT 1;
$function$
;

CREATE OR REPLACE FUNCTION public.get_cycle_status_summary(p_cid uuid)
 RETURNS TABLE(total_expected integer, total_received integer, total_pending integer, total_late integer, total_missed integer, collected_amt numeric, expected_amt numeric, pct numeric)
 LANGUAGE plpgsql
AS $function$
BEGIN
    RETURN QUERY SELECT COUNT(*)::INT, COUNT(*) FILTER (WHERE contribution_status='completed')::INT,
        COUNT(*) FILTER (WHERE contribution_status IN ('pending','partial'))::INT, COUNT(*) FILTER (WHERE contribution_status='late')::INT,
        COUNT(*) FILTER (WHERE contribution_status='missed')::INT, COALESCE(SUM(contributed_amount),0),
        COALESCE(SUM(expected_amount),0), CASE WHEN SUM(expected_amount)>0 THEN ROUND(SUM(contributed_amount)/SUM(expected_amount)*100,2) ELSE 0 END
    FROM cycle_contributions WHERE cycle_id = p_cid;
END; $function$
;

CREATE OR REPLACE FUNCTION public.get_decay_rate(p_inactive_days integer)
 RETURNS numeric
 LANGUAGE plpgsql
 IMMUTABLE
AS $function$
BEGIN
    RETURN CASE
        WHEN p_inactive_days >= 365 THEN -30.00  -- Freeze at floor
        WHEN p_inactive_days >= 240 THEN -25.00
        WHEN p_inactive_days >= 180 THEN -20.00
        WHEN p_inactive_days >= 120 THEN -15.00
        WHEN p_inactive_days >= 90 THEN -10.00
        WHEN p_inactive_days >= 60 THEN -6.00
        WHEN p_inactive_days >= 30 THEN -3.00
        ELSE 0.00
    END;
END;
$function$
;

CREATE OR REPLACE FUNCTION public.get_default_cascade_summary(p_cascade_id uuid)
 RETURNS TABLE(default_id uuid, defaulter_name text, total_owed numeric, amount_recovered numeric, default_status text, vouchers_impacted integer, resolution_method text, payout_reduction numeric, recovery_plan_status text, cascade_completed boolean, events_count integer)
 LANGUAGE plpgsql
AS $function$
BEGIN
    RETURN QUERY
    SELECT
        d.id,
        p.full_name,
        d.total_owed,
        d.amount_recovered,
        d.default_status,
        d.voucher_impacts_applied,
        cdr.resolution_method,
        cdr.payout_reduction,
        rp.plan_status,
        d.cascade_completed,
        (SELECT COUNT(*)::INTEGER FROM cascade_events WHERE cascade_id = p_cascade_id)
    FROM defaults d
    JOIN profiles p ON d.user_id = p.id
    LEFT JOIN circle_default_resolutions cdr ON d.id = cdr.default_id
    LEFT JOIN recovery_plans rp ON d.recovery_plan_id = rp.id
    WHERE d.cascade_id = p_cascade_id;
END;
$function$
;

CREATE OR REPLACE FUNCTION public.get_dissolution_vote_threshold(p_trigger_type dissolution_trigger)
 RETURNS numeric
 LANGUAGE plpgsql
 STABLE
AS $function$
DECLARE
    v_threshold DECIMAL(3,2);
BEGIN
    SELECT vote_threshold INTO v_threshold
    FROM dissolution_trigger_config
    WHERE trigger_type = p_trigger_type;

    RETURN COALESCE(v_threshold, 0.67);
END;
$function$
;

CREATE OR REPLACE FUNCTION public.get_dissolution_xn_impact(p_trigger_type dissolution_trigger)
 RETURNS integer
 LANGUAGE plpgsql
 STABLE
AS $function$
DECLARE
    v_impact INTEGER;
BEGIN
    SELECT xn_score_impact INTO v_impact
    FROM dissolution_trigger_config
    WHERE trigger_type = p_trigger_type;

    RETURN COALESCE(v_impact, 0);
END;
$function$
;

CREATE OR REPLACE FUNCTION public.get_effective_rate(p_loan_id uuid, p_as_of_date date DEFAULT CURRENT_DATE)
 RETURNS numeric
 LANGUAGE plpgsql
 STABLE
AS $function$
DECLARE
    v_loan RECORD;
BEGIN
    SELECT * INTO v_loan FROM loans WHERE id = p_loan_id;
    IF NOT FOUND THEN RETURN NULL; END IF;

    CASE v_loan.interest_rate_type
        WHEN 'fixed', 'risk_based' THEN
            RETURN v_loan.apr / 100;
        WHEN 'promotional' THEN
            IF v_loan.promotional_rate_end_date IS NOT NULL
               AND p_as_of_date < v_loan.promotional_rate_end_date THEN
                RETURN v_loan.promotional_rate;
            ELSE
                RETURN COALESCE(v_loan.post_promotional_rate, v_loan.apr / 100);
            END IF;
        ELSE
            RETURN v_loan.apr / 100;
    END CASE;
END;
$function$
;

CREATE OR REPLACE FUNCTION public.get_elder_tier(score integer)
 RETURNS text
 LANGUAGE plpgsql
 IMMUTABLE
AS $function$
BEGIN
  IF score >= 800 THEN RETURN 'grand_elder';
  ELSIF score >= 600 THEN RETURN 'senior_elder';
  ELSE RETURN 'elder';
  END IF;
END;
$function$
;

CREATE OR REPLACE FUNCTION public.get_eligible_elders(p_domain_id text DEFAULT NULL::text, p_limit integer DEFAULT 10)
 RETURNS TABLE(elder_profile_id uuid, elder_user_id uuid, elder_name text, tier text, honor_score integer, expertise_points integer, active_vouches_count bigint, active_cases_count bigint, match_score numeric)
 LANGUAGE plpgsql
 SECURITY DEFINER
AS $function$
BEGIN
  RETURN QUERY
  SELECT
    ep.id AS elder_profile_id,
    ep.user_id AS elder_user_id,
    p.full_name AS elder_name,
    ep.tier,
    ep.honor_score,
    COALESCE(ue.points, 0) AS expertise_points,
    (SELECT COUNT(*) FROM vouch_grants vg WHERE vg.elder_id = ep.id AND vg.status = 'active') AS active_vouches_count,
    (SELECT COUNT(*) FROM mediation_cases mc WHERE mc.assigned_elder_id = ep.id AND mc.status IN ('assigned', 'in_progress')) AS active_cases_count,
    -- Match score: expertise (60%) + honor (40%) - overload penalty
    (
      COALESCE(ue.points, 0) * 0.6 +
      ep.honor_score * 0.04 -
      (SELECT COUNT(*) FROM vouch_grants vg WHERE vg.elder_id = ep.id AND vg.status = 'active') * 2 -
      (SELECT COUNT(*) FROM mediation_cases mc WHERE mc.assigned_elder_id = ep.id AND mc.status IN ('assigned', 'in_progress')) * 3
    )::NUMERIC AS match_score
  FROM elder_profiles ep
  JOIN profiles p ON p.id = ep.user_id
  LEFT JOIN user_expertise ue ON ue.user_id = ep.user_id AND ue.domain_id = p_domain_id
  WHERE ep.status = 'active'
    AND ep.can_vouch = true
  ORDER BY match_score DESC
  LIMIT p_limit;
END;
$function$
;

CREATE OR REPLACE FUNCTION public.get_factor_status(score numeric, max_score numeric)
 RETURNS factor_status
 LANGUAGE plpgsql
 IMMUTABLE
AS $function$
DECLARE
    pct DECIMAL;
BEGIN
    IF max_score = 0 THEN
        RETURN 'critical'::factor_status;
    END IF;

    pct := (score / max_score) * 100;

    RETURN CASE
        WHEN pct >= 90 THEN 'excellent'::factor_status
        WHEN pct >= 70 THEN 'good'::factor_status
        WHEN pct >= 50 THEN 'fair'::factor_status
        WHEN pct >= 30 THEN 'needs_work'::factor_status
        ELSE 'critical'::factor_status
    END;
END;
$function$
;

CREATE OR REPLACE FUNCTION public.get_factor_trend(current_score numeric, previous_score numeric)
 RETURNS factor_trend
 LANGUAGE plpgsql
 IMMUTABLE
AS $function$
BEGIN
    IF previous_score IS NULL THEN
        RETURN 'stable'::factor_trend;
    END IF;

    IF current_score > previous_score + 0.5 THEN
        RETURN 'improving'::factor_trend;
    ELSIF current_score < previous_score - 0.5 THEN
        RETURN 'declining'::factor_trend;
    ELSE
        RETURN 'stable'::factor_trend;
    END IF;
END;
$function$
;

CREATE OR REPLACE FUNCTION public.get_improvement_tips(p_user_id uuid, p_limit integer DEFAULT 5)
 RETURNS jsonb
 LANGUAGE plpgsql
 STABLE
AS $function$
DECLARE
    v_tips JSONB := '[]';
    v_tip RECORD;
    v_score_record RECORD;
    v_payment RECORD;
    v_completion RECORD;
    v_tenure RECORD;
    v_community RECORD;
    v_financial RECORD;
BEGIN
    -- Get current scores
    SELECT * INTO v_score_record FROM xn_scores WHERE user_id = p_user_id;
    SELECT * INTO v_payment FROM calculate_payment_reliability_factor(p_user_id);
    SELECT * INTO v_completion FROM calculate_circle_completion_factor(p_user_id);
    SELECT * INTO v_tenure FROM calculate_tenure_activity_factor(p_user_id);
    SELECT * INTO v_community FROM calculate_community_standing_factor(p_user_id);
    SELECT * INTO v_financial FROM calculate_financial_behavior_factor(p_user_id);

    -- Get applicable tips
    FOR v_tip IN
        SELECT
            t.*,
            CASE t.factor_key
                WHEN 'payment_reliability' THEN
                    CASE t.component_key
                        WHEN 'on_time_rate' THEN v_payment.on_time_rate_score
                        WHEN 'payment_streak' THEN v_payment.payment_streak_score
                        WHEN 'no_defaults' THEN v_payment.no_defaults_score
                        ELSE v_payment.total_score
                    END
                WHEN 'circle_completion' THEN
                    CASE t.component_key
                        WHEN 'completion_rate' THEN v_completion.completion_rate_score
                        WHEN 'full_cycle_bonus' THEN v_completion.full_cycle_score
                        WHEN 'no_abandonment' THEN v_completion.no_abandonment_score
                        ELSE v_completion.total_score
                    END
                WHEN 'tenure_activity' THEN
                    CASE t.component_key
                        WHEN 'account_age' THEN v_tenure.account_age_score
                        WHEN 'tenure_bonus' THEN v_tenure.tenure_bonus_score
                        WHEN 'recent_activity' THEN v_tenure.recent_activity_score
                        ELSE v_tenure.total_score
                    END
                WHEN 'community_standing' THEN
                    CASE t.component_key
                        WHEN 'vouches_received' THEN v_community.vouches_received_score
                        WHEN 'member_diversity' THEN v_community.member_diversity_score
                        WHEN 'elder_connections' THEN v_community.elder_connections_score
                        WHEN 'vouching_reliability' THEN v_community.vouching_reliability_score
                        ELSE v_community.total_score
                    END
                WHEN 'financial_behavior' THEN
                    CASE t.component_key
                        WHEN 'wallet_usage' THEN v_financial.wallet_usage_score
                        WHEN 'payout_retention' THEN v_financial.payout_retention_score
                        WHEN 'savings_engagement' THEN v_financial.savings_engagement_score
                        ELSE v_financial.total_score
                    END
            END as current_score
        FROM xn_score_improvement_tips t
        WHERE t.is_active = TRUE
        ORDER BY t.priority, t.potential_points DESC
    LOOP
        -- Check if tip applies based on thresholds
        IF (v_tip.max_score_threshold IS NULL OR v_tip.current_score <= v_tip.max_score_threshold)
           AND (v_tip.min_score_threshold IS NULL OR v_tip.current_score >= v_tip.min_score_threshold)
        THEN
            v_tips := v_tips || jsonb_build_object(
                'id', v_tip.id,
                'factor', v_tip.factor_key,
                'component', v_tip.component_key,
                'title', v_tip.tip_title,
                'description', v_tip.tip_description,
                'action', v_tip.tip_action,
                'priority', v_tip.priority,
                'potential_points', v_tip.potential_points,
                'current_score', ROUND(v_tip.current_score, 2)
            );

            IF jsonb_array_length(v_tips) >= p_limit THEN
                EXIT;
            END IF;
        END IF;
    END LOOP;

    RETURN v_tips;
END;
$function$
;

CREATE OR REPLACE FUNCTION public.get_interest_config(p_key text)
 RETURNS jsonb
 LANGUAGE sql
 STABLE
AS $function$
    SELECT config_value FROM interest_calculation_config WHERE config_key = p_key;
$function$
;

CREATE OR REPLACE FUNCTION public.get_last_financial_activity(p_user_id uuid)
 RETURNS timestamp with time zone
 LANGUAGE plpgsql
 STABLE
AS $function$
DECLARE
    v_last_activity TIMESTAMPTZ;
    v_contribution TIMESTAMPTZ;
    v_payout TIMESTAMPTZ;
    v_wallet TIMESTAMPTZ;
BEGIN
    -- Check contributions (always exists)
    -- Status can be 'completed' or 'late' (both indicate paid)
    SELECT MAX(paid_at) INTO v_contribution
    FROM contributions
    WHERE user_id = p_user_id AND status IN ('completed', 'late');

    -- Check payouts received (always exists)
    SELECT MAX(completed_at) INTO v_payout
    FROM payout_executions
    WHERE recipient_user_id = p_user_id AND execution_status = 'completed';

    -- Check wallet deposits (always exists)
    SELECT MAX(created_at) INTO v_wallet
    FROM wallet_transactions
    WHERE user_id = p_user_id
    AND transaction_type IN ('deposit', 'incoming_transfer')
    AND transaction_status = 'completed';

    -- Note: savings_contributions and remittances tables may not exist yet
    -- They can be added when those features are implemented

    -- Get the most recent activity
    v_last_activity := GREATEST(
        COALESCE(v_contribution, '1970-01-01'::TIMESTAMPTZ),
        COALESCE(v_payout, '1970-01-01'::TIMESTAMPTZ),
        COALESCE(v_wallet, '1970-01-01'::TIMESTAMPTZ)
    );

    -- Return NULL if no activity ever
    IF v_last_activity = '1970-01-01'::TIMESTAMPTZ THEN
        RETURN NULL;
    END IF;

    RETURN v_last_activity;
END;
$function$
;

CREATE OR REPLACE FUNCTION public.get_member_circle_position(p_circle_id uuid, p_user_id uuid)
 RETURNS TABLE(total_contributed numeric, total_received numeric, has_received_payout boolean, net_position numeric, current_position integer, remaining_cycles_to_pay integer, is_current_beneficiary boolean)
 LANGUAGE plpgsql
 STABLE
AS $function$
DECLARE
    v_circle RECORD;
    v_member RECORD;
    v_position INTEGER := 0;
    v_total_contributed DECIMAL(15,2) := 0;
    v_total_received DECIMAL(15,2) := 0;
    v_is_current_beneficiary BOOLEAN := false;
BEGIN
    SELECT * INTO v_circle FROM circles WHERE id = p_circle_id;
    SELECT * INTO v_member FROM circle_members WHERE circle_id = p_circle_id AND user_id = p_user_id;
    v_position := COALESCE(v_member.position, 0);

    -- Try cycle_contributions first, then contributions
    BEGIN
        SELECT COALESCE(SUM(contributed_amount), 0) INTO v_total_contributed
        FROM cycle_contributions WHERE circle_id = p_circle_id AND user_id = p_user_id AND status = 'completed';
    EXCEPTION WHEN undefined_table THEN
        SELECT COALESCE(SUM(amount), 0) INTO v_total_contributed
        FROM contributions WHERE circle_id = p_circle_id AND user_id = p_user_id AND status = 'completed';
    END;

    -- Try circle_cycles first, then payouts
    BEGIN
        SELECT COALESCE(SUM(payout_amount), 0) INTO v_total_received
        FROM circle_cycles WHERE circle_id = p_circle_id AND recipient_user_id = p_user_id AND status = 'completed';
    EXCEPTION WHEN undefined_table THEN
        SELECT COALESCE(SUM(amount), 0) INTO v_total_received
        FROM payouts WHERE circle_id = p_circle_id AND recipient_id = p_user_id AND status = 'completed';
    END;

    RETURN QUERY SELECT
        v_total_contributed,
        v_total_received,
        v_total_received > 0,
        v_total_contributed - v_total_received,
        v_position,
        CASE WHEN v_total_received > 0 THEN GREATEST(0, COALESCE(v_circle.total_cycles, v_circle.member_count) - COALESCE(v_circle.current_cycle, 1)) ELSE 0 END::INTEGER,
        v_is_current_beneficiary;
END;
$function$
;

CREATE OR REPLACE FUNCTION public.get_next_payment_obligation(p_loan_id uuid)
 RETURNS TABLE(obligation_id uuid, obligation_number integer, due_date date, days_until_due integer, total_due_cents integer, principal_due_cents integer, interest_due_cents integer, fees_due_cents integer, status obligation_status, is_overdue boolean, late_fee_cents integer)
 LANGUAGE plpgsql
 STABLE
AS $function$
BEGIN
    RETURN QUERY SELECT o.id, o.obligation_number, o.due_date, (o.due_date - CURRENT_DATE)::INTEGER,
        o.total_due_cents, o.principal_due_cents, o.interest_due_cents, o.fees_due_cents,
        o.status, o.due_date < CURRENT_DATE, COALESCE(o.late_fee_cents, 0)
    FROM loan_payment_obligations o WHERE o.loan_id = p_loan_id AND o.status IN ('upcoming', 'due', 'overdue', 'partial')
    ORDER BY o.due_date ASC LIMIT 1;
END;
$function$
;

CREATE OR REPLACE FUNCTION public.get_payment_obligations(p_loan_id uuid, p_status obligation_status[] DEFAULT NULL::obligation_status[], p_limit integer DEFAULT 12)
 RETURNS TABLE(obligation_id uuid, obligation_number integer, period_start date, period_end date, due_date date, total_due_cents integer, total_paid_cents integer, remaining_cents integer, status obligation_status, is_overdue boolean, days_overdue integer, late_fee_cents integer, paid_at timestamp with time zone, paid_via text)
 LANGUAGE plpgsql
 STABLE
AS $function$
BEGIN
    RETURN QUERY SELECT o.id, o.obligation_number, o.period_start_date, o.period_end_date, o.due_date,
        o.total_due_cents, o.total_paid_cents, (o.total_due_cents - o.total_paid_cents),
        o.status, o.due_date < CURRENT_DATE AND o.status NOT IN ('paid', 'waived'),
        CASE WHEN o.due_date < CURRENT_DATE THEN (CURRENT_DATE - o.due_date)::INTEGER ELSE 0 END,
        COALESCE(o.late_fee_cents, 0), o.paid_at, o.paid_via
    FROM loan_payment_obligations o WHERE o.loan_id = p_loan_id AND (p_status IS NULL OR o.status = ANY(p_status))
    ORDER BY o.due_date DESC LIMIT p_limit;
END;
$function$
;

CREATE OR REPLACE FUNCTION public.get_pending_notifications(p_limit integer DEFAULT 100)
 RETURNS TABLE(queue_id uuid, notification_id uuid, user_id uuid, channel character varying, payload jsonb, push_tokens text[])
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
BEGIN
    RETURN QUERY
    SELECT
        q.id as queue_id,
        q.notification_id,
        q.user_id,
        q.channel,
        q.payload,
        CASE
            WHEN q.channel = 'push' THEN
                ARRAY(
                    SELECT pt.token
                    FROM push_tokens pt
                    WHERE pt.user_id = q.user_id
                    AND pt.active = TRUE
                )
            ELSE ARRAY[]::TEXT[]
        END as push_tokens
    FROM notification_queue q
    WHERE q.status IN ('pending', 'failed')
    AND q.next_attempt_at <= NOW()
    AND q.attempts < q.max_attempts
    ORDER BY
        CASE WHEN (q.payload->>'priority') = 'urgent' THEN 0
             WHEN (q.payload->>'priority') = 'high' THEN 1
             WHEN (q.payload->>'priority') = 'normal' THEN 2
             ELSE 3
        END,
        q.created_at
    LIMIT p_limit
    FOR UPDATE SKIP LOCKED;
END;
$function$
;

CREATE OR REPLACE FUNCTION public.get_pending_swap_requests_for_user(p_user_id uuid)
 RETURNS TABLE(request_id uuid, circle_id uuid, circle_name text, requester_id uuid, requester_name text, requester_position integer, your_position integer, request_reason text, expires_at timestamp with time zone, created_at timestamp with time zone)
 LANGUAGE plpgsql
 STABLE
AS $function$
BEGIN
    RETURN QUERY
    SELECT
        psr.id,
        psr.circle_id,
        c.name,
        psr.requester_user_id,
        p.full_name,
        psr.requester_position,
        psr.target_position,
        psr.request_reason,
        psr.expires_at,
        psr.created_at
    FROM position_swap_requests psr
    JOIN circles c ON c.id = psr.circle_id
    JOIN profiles p ON p.id = psr.requester_user_id
    WHERE psr.target_user_id = p_user_id
    AND psr.swap_status = 'pending_target'
    AND psr.expires_at > now()
    ORDER BY psr.created_at DESC;
END;
$function$
;

CREATE OR REPLACE FUNCTION public.get_referral_stats(p_user_id uuid)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
    v_stats JSONB;
    v_referral_code TEXT;
BEGIN
    -- Get or create referral code
    SELECT referral_code INTO v_referral_code
    FROM referrals
    WHERE referrer_id = p_user_id
    ORDER BY created_at DESC
    LIMIT 1;

    IF v_referral_code IS NULL THEN
        v_referral_code := generate_referral_code(p_user_id);
        INSERT INTO referrals (referrer_id, referral_code, status)
        VALUES (p_user_id, v_referral_code, 'pending');
    END IF;

    SELECT jsonb_build_object(
        'referral_code', v_referral_code,
        'referral_link', 'https://tandaxn.app/join?ref=' || v_referral_code,
        'total_referrals', COUNT(*) FILTER (WHERE status IN ('signed_up', 'completed')),
        'pending_rewards', COUNT(*) FILTER (WHERE status = 'signed_up'),
        'completed_referrals', COUNT(*) FILTER (WHERE status = 'completed'),
        'total_earned', COALESCE(SUM(reward_amount) FILTER (WHERE reward_paid = TRUE), 0),
        'pending_earnings', COALESCE(SUM(reward_amount) FILTER (WHERE status = 'signed_up'), 0)
    ) INTO v_stats
    FROM referrals
    WHERE referrer_id = p_user_id;

    RETURN v_stats;
END;
$function$
;

CREATE OR REPLACE FUNCTION public.get_risk_grade(p_credit_score integer)
 RETURNS risk_grade
 LANGUAGE plpgsql
 IMMUTABLE
AS $function$
BEGIN
    RETURN CASE
        WHEN p_credit_score >= 740 THEN 'A'::risk_grade
        WHEN p_credit_score >= 630 THEN 'B'::risk_grade
        WHEN p_credit_score >= 520 THEN 'C'::risk_grade
        WHEN p_credit_score >= 410 THEN 'D'::risk_grade
        ELSE 'E'::risk_grade
    END;
END;
$function$
;

CREATE OR REPLACE FUNCTION public.get_score_based_limit(p_credit_score integer)
 RETURNS integer
 LANGUAGE plpgsql
 IMMUTABLE
AS $function$
BEGIN
    RETURN CASE
        WHEN p_credit_score >= 740 THEN 1000000  -- $10,000
        WHEN p_credit_score >= 630 THEN 500000   -- $5,000
        WHEN p_credit_score >= 520 THEN 200000   -- $2,000
        WHEN p_credit_score >= 410 THEN 50000    -- $500
        ELSE 0
    END;
END;
$function$
;

CREATE OR REPLACE FUNCTION public.get_score_breakdown(p_user_id uuid)
 RETURNS jsonb
 LANGUAGE plpgsql
AS $function$
DECLARE
    v_cache RECORD;
    v_breakdown JSONB;
BEGIN
    -- Check for valid cache
    SELECT * INTO v_cache
    FROM xn_score_breakdown_cache
    WHERE user_id = p_user_id
    AND expires_at > now();

    IF FOUND THEN
        -- Return cached breakdown
        RETURN jsonb_build_object(
            'user_id', p_user_id,
            'total_score', v_cache.total_score,
            'tier', (SELECT score_tier FROM xn_scores WHERE user_id = p_user_id),
            'factors', jsonb_build_object(
                'payment_reliability', jsonb_build_object(
                    'score', v_cache.payment_reliability_score,
                    'max_score', 35,
                    'status', v_cache.payment_reliability_status,
                    'trend', v_cache.payment_reliability_trend
                ),
                'circle_completion', jsonb_build_object(
                    'score', v_cache.circle_completion_score,
                    'max_score', 20,
                    'status', v_cache.circle_completion_status,
                    'trend', v_cache.circle_completion_trend
                ),
                'tenure_activity', jsonb_build_object(
                    'score', v_cache.tenure_activity_score,
                    'max_score', 15,
                    'status', v_cache.tenure_activity_status,
                    'trend', v_cache.tenure_activity_trend
                ),
                'community_standing', jsonb_build_object(
                    'score', v_cache.community_standing_score,
                    'max_score', 15,
                    'status', v_cache.community_standing_status,
                    'trend', v_cache.community_standing_trend
                ),
                'financial_behavior', jsonb_build_object(
                    'score', v_cache.financial_behavior_score,
                    'max_score', 15,
                    'status', v_cache.financial_behavior_status,
                    'trend', v_cache.financial_behavior_trend
                )
            ),
            'improvement_tips', v_cache.improvement_tips,
            'percentiles', v_cache.factor_percentiles,
            'cached', TRUE,
            'calculated_at', v_cache.calculated_at
        );
    END IF;

    -- Calculate fresh breakdown
    v_breakdown := calculate_score_breakdown(p_user_id);

    -- Update cache
    PERFORM refresh_score_breakdown(p_user_id);

    RETURN v_breakdown;
END;
$function$
;

CREATE OR REPLACE FUNCTION public.get_swap_requests_awaiting_confirmation(p_user_id uuid)
 RETURNS TABLE(request_id uuid, circle_id uuid, circle_name text, target_id uuid, target_name text, your_position integer, target_position integer, cooling_off_ends_at timestamp with time zone, expires_at timestamp with time zone)
 LANGUAGE plpgsql
 STABLE
AS $function$
BEGIN
    RETURN QUERY
    SELECT
        psr.id,
        psr.circle_id,
        c.name,
        psr.target_user_id,
        p.full_name,
        psr.requester_position,
        psr.target_position,
        psr.cooling_off_ends_at,
        psr.expires_at
    FROM position_swap_requests psr
    JOIN circles c ON c.id = psr.circle_id
    JOIN profiles p ON p.id = psr.target_user_id
    WHERE psr.requester_user_id = p_user_id
    AND psr.swap_status = 'pending_confirmation'
    AND psr.expires_at > now()
    ORDER BY psr.target_accepted_at DESC;
END;
$function$
;

CREATE OR REPLACE FUNCTION public.get_swap_requests_pending_elder_approval(p_circle_id uuid)
 RETURNS TABLE(request_id uuid, requester_id uuid, requester_name text, requester_position integer, requester_xn_score integer, target_id uuid, target_name text, target_position integer, target_xn_score integer, request_reason text, created_at timestamp with time zone)
 LANGUAGE plpgsql
 STABLE
AS $function$
BEGIN
    RETURN QUERY
    SELECT
        psr.id,
        psr.requester_user_id,
        rp.full_name,
        psr.requester_position,
        psr.requester_xn_score,
        psr.target_user_id,
        tp.full_name,
        psr.target_position,
        psr.target_xn_score,
        psr.request_reason,
        psr.created_at
    FROM position_swap_requests psr
    JOIN profiles rp ON rp.id = psr.requester_user_id
    JOIN profiles tp ON tp.id = psr.target_user_id
    WHERE psr.circle_id = p_circle_id
    AND psr.swap_status = 'pending_elder_approval'
    ORDER BY psr.created_at ASC;
END;
$function$
;

CREATE OR REPLACE FUNCTION public.get_unread_notification_count()
 RETURNS integer
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
    v_count INTEGER;
BEGIN
    SELECT COUNT(*)::INTEGER INTO v_count
    FROM notifications
    WHERE user_id = auth.uid()
    AND read = FALSE
    AND (expires_at IS NULL OR expires_at > NOW());

    RETURN v_count;
END;
$function$
;

CREATE OR REPLACE FUNCTION public.get_user_dashboard(p_user_id uuid)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
    v_result JSONB;
    v_user RECORD;
    v_wallet RECORD;
    v_circles_summary JSONB;
    v_upcoming_payments JSONB;
    v_recent_activity JSONB;
    v_active_loans JSONB;
    v_unread_notifications INTEGER;
BEGIN
    -- Get user info and XnScore
    SELECT
        id,
        full_name,
        email,
        phone,
        avatar_url,
        COALESCE(xn_score, 30) AS xn_score,
        kyc_verified,
        created_at
    INTO v_user
    FROM users
    WHERE id = p_user_id;

    IF v_user IS NULL THEN
        RETURN jsonb_build_object('error', 'User not found');
    END IF;

    -- Get wallet balance
    SELECT
        COALESCE(balance, 0) AS balance,
        COALESCE(pending_balance, 0) AS pending_balance,
        currency
    INTO v_wallet
    FROM wallets
    WHERE user_id = p_user_id;

    -- Get circles summary
    SELECT jsonb_build_object(
        'active_count', COUNT(*) FILTER (WHERE g.status = 'active'),
        'total_contributed', COALESCE(SUM(
            CASE WHEN g.status = 'active' THEN
                (SELECT COALESCE(SUM(c.amount), 0) FROM contributions c
                 WHERE c.group_id = g.id AND c.user_id = p_user_id AND c.status = 'completed')
            ELSE 0 END
        ), 0),
        'next_payout_amount', (
            SELECT g2.contribution_amount * g2.max_members
            FROM groups g2
            JOIN group_members gm2 ON gm2.group_id = g2.id
            WHERE gm2.user_id = p_user_id
            AND g2.status = 'active'
            AND gm2.payout_position = g2.current_cycle + 1
            LIMIT 1
        ),
        'circles', (
            SELECT jsonb_agg(jsonb_build_object(
                'id', g.id,
                'name', g.name,
                'contribution_amount', g.contribution_amount,
                'next_payout_date', g.next_payout_date,
                'current_cycle', g.current_cycle,
                'max_members', g.max_members,
                'my_position', gm.payout_position,
                'status', g.status
            ) ORDER BY g.next_payout_date)
            FROM groups g
            JOIN group_members gm ON gm.group_id = g.id
            WHERE gm.user_id = p_user_id
            AND g.status = 'active'
            LIMIT 5
        )
    ) INTO v_circles_summary
    FROM groups g
    JOIN group_members gm ON gm.group_id = g.id
    WHERE gm.user_id = p_user_id;

    -- Get upcoming payments (contributions and loan payments)
    SELECT jsonb_agg(payment ORDER BY due_date) INTO v_upcoming_payments
    FROM (
        -- Upcoming contributions
        SELECT jsonb_build_object(
            'type', 'contribution',
            'amount', g.contribution_amount,
            'group_name', g.name,
            'group_id', g.id,
            'due_date', g.next_payout_date,
            'days_until_due', EXTRACT(DAY FROM (g.next_payout_date - CURRENT_DATE))
        ) AS payment,
        g.next_payout_date AS due_date
        FROM groups g
        JOIN group_members gm ON gm.group_id = g.id
        WHERE gm.user_id = p_user_id
        AND g.status = 'active'
        AND g.next_payout_date IS NOT NULL
        AND g.next_payout_date >= CURRENT_DATE
        AND NOT EXISTS (
            SELECT 1 FROM contributions c
            WHERE c.group_id = g.id
            AND c.user_id = p_user_id
            AND c.cycle_number = g.current_cycle
            AND c.status = 'completed'
        )

        UNION ALL

        -- Upcoming loan payments
        SELECT jsonb_build_object(
            'type', 'loan_payment',
            'amount', l.monthly_payment,
            'group_name', g.name,
            'loan_id', l.id,
            'due_date', l.next_payment_date,
            'days_until_due', EXTRACT(DAY FROM (l.next_payment_date - CURRENT_DATE)),
            'total_remaining', l.amount_due
        ) AS payment,
        l.next_payment_date AS due_date
        FROM loans l
        JOIN groups g ON g.id = l.group_id
        WHERE l.borrower_id = p_user_id
        AND l.status = 'active'
        AND l.next_payment_date IS NOT NULL
        AND l.next_payment_date >= CURRENT_DATE
    ) payments
    WHERE due_date <= CURRENT_DATE + INTERVAL '30 days'
    LIMIT 5;

    -- Get recent activity
    SELECT jsonb_agg(activity ORDER BY created_at DESC) INTO v_recent_activity
    FROM (
        -- Recent contributions
        SELECT jsonb_build_object(
            'type', 'contribution',
            'amount', c.amount,
            'group_name', g.name,
            'status', c.status,
            'created_at', c.created_at
        ) AS activity,
        c.created_at
        FROM contributions c
        JOIN groups g ON g.id = c.group_id
        WHERE c.user_id = p_user_id
        AND c.created_at >= CURRENT_DATE - INTERVAL '30 days'

        UNION ALL

        -- Recent payouts received
        SELECT jsonb_build_object(
            'type', 'payout_received',
            'amount', p.amount,
            'group_name', g.name,
            'status', p.status,
            'created_at', p.payout_date
        ) AS activity,
        p.payout_date AS created_at
        FROM payouts p
        JOIN groups g ON g.id = p.group_id
        WHERE p.user_id = p_user_id
        AND p.payout_date >= CURRENT_DATE - INTERVAL '30 days'

        UNION ALL

        -- Recent loan payments
        SELECT jsonb_build_object(
            'type', 'loan_payment',
            'amount', lp.amount,
            'loan_id', lp.loan_id,
            'status', lp.status,
            'created_at', lp.created_at
        ) AS activity,
        lp.created_at
        FROM loan_payments lp
        JOIN loans l ON l.id = lp.loan_id
        WHERE l.borrower_id = p_user_id
        AND lp.created_at >= CURRENT_DATE - INTERVAL '30 days'
    ) activities
    LIMIT 10;

    -- Get active loans summary
    SELECT jsonb_agg(jsonb_build_object(
        'id', l.id,
        'amount', l.amount,
        'amount_due', l.amount_due,
        'monthly_payment', l.monthly_payment,
        'next_payment_date', l.next_payment_date,
        'group_name', g.name,
        'status', l.status
    )) INTO v_active_loans
    FROM loans l
    JOIN groups g ON g.id = l.group_id
    WHERE l.borrower_id = p_user_id
    AND l.status IN ('active', 'approved');

    -- Get unread notifications count
    SELECT COUNT(*) INTO v_unread_notifications
    FROM notifications
    WHERE user_id = p_user_id
    AND read = FALSE;

    -- Build final result
    v_result := jsonb_build_object(
        'user', jsonb_build_object(
            'id', v_user.id,
            'full_name', v_user.full_name,
            'email', v_user.email,
            'avatar_url', v_user.avatar_url,
            'xn_score', v_user.xn_score,
            'xn_tier', get_xn_tier(v_user.xn_score),
            'kyc_verified', v_user.kyc_verified,
            'member_since', v_user.created_at
        ),
        'wallet', jsonb_build_object(
            'balance', COALESCE(v_wallet.balance, 0),
            'pending_balance', COALESCE(v_wallet.pending_balance, 0),
            'currency', COALESCE(v_wallet.currency, 'USD')
        ),
        'circles', COALESCE(v_circles_summary, '{}'::jsonb),
        'upcoming_payments', COALESCE(v_upcoming_payments, '[]'::jsonb),
        'recent_activity', COALESCE(v_recent_activity, '[]'::jsonb),
        'active_loans', COALESCE(v_active_loans, '[]'::jsonb),
        'unread_notifications', v_unread_notifications,
        'fetched_at', NOW()
    );

    RETURN v_result;
END;
$function$
;

CREATE OR REPLACE FUNCTION public.get_user_late_summary(p_user_id uuid)
 RETURNS TABLE(total_late_contributions integer, total_defaults integer, total_outstanding numeric, active_payment_plans integer, has_restrictions boolean)
 LANGUAGE plpgsql
AS $function$
BEGIN
    RETURN QUERY
    SELECT
        (SELECT COUNT(*)::INTEGER FROM late_contributions WHERE user_id = p_user_id),
        (SELECT COUNT(*)::INTEGER FROM late_contributions WHERE user_id = p_user_id AND late_status = 'defaulted'),
        COALESCE((SELECT SUM(outstanding_amount) FROM late_contributions WHERE user_id = p_user_id AND late_status NOT IN ('paid_late', 'covered', 'forgiven')), 0::DECIMAL),
        (SELECT COUNT(*)::INTEGER FROM payment_plans WHERE user_id = p_user_id AND plan_status = 'active'),
        EXISTS (SELECT 1 FROM user_restrictions WHERE user_id = p_user_id AND lifted_at IS NULL);
END;
$function$
;

CREATE OR REPLACE FUNCTION public.get_user_uncovered_defaults(p_user_id uuid)
 RETURNS TABLE(total_count integer, total_amount numeric, oldest_default_date timestamp with time zone)
 LANGUAGE plpgsql
AS $function$
BEGIN
    RETURN QUERY
    SELECT
        COUNT(*)::INTEGER as total_count,
        COALESCE(SUM(amount - COALESCE(covered_amount, 0) - COALESCE(recovered_amount, 0)), 0) as total_amount,
        MIN(created_at) as oldest_default_date
    FROM defaults
    WHERE user_id = p_user_id
      AND status IN ('unresolved', 'grace_period');
END;
$function$
;

CREATE OR REPLACE FUNCTION public.get_vouch_limits(p_user_id uuid)
 RETURNS TABLE(can_vouch boolean, reason text, active_vouches integer, max_vouches integer, remaining_vouches integer, vouch_power numeric)
 LANGUAGE plpgsql
 STABLE
AS $function$
DECLARE
    v_score RECORD;
    v_active_count INTEGER;
    v_max INTEGER;
BEGIN
    SELECT * INTO v_score FROM xn_scores WHERE xn_scores.user_id = p_user_id;

    IF NOT FOUND THEN
        RETURN QUERY SELECT FALSE, 'No XnScore'::TEXT, 0, 0, 0, 0::DECIMAL;
        RETURN;
    END IF;

    -- Must have score >= 70 to vouch
    IF v_score.total_score < 70 THEN
        RETURN QUERY SELECT
            FALSE,
            format('XnScore must be >= 70 to vouch (you have %s)', v_score.total_score),
            0, 0, 0, v_score.total_score;
        RETURN;
    END IF;

    -- Check if restricted
    IF v_score.voucher_reliability = 'restricted' THEN
        RETURN QUERY SELECT
            FALSE,
            'Vouching privileges suspended due to vouchee defaults'::TEXT,
            0, 0, 0, v_score.total_score;
        RETURN;
    END IF;

    -- Count active vouches
    SELECT COUNT(*) INTO v_active_count
    FROM vouches
    WHERE voucher_user_id = p_user_id AND vouch_status = 'active';

    -- Max vouches based on score
    IF v_score.total_score >= 90 THEN
        v_max := 5;
    ELSIF v_score.total_score >= 80 THEN
        v_max := 4;
    ELSE
        v_max := 3;
    END IF;

    RETURN QUERY SELECT
        v_active_count < v_max,
        CASE WHEN v_active_count < v_max THEN 'Can vouch'::TEXT ELSE 'Vouch limit reached'::TEXT END,
        v_active_count,
        v_max,
        v_max - v_active_count,
        v_score.total_score;
END;
$function$
;

CREATE OR REPLACE FUNCTION public.get_wallet_summary(p_user_id uuid)
 RETURNS TABLE(wallet_id uuid, main_balance numeric, reserved_balance numeric, committed_balance numeric, total_balance numeric, available_balance numeric, total_savings numeric, savings_goals_count integer, upcoming_contributions numeric, money_retention_rate numeric)
 LANGUAGE plpgsql
AS $function$
BEGIN
    RETURN QUERY
    SELECT w.id, w.main_balance_cents / 100.0, w.reserved_balance_cents / 100.0,
        w.committed_balance_cents / 100.0, w.total_balance_cents / 100.0,
        w.available_balance_cents / 100.0, COALESCE(sg.total_savings, 0) / 100.0,
        COALESCE(sg.goals_count, 0)::INTEGER, COALESCE(cr.upcoming_total, 0) / 100.0,
        w.money_retention_rate
    FROM user_wallets w
    LEFT JOIN (
        SELECT usg.wallet_id, SUM(usg.current_balance_cents) as total_savings, COUNT(*) as goals_count
        FROM user_savings_goals usg WHERE usg.goal_status = 'active' GROUP BY usg.wallet_id
    ) sg ON w.id = sg.wallet_id
    LEFT JOIN (
        SELECT cres.wallet_id, SUM(cres.amount_cents) as upcoming_total
        FROM contribution_reservations cres
        WHERE cres.reservation_status = 'reserved' AND cres.due_date <= CURRENT_DATE + INTERVAL '30 days'
        GROUP BY cres.wallet_id
    ) cr ON w.id = cr.wallet_id
    WHERE w.user_id = p_user_id;
END;
$function$
;

CREATE OR REPLACE FUNCTION public.get_xn_tier(p_score numeric)
 RETURNS jsonb
 LANGUAGE plpgsql
 IMMUTABLE
AS $function$
BEGIN
    -- 6 Tiers based on V3.0 algorithm (0-100 scale)
    IF p_score >= 90 THEN
        RETURN jsonb_build_object(
            'tier', 1,
            'name', 'Elite',
            'color', '#FFD700',
            'min_score', 90,
            'max_score', 100,
            'benefits', jsonb_build_object(
                'slot_access', 'any',
                'early_fee', 0.5,
                'late_bonus', 3,
                'loan_limit', 5000
            )
        );
    ELSIF p_score >= 75 THEN
        RETURN jsonb_build_object(
            'tier', 2,
            'name', 'Excellent',
            'color', '#00C6AE',
            'min_score', 75,
            'max_score', 89,
            'benefits', jsonb_build_object(
                'slot_access', 'any',
                'early_fee', 1,
                'late_bonus', 2.5,
                'loan_limit', 3000
            )
        );
    ELSIF p_score >= 60 THEN
        RETURN jsonb_build_object(
            'tier', 3,
            'name', 'Good',
            'color', '#00C6AE',
            'min_score', 60,
            'max_score', 74,
            'benefits', jsonb_build_object(
                'slot_access', '4+',
                'early_fee', 2,
                'late_bonus', 2,
                'loan_limit', 1500
            )
        );
    ELSIF p_score >= 45 THEN
        RETURN jsonb_build_object(
            'tier', 4,
            'name', 'Fair',
            'color', '#D97706',
            'min_score', 45,
            'max_score', 59,
            'benefits', jsonb_build_object(
                'slot_access', '7+',
                'early_fee', 4,
                'late_bonus', 1,
                'loan_limit', 500
            )
        );
    ELSIF p_score >= 25 THEN
        RETURN jsonb_build_object(
            'tier', 5,
            'name', 'Poor',
            'color', '#EF4444',
            'min_score', 25,
            'max_score', 44,
            'benefits', jsonb_build_object(
                'slot_access', 'last_3',
                'early_fee', 7,
                'late_bonus', 0,
                'loan_limit', 0
            )
        );
    ELSE
        RETURN jsonb_build_object(
            'tier', 6,
            'name', 'Critical',
            'color', '#991B1B',
            'min_score', 0,
            'max_score', 24,
            'benefits', jsonb_build_object(
                'slot_access', 'none',
                'early_fee', 0,
                'late_bonus', 0,
                'loan_limit', 0,
                'restricted', true
            )
        );
    END IF;
END;
$function$
;

CREATE OR REPLACE FUNCTION public.get_xnscore_age_cap(account_age_days integer)
 RETURNS integer
 LANGUAGE plpgsql
 IMMUTABLE
AS $function$
BEGIN
    RETURN CASE
        WHEN account_age_days < 30 THEN 40    -- Probation
        WHEN account_age_days < 90 THEN 55    -- Building trust
        WHEN account_age_days < 180 THEN 70   -- Established
        WHEN account_age_days < 365 THEN 85   -- Trusted
        WHEN account_age_days < 548 THEN 90   -- Veteran (18 months)
        ELSE 100                               -- Full trust (18+ months)
    END;
END;
$function$
;

CREATE OR REPLACE FUNCTION public.get_xnscore_tier(score numeric)
 RETURNS xnscore_tier
 LANGUAGE plpgsql
 IMMUTABLE
AS $function$
BEGIN
    RETURN CASE
        WHEN score >= 90 THEN 'elite'::xnscore_tier
        WHEN score >= 75 THEN 'excellent'::xnscore_tier
        WHEN score >= 60 THEN 'good'::xnscore_tier
        WHEN score >= 45 THEN 'fair'::xnscore_tier
        WHEN score >= 25 THEN 'poor'::xnscore_tier
        ELSE 'critical'::xnscore_tier
    END;
END;
$function$
;

CREATE OR REPLACE FUNCTION public.handle_migration_status_change()
 RETURNS trigger
 LANGUAGE plpgsql
AS $function$
BEGIN
    -- Set started_at when moving from mock to in_progress
    IF OLD.status = 'mock' AND NEW.status = 'in_progress' AND NEW.started_at IS NULL THEN
        NEW.started_at = NOW();
    END IF;

    -- Set connected_at when moving to connected
    IF NEW.status = 'connected' AND OLD.status != 'connected' AND NEW.connected_at IS NULL THEN
        NEW.connected_at = NOW();
    END IF;

    -- Set verified_at when moving to verified
    IF NEW.status = 'verified' AND OLD.status != 'verified' AND NEW.verified_at IS NULL THEN
        NEW.verified_at = NOW();
    END IF;

    -- Log the status change
    IF OLD.status != NEW.status THEN
        INSERT INTO migration_audit_log (screen_id, screen_code, action, old_value, new_value)
        VALUES (NEW.id, NEW.screen_code, 'status_change',
                jsonb_build_object('status', OLD.status),
                jsonb_build_object('status', NEW.status));
    END IF;

    -- Update wave status aggregates
    PERFORM refresh_wave_status();

    RETURN NEW;
END;
$function$
;

CREATE OR REPLACE FUNCTION public.handle_new_profile_wallet()
 RETURNS trigger
 LANGUAGE plpgsql
 SECURITY DEFINER
AS $function$
BEGIN
  INSERT INTO public.wallets (user_id, balance, currency)
  VALUES (NEW.id, 0, 'USD')
  ON CONFLICT (user_id) DO NOTHING;
  RETURN NEW;
END;
$function$
;

CREATE OR REPLACE FUNCTION public.handle_new_user()
 RETURNS trigger
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
BEGIN
  INSERT INTO public.profiles (id, email, phone, full_name, xn_score, password_set)
  VALUES (
    NEW.id,
    NEW.email,
    COALESCE(NEW.raw_user_meta_data->>'phone', NEW.phone),
    COALESCE(NEW.raw_user_meta_data->>'full_name', NEW.raw_user_meta_data->>'name', NEW.email),
    COALESCE((NEW.raw_user_meta_data->>'xn_score')::INTEGER, 30),
    (NEW.encrypted_password IS NOT NULL AND NEW.encrypted_password <> '')
  )
  ON CONFLICT (id) DO UPDATE SET
    email = EXCLUDED.email,
    phone = COALESCE(EXCLUDED.phone, profiles.phone),
    full_name = COALESCE(EXCLUDED.full_name, profiles.full_name),
    updated_at = NOW();
  RETURN NEW;
EXCEPTION WHEN OTHERS THEN
  RAISE LOG 'handle_new_user error: %', SQLERRM;
  RETURN NEW;
END;
$function$
;

CREATE OR REPLACE FUNCTION public.has_encrypted_password()
 RETURNS boolean
 LANGUAGE sql
 SECURITY DEFINER
 SET search_path TO 'public', 'auth'
AS $function$
  SELECT EXISTS (
    SELECT 1 FROM auth.users
    WHERE id = auth.uid()
      AND encrypted_password IS NOT NULL
      AND encrypted_password <> ''
  );
$function$
;

