CREATE OR REPLACE FUNCTION public.initiate_dissolution(p_circle_id uuid, p_trigger_type dissolution_trigger, p_reason text, p_initiated_by uuid DEFAULT NULL::uuid, p_evidence_urls text[] DEFAULT NULL::text[])
 RETURNS uuid
 LANGUAGE plpgsql
 SECURITY DEFINER
AS $function$
DECLARE
    v_dissolution_id UUID;
    v_config dissolution_trigger_config%ROWTYPE;
    v_member_count INTEGER;
    v_pool_balance DECIMAL(15,2);
BEGIN
    -- Get trigger configuration
    SELECT * INTO v_config FROM dissolution_trigger_config WHERE trigger_type = p_trigger_type;

    IF NOT FOUND THEN
        RAISE EXCEPTION 'Invalid dissolution trigger type: %', p_trigger_type;
    END IF;

    -- Check for existing pending dissolution
    IF EXISTS (
        SELECT 1 FROM dissolution_requests
        WHERE circle_id = p_circle_id
        AND status NOT IN ('completed', 'rejected', 'cancelled')
    ) THEN
        RAISE EXCEPTION 'Circle already has a pending dissolution request';
    END IF;

    -- Get member count
    SELECT COUNT(*) INTO v_member_count
    FROM circle_members
    WHERE circle_id = p_circle_id
    AND status = 'active';

    -- Get current pool balance
    SELECT COALESCE(current_balance, 0) INTO v_pool_balance
    FROM circles
    WHERE id = p_circle_id;

    -- Create dissolution request
    INSERT INTO dissolution_requests (
        circle_id,
        trigger_type,
        status,
        reason,
        evidence_urls,
        initiated_by,
        initiated_by_system,
        total_eligible_voters,
        total_pool_amount,
        voting_starts_at,
        voting_ends_at,
        objection_window_starts_at,
        objection_window_ends_at
    ) VALUES (
        p_circle_id,
        p_trigger_type,
        CASE
            WHEN v_config.requires_vote THEN 'voting'::dissolution_status
            ELSE 'objection_window'::dissolution_status
        END,
        p_reason,
        p_evidence_urls,
        p_initiated_by,
        p_initiated_by IS NULL,
        v_member_count,
        v_pool_balance,
        CASE WHEN v_config.requires_vote THEN now() ELSE NULL END,
        CASE WHEN v_config.requires_vote THEN now() + (v_config.voting_period_hours || ' hours')::INTERVAL ELSE NULL END,
        CASE
            WHEN v_config.requires_vote THEN NULL
            ELSE now()
        END,
        CASE
            WHEN v_config.requires_vote THEN NULL
            ELSE now() + (v_config.objection_window_hours || ' hours')::INTERVAL
        END
    ) RETURNING id INTO v_dissolution_id;

    -- Record event
    INSERT INTO dissolution_events (
        dissolution_request_id,
        event_type,
        event_description,
        actor_id,
        actor_type,
        new_state
    ) VALUES (
        v_dissolution_id,
        'dissolution_initiated',
        'Dissolution request initiated with trigger: ' || p_trigger_type::TEXT,
        p_initiated_by,
        CASE WHEN p_initiated_by IS NULL THEN 'system' ELSE 'user' END,
        jsonb_build_object('trigger_type', p_trigger_type, 'reason', p_reason)
    );

    -- Calculate member positions
    PERFORM calculate_all_member_positions(v_dissolution_id);

    RETURN v_dissolution_id;
END;
$function$
;

CREATE OR REPLACE FUNCTION public.initiate_member_removal(p_circle_id uuid, p_member_user_id uuid, p_reason removal_reason, p_reason_details text DEFAULT NULL::text, p_initiated_by uuid DEFAULT NULL::uuid)
 RETURNS uuid
 LANGUAGE plpgsql
 SECURITY DEFINER
AS $function$
DECLARE
    v_request_id UUID;
    v_position RECORD;
    v_settlement RECORD;
    v_settings circle_removal_settings%ROWTYPE;
    v_is_self_removal BOOLEAN;
    v_initiated_by_type TEXT;
    v_requires_vote BOOLEAN := false;
BEGIN
    IF EXISTS (SELECT 1 FROM member_removal_requests WHERE circle_id = p_circle_id AND member_user_id = p_member_user_id AND status NOT IN ('completed', 'rejected', 'cancelled')) THEN
        RAISE EXCEPTION 'Member already has a pending removal request';
    END IF;

    IF NOT EXISTS (SELECT 1 FROM circle_members WHERE circle_id = p_circle_id AND user_id = p_member_user_id) THEN
        RAISE EXCEPTION 'User is not a member of this circle';
    END IF;

    SELECT * INTO v_position FROM get_member_circle_position(p_circle_id, p_member_user_id);
    SELECT * INTO v_settlement FROM calculate_removal_settlement(p_circle_id, p_member_user_id, p_reason);
    SELECT * INTO v_settings FROM circle_removal_settings WHERE circle_id = p_circle_id;

    v_is_self_removal := (p_initiated_by = p_member_user_id);
    IF p_initiated_by IS NULL THEN v_initiated_by_type := 'system';
    ELSIF v_is_self_removal THEN v_initiated_by_type := 'user';
    ELSIF EXISTS (SELECT 1 FROM circle_members WHERE circle_id = p_circle_id AND user_id = p_initiated_by AND role IN ('elder', 'admin', 'creator')) THEN v_initiated_by_type := 'elder';
    ELSE v_initiated_by_type := 'user';
    END IF;

    IF v_settings IS NOT NULL AND v_settings.require_vote_for_removal AND NOT v_is_self_removal AND p_reason NOT IN ('emergency', 'admin') THEN
        v_requires_vote := true;
    END IF;

    INSERT INTO member_removal_requests (
        circle_id, member_user_id, reason, reason_details, status,
        initiated_by, initiated_by_type, is_self_removal,
        total_contributed, total_received, has_received_payout, member_position, was_current_beneficiary,
        settlement_type, settlement_amount, exit_fee_amount, debt_amount,
        requires_vote, voting_starts_at, voting_ends_at, grace_period_ends_at, can_be_cancelled_until
    ) VALUES (
        p_circle_id, p_member_user_id, p_reason, p_reason_details,
        CASE WHEN v_requires_vote OR (v_is_self_removal AND p_reason = 'voluntary') THEN 'pending_approval'::removal_status ELSE 'approved'::removal_status END,
        p_initiated_by, v_initiated_by_type, v_is_self_removal,
        v_position.total_contributed, v_position.total_received, v_position.has_received_payout, v_position.current_position, v_position.is_current_beneficiary,
        v_settlement.settlement_type, v_settlement.refund_amount, v_settlement.exit_fee_amount, v_settlement.debt_amount,
        v_requires_vote,
        CASE WHEN v_requires_vote THEN now() ELSE NULL END,
        CASE WHEN v_requires_vote THEN now() + (COALESCE(v_settings.voting_period_hours, 48) || ' hours')::INTERVAL ELSE NULL END,
        CASE WHEN v_is_self_removal AND p_reason = 'voluntary' THEN now() + (COALESCE(v_settings.grace_period_days, 7) || ' days')::INTERVAL ELSE NULL END,
        CASE WHEN v_is_self_removal THEN now() + '24 hours'::INTERVAL ELSE NULL END
    ) RETURNING id INTO v_request_id;

    IF NOT v_requires_vote AND NOT (v_is_self_removal AND p_reason = 'voluntary') THEN
        PERFORM execute_member_removal(v_request_id, p_initiated_by);
    END IF;

    RETURN v_request_id;
END;
$function$
;

CREATE OR REPLACE FUNCTION public.intervention_status_timestamps()
 RETURNS trigger
 LANGUAGE plpgsql
AS $function$
BEGIN
  IF NEW.status = 'sent' AND OLD.status != 'sent' THEN
    NEW.sent_at = COALESCE(NEW.sent_at, NOW());
  END IF;
  IF NEW.status = 'viewed' AND OLD.status != 'viewed' THEN
    NEW.viewed_at = COALESCE(NEW.viewed_at, NOW());
  END IF;
  IF NEW.status = 'engaged' AND OLD.status NOT IN ('engaged','accepted','paid') THEN
    NEW.engaged_at = COALESCE(NEW.engaged_at, NOW());
  END IF;
  IF NEW.status IN ('accepted','paid') AND OLD.status NOT IN ('accepted','paid') THEN
    NEW.response_at = COALESCE(NEW.response_at, NOW());
  END IF;
  IF NEW.status = 'paid' AND OLD.status != 'paid' THEN
    NEW.default_prevented = true;
    NEW.outcome_recorded_at = COALESCE(NEW.outcome_recorded_at, NOW());
  END IF;
  IF NEW.status = 'escalated' AND OLD.status != 'escalated' THEN
    NEW.escalated_at = COALESCE(NEW.escalated_at, NOW());
  END IF;
  IF NEW.status = 'expired' AND OLD.status != 'expired' AND NEW.default_prevented IS NULL THEN
    NEW.default_prevented = false;
    NEW.outcome_recorded_at = COALESCE(NEW.outcome_recorded_at, NOW());
  END IF;
  RETURN NEW;
END;
$function$
;

CREATE OR REPLACE FUNCTION public.invalidate_breakdown_cache_on_score_change()
 RETURNS trigger
 LANGUAGE plpgsql
AS $function$
BEGIN
    -- Mark cache as expired when score changes significantly
    IF ABS(NEW.total_score - COALESCE(OLD.total_score, 0)) >= 1 THEN
        UPDATE xn_score_breakdown_cache
        SET expires_at = now() - INTERVAL '1 second'
        WHERE user_id = NEW.user_id;
    END IF;
    RETURN NEW;
END;
$function$
;

CREATE OR REPLACE FUNCTION public.is_community_member(p_community_id uuid)
 RETURNS boolean
 LANGUAGE sql
 STABLE SECURITY DEFINER
AS $function$
    SELECT EXISTS (
        SELECT 1 FROM public.community_memberships
        WHERE community_id = p_community_id
        AND user_id = auth.uid()
        AND status = 'active'
    );
$function$
;

CREATE OR REPLACE FUNCTION public.is_platform_admin()
 RETURNS boolean
 LANGUAGE plpgsql
 STABLE SECURITY DEFINER
AS $function$
BEGIN
    RETURN COALESCE(
        (auth.jwt() -> 'app_metadata' ->> 'platform_role') IN ('admin', 'elder'),
        false
    );
END;
$function$
;

CREATE OR REPLACE FUNCTION public.is_savings_goal_locked(p_locked_until date)
 RETURNS boolean
 LANGUAGE plpgsql
 STABLE
AS $function$
BEGIN
    RETURN p_locked_until IS NOT NULL AND p_locked_until > CURRENT_DATE;
END;
$function$
;

