 RETURNS boolean
 LANGUAGE sql
 STABLE SECURITY DEFINER
 SET search_path TO 'public'
AS $function$ SELECT EXISTS (SELECT 1 FROM trips WHERE id = p_trip_id AND organizer_id = p_user_id); $function$
;

CREATE OR REPLACE FUNCTION public.is_trip_participant(p_trip_id uuid, p_user_id uuid)
 RETURNS boolean
 LANGUAGE sql
 STABLE SECURITY DEFINER
 SET search_path TO 'public'
AS $function$ SELECT EXISTS (SELECT 1 FROM trip_participants WHERE trip_id = p_trip_id AND user_id = p_user_id); $function$
;

CREATE OR REPLACE FUNCTION public.is_user_financially_active(p_user_id uuid, p_days integer)
 RETURNS boolean
 LANGUAGE plpgsql
 STABLE
AS $function$
DECLARE
    v_last_activity TIMESTAMPTZ;
BEGIN
    v_last_activity := get_last_financial_activity(p_user_id);

    IF v_last_activity IS NULL THEN
        RETURN FALSE;
    END IF;

    RETURN v_last_activity >= (now() - (p_days || ' days')::INTERVAL);
END;
$function$
;

CREATE OR REPLACE FUNCTION public.join_group(p_user_id uuid, p_group_id uuid, p_invite_code text DEFAULT NULL::text)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
    v_group RECORD;
    v_user RECORD;
    v_current_members INTEGER;
    v_next_position INTEGER;
    v_membership_id UUID;
    v_xn_score DECIMAL(5,2);
    v_min_score DECIMAL(5,2);
BEGIN
    -- Get group details
    SELECT * INTO v_group FROM groups WHERE id = p_group_id;

    IF v_group IS NULL THEN
        RETURN jsonb_build_object('error', 'Circle not found', 'code', 'GROUP_NOT_FOUND');
    END IF;

    -- Check if group is open for joining
    IF v_group.status NOT IN ('pending', 'forming', 'open') THEN
        RETURN jsonb_build_object(
            'error', 'This circle is not accepting new members',
            'code', 'GROUP_NOT_OPEN',
            'status', v_group.status
        );
    END IF;

    -- Check invite code if group is private
    IF v_group.is_private = TRUE AND p_invite_code IS NULL THEN
        RETURN jsonb_build_object('error', 'Invite code required for private circles', 'code', 'INVITE_REQUIRED');
    END IF;

    IF v_group.is_private = TRUE AND v_group.invite_code != p_invite_code THEN
        RETURN jsonb_build_object('error', 'Invalid invite code', 'code', 'INVALID_INVITE');
    END IF;

    -- Get user info
    SELECT * INTO v_user FROM users WHERE id = p_user_id;

    IF v_user IS NULL THEN
        RETURN jsonb_build_object('error', 'User not found', 'code', 'USER_NOT_FOUND');
    END IF;

    -- Check XnScore requirement
    v_xn_score := COALESCE(v_user.xn_score, 30);
    v_min_score := COALESCE(v_group.min_xn_score, 0);

    IF v_xn_score < v_min_score THEN
        RETURN jsonb_build_object(
            'error', 'Your XnScore does not meet the minimum requirement',
            'code', 'INSUFFICIENT_SCORE',
            'your_score', v_xn_score,
            'required_score', v_min_score
        );
    END IF;

    -- Check if user is already a member
    IF EXISTS (
        SELECT 1 FROM group_members
        WHERE group_id = p_group_id
        AND user_id = p_user_id
        AND status IN ('active', 'pending')
    ) THEN
        RETURN jsonb_build_object('error', 'You are already a member of this circle', 'code', 'ALREADY_MEMBER');
    END IF;

    -- Check current member count
    SELECT COUNT(*) INTO v_current_members
    FROM group_members
    WHERE group_id = p_group_id
    AND status IN ('active', 'pending');

    IF v_current_members >= v_group.max_members THEN
        RETURN jsonb_build_object('error', 'This circle is full', 'code', 'GROUP_FULL');
    END IF;

    -- Determine next payout position
    SELECT COALESCE(MAX(payout_position), 0) + 1 INTO v_next_position
    FROM group_members
    WHERE group_id = p_group_id
    AND status IN ('active', 'pending');

    -- Create membership
    INSERT INTO group_members (
        group_id,
        user_id,
        payout_position,
        status,
        joined_at
    ) VALUES (
        p_group_id,
        p_user_id,
        v_next_position,
        CASE
            WHEN v_group.requires_approval THEN 'pending'
            ELSE 'active'
        END,
        NOW()
    )
    RETURNING id INTO v_membership_id;

    -- Send notification to user
    PERFORM create_notification(
        p_user_id,
        'circle',
        'group',
        CASE
            WHEN v_group.requires_approval THEN 'Join Request Submitted'
            ELSE 'Welcome to ' || v_group.name || '!'
        END,
        CASE
            WHEN v_group.requires_approval THEN 'Your request to join ' || v_group.name || ' has been submitted. Waiting for admin approval.'
            ELSE 'You have successfully joined ' || v_group.name || '. Your payout position is #' || v_next_position || '.'
        END,
        jsonb_build_object('group_id', p_group_id, 'group_name', v_group.name, 'position', v_next_position),
        'normal',
        NULL,
        'circle',
        p_group_id::TEXT,
        '/circles/' || p_group_id
    );

    -- Notify group admin if approval required
    IF v_group.requires_approval THEN
        PERFORM create_notification(
            v_group.admin_id,
            'circle',
            'group',
            'New Join Request',
            v_user.full_name || ' wants to join ' || v_group.name || '. XnScore: ' || v_xn_score,
            jsonb_build_object('group_id', p_group_id, 'user_id', p_user_id, 'user_name', v_user.full_name, 'xn_score', v_xn_score),
            'high',
            NULL,
            'circle',
            p_group_id::TEXT,
            '/circles/' || p_group_id || '/requests'
        );
    END IF;

    -- Check if group is now full and should start
    IF v_current_members + 1 >= v_group.max_members AND v_group.status = 'forming' THEN
        UPDATE groups
        SET status = 'active', started_at = NOW(), updated_at = NOW()
        WHERE id = p_group_id;

        -- Notify all members that circle is starting
        INSERT INTO notifications (user_id, type, category, title, body, data, related_entity_type, related_entity_id)
        SELECT
            gm.user_id,
            'circle',
            'group',
            v_group.name || ' is Starting!',
            'Your circle is now full and will begin. First contribution is due soon.',
            jsonb_build_object('group_id', p_group_id, 'group_name', v_group.name),
            'circle',
            p_group_id::TEXT
        FROM group_members gm
        WHERE gm.group_id = p_group_id
        AND gm.status = 'active';
    END IF;

    RETURN jsonb_build_object(
        'success', true,
        'membership_id', v_membership_id,
        'group_id', p_group_id,
        'group_name', v_group.name,
        'payout_position', v_next_position,
        'status', CASE WHEN v_group.requires_approval THEN 'pending_approval' ELSE 'active' END,
        'message', CASE
            WHEN v_group.requires_approval THEN 'Join request submitted. Waiting for approval.'
            ELSE 'Successfully joined ' || v_group.name
        END
    );
END;
$function$
;

CREATE OR REPLACE FUNCTION public.leave_group(p_user_id uuid, p_group_id uuid, p_reason text DEFAULT NULL::text)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
    v_group RECORD;
    v_membership RECORD;
    v_user RECORD;
    v_total_contributed DECIMAL(10,2);
    v_total_received DECIMAL(10,2);
    v_penalty_amount DECIMAL(10,2) := 0;
    v_can_leave BOOLEAN := TRUE;
    v_leave_reason TEXT;
BEGIN
    -- Get group details
    SELECT * INTO v_group FROM groups WHERE id = p_group_id;

    IF v_group IS NULL THEN
        RETURN jsonb_build_object('error', 'Circle not found', 'code', 'GROUP_NOT_FOUND');
    END IF;

    -- Get membership
    SELECT * INTO v_membership
    FROM group_members
    WHERE group_id = p_group_id
    AND user_id = p_user_id
    AND status = 'active';

    IF v_membership IS NULL THEN
        RETURN jsonb_build_object('error', 'You are not an active member of this circle', 'code', 'NOT_MEMBER');
    END IF;

    -- Get user info
    SELECT * INTO v_user FROM users WHERE id = p_user_id;

    -- Calculate contribution/payout balance
    SELECT COALESCE(SUM(amount), 0) INTO v_total_contributed
    FROM contributions
    WHERE group_id = p_group_id
    AND user_id = p_user_id
    AND status = 'completed';

    SELECT COALESCE(SUM(amount), 0) INTO v_total_received
    FROM payouts
    WHERE group_id = p_group_id
    AND user_id = p_user_id
    AND status = 'completed';

    -- Check if user is admin
    IF v_group.admin_id = p_user_id THEN
        -- Admin can only leave if there are other members to take over
        IF (SELECT COUNT(*) FROM group_members WHERE group_id = p_group_id AND status = 'active') > 1 THEN
            -- Transfer admin to next senior member
            UPDATE groups
            SET admin_id = (
                SELECT user_id FROM group_members
                WHERE group_id = p_group_id
                AND user_id != p_user_id
                AND status = 'active'
                ORDER BY joined_at
                LIMIT 1
            ),
            updated_at = NOW()
            WHERE id = p_group_id;
        ELSE
            -- Last member, group will be cancelled
            UPDATE groups
            SET status = 'cancelled', updated_at = NOW()
            WHERE id = p_group_id;
        END IF;
    END IF;

    -- Check leaving conditions for active groups
    IF v_group.status = 'active' THEN
        -- User has received payout but not contributed enough
        IF v_total_received > v_total_contributed THEN
            v_penalty_amount := v_total_received - v_total_contributed;
            v_leave_reason := 'Outstanding balance: User received more than contributed';

            -- Check if user has wallet balance to cover
            DECLARE
                v_wallet_balance DECIMAL(10,2);
            BEGIN
                SELECT COALESCE(balance, 0) INTO v_wallet_balance
                FROM wallets WHERE user_id = p_user_id;

                IF v_wallet_balance < v_penalty_amount THEN
                    RETURN jsonb_build_object(
                        'error', 'Cannot leave with outstanding balance',
                        'code', 'OUTSTANDING_BALANCE',
                        'amount_owed', v_penalty_amount,
                        'wallet_balance', v_wallet_balance,
                        'action_required', 'Please settle your balance before leaving'
                    );
                END IF;

                -- Deduct penalty from wallet
                UPDATE wallets
                SET balance = balance - v_penalty_amount, updated_at = NOW()
                WHERE user_id = p_user_id;

                -- Add to group pool or distribute
                -- For now, add to next payout pool
            END;
        END IF;

        -- Apply early exit XnScore penalty
        PERFORM update_xnscore_for_event(p_user_id, 'early_exit', p_group_id);
    END IF;

    -- Update membership status
    UPDATE group_members
    SET
        status = 'left',
        left_reason = COALESCE(p_reason, 'User initiated'),
        updated_at = NOW()
    WHERE group_id = p_group_id
    AND user_id = p_user_id;

    -- Increment user's penalty count
    UPDATE group_members
    SET penalty_count = COALESCE(penalty_count, 0) + 1
    WHERE group_id = p_group_id
    AND user_id = p_user_id;

    -- Notify user
    PERFORM create_notification(
        p_user_id,
        'circle',
        'group',
        'Left ' || v_group.name,
        'You have left the circle. ' ||
        CASE
            WHEN v_penalty_amount > 0 THEN 'A balance of $' || v_penalty_amount || ' was deducted from your wallet.'
            ELSE ''
        END,
        jsonb_build_object(
            'group_id', p_group_id,
            'group_name', v_group.name,
            'penalty_amount', v_penalty_amount
        ),
        'normal',
        NULL,
        'circle',
        p_group_id::TEXT,
        NULL
    );

    -- Notify group admin
    IF v_group.admin_id != p_user_id THEN
        PERFORM create_notification(
            v_group.admin_id,
            'circle',
            'group',
            'Member Left Circle',
            v_user.full_name || ' has left ' || v_group.name || '.',
            jsonb_build_object(
                'group_id', p_group_id,
                'user_id', p_user_id,
                'user_name', v_user.full_name,
                'reason', p_reason
            ),
            'high',
            NULL,
            'circle',
            p_group_id::TEXT,
            '/circles/' || p_group_id
        );
    END IF;

    RETURN jsonb_build_object(
        'success', true,
        'group_id', p_group_id,
        'group_name', v_group.name,
        'total_contributed', v_total_contributed,
        'total_received', v_total_received,
        'penalty_applied', v_penalty_amount,
        'xn_score_impact', -3,
        'message', 'You have successfully left ' || v_group.name
    );
END;
$function$
;

CREATE OR REPLACE FUNCTION public.log_affordability_check(p_user_id uuid, p_circle_id uuid, p_monthly_income numeric, p_income_verified boolean, p_current_obligations numeric, p_proposed_obligation numeric, p_result character varying, p_score integer, p_risk_level character varying, p_reasons text[], p_warnings text[])
 RETURNS uuid
 LANGUAGE plpgsql
AS $function$
DECLARE
    v_check_id UUID;
BEGIN
    INSERT INTO affordability_checks (
        user_id, circle_id, monthly_income_used, income_was_verified,
        current_obligations, proposed_obligation,
        current_ratio, proposed_ratio,
        result, score, risk_level, reasons, warnings
    ) VALUES (
        p_user_id, p_circle_id, p_monthly_income, p_income_verified,
        p_current_obligations, p_proposed_obligation,
        p_current_obligations / NULLIF(p_monthly_income, 0),
        (p_current_obligations + p_proposed_obligation) / NULLIF(p_monthly_income, 0),
        p_result, p_score, p_risk_level, p_reasons, p_warnings
    )
    RETURNING id INTO v_check_id;

    RETURN v_check_id;
END;
$function$
;

CREATE OR REPLACE FUNCTION public.log_community_activity(p_community_id uuid, p_actor_user_id uuid, p_activity_type text, p_title text, p_description text DEFAULT NULL::text, p_circle_id uuid DEFAULT NULL::uuid, p_target_user_id uuid DEFAULT NULL::uuid, p_metadata jsonb DEFAULT NULL::jsonb)
 RETURNS uuid
 LANGUAGE plpgsql
AS $function$
DECLARE
    activity_id UUID;
BEGIN
    INSERT INTO public.community_activities (
        community_id, actor_user_id, activity_type, title,
        description, circle_id, target_user_id, metadata
    )
    VALUES (
        p_community_id, p_actor_user_id, p_activity_type, p_title,
        p_description, p_circle_id, p_target_user_id, p_metadata
    )
    RETURNING id INTO activity_id;
    RETURN activity_id;
END;
$function$
;

CREATE OR REPLACE FUNCTION public.make_debt_payment(p_debt_id uuid, p_user_id uuid, p_amount numeric, p_payment_method text, p_payment_reference text DEFAULT NULL::text)
 RETURNS uuid
 LANGUAGE plpgsql
 SECURITY DEFINER
AS $function$
DECLARE v_debt member_debts%ROWTYPE; v_payment_id UUID; v_new_remaining DECIMAL(15,2);
BEGIN
    SELECT * INTO v_debt FROM member_debts WHERE id = p_debt_id;
    IF NOT FOUND THEN RAISE EXCEPTION 'Debt not found'; END IF;
    IF v_debt.user_id != p_user_id THEN RAISE EXCEPTION 'Not your debt'; END IF;
    IF v_debt.debt_status NOT IN ('pending', 'repaying') THEN RAISE EXCEPTION 'Not payable'; END IF;
    IF p_amount <= 0 THEN RAISE EXCEPTION 'Amount must be positive'; END IF;
    IF p_amount > v_debt.remaining_amount THEN p_amount := v_debt.remaining_amount; END IF;

    INSERT INTO debt_payments (debt_id, user_id, amount, payment_method, payment_reference, payment_status)
    VALUES (p_debt_id, p_user_id, p_amount, p_payment_method, p_payment_reference, 'completed') RETURNING id INTO v_payment_id;

    v_new_remaining := v_debt.remaining_amount - p_amount;
    IF v_new_remaining <= 0 THEN
        UPDATE member_debts SET remaining_amount = 0, debt_status = 'settled', settled_at = now(), updated_at = now() WHERE id = p_debt_id;
        UPDATE profiles SET xn_score = LEAST(100, xn_score + 10) WHERE id = p_user_id;
    ELSE
        UPDATE member_debts SET remaining_amount = v_new_remaining, debt_status = 'repaying', installments_remaining = CASE WHEN installments_remaining IS NOT NULL THEN installments_remaining - 1 ELSE NULL END, updated_at = now() WHERE id = p_debt_id;
    END IF;
    RETURN v_payment_id;
END;
$function$
;

CREATE OR REPLACE FUNCTION public.mark_all_notifications_read()
 RETURNS integer
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
    v_count INTEGER;
BEGIN
    UPDATE notifications
    SET
        read = TRUE,
        read_at = NOW(),
        updated_at = NOW()
    WHERE user_id = auth.uid()
    AND read = FALSE;

    GET DIAGNOSTICS v_count = ROW_COUNT;
    RETURN v_count;
END;
$function$
;

CREATE OR REPLACE FUNCTION public.mark_late_fees_paid(p_loan_id uuid, p_amount_cents integer)
 RETURNS void
 LANGUAGE plpgsql
AS $function$
DECLARE
    v_fee RECORD;
    v_remaining INTEGER := p_amount_cents;
    v_to_pay INTEGER;
BEGIN
    FOR v_fee IN
        SELECT * FROM loan_late_fees
        WHERE loan_id = p_loan_id AND status = 'pending'
        ORDER BY fee_applied_date ASC
    LOOP
        EXIT WHEN v_remaining <= 0;
        v_to_pay := LEAST(v_remaining, v_fee.calculated_fee_cents - COALESCE(v_fee.paid_amount_cents, 0));
        v_remaining := v_remaining - v_to_pay;

        IF v_to_pay + COALESCE(v_fee.paid_amount_cents, 0) >= v_fee.calculated_fee_cents THEN
            UPDATE loan_late_fees SET paid_amount_cents = calculated_fee_cents,
                status = 'paid', paid_at = now(), updated_at = now() WHERE id = v_fee.id;
        ELSE
            UPDATE loan_late_fees SET paid_amount_cents = COALESCE(paid_amount_cents, 0) + v_to_pay,
                updated_at = now() WHERE id = v_fee.id;
        END IF;
    END LOOP;
END;
$function$
;

CREATE OR REPLACE FUNCTION public.mark_notification_read(p_notification_id uuid)
 RETURNS boolean
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
BEGIN
    UPDATE notifications
    SET
        read = TRUE,
        read_at = NOW(),
        updated_at = NOW()
    WHERE id = p_notification_id
    AND user_id = auth.uid();

    RETURN FOUND;
END;
$function$
;

CREATE OR REPLACE FUNCTION public.mark_reminder_sent(p_id uuid, p_notif_id text DEFAULT NULL::text)
 RETURNS boolean
 LANGUAGE plpgsql
 SECURITY DEFINER
AS $function$
BEGIN
    UPDATE loan_payment_reminders SET status = 'sent', sent_at = now(), notification_id = p_notif_id, updated_at = now() WHERE id = p_id;
    RETURN FOUND;
END;
$function$
;

CREATE OR REPLACE FUNCTION public.pause_group(p_group_id uuid, p_reason text)
 RETURNS void
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
BEGIN
    UPDATE groups SET status = 'paused', updated_at = NOW() WHERE id = p_group_id;

    INSERT INTO admin_audit_log (admin_id, action, entity_type, entity_id, details)
    VALUES (auth.uid(), 'pause_group', 'group', p_group_id, jsonb_build_object('reason', p_reason));
END;
$function$
;

CREATE OR REPLACE FUNCTION public.process_account_deletion(p_request_id uuid)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
    v_request RECORD;
    v_deleted_data JSONB;
BEGIN
    -- Get request
    SELECT * INTO v_request
    FROM user_deletion_requests
    WHERE id = p_request_id
    AND status = 'pending'
    AND retention_end_date <= CURRENT_DATE;

    IF v_request IS NULL THEN
        RETURN jsonb_build_object('error', 'Request not found or not ready for processing');
    END IF;

    -- Mark as processing
    UPDATE user_deletion_requests
    SET status = 'processing', processed_at = NOW()
    WHERE id = p_request_id;

    -- Collect summary of what will be deleted
    v_deleted_data := jsonb_build_object(
        'notifications_deleted', (SELECT COUNT(*) FROM notifications WHERE user_id = v_request.user_id),
        'contributions_count', (SELECT COUNT(*) FROM contributions WHERE user_id = v_request.user_id),
        'circles_participated', (SELECT COUNT(*) FROM group_members WHERE user_id = v_request.user_id),
        'wallet_cleared', TRUE
    );

    -- Delete user data in order (respecting foreign keys)

    -- 1. Delete notifications
    DELETE FROM notifications WHERE user_id = v_request.user_id;

    -- 2. Delete push tokens
    DELETE FROM push_tokens WHERE user_id = v_request.user_id;

    -- 3. Delete notification preferences
    DELETE FROM notification_preferences WHERE user_id = v_request.user_id;

    -- 4. Anonymize contributions (keep for group history)
    UPDATE contributions
    SET user_id = NULL
    WHERE user_id = v_request.user_id;

    -- 5. Anonymize group memberships (keep for group history)
    UPDATE group_members
    SET user_id = NULL, status = 'deleted'
    WHERE user_id = v_request.user_id;

    -- 6. Anonymize payouts
    UPDATE payouts
    SET user_id = NULL
    WHERE user_id = v_request.user_id;

    -- 7. Anonymize loans
    UPDATE loans
    SET borrower_id = NULL
    WHERE borrower_id = v_request.user_id;

    -- 8. Delete wallet
    DELETE FROM wallets WHERE user_id = v_request.user_id;

    -- 9. Delete XnScore history
    DELETE FROM xn_score_history WHERE user_id = v_request.user_id;

    -- 10. Finally, delete the user
    DELETE FROM users WHERE id = v_request.user_id;

    -- Mark request as completed
    UPDATE user_deletion_requests
    SET
        status = 'completed',
        completed_at = NOW(),
        metadata = v_deleted_data
    WHERE id = p_request_id;

    RETURN jsonb_build_object(
        'success', true,
        'user_id', v_request.user_id,
        'deleted_data', v_deleted_data,
        'completed_at', NOW()
    );
END;
$function$
;

CREATE OR REPLACE FUNCTION public.process_all_autopay()
 RETURNS TABLE(configs_processed integer, payments_successful integer, payments_failed integer, total_amount_cents bigint)
 LANGUAGE plpgsql
 SECURITY DEFINER
AS $function$
DECLARE
    v_config RECORD;
    v_result RECORD;
    v_proc INTEGER := 0;
    v_ok INTEGER := 0;
    v_fail INTEGER := 0;
    v_total BIGINT := 0;
BEGIN
    FOR v_config IN SELECT ac.* FROM loan_autopay_configs ac JOIN loans l ON l.id = ac.loan_id
        WHERE ac.status = 'active' AND l.status = 'active' AND ac.next_scheduled_at <= now() LIMIT 50
    LOOP
        BEGIN
            SELECT * INTO v_result FROM process_autopay_payment(v_config.id);
            IF v_result.success THEN v_ok := v_ok + 1; v_total := v_total + v_result.amount_cents;
            ELSE
                v_fail := v_fail + 1;
                UPDATE loan_autopay_configs SET consecutive_failures = consecutive_failures + 1, current_retry_count = current_retry_count + 1,
                    last_execution_status = 'failed', last_execution_error = v_result.error_message,
                    status = CASE WHEN consecutive_failures + 1 >= max_retries THEN 'failed'::autopay_status ELSE status END, updated_at = now()
                WHERE id = v_config.id;
            END IF;
            v_proc := v_proc + 1;
        EXCEPTION WHEN OTHERS THEN v_fail := v_fail + 1;
        END;
    END LOOP;
    RETURN QUERY SELECT v_proc, v_ok, v_fail, v_total;
END;
$function$
;

CREATE OR REPLACE FUNCTION public.process_all_inactivity_decays()
 RETURNS TABLE(users_processed integer, users_decayed integer, total_decay_applied numeric)
 LANGUAGE plpgsql
AS $function$
DECLARE
    v_processed INTEGER := 0;
    v_decayed INTEGER := 0;
    v_total_decay DECIMAL := 0;
    v_user RECORD;
    v_result RECORD;
BEGIN
    -- Process all users who may need decay
    FOR v_user IN
        SELECT xs.user_id
        FROM xn_scores xs
        WHERE xs.total_score > 15  -- Above floor
        AND xs.score_frozen = FALSE
        AND (
            xs.last_financial_activity_at IS NULL
            OR xs.last_financial_activity_at < now() - INTERVAL '30 days'
        )
        AND (
            xs.in_recovery_period = FALSE
            OR xs.recovery_ends_at < now()
        )
    LOOP
        v_processed := v_processed + 1;

        SELECT * INTO v_result FROM apply_inactivity_decay(v_user.user_id);

        IF v_result.success AND v_result.decay_applied > 0 THEN
            v_decayed := v_decayed + 1;
            v_total_decay := v_total_decay + v_result.decay_applied;
        END IF;
    END LOOP;

    RETURN QUERY SELECT v_processed, v_decayed, v_total_decay;
END;
$function$
;

CREATE OR REPLACE FUNCTION public.process_all_tenure_bonuses()
 RETURNS TABLE(users_processed integer, users_awarded integer, total_bonus_applied numeric)
 LANGUAGE plpgsql
AS $function$
DECLARE
    v_processed INTEGER := 0;
    v_awarded INTEGER := 0;
    v_total_bonus DECIMAL := 0;
    v_user RECORD;
    v_result RECORD;
BEGIN
    -- Process all users who may be eligible
    FOR v_user IN
        SELECT xs.user_id
        FROM xn_scores xs
        JOIN profiles p ON p.id = xs.user_id
        WHERE xs.score_frozen = FALSE
        AND COALESCE(xs.tenure_bonus, 0) < 25  -- Not maxed
        AND (
            xs.next_tenure_check_date IS NULL
            OR xs.next_tenure_check_date <= CURRENT_DATE
        )
    LOOP
        v_processed := v_processed + 1;

        SELECT * INTO v_result FROM apply_tenure_bonus(v_user.user_id);

        IF v_result.success THEN
            v_awarded := v_awarded + 1;
            v_total_bonus := v_total_bonus + v_result.bonus_applied;
        END IF;
    END LOOP;

    RETURN QUERY SELECT v_processed, v_awarded, v_total_bonus;
END;
$function$
;

CREATE OR REPLACE FUNCTION public.process_autopay_payment(p_config_id uuid)
 RETURNS TABLE(success boolean, payment_id uuid, amount_cents integer, obligation_id uuid, error_message text)
 LANGUAGE plpgsql
 SECURITY DEFINER
AS $function$
DECLARE
    v_config RECORD;
    v_loan RECORD;
    v_obl RECORD;
    v_amount INTEGER;
    v_pay RECORD;
BEGIN
    SELECT * INTO v_config FROM loan_autopay_configs WHERE id = p_config_id;
    IF NOT FOUND THEN RETURN QUERY SELECT FALSE, NULL::UUID, 0, NULL::UUID, 'Config not found'; RETURN; END IF;
    IF v_config.status != 'active' THEN RETURN QUERY SELECT FALSE, NULL::UUID, 0, NULL::UUID, 'Not active'; RETURN; END IF;

    SELECT * INTO v_loan FROM loans WHERE id = v_config.loan_id;
    IF v_loan.status != 'active' THEN RETURN QUERY SELECT FALSE, NULL::UUID, 0, NULL::UUID, 'Loan not active'; RETURN; END IF;

    SELECT * INTO v_obl FROM loan_payment_obligations WHERE loan_id = v_config.loan_id AND status IN ('due', 'upcoming', 'overdue') AND due_date <= CURRENT_DATE + 1 ORDER BY due_date ASC LIMIT 1;
    IF NOT FOUND THEN RETURN QUERY SELECT FALSE, NULL::UUID, 0, NULL::UUID, 'No payment due'; RETURN; END IF;

    v_amount := CASE v_config.autopay_type WHEN 'minimum' THEN v_obl.total_due_cents WHEN 'scheduled' THEN v_obl.estimated_payment_cents
        WHEN 'fixed' THEN v_config.fixed_amount_cents WHEN 'full_balance' THEN v_loan.total_outstanding_cents ELSE v_obl.total_due_cents END;

    SELECT * INTO v_pay FROM apply_payment_to_loan(v_config.loan_id, v_amount, 'autopay', v_config.payment_method_id::TEXT, NULL);

    UPDATE loan_payment_obligations SET status = CASE WHEN v_pay.remaining_principal_cents <= 0 THEN 'paid'::obligation_status ELSE 'partial'::obligation_status END,
        principal_paid_cents = v_pay.principal_paid_cents, interest_paid_cents = v_pay.interest_paid_cents, fees_paid_cents = v_pay.fees_paid_cents,
        total_paid_cents = v_amount, payment_id = v_pay.payment_id, paid_at = now(), paid_via = 'autopay', updated_at = now() WHERE id = v_obl.id;

    UPDATE loan_autopay_configs SET last_executed_at = now(), last_execution_status = 'success', total_payments_made = total_payments_made + 1,
        total_amount_paid_cents = total_amount_paid_cents + v_amount, consecutive_failures = 0, current_retry_count = 0, updated_at = now() WHERE id = p_config_id;

    UPDATE loan_autopay_configs SET next_scheduled_at = (SELECT (due_date::TIMESTAMPTZ + INTERVAL '9 hours') FROM loan_payment_obligations
        WHERE loan_id = v_config.loan_id AND status = 'upcoming' ORDER BY due_date ASC LIMIT 1) WHERE id = p_config_id;

    IF v_obl.due_date >= CURRENT_DATE THEN
        UPDATE loan_payment_obligations SET xnscore_event_triggered = TRUE, xnscore_adjustment = 3 WHERE id = v_obl.id;
    END IF;

    RETURN QUERY SELECT TRUE, v_pay.payment_id, v_amount, v_obl.id, NULL::TEXT;
END;
$function$
;

CREATE OR REPLACE FUNCTION public.process_daily_decay_check()
 RETURNS jsonb
 LANGUAGE plpgsql
AS $function$
DECLARE
    v_decay_result RECORD;
    v_expired_recoveries INTEGER := 0;
    v_user RECORD;
BEGIN
    -- 1. Process inactivity decays
    SELECT * INTO v_decay_result FROM process_all_inactivity_decays();

    -- 2. End expired recovery periods
    FOR v_user IN
        SELECT user_id FROM xn_scores
        WHERE in_recovery_period = TRUE
        AND recovery_ends_at <= now()
    LOOP
        PERFORM end_recovery_period(v_user.user_id);
        v_expired_recoveries := v_expired_recoveries + 1;
    END LOOP;

    -- 3. Reset monthly counters if new month
    UPDATE xn_scores SET
        contributions_this_month = 0,
        on_time_payments_this_month = 0,
        current_month_start = date_trunc('month', now())::DATE
    WHERE current_month_start IS NULL
       OR current_month_start < date_trunc('month', now())::DATE;

    RETURN jsonb_build_object(
        'decay_users_processed', v_decay_result.users_processed,
        'decay_users_decayed', v_decay_result.users_decayed,
        'decay_total_applied', v_decay_result.total_decay_applied,
        'expired_recoveries', v_expired_recoveries,
        'run_at', now()
    );
END;
$function$
;

CREATE OR REPLACE FUNCTION public.process_default_payment(p_default_id uuid, p_amount numeric, p_payment_method character varying, p_transaction_id text DEFAULT NULL::text)
 RETURNS TABLE(success boolean, remaining_amount numeric, is_fully_resolved boolean, message text)
 LANGUAGE plpgsql
AS $function$
DECLARE
    v_default RECORD;
    v_new_recovered DECIMAL(12,2);
    v_remaining DECIMAL(12,2);
BEGIN
    -- Get default
    SELECT * INTO v_default FROM defaults WHERE id = p_default_id;

    IF v_default IS NULL THEN
        RETURN QUERY SELECT FALSE, 0::DECIMAL, FALSE, 'Default not found'::TEXT;
        RETURN;
    END IF;

    -- Calculate new recovered amount
    v_new_recovered := COALESCE(v_default.recovered_amount, 0) + p_amount;
    v_remaining := v_default.amount - COALESCE(v_default.covered_amount, 0) - v_new_recovered;

    -- Update default
    UPDATE defaults
    SET
        recovered_amount = v_new_recovered,
        status = CASE WHEN v_remaining <= 0 THEN 'resolved' ELSE status END,
        resolved_at = CASE WHEN v_remaining <= 0 THEN NOW() ELSE resolved_at END,
        resolution_method = CASE WHEN v_remaining <= 0 THEN 'full_payment' ELSE resolution_method END
    WHERE id = p_default_id;

    -- Record recovery attempt
    INSERT INTO default_recovery_attempts (
        default_id, attempt_type, amount_attempted, amount_recovered, status, payment_method, transaction_id, completed_at
    ) VALUES (
        p_default_id, 'manual_payment', p_amount, p_amount, 'success', p_payment_method, p_transaction_id, NOW()
    );

    RETURN QUERY SELECT TRUE, GREATEST(0, v_remaining), v_remaining <= 0, 'Payment processed successfully'::TEXT;
END;
$function$
;

CREATE OR REPLACE FUNCTION public.process_dissolution_vote_results(p_dissolution_id uuid)
 RETURNS text
 LANGUAGE plpgsql
 SECURITY DEFINER
AS $function$
DECLARE
    v_dissolution dissolution_requests%ROWTYPE;
    v_threshold DECIMAL(3,2);
    v_approval_rate DECIMAL(5,4);
    v_new_status dissolution_status;
    v_config dissolution_trigger_config%ROWTYPE;
BEGIN
    -- Get dissolution request
    SELECT * INTO v_dissolution FROM dissolution_requests WHERE id = p_dissolution_id;

    IF NOT FOUND THEN
        RAISE EXCEPTION 'Dissolution request not found';
    END IF;

    IF v_dissolution.status != 'voting' THEN
        RAISE EXCEPTION 'Dissolution is not in voting status';
    END IF;

    -- Get config
    SELECT * INTO v_config FROM dissolution_trigger_config WHERE trigger_type = v_dissolution.trigger_type;
    v_threshold := v_config.vote_threshold;

    -- Calculate approval rate (excluding abstentions)
    IF (v_dissolution.votes_for + v_dissolution.votes_against) > 0 THEN
        v_approval_rate := v_dissolution.votes_for::DECIMAL / (v_dissolution.votes_for + v_dissolution.votes_against);
    ELSE
        v_approval_rate := 0;
    END IF;

    -- Determine outcome
    IF v_approval_rate >= v_threshold THEN
        -- Vote passed, move to objection window
        v_new_status := 'objection_window';

        UPDATE dissolution_requests
        SET
            status = v_new_status,
            objection_window_starts_at = now(),
            objection_window_ends_at = now() + (v_config.objection_window_hours || ' hours')::INTERVAL,
            updated_at = now()
        WHERE id = p_dissolution_id;
    ELSE
        -- Vote failed
        v_new_status := 'rejected';

        UPDATE dissolution_requests
        SET
            status = v_new_status,
            resolved_at = now(),
            resolution_notes = 'Vote did not meet threshold. Approval rate: ' || ROUND(v_approval_rate * 100, 2) || '%, Required: ' || ROUND(v_threshold * 100, 2) || '%',
            updated_at = now()
        WHERE id = p_dissolution_id;
    END IF;

    -- Record event
    INSERT INTO dissolution_events (
        dissolution_request_id,
        event_type,
        event_description,
        actor_type,
        new_state
    ) VALUES (
        p_dissolution_id,
        'vote_results_processed',
        'Vote results: ' || v_new_status::TEXT || ' (Approval: ' || ROUND(v_approval_rate * 100, 2) || '%)',
        'system',
        jsonb_build_object(
            'approval_rate', v_approval_rate,
            'threshold', v_threshold,
            'votes_for', v_dissolution.votes_for,
            'votes_against', v_dissolution.votes_against,
            'new_status', v_new_status
        )
    );

    RETURN v_new_status::TEXT;
END;
$function$
;

CREATE OR REPLACE FUNCTION public.process_expired_dissolution_votes()
 RETURNS integer
 LANGUAGE plpgsql
AS $function$
DECLARE
    v_processed INTEGER := 0;
    v_dissolution RECORD;
BEGIN
    FOR v_dissolution IN
        SELECT id FROM dissolution_requests
        WHERE status = 'voting'
        AND voting_ends_at <= now()
    LOOP
        PERFORM process_dissolution_vote_results(v_dissolution.id);
        v_processed := v_processed + 1;
    END LOOP;

    RETURN v_processed;
END;
$function$
;

CREATE OR REPLACE FUNCTION public.process_expired_grace_periods()
 RETURNS integer
 LANGUAGE plpgsql
AS $function$
DECLARE v_processed INTEGER := 0; v_request RECORD;
BEGIN
    FOR v_request IN SELECT id FROM member_removal_requests WHERE status = 'pending_approval' AND is_self_removal = true AND reason = 'voluntary' AND grace_period_ends_at <= now() LOOP
        UPDATE member_removal_requests SET status = 'approved', updated_at = now() WHERE id = v_request.id;
        PERFORM execute_member_removal(v_request.id, NULL); v_processed := v_processed + 1;
    END LOOP;
    RETURN v_processed;
END;
$function$
;

CREATE OR REPLACE FUNCTION public.process_expired_objection_windows()
 RETURNS integer
 LANGUAGE plpgsql
AS $function$
DECLARE
    v_processed INTEGER := 0;
    v_dissolution RECORD;
BEGIN
    FOR v_dissolution IN
        SELECT id FROM dissolution_requests
        WHERE status = 'objection_window'
        AND objection_window_ends_at <= now()
    LOOP
        PERFORM finalize_objection_window(v_dissolution.id);
        v_processed := v_processed + 1;
    END LOOP;

    RETURN v_processed;
END;
$function$
;

CREATE OR REPLACE FUNCTION public.process_expired_removal_votes()
 RETURNS integer
 LANGUAGE plpgsql
AS $function$
DECLARE v_processed INTEGER := 0; v_request RECORD;
BEGIN
    FOR v_request IN SELECT id FROM member_removal_requests WHERE status = 'pending_approval' AND requires_vote = true AND voting_ends_at <= now() LOOP
        PERFORM process_removal_vote_results(v_request.id); v_processed := v_processed + 1;
    END LOOP;
    RETURN v_processed;
END;
$function$
;

CREATE OR REPLACE FUNCTION public.process_expired_swap_requests()
 RETURNS integer
 LANGUAGE plpgsql
AS $function$
DECLARE
    v_processed INTEGER := 0;
    v_request RECORD;
BEGIN
    FOR v_request IN
        SELECT id FROM position_swap_requests
        WHERE swap_status IN ('pending_target', 'pending_confirmation', 'pending_elder_approval')
        AND expires_at <= now()
    LOOP
        UPDATE position_swap_requests SET swap_status = 'expired', updated_at = now() WHERE id = v_request.id;

        INSERT INTO position_swap_events (swap_request_id, event_type, actor_role, event_details)
        VALUES (v_request.id, 'swap_expired', 'system', 'Request expired without completion');

        v_processed := v_processed + 1;
    END LOOP;

    RETURN v_processed;
END;
$function$
;

CREATE OR REPLACE FUNCTION public.process_join_request(p_admin_id uuid, p_group_id uuid, p_user_id uuid, p_action text, p_reason text DEFAULT NULL::text)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
    v_group RECORD;
    v_membership RECORD;
    v_user RECORD;
BEGIN
    -- Verify admin
    SELECT * INTO v_group FROM groups WHERE id = p_group_id;

    IF v_group IS NULL THEN
        RETURN jsonb_build_object('error', 'Circle not found', 'code', 'GROUP_NOT_FOUND');
    END IF;

    IF v_group.admin_id != p_admin_id THEN
        RETURN jsonb_build_object('error', 'Only the circle admin can process join requests', 'code', 'NOT_ADMIN');
    END IF;

    -- Get pending membership
    SELECT * INTO v_membership
    FROM group_members
    WHERE group_id = p_group_id
    AND user_id = p_user_id
    AND status = 'pending';

    IF v_membership IS NULL THEN
        RETURN jsonb_build_object('error', 'No pending request found', 'code', 'REQUEST_NOT_FOUND');
    END IF;

    -- Get user info
    SELECT * INTO v_user FROM users WHERE id = p_user_id;

    IF p_action = 'approve' THEN
        -- Approve the request
        UPDATE group_members
        SET status = 'active', updated_at = NOW()
        WHERE group_id = p_group_id AND user_id = p_user_id;

        -- Notify user
        PERFORM create_notification(
            p_user_id,
            'circle',
            'group',
            'Welcome to ' || v_group.name || '!',
            'Your request to join has been approved. Your payout position is #' || v_membership.payout_position || '.',
            jsonb_build_object('group_id', p_group_id, 'group_name', v_group.name, 'position', v_membership.payout_position),
            'high',
            NULL,
            'circle',
            p_group_id::TEXT,
            '/circles/' || p_group_id
        );

        RETURN jsonb_build_object(
            'success', true,
            'action', 'approved',
            'user_id', p_user_id,
            'user_name', v_user.full_name,
            'message', v_user.full_name || ' has been approved to join ' || v_group.name
        );
    ELSIF p_action = 'reject' THEN
        -- Reject the request
        UPDATE group_members
        SET status = 'rejected', left_reason = COALESCE(p_reason, 'Rejected by admin'), updated_at = NOW()
        WHERE group_id = p_group_id AND user_id = p_user_id;

        -- Notify user
        PERFORM create_notification(
            p_user_id,
            'circle',
            'group',
            'Join Request Declined',
            'Your request to join ' || v_group.name || ' was not approved.' ||
            CASE WHEN p_reason IS NOT NULL THEN ' Reason: ' || p_reason ELSE '' END,
            jsonb_build_object('group_id', p_group_id, 'group_name', v_group.name, 'reason', p_reason),
            'normal',
            NULL,
            'circle',
            p_group_id::TEXT,
            NULL
        );

        RETURN jsonb_build_object(
            'success', true,
            'action', 'rejected',
            'user_id', p_user_id,
            'user_name', v_user.full_name,
            'reason', p_reason,
            'message', v_user.full_name || '''s request has been declined'
        );
    ELSE
        RETURN jsonb_build_object('error', 'Invalid action. Use ''approve'' or ''reject''', 'code', 'INVALID_ACTION');
    END IF;
END;
$function$
;

CREATE OR REPLACE FUNCTION public.process_loan_application(p_admin_id uuid, p_loan_id uuid, p_action text, p_reason text DEFAULT NULL::text)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
    v_loan RECORD;
    v_group RECORD;
    v_user RECORD;
    v_pool_balance DECIMAL(10,2);
BEGIN
    -- Get loan details
    SELECT * INTO v_loan FROM loans WHERE id = p_loan_id;

    IF v_loan IS NULL THEN
        RETURN jsonb_build_object('error', 'Loan not found', 'code', 'LOAN_NOT_FOUND');
    END IF;

    IF v_loan.status != 'pending' THEN
        RETURN jsonb_build_object('error', 'Loan is not pending approval', 'code', 'NOT_PENDING');
    END IF;

    -- Get group and verify admin
    SELECT * INTO v_group FROM groups WHERE id = v_loan.group_id;

    IF v_group.admin_id != p_admin_id THEN
        RETURN jsonb_build_object('error', 'Only the circle admin can process loan applications', 'code', 'NOT_ADMIN');
    END IF;

    -- Get borrower info
    SELECT * INTO v_user FROM users WHERE id = v_loan.borrower_id;

    IF p_action = 'approve' THEN
        -- Check if group has sufficient funds (optional - depends on your model)
        -- For now, we'll just approve

        -- Update loan status
        UPDATE loans
        SET
            status = 'approved',
            approved_at = NOW(),
            approved_by = p_admin_id,
            next_payment_date = CURRENT_DATE + INTERVAL '1 month',
            updated_at = NOW()
        WHERE id = p_loan_id;

        -- Disburse funds to user's wallet
        UPDATE wallets
        SET
            balance = balance + v_loan.amount,
            updated_at = NOW()
        WHERE user_id = v_loan.borrower_id;

        -- Create transaction record
        INSERT INTO wallet_transactions (
            wallet_id,
            type,
            amount,
            description,
            reference_type,
            reference_id,
            status
        )
        SELECT
            id,
            'loan_disbursement',
            v_loan.amount,
            'Loan disbursement from ' || v_group.name,
            'loan',
            p_loan_id,
            'completed'
        FROM wallets
        WHERE user_id = v_loan.borrower_id;

        -- Notify borrower
        PERFORM create_notification(
            v_loan.borrower_id,
            'loan',
            'loan',
            'Loan Approved! 🎉',
            'Your loan of $' || v_loan.amount || ' has been approved! Funds have been added to your wallet. First payment of $' || v_loan.monthly_payment || ' is due in 30 days.',
            jsonb_build_object(
                'loan_id', p_loan_id,
                'amount', v_loan.amount,
                'monthly_payment', v_loan.monthly_payment,
                'first_payment_date', CURRENT_DATE + INTERVAL '1 month'
            ),
            'urgent',
            NULL,
            'loan',
            p_loan_id::TEXT,
            '/loans/' || p_loan_id
        );

        RETURN jsonb_build_object(
            'success', true,
            'action', 'approved',
            'loan_id', p_loan_id,
            'borrower', v_user.full_name,
            'amount', v_loan.amount,
            'message', 'Loan approved and funds disbursed to ' || v_user.full_name
        );

    ELSIF p_action = 'reject' THEN
        -- Reject the loan
        UPDATE loans
        SET
            status = 'rejected',
            rejected_reason = COALESCE(p_reason, 'Rejected by admin'),
            updated_at = NOW()
        WHERE id = p_loan_id;

        -- Notify borrower
        PERFORM create_notification(
            v_loan.borrower_id,
            'loan',
            'loan',
            'Loan Application Declined',
            'Your loan application for $' || v_loan.amount || ' was not approved.' ||
            CASE WHEN p_reason IS NOT NULL THEN ' Reason: ' || p_reason ELSE '' END,
            jsonb_build_object('loan_id', p_loan_id, 'reason', p_reason),
            'normal',
            NULL,
            'loan',
            p_loan_id::TEXT,
            NULL
        );

        RETURN jsonb_build_object(
            'success', true,
            'action', 'rejected',
            'loan_id', p_loan_id,
            'borrower', v_user.full_name,
            'reason', p_reason,
            'message', 'Loan application has been declined'
        );
    ELSE
        RETURN jsonb_build_object('error', 'Invalid action. Use ''approve'' or ''reject''', 'code', 'INVALID_ACTION');
    END IF;
END;
$function$
;

CREATE OR REPLACE FUNCTION public.process_monthly_tenure_check()
 RETURNS jsonb
 LANGUAGE plpgsql
AS $function$
DECLARE
    v_tenure_result RECORD;
BEGIN
    -- Process tenure bonuses
    SELECT * INTO v_tenure_result FROM process_all_tenure_bonuses();

    RETURN jsonb_build_object(
        'tenure_users_processed', v_tenure_result.users_processed,
        'tenure_users_awarded', v_tenure_result.users_awarded,
