;

CREATE OR REPLACE FUNCTION public.process_notification_queue()
 RETURNS void
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
    v_url TEXT;
    v_service_role_key TEXT;
    v_project_ref TEXT := 'fjqdkyjkwqeoafwvnjgv';
BEGIN
    -- Build the Edge Function URL
    v_url := 'https://' || v_project_ref || '.supabase.co/functions/v1/send-notification';

    -- Get service role key from vault (you need to store this in vault first)
    -- For now, we'll use a direct approach

    -- Make HTTP request to process queue
    PERFORM net.http_post(
        url := v_url,
        headers := jsonb_build_object(
            'Content-Type', 'application/json',
            'Authorization', 'Bearer ' || current_setting('app.settings.service_role_key', true)
        ),
        body := jsonb_build_object(
            'action', 'process-queue',
            'limit', 100
        )
    );

    RAISE NOTICE 'Notification queue processing triggered at %', NOW();
END;
$function$
;

CREATE OR REPLACE FUNCTION public.process_notification_queue_direct()
 RETURNS integer
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
    v_processed INTEGER := 0;
    v_queue_item RECORD;
BEGIN
    -- Get pending items older than retry delay
    FOR v_queue_item IN
        SELECT
            nq.id,
            nq.notification_id,
            nq.user_id,
            nq.channel,
            nq.payload,
            nq.attempts
        FROM notification_queue nq
        WHERE nq.status IN ('pending', 'failed')
        AND nq.next_attempt_at <= NOW()
        AND nq.attempts < nq.max_attempts
        ORDER BY
            CASE WHEN (nq.payload->>'priority') = 'urgent' THEN 0
                 WHEN (nq.payload->>'priority') = 'high' THEN 1
                 ELSE 2
            END,
            nq.created_at
        LIMIT 100
        FOR UPDATE SKIP LOCKED
    LOOP
        -- Update attempt count
        UPDATE notification_queue
        SET
            status = 'processing',
            attempts = attempts + 1,
            last_attempt_at = NOW()
        WHERE id = v_queue_item.id;

        -- Mark as sent (actual sending happens via Edge Function webhook or external service)
        -- For push notifications, we mark them for the Edge Function to pick up
        -- For email, same approach

        -- If this is a simple in-app notification, just mark as processed
        IF v_queue_item.channel = 'in_app' THEN
            UPDATE notification_queue
            SET
                status = 'sent',
                processed_at = NOW()
            WHERE id = v_queue_item.id;

            v_processed := v_processed + 1;
        ELSE
            -- For push/email, mark as pending for Edge Function
            -- The Edge Function will be called separately
            UPDATE notification_queue
            SET status = 'pending'
            WHERE id = v_queue_item.id;
        END IF;
    END LOOP;

    RETURN v_processed;
END;
$function$
;

CREATE OR REPLACE FUNCTION public.process_pending_deletions()
 RETURNS integer
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
    v_request RECORD;
    v_processed INTEGER := 0;
BEGIN
    FOR v_request IN
        SELECT id
        FROM user_deletion_requests
        WHERE status = 'pending'
        AND retention_end_date <= CURRENT_DATE
    LOOP
        PERFORM process_account_deletion(v_request.id);
        v_processed := v_processed + 1;
    END LOOP;

    RAISE NOTICE 'Processed % account deletions', v_processed;
    RETURN v_processed;
END;
$function$
;

CREATE OR REPLACE FUNCTION public.process_pool_coverage(p_default_id uuid)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
AS $function$
DECLARE
  v_default RECORD;
  v_pool RECORD;
  v_shortfall_cents BIGINT;
  v_max_coverage_cents BIGINT;
  v_approved_cents BIGINT;
  v_coverage_pct DECIMAL(5,4);
  v_claim_id UUID;
  v_new_balance BIGINT;
  v_claim_status TEXT;
BEGIN
  SELECT * INTO v_default
  FROM defaults
  WHERE id = p_default_id;

  IF v_default IS NULL THEN
    RETURN jsonb_build_object('error', 'Default not found', 'approved_cents', 0);
  END IF;

  SELECT * INTO v_pool
  FROM circle_insurance_pools
  WHERE circle_id = v_default.circle_id;

  IF v_pool IS NULL OR v_pool.balance_cents <= 0 OR v_pool.status != 'active' THEN
    RETURN jsonb_build_object(
      'approved_cents', 0,
      'coverage_pct', 0,
      'reason', CASE
        WHEN v_pool IS NULL THEN 'No insurance pool for this circle'
        WHEN v_pool.balance_cents <= 0 THEN 'Insurance pool depleted'
        ELSE 'Insurance pool not active (status: ' || v_pool.status || ')'
      END
    );
  END IF;

  v_shortfall_cents := ROUND(v_default.total_owed * 100);
  v_max_coverage_cents := ROUND(v_shortfall_cents * 0.80);
  v_approved_cents := LEAST(v_max_coverage_cents, v_pool.balance_cents);

  IF v_approved_cents >= v_max_coverage_cents THEN
    v_claim_status := 'approved';
  ELSIF v_approved_cents > 0 THEN
    v_claim_status := 'partial';
  ELSE
    v_claim_status := 'denied';
  END IF;

  IF v_shortfall_cents > 0 THEN
    v_coverage_pct := v_approved_cents::DECIMAL / v_shortfall_cents;
  ELSE
    v_coverage_pct := 0;
  END IF;

  v_new_balance := v_pool.balance_cents - v_approved_cents;

  INSERT INTO insurance_coverage_claims (
    pool_id, circle_id, default_id, cycle_id, defaulter_user_id,
    shortfall_amount_cents, max_coverage_cents, approved_amount_cents,
    coverage_pct, pool_balance_before_cents, pool_balance_after_cents,
    status, processed_at
  ) VALUES (
    v_pool.id, v_default.circle_id, p_default_id, v_default.cycle_id,
    v_default.user_id,
    v_shortfall_cents, v_max_coverage_cents, v_approved_cents,
    v_coverage_pct, v_pool.balance_cents, v_new_balance,
    v_claim_status, NOW()
  )
  RETURNING id INTO v_claim_id;

  UPDATE circle_insurance_pools
  SET
    balance_cents = v_new_balance,
    total_paid_out_cents = total_paid_out_cents + v_approved_cents,
    total_claims = total_claims + 1,
    approved_claims = CASE WHEN v_approved_cents > 0
      THEN approved_claims + 1 ELSE approved_claims END,
    status = CASE WHEN v_new_balance <= 0 THEN 'depleted' ELSE status END,
    updated_at = NOW()
  WHERE id = v_pool.id;

  IF v_approved_cents > 0 THEN
    INSERT INTO insurance_pool_transactions (
      pool_id, circle_id, transaction_type, amount_cents,
      running_balance_cents, default_id, claim_id,
      user_id, description
    ) VALUES (
      v_pool.id, v_default.circle_id, 'coverage_payout',
      -v_approved_cents,
      v_new_balance, p_default_id, v_claim_id,
      v_default.user_id,
      'Default coverage: ' || v_claim_status || ' (' ||
        ROUND(v_coverage_pct * 100, 1) || '% of shortfall)'
    );
  END IF;

  RETURN jsonb_build_object(
    'claim_id', v_claim_id,
    'approved_cents', v_approved_cents,
    'coverage_pct', v_coverage_pct,
    'claim_status', v_claim_status,
    'pool_balance_before', v_pool.balance_cents,
    'pool_balance_after', v_new_balance,
    'shortfall_cents', v_shortfall_cents,
    'max_coverage_cents', v_max_coverage_cents
  );
END;
$function$
;

CREATE OR REPLACE FUNCTION public.process_pool_withholding(p_contribution_id uuid, p_amount_cents bigint)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
AS $function$
DECLARE
  v_circle_id UUID;
  v_user_id UUID;
  v_pool RECORD;
  v_withheld BIGINT;
  v_new_balance BIGINT;
BEGIN
  SELECT circle_id, user_id
  INTO v_circle_id, v_user_id
  FROM cycle_contributions
  WHERE id = p_contribution_id;

  IF v_circle_id IS NULL THEN
    RETURN jsonb_build_object(
      'error', 'Contribution not found',
      'withheld_cents', 0,
      'net_amount_cents', p_amount_cents,
      'pool_balance_cents', 0
    );
  END IF;

  SELECT * INTO v_pool
  FROM circle_insurance_pools
  WHERE circle_id = v_circle_id;

  IF v_pool IS NULL THEN
    INSERT INTO circle_insurance_pools (circle_id)
    VALUES (v_circle_id)
    ON CONFLICT (circle_id) DO NOTHING
    RETURNING * INTO v_pool;

    IF v_pool IS NULL THEN
      SELECT * INTO v_pool
      FROM circle_insurance_pools
      WHERE circle_id = v_circle_id;
    END IF;
  END IF;

  IF v_pool.status != 'active' THEN
    RETURN jsonb_build_object(
      'withheld_cents', 0,
      'net_amount_cents', p_amount_cents,
      'pool_balance_cents', v_pool.balance_cents,
      'pool_status', v_pool.status
    );
  END IF;

  v_withheld := ROUND(p_amount_cents * v_pool.current_rate);
  v_new_balance := v_pool.balance_cents + v_withheld;

  UPDATE circle_insurance_pools
  SET
    balance_cents = v_new_balance,
    total_withheld_cents = total_withheld_cents + v_withheld,
    updated_at = NOW()
  WHERE id = v_pool.id;

  INSERT INTO insurance_pool_transactions (
    pool_id, circle_id, transaction_type, amount_cents,
    running_balance_cents, contribution_id, user_id, description
  ) VALUES (
    v_pool.id, v_circle_id, 'withholding', v_withheld,
    v_new_balance, p_contribution_id, v_user_id,
    'Insurance pool withholding at ' || (v_pool.current_rate * 100)::TEXT || '% rate'
  );

  RETURN jsonb_build_object(
    'withheld_cents', v_withheld,
    'net_amount_cents', p_amount_cents - v_withheld,
    'pool_balance_cents', v_new_balance,
    'rate_applied', v_pool.current_rate
  );
END;
$function$
;

CREATE OR REPLACE FUNCTION public.process_queued_score_increases()
 RETURNS integer
 LANGUAGE plpgsql
AS $function$
DECLARE
    v_processed INTEGER := 0;
    v_queue RECORD;
BEGIN
    FOR v_queue IN
        SELECT * FROM xnscore_queued_increases
        WHERE processed = FALSE
        AND process_after <= CURRENT_DATE
        ORDER BY created_at ASC
    LOOP
        -- Apply the queued increase
        PERFORM apply_xnscore_adjustment(
            v_queue.user_id,
            v_queue.amount,
            'queued_increase_' || v_queue.source_event,
            v_queue.source_id
        );

        -- Mark as processed
        UPDATE xnscore_queued_increases SET
            processed = TRUE,
            processed_at = now(),
            actual_amount_applied = v_queue.amount
        WHERE id = v_queue.id;

        v_processed := v_processed + 1;
    END LOOP;

    RETURN v_processed;
END;
$function$
;

CREATE OR REPLACE FUNCTION public.process_removal_vote_results(p_removal_request_id uuid)
 RETURNS text
 LANGUAGE plpgsql
 SECURITY DEFINER
AS $function$
DECLARE
    v_request member_removal_requests%ROWTYPE;
    v_settings circle_removal_settings%ROWTYPE;
    v_threshold DECIMAL(3,2);
    v_approval_rate DECIMAL(5,4);
    v_new_status removal_status;
BEGIN
    SELECT * INTO v_request FROM member_removal_requests WHERE id = p_removal_request_id;
    IF NOT FOUND THEN RAISE EXCEPTION 'Removal request not found'; END IF;
    IF v_request.status != 'pending_approval' THEN RAISE EXCEPTION 'Not pending approval'; END IF;

    SELECT * INTO v_settings FROM circle_removal_settings WHERE circle_id = v_request.circle_id;
    v_threshold := COALESCE(v_settings.vote_threshold_percentage, 0.60);

    IF (v_request.votes_for + v_request.votes_against) > 0 THEN
        v_approval_rate := v_request.votes_for::DECIMAL / (v_request.votes_for + v_request.votes_against);
    ELSE v_approval_rate := 0;
    END IF;

    v_new_status := CASE WHEN v_approval_rate >= v_threshold THEN 'approved' ELSE 'rejected' END;
    UPDATE member_removal_requests SET status = v_new_status, updated_at = now() WHERE id = p_removal_request_id;
    IF v_new_status = 'approved' THEN PERFORM execute_member_removal(p_removal_request_id, NULL); END IF;

    RETURN v_new_status::TEXT;
END;
$function$
;

CREATE OR REPLACE FUNCTION public.process_wallet_credit(p_wallet_id uuid, p_amount_cents bigint, p_transaction_type text, p_reference_type text, p_reference_id uuid, p_description text, p_metadata jsonb DEFAULT '{}'::jsonb)
 RETURNS uuid
 LANGUAGE plpgsql
AS $function$
DECLARE
    v_wallet user_wallets%ROWTYPE;
    v_transaction_id UUID;
BEGIN
    SELECT * INTO v_wallet FROM user_wallets WHERE id = p_wallet_id FOR UPDATE;
    IF v_wallet IS NULL THEN RAISE EXCEPTION 'Wallet not found'; END IF;
    IF v_wallet.wallet_status != 'active' THEN RAISE EXCEPTION 'Wallet is not active'; END IF;

    INSERT INTO wallet_transactions (wallet_id, user_id, transaction_type, direction, amount_cents,
        balance_type, balance_before_cents, balance_after_cents, reference_type, reference_id,
        description, transaction_status, metadata)
    VALUES (p_wallet_id, v_wallet.user_id, p_transaction_type, 'credit', p_amount_cents, 'main',
        v_wallet.main_balance_cents, v_wallet.main_balance_cents + p_amount_cents,
        p_reference_type, p_reference_id, p_description, 'completed', p_metadata)
    RETURNING id INTO v_transaction_id;

    UPDATE user_wallets SET main_balance_cents = main_balance_cents + p_amount_cents,
        last_activity_at = NOW(), updated_at = NOW() WHERE id = p_wallet_id;

    IF p_transaction_type = 'circle_payout' THEN
        UPDATE user_wallets SET total_payouts_received_cents = total_payouts_received_cents + p_amount_cents
        WHERE id = p_wallet_id;
    END IF;

    RETURN v_transaction_id;
END;
$function$
;

CREATE OR REPLACE FUNCTION public.process_wallet_debit(p_wallet_id uuid, p_amount_cents bigint, p_transaction_type text, p_reference_type text, p_reference_id uuid, p_description text, p_metadata jsonb DEFAULT '{}'::jsonb)
 RETURNS uuid
 LANGUAGE plpgsql
AS $function$
DECLARE
    v_wallet user_wallets%ROWTYPE;
    v_transaction_id UUID;
BEGIN
    SELECT * INTO v_wallet FROM user_wallets WHERE id = p_wallet_id FOR UPDATE;
    IF v_wallet IS NULL THEN RAISE EXCEPTION 'Wallet not found'; END IF;
    IF v_wallet.wallet_status != 'active' THEN RAISE EXCEPTION 'Wallet is not active'; END IF;
    IF v_wallet.main_balance_cents < p_amount_cents THEN RAISE EXCEPTION 'Insufficient balance'; END IF;

    INSERT INTO wallet_transactions (wallet_id, user_id, transaction_type, direction, amount_cents,
        balance_type, balance_before_cents, balance_after_cents, reference_type, reference_id,
        description, transaction_status, metadata)
    VALUES (p_wallet_id, v_wallet.user_id, p_transaction_type, 'debit', p_amount_cents, 'main',
        v_wallet.main_balance_cents, v_wallet.main_balance_cents - p_amount_cents,
        p_reference_type, p_reference_id, p_description, 'completed', p_metadata)
    RETURNING id INTO v_transaction_id;

    UPDATE user_wallets SET main_balance_cents = main_balance_cents - p_amount_cents,
        last_activity_at = NOW(), updated_at = NOW() WHERE id = p_wallet_id;

    IF p_transaction_type = 'withdrawal' THEN
        UPDATE user_wallets SET total_withdrawals_cents = total_withdrawals_cents + p_amount_cents,
            money_retention_rate = CASE WHEN total_payouts_received_cents > 0
                THEN GREATEST(0, (total_payouts_received_cents - total_withdrawals_cents - p_amount_cents)::DECIMAL / total_payouts_received_cents)
                ELSE 1.0 END
        WHERE id = p_wallet_id;
    END IF;

    RETURN v_transaction_id;
END;
$function$
;

CREATE OR REPLACE FUNCTION public.recalculate_all_xn_scores()
 RETURNS integer
 LANGUAGE plpgsql
 SECURITY DEFINER
AS $function$
DECLARE v_count INTEGER := 0; v_user RECORD;
BEGIN
  FOR v_user IN SELECT user_id FROM xn_scores WHERE score_frozen = false
  LOOP
    BEGIN
      PERFORM recalculate_xn_score(v_user.user_id);
      v_count := v_count + 1;
    EXCEPTION WHEN OTHERS THEN
      RAISE WARNING 'recalculate_xn_score failed for user %: %', v_user.user_id, SQLERRM;
    END;
  END LOOP;
  RETURN v_count;
END;
$function$
;

CREATE OR REPLACE FUNCTION public.recalculate_full_xnscore(p_user_id uuid)
 RETURNS TABLE(success boolean, previous_score numeric, new_score numeric, factor_totals jsonb)
 LANGUAGE plpgsql
AS $function$
DECLARE
    v_score_record RECORD;
    v_payment RECORD;
    v_completion RECORD;
    v_tenure RECORD;
    v_community RECORD;
    v_financial RECORD;
    v_new_raw DECIMAL;
    v_new_capped DECIMAL;
    v_age_cap INTEGER;
BEGIN
    -- Get current score
    SELECT * INTO v_score_record FROM xn_scores WHERE xn_scores.user_id = p_user_id;

    IF NOT FOUND THEN
        RETURN QUERY SELECT FALSE, 0::DECIMAL, 0::DECIMAL, '{}'::JSONB;
        RETURN;
    END IF;

    -- Calculate all factors
    SELECT * INTO v_payment FROM calculate_payment_reliability_factor(p_user_id);
    SELECT * INTO v_completion FROM calculate_circle_completion_factor(p_user_id);
    SELECT * INTO v_tenure FROM calculate_tenure_activity_factor(p_user_id);
    SELECT * INTO v_community FROM calculate_community_standing_factor(p_user_id);
    SELECT * INTO v_financial FROM calculate_financial_behavior_factor(p_user_id);

    -- Sum up raw score
    v_new_raw := COALESCE(v_payment.total_score, 0) +
                 COALESCE(v_completion.total_score, 0) +
                 COALESCE(v_tenure.total_score, 0) +
                 COALESCE(v_community.total_score, 0) +
                 COALESCE(v_financial.total_score, 0);

    -- Apply age cap
    v_age_cap := get_xnscore_age_cap(v_score_record.account_age_days);
    v_new_capped := LEAST(v_new_raw, v_age_cap);

    -- Update score
    UPDATE xn_scores SET
        previous_score = total_score,
        raw_score = v_new_raw,
        total_score = v_new_capped,
        score_tier = get_xnscore_tier(v_new_capped),
        payment_history_score = v_payment.total_score,
        completion_score = v_completion.total_score,
        time_reliability_score = v_tenure.total_score,
        diversity_social_score = v_community.total_score,
        deposit_score = v_financial.total_score,
        age_cap_applied = v_new_capped < v_new_raw,
        max_allowed_score = v_age_cap,
        last_calculated_at = now(),
        calculation_trigger = 'full_recalculation',
        updated_at = now()
    WHERE xn_scores.user_id = p_user_id;

    -- Refresh breakdown cache
    PERFORM refresh_score_breakdown(p_user_id);

    RETURN QUERY SELECT
        TRUE,
        v_score_record.total_score,
        v_new_capped,
        jsonb_build_object(
            'payment_reliability', v_payment.total_score,
            'circle_completion', v_completion.total_score,
            'tenure_activity', v_tenure.total_score,
            'community_standing', v_community.total_score,
            'financial_behavior', v_financial.total_score,
            'raw_total', v_new_raw,
            'age_cap', v_age_cap,
            'capped_total', v_new_capped
        );
END;
$function$
;

CREATE OR REPLACE FUNCTION public.record_decay_event(p_user_id uuid, p_decay_amount numeric, p_reason text, p_details jsonb DEFAULT NULL::jsonb)
 RETURNS uuid
 LANGUAGE plpgsql
AS $function$
DECLARE
    v_score RECORD;
    v_decay_reason decay_reason;
    v_history_id UUID;
BEGIN
    SELECT * INTO v_score FROM xn_scores WHERE user_id = p_user_id;

    IF NOT FOUND THEN
        RETURN NULL;
    END IF;

    -- Map reason string to enum
    v_decay_reason := CASE
        WHEN p_reason LIKE '%30%' THEN 'inactivity_30d'::decay_reason
        WHEN p_reason LIKE '%60%' THEN 'inactivity_60d'::decay_reason
        WHEN p_reason LIKE '%90%' THEN 'inactivity_90d'::decay_reason
        WHEN p_reason LIKE '%120%' THEN 'inactivity_120d'::decay_reason
        WHEN p_reason LIKE '%180%' THEN 'inactivity_180d'::decay_reason
        WHEN p_reason LIKE '%240%' THEN 'inactivity_240d'::decay_reason
        WHEN p_reason LIKE '%365%' THEN 'inactivity_365d'::decay_reason
        WHEN p_reason LIKE '%manual%' THEN 'manual_decay'::decay_reason
        WHEN p_reason LIKE '%suspend%' THEN 'suspension_decay'::decay_reason
        WHEN p_reason LIKE '%fraud%' THEN 'fraud_decay'::decay_reason
        ELSE 'inactivity_90d'::decay_reason
    END;

    INSERT INTO xnscore_decay_history (
        user_id, decay_reason, decay_amount,
        score_before, score_after,
        days_inactive, last_financial_activity_at,
        total_decay_this_period, decay_details
    ) VALUES (
        p_user_id, v_decay_reason, ABS(p_decay_amount),
        v_score.total_score, GREATEST(15, v_score.total_score + p_decay_amount),
        v_score.financial_inactive_days, v_score.last_financial_activity_at,
        COALESCE(v_score.total_inactivity_penalty, 0) + ABS(p_decay_amount),
        p_details
    )
    RETURNING id INTO v_history_id;

    RETURN v_history_id;
END;
$function$
;

CREATE OR REPLACE FUNCTION public.record_loan_payment(p_loan_id uuid, p_amount_cents integer, p_payment_method text, p_payment_source_id text DEFAULT NULL::text)
 RETURNS uuid
 LANGUAGE plpgsql
 SECURITY DEFINER
AS $function$
DECLARE
    v_loan RECORD;
    v_schedule RECORD;
    v_payment_id UUID;
    v_is_on_time BOOLEAN;
    v_days_late INTEGER;
    v_principal_allocation INTEGER;
    v_interest_allocation INTEGER;
    v_fees_allocation INTEGER;
BEGIN
    -- Get loan
    SELECT * INTO v_loan FROM loans WHERE id = p_loan_id;

    IF NOT FOUND THEN
        RAISE EXCEPTION 'Loan not found';
    END IF;

    -- Get next scheduled payment
    SELECT * INTO v_schedule
    FROM loan_payment_schedule
    WHERE loan_id = p_loan_id AND status IN ('scheduled', 'partial', 'late')
    ORDER BY payment_number ASC
    LIMIT 1;

    -- Determine if on time
    v_is_on_time := CURRENT_DATE <= v_schedule.due_date + 5; -- 5 day grace period
    v_days_late := GREATEST(0, CURRENT_DATE - v_schedule.due_date - 5);

    -- Allocate payment (interest first, then principal, then fees)
    v_interest_allocation := LEAST(p_amount_cents, v_schedule.interest_due_cents - v_schedule.interest_paid_cents);
    v_principal_allocation := LEAST(p_amount_cents - v_interest_allocation, v_schedule.principal_due_cents - v_schedule.principal_paid_cents);
    v_fees_allocation := p_amount_cents - v_interest_allocation - v_principal_allocation;

    -- Create payment record
    INSERT INTO loan_payments (
        loan_id, user_id, schedule_id,
        amount_cents, principal_cents, interest_cents, fees_cents,
        payment_method, payment_source_id,
        was_on_time, days_late, status
    ) VALUES (
        p_loan_id, v_loan.user_id, v_schedule.id,
        p_amount_cents, v_principal_allocation, v_interest_allocation, v_fees_allocation,
        p_payment_method, p_payment_source_id,
        v_is_on_time, v_days_late, 'completed'::loan_payment_status
    )
    RETURNING id INTO v_payment_id;

    -- Update schedule
    UPDATE loan_payment_schedule SET
        principal_paid_cents = principal_paid_cents + v_principal_allocation,
        interest_paid_cents = interest_paid_cents + v_interest_allocation,
        fees_paid_cents = fees_paid_cents + v_fees_allocation,
        total_paid_cents = total_paid_cents + p_amount_cents,
        status = CASE
            WHEN (principal_paid_cents + v_principal_allocation) >= principal_due_cents
                 AND (interest_paid_cents + v_interest_allocation) >= interest_due_cents
            THEN 'paid'::payment_schedule_status
            ELSE 'partial'::payment_schedule_status
        END,
        paid_at = CASE
            WHEN (principal_paid_cents + v_principal_allocation) >= principal_due_cents
            THEN now()
            ELSE NULL
        END,
        updated_at = now()
    WHERE id = v_schedule.id;

    -- Update loan balances
    UPDATE loans SET
        outstanding_principal_cents = outstanding_principal_cents - v_principal_allocation,
        outstanding_interest_cents = outstanding_interest_cents - v_interest_allocation,
        outstanding_fees_cents = outstanding_fees_cents - v_fees_allocation,
        total_outstanding_cents = outstanding_principal_cents - v_principal_allocation +
                                  outstanding_interest_cents - v_interest_allocation +
                                  outstanding_fees_cents - v_fees_allocation,
        payments_made = payments_made + 1,
        days_past_due = 0,
        is_delinquent = FALSE,
        delinquent_since = NULL,
        next_payment_date = (
            SELECT due_date FROM loan_payment_schedule
            WHERE loan_id = p_loan_id AND status IN ('scheduled', 'partial')
            ORDER BY payment_number ASC LIMIT 1
        ),
        updated_at = now()
    WHERE id = p_loan_id;

    -- Check if loan is paid off
    IF (SELECT outstanding_principal_cents FROM loans WHERE id = p_loan_id) <= 0 THEN
        UPDATE loans SET
            status = 'paid_off',
            closed_at = now(),
            closed_reason = 'full_payment'
        WHERE id = p_loan_id;

        -- Release guarantees and co-signers
        UPDATE loan_guarantees SET
            status = 'released',
            released_at = now(),
            release_reason = 'loan_paid_off'
        WHERE loan_id = p_loan_id;

        UPDATE loan_co_signers SET
            status = 'released',
            released_at = now(),
            release_reason = 'loan_paid_off'
        WHERE loan_id = p_loan_id;
    END IF;

    -- Apply XnScore event
    PERFORM apply_xnscore_adjustment(
        v_loan.user_id,
        CASE WHEN v_is_on_time THEN 3 ELSE -5 END,
        CASE WHEN v_is_on_time THEN 'loan.repaid_on_time' ELSE 'loan.payment_late' END,
        v_payment_id
    );

    UPDATE loan_payments SET xnscore_event_triggered = TRUE WHERE id = v_payment_id;

    RETURN v_payment_id;
END;
$function$
;

CREATE OR REPLACE FUNCTION public.record_tenure_event(p_user_id uuid, p_bonus_amount numeric, p_month_number integer)
 RETURNS uuid
 LANGUAGE plpgsql
AS $function$
DECLARE
    v_score RECORD;
    v_history_id UUID;
    v_total_tenure DECIMAL;
BEGIN
    SELECT * INTO v_score FROM xn_scores WHERE user_id = p_user_id;

    IF NOT FOUND THEN
        RETURN NULL;
    END IF;

    v_total_tenure := COALESCE(v_score.tenure_bonus, 0) + p_bonus_amount;

    INSERT INTO xnscore_tenure_history (
        user_id, tenure_month, bonus_amount,
        score_before, score_after,
        was_active_this_month, had_on_time_payment,
        contribution_count_this_month, total_tenure_bonus_earned
    ) VALUES (
        p_user_id, p_month_number, p_bonus_amount,
        v_score.total_score, v_score.total_score + p_bonus_amount,
        TRUE, v_score.on_time_payments_this_month > 0,
        v_score.contributions_this_month, v_total_tenure
    )
    ON CONFLICT (user_id, tenure_month) DO NOTHING
    RETURNING id INTO v_history_id;

    RETURN v_history_id;
END;
$function$
;

CREATE OR REPLACE FUNCTION public.refresh_score_breakdown(p_user_id uuid)
 RETURNS boolean
 LANGUAGE plpgsql
AS $function$
DECLARE
    v_breakdown JSONB;
    v_score_record RECORD;
    v_tips JSONB;
BEGIN
    -- Calculate breakdown
    v_breakdown := calculate_score_breakdown(p_user_id);

    IF v_breakdown ? 'error' THEN
        RETURN FALSE;
    END IF;

    -- Get tips
    v_tips := get_improvement_tips(p_user_id, 5);

    -- Upsert cache
    INSERT INTO xn_score_breakdown_cache (
        user_id, total_score,
        payment_reliability_score, payment_reliability_status, payment_reliability_trend,
        circle_completion_score, circle_completion_status, circle_completion_trend,
        tenure_activity_score, tenure_activity_status, tenure_activity_trend,
        community_standing_score, community_standing_status, community_standing_trend,
        financial_behavior_score, financial_behavior_status, financial_behavior_trend,
        factor_breakdown, improvement_tips,
        calculated_at, expires_at
    ) VALUES (
        p_user_id,
        (v_breakdown->>'total_score')::DECIMAL,
        (v_breakdown->'factors'->'payment_reliability'->>'score')::DECIMAL,
        (v_breakdown->'factors'->'payment_reliability'->>'status')::factor_status,
        (v_breakdown->'factors'->'payment_reliability'->>'trend')::factor_trend,
        (v_breakdown->'factors'->'circle_completion'->>'score')::DECIMAL,
        (v_breakdown->'factors'->'circle_completion'->>'status')::factor_status,
        (v_breakdown->'factors'->'circle_completion'->>'trend')::factor_trend,
        (v_breakdown->'factors'->'tenure_activity'->>'score')::DECIMAL,
        (v_breakdown->'factors'->'tenure_activity'->>'status')::factor_status,
        (v_breakdown->'factors'->'tenure_activity'->>'trend')::factor_trend,
        (v_breakdown->'factors'->'community_standing'->>'score')::DECIMAL,
        (v_breakdown->'factors'->'community_standing'->>'status')::factor_status,
        (v_breakdown->'factors'->'community_standing'->>'trend')::factor_trend,
        (v_breakdown->'factors'->'financial_behavior'->>'score')::DECIMAL,
        (v_breakdown->'factors'->'financial_behavior'->>'status')::factor_status,
        (v_breakdown->'factors'->'financial_behavior'->>'trend')::factor_trend,
        v_breakdown->'factors',
        v_tips,
        now(),
        now() + INTERVAL '1 hour'
    )
    ON CONFLICT (user_id) DO UPDATE SET
        total_score = EXCLUDED.total_score,
        payment_reliability_score = EXCLUDED.payment_reliability_score,
        payment_reliability_status = EXCLUDED.payment_reliability_status,
        payment_reliability_trend = EXCLUDED.payment_reliability_trend,
        circle_completion_score = EXCLUDED.circle_completion_score,
        circle_completion_status = EXCLUDED.circle_completion_status,
        circle_completion_trend = EXCLUDED.circle_completion_trend,
        tenure_activity_score = EXCLUDED.tenure_activity_score,
        tenure_activity_status = EXCLUDED.tenure_activity_status,
        tenure_activity_trend = EXCLUDED.tenure_activity_trend,
        community_standing_score = EXCLUDED.community_standing_score,
        community_standing_status = EXCLUDED.community_standing_status,
        community_standing_trend = EXCLUDED.community_standing_trend,
        financial_behavior_score = EXCLUDED.financial_behavior_score,
        financial_behavior_status = EXCLUDED.financial_behavior_status,
        financial_behavior_trend = EXCLUDED.financial_behavior_trend,
        factor_breakdown = EXCLUDED.factor_breakdown,
        improvement_tips = EXCLUDED.improvement_tips,
        calculated_at = EXCLUDED.calculated_at,
        expires_at = EXCLUDED.expires_at,
        updated_at = now();

    -- Also update main xn_scores table
    UPDATE xn_scores SET
        factor_scores = v_breakdown->'factors',
        breakdown_cached_at = now(),
        improvement_tips_cache = v_tips,
        top_improvement_factor = (v_tips->0->>'factor')
    WHERE xn_scores.user_id = p_user_id;

    RETURN TRUE;
END;
$function$
;

CREATE OR REPLACE FUNCTION public.refresh_wave_status()
 RETURNS void
 LANGUAGE plpgsql
AS $function$
BEGIN
    INSERT INTO migration_wave_status (wave, total_screens, connected_screens, verified_screens, blocked_screens)
    SELECT
        ms.wave,
        COUNT(*)::SMALLINT,
        COUNT(*) FILTER (WHERE ms.status IN ('connected', 'verified'))::SMALLINT,
        COUNT(*) FILTER (WHERE ms.status = 'verified')::SMALLINT,
        COUNT(*) FILTER (WHERE ms.status = 'blocked')::SMALLINT
    FROM migration_screens ms
    WHERE ms.wave BETWEEN 1 AND 3
    GROUP BY ms.wave
    ON CONFLICT (wave) DO UPDATE SET
        total_screens = EXCLUDED.total_screens,
        connected_screens = EXCLUDED.connected_screens,
        verified_screens = EXCLUDED.verified_screens,
        blocked_screens = EXCLUDED.blocked_screens,
        updated_at = NOW();
END;
$function$
;

CREATE OR REPLACE FUNCTION public.refund_transaction(p_transaction_id uuid, p_reason text)
 RETURNS uuid
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
    v_transaction transactions%ROWTYPE;
    v_refund_id UUID;
BEGIN
    SELECT * INTO v_transaction FROM transactions WHERE id = p_transaction_id;

    IF v_transaction.status != 'completed' THEN
        RAISE EXCEPTION 'Can only refund completed transactions';
    END IF;

    -- Create refund transaction
    INSERT INTO transactions (user_id, type, amount, currency, status, description, reference_type, reference_id)
    VALUES (v_transaction.user_id, 'refund', v_transaction.amount, v_transaction.currency, 'completed',
            'Refund for ' || v_transaction.id, 'refund', v_transaction.id)
    RETURNING id INTO v_refund_id;

    -- Mark original as refunded
    UPDATE transactions SET status = 'refunded', updated_at = NOW() WHERE id = p_transaction_id;

    -- Credit user wallet
    UPDATE users SET wallet_balance = wallet_balance + v_transaction.amount WHERE id = v_transaction.user_id;

    INSERT INTO admin_audit_log (admin_id, action, entity_type, entity_id, details)
    VALUES (auth.uid(), 'refund_transaction', 'transaction', p_transaction_id,
            jsonb_build_object('reason', p_reason, 'amount', v_transaction.amount, 'refund_id', v_refund_id));

    RETURN v_refund_id;
END;
$function$
;

CREATE OR REPLACE FUNCTION public.register_push_token(p_token text, p_platform character varying, p_device_id text DEFAULT NULL::text, p_device_name text DEFAULT NULL::text, p_app_version text DEFAULT NULL::text, p_os_version text DEFAULT NULL::text)
 RETURNS uuid
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
    v_token_id UUID;
BEGIN
    -- Upsert push token
    INSERT INTO push_tokens (
        user_id, token, platform, device_id, device_name,
        app_version, os_version, active, last_used_at
    ) VALUES (
        auth.uid(), p_token, p_platform, p_device_id, p_device_name,
        p_app_version, p_os_version, TRUE, NOW()
    )
    ON CONFLICT (user_id, token) DO UPDATE SET
        active = TRUE,
        device_name = EXCLUDED.device_name,
        app_version = EXCLUDED.app_version,
        os_version = EXCLUDED.os_version,
        last_used_at = NOW(),
        updated_at = NOW()
    RETURNING id INTO v_token_id;

    RETURN v_token_id;
END;
$function$
;

CREATE OR REPLACE FUNCTION public.reject_kyc(p_user_id uuid, p_reason text)
 RETURNS void
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
BEGIN
    UPDATE users SET kyc_status = 'rejected', updated_at = NOW() WHERE id = p_user_id;

    INSERT INTO admin_audit_log (admin_id, action, entity_type, entity_id, details)
    VALUES (auth.uid(), 'reject_kyc', 'user', p_user_id, jsonb_build_object('reason', p_reason));
END;
$function$
;

CREATE OR REPLACE FUNCTION public.request_account_deletion(p_user_id uuid, p_reason text DEFAULT NULL::text)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
    v_user RECORD;
    v_active_circles INTEGER;
    v_active_loans INTEGER;
    v_pending_balance DECIMAL;
    v_request_id UUID;
BEGIN
    -- Get user info
    SELECT * INTO v_user FROM users WHERE id = p_user_id;

    IF v_user IS NULL THEN
        RETURN jsonb_build_object('error', 'User not found');
    END IF;

    -- Check for blockers
    -- 1. Active circles
    SELECT COUNT(*) INTO v_active_circles
    FROM group_members gm
    JOIN groups g ON g.id = gm.group_id
    WHERE gm.user_id = p_user_id
    AND gm.status = 'active'
    AND g.status = 'active';

    IF v_active_circles > 0 THEN
        RETURN jsonb_build_object(
            'error', 'Cannot delete account with active circles',
            'active_circles', v_active_circles,
            'action_required', 'Please leave all active circles first'
        );
    END IF;

    -- 2. Active loans
    SELECT COUNT(*) INTO v_active_loans
    FROM loans
    WHERE borrower_id = p_user_id
    AND status IN ('active', 'approved', 'pending');

    IF v_active_loans > 0 THEN
        RETURN jsonb_build_object(
            'error', 'Cannot delete account with outstanding loans',
            'active_loans', v_active_loans,
            'action_required', 'Please repay all loans first'
        );
    END IF;

    -- 3. Check wallet balance
    SELECT COALESCE(balance, 0) + COALESCE(pending_balance, 0) INTO v_pending_balance
    FROM wallets
    WHERE user_id = p_user_id;

    IF v_pending_balance > 0 THEN
        RETURN jsonb_build_object(
            'error', 'Cannot delete account with remaining balance',
            'balance', v_pending_balance,
            'action_required', 'Please withdraw your balance first'
        );
    END IF;

    -- Check for existing pending request
    IF EXISTS (
        SELECT 1 FROM user_deletion_requests
        WHERE user_id = p_user_id
        AND status = 'pending'
    ) THEN
        RETURN jsonb_build_object(
            'error', 'Deletion request already pending',
            'message', 'Your account deletion is already in progress'
        );
    END IF;

    -- Create deletion request
    INSERT INTO user_deletion_requests (
        user_id,
        email,
        reason,
        status,
        retention_end_date
    ) VALUES (
        p_user_id,
        v_user.email,
        p_reason,
        'pending',
        CURRENT_DATE + INTERVAL '30 days' -- 30-day retention period
    )
    RETURNING id INTO v_request_id;

    -- Send notification
    PERFORM create_notification(
        p_user_id,
        'security',
        'account',
        'Account Deletion Requested',
        'Your account deletion request has been received. Your account will be deleted after 30 days. You can cancel this request by logging in.',
        NULL,
        'high',
        NULL,
        NULL,
        NULL,
        NULL
    );

    RETURN jsonb_build_object(
        'success', true,
        'request_id', v_request_id,
        'retention_end_date', CURRENT_DATE + INTERVAL '30 days',
        'message', 'Your account will be deleted after 30 days. You can cancel this request by logging in before then.'
    );
END;
$function$
;

CREATE OR REPLACE FUNCTION public.respond_to_swap_request(p_request_id uuid, p_target_id uuid, p_accept boolean, p_reason text DEFAULT NULL::text)
 RETURNS boolean
 LANGUAGE plpgsql
 SECURITY DEFINER
AS $function$
DECLARE
    v_request position_swap_requests%ROWTYPE;
    v_config JSONB;
    v_cooling_hours INTEGER;
BEGIN
    -- Get the request
    SELECT * INTO v_request FROM position_swap_requests WHERE id = p_request_id;

    IF NOT FOUND THEN
        RAISE EXCEPTION 'Swap request not found';
    END IF;

    -- Verify caller is the target
    IF v_request.target_user_id != p_target_id THEN
        RAISE EXCEPTION 'Only the target member can respond';
    END IF;

    -- Check status
    IF v_request.swap_status != 'pending_target' THEN
        RAISE EXCEPTION 'Request is not pending target response';
    END IF;

    -- Check expiry
    IF v_request.expires_at < now() THEN
        UPDATE position_swap_requests SET swap_status = 'expired', updated_at = now() WHERE id = p_request_id;
        INSERT INTO position_swap_events (swap_request_id, event_type, actor_role, event_details)
        VALUES (p_request_id, 'swap_expired', 'system', 'Request expired before target responded');
        RAISE EXCEPTION 'Request has expired';
    END IF;

    IF p_accept THEN
        -- Get cooling off period
        v_config := get_circle_swap_config(v_request.circle_id);
        v_cooling_hours := (v_config->>'cooling_off_hours')::INTEGER;

        -- Update to pending confirmation (double-confirmation step)
        UPDATE position_swap_requests SET
            swap_status = 'pending_confirmation',
            target_accepted_at = now(),
            target_response_reason = p_reason,
            cooling_off_ends_at = now() + (v_cooling_hours || ' hours')::INTERVAL,
            updated_at = now()
        WHERE id = p_request_id;

        INSERT INTO position_swap_events (
            swap_request_id, event_type, actor_user_id, actor_role, event_details
        ) VALUES (
            p_request_id, 'target_accepted', p_target_id, 'target',
            COALESCE(p_reason, 'Accepted swap request')
        );
    ELSE
        -- Reject the swap
        UPDATE position_swap_requests SET
            swap_status = 'rejected',
            target_response_reason = p_reason,
            updated_at = now()
        WHERE id = p_request_id;

        INSERT INTO position_swap_events (
            swap_request_id, event_type, actor_user_id, actor_role, event_details
        ) VALUES (
            p_request_id, 'target_rejected', p_target_id, 'target',
            COALESCE(p_reason, 'Declined swap request')
        );
    END IF;

    RETURN true;
END;
$function$
;

CREATE OR REPLACE FUNCTION public.restore_deleted_group(p_group_id uuid, p_admin_id uuid)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
    v_group RECORD;
BEGIN
    SELECT * INTO v_group FROM groups WHERE id = p_group_id AND deleted_at IS NOT NULL;

    IF v_group IS NULL THEN
        RETURN jsonb_build_object('error', 'Deleted group not found');
    END IF;

    IF v_group.admin_id != p_admin_id THEN
        RETURN jsonb_build_object('error', 'Only group admin can restore the group');
    END IF;

    -- Restore
    UPDATE groups
    SET deleted_at = NULL, status = 'pending', updated_at = NOW()
    WHERE id = p_group_id;

    RETURN jsonb_build_object(
        'success', true,
        'group_id', p_group_id,
        'restored_at', NOW()
    );
END;
$function$
;

CREATE OR REPLACE FUNCTION public.resume_group(p_group_id uuid)
 RETURNS void
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
BEGIN
    UPDATE groups SET status = 'active', updated_at = NOW() WHERE id = p_group_id;

    INSERT INTO admin_audit_log (admin_id, action, entity_type, entity_id, details)
    VALUES (auth.uid(), 'resume_group', 'group', p_group_id, '{}'::jsonb);
END;
$function$
;

CREATE OR REPLACE FUNCTION public.retry_failed_autopay(p_config_id uuid)
 RETURNS TABLE(success boolean, payment_id uuid, amount_cents integer, message text)
 LANGUAGE plpgsql
 SECURITY DEFINER
AS $function$
DECLARE
    v_config RECORD;
    v_result RECORD;
BEGIN
    SELECT * INTO v_config FROM loan_autopay_configs WHERE id = p_config_id;
    IF NOT FOUND THEN RETURN QUERY SELECT FALSE, NULL::UUID, 0, 'Not found'; RETURN; END IF;
    IF v_config.current_retry_count >= v_config.max_retries THEN RETURN QUERY SELECT FALSE, NULL::UUID, 0, 'Max retries'; RETURN; END IF;

    UPDATE loan_autopay_configs SET status = 'active', updated_at = now() WHERE id = p_config_id;
    SELECT * INTO v_result FROM process_autopay_payment(p_config_id);

    IF v_result.success THEN RETURN QUERY SELECT TRUE, v_result.payment_id, v_result.amount_cents, 'Success';
    ELSE RETURN QUERY SELECT FALSE, NULL::UUID, 0, v_result.error_message; END IF;
END;
$function$
;

CREATE OR REPLACE FUNCTION public.run_daily_interest_accrual()
 RETURNS TABLE(loans_processed integer, total_interest_accrued_cents bigint, errors_count integer)
 LANGUAGE plpgsql
 SECURITY DEFINER
AS $function$
DECLARE
    v_loan RECORD;
    v_interest RECORD;
    v_processed INTEGER := 0;
    v_total_interest BIGINT := 0;
    v_errors INTEGER := 0;
BEGIN
    FOR v_loan IN SELECT * FROM loans WHERE status = 'active' LOOP
        BEGIN
            SELECT * INTO v_interest FROM calculate_accrued_interest(v_loan.id);
            IF v_interest.accrued_interest_cents > 0 THEN
                UPDATE loans SET
                    accrued_interest_cents = COALESCE(accrued_interest_cents, 0) + v_interest.accrued_interest_cents,
                    total_interest_accrued_cents = COALESCE(total_interest_accrued_cents, 0) + v_interest.accrued_interest_cents,
                    last_interest_accrual_date = now(), updated_at = now()
                WHERE id = v_loan.id;

                INSERT INTO loan_interest_accruals (
                    loan_id, accrual_date, period_start_date, period_end_date, days_in_period,
                    principal_balance_cents, rate_type, annual_rate, daily_rate,
                    interest_accrued_cents, cumulative_interest_cents, triggered_by
                ) VALUES (
                    v_loan.id, CURRENT_DATE, v_interest.period_start_date, v_interest.period_end_date,
                    v_interest.days_in_period, v_loan.outstanding_principal_cents,
                    v_interest.rate_type, v_interest.effective_rate, v_interest.effective_rate / 365,
                    v_interest.accrued_interest_cents,
                    COALESCE(v_loan.total_interest_accrued_cents, 0) + v_interest.accrued_interest_cents,
                    'daily_cron'::accrual_trigger
                );
                v_total_interest := v_total_interest + v_interest.accrued_interest_cents;
            END IF;
            v_processed := v_processed + 1;
        EXCEPTION WHEN OTHERS THEN
            v_errors := v_errors + 1;
        END;
    END LOOP;
    RETURN QUERY SELECT v_processed, v_total_interest, v_errors;
END;
$function$
;

CREATE OR REPLACE FUNCTION public.run_daily_payment_reminders()
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
    v_contribution_reminders INTEGER;
    v_loan_reminders INTEGER;
    v_overdue_contributions INTEGER;
    v_overdue_loans INTEGER;
BEGIN
    -- Send contribution reminders
    v_contribution_reminders := send_contribution_reminders();

    -- Send loan repayment reminders
    v_loan_reminders := send_loan_repayment_reminders();

    -- Check overdue contributions
    v_overdue_contributions := check_overdue_contributions();

    -- Check overdue loans
    v_overdue_loans := check_overdue_loans();

    RAISE NOTICE 'Daily payment check complete: % contribution reminders, % loan reminders, % overdue contributions, % overdue loans',
        v_contribution_reminders, v_loan_reminders, v_overdue_contributions, v_overdue_loans;

    RETURN jsonb_build_object(
        'contribution_reminders', v_contribution_reminders,
        'loan_reminders', v_loan_reminders,
        'overdue_contributions', v_overdue_contributions,
        'overdue_loans', v_overdue_loans,
        'run_at', NOW()
    );
END;
$function$
;

CREATE OR REPLACE FUNCTION public.run_overdue_check()
 RETURNS TABLE(payments_checked integer, late_fees_applied integer, xnscore_events integer, errors_count integer)
 LANGUAGE plpgsql
 SECURITY DEFINER
AS $function$
DECLARE
    v_payment RECORD;
    v_checked INTEGER := 0;
    v_fees_applied INTEGER := 0;
    v_xnscore_events INTEGER := 0;
    v_errors INTEGER := 0;
    v_days_past_due INTEGER;
    v_fee_result RECORD;
BEGIN
    FOR v_payment IN
        SELECT ps.*, l.user_id, l.loan_product_id
        FROM loan_payment_schedule ps
        JOIN loans l ON l.id = ps.loan_id
        WHERE ps.status IN ('scheduled', 'partial')
        AND ps.due_date < CURRENT_DATE AND l.status = 'active'
    LOOP
        BEGIN
            v_days_past_due := CURRENT_DATE - v_payment.due_date;

            IF v_days_past_due > 5 AND NOT v_payment.late_fee_applied THEN
                SELECT * INTO v_fee_result
                FROM apply_late_fee_to_loan(v_payment.loan_id, v_payment.id, v_days_past_due);
                IF v_fee_result.applied THEN v_fees_applied := v_fees_applied + 1; END IF;
            END IF;

            IF v_payment.status = 'scheduled' THEN
                UPDATE loan_payment_schedule SET status = 'late', days_overdue = v_days_past_due,
                    updated_at = now() WHERE id = v_payment.id;
            END IF;

            UPDATE loans SET days_past_due = v_days_past_due, is_delinquent = TRUE,
                delinquent_since = COALESCE(delinquent_since, v_payment.due_date), updated_at = now()
            WHERE id = v_payment.loan_id;

            v_checked := v_checked + 1;
        EXCEPTION WHEN OTHERS THEN
            v_errors := v_errors + 1;
        END;
    END LOOP;
    RETURN QUERY SELECT v_checked, v_fees_applied, v_xnscore_events, v_errors;
END;
$function$
;

CREATE OR REPLACE FUNCTION public.run_scoring_pipeline()
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
AS $function$
DECLARE
  v_run_id UUID;
  v_profiles INTEGER := 0;
  v_defaults INTEGER := 0;
  v_circles INTEGER := 0;
  v_xnscores INTEGER := 0;
  v_alerts INTEGER := 0;
  v_honor INTEGER := 0;
  v_tiers INTEGER := 0;
  v_step_timings JSONB := '{}';
  v_errors JSONB := '[]';
  v_step_start TIMESTAMPTZ;
  v_pipeline_start TIMESTAMPTZ := clock_timestamp();
BEGIN
  INSERT INTO scoring_pipeline_runs (run_date, status, started_at)
  VALUES (CURRENT_DATE, 'running', NOW())
  RETURNING id INTO v_run_id;

  -- Step 1: Recompute member profiles
  v_step_start := clock_timestamp();
  BEGIN
    SELECT compute_all_member_profiles() INTO v_profiles;
  EXCEPTION WHEN OTHERS THEN
    v_errors := v_errors || jsonb_build_object('step', 'profiles', 'error', SQLERRM);
    v_profiles := 0;
  END;
  v_step_timings := v_step_timings || jsonb_build_object(
    'profiles_ms', EXTRACT(MILLISECONDS FROM clock_timestamp() - v_step_start)::INTEGER
  );

  -- Step 2: Compute default probabilities
  v_step_start := clock_timestamp();
  BEGIN
    SELECT compute_all_default_probabilities() INTO v_defaults;
  EXCEPTION WHEN OTHERS THEN
    v_errors := v_errors || jsonb_build_object('step', 'default_probabilities', 'error', SQLERRM);
    v_defaults := 0;
  END;
  v_step_timings := v_step_timings || jsonb_build_object(
    'default_probs_ms', EXTRACT(MILLISECONDS FROM clock_timestamp() - v_step_start)::INTEGER
  );

  -- Step 3: Compute circle health scores
  v_step_start := clock_timestamp();
  BEGIN
    SELECT compute_all_circle_health_scores() INTO v_circles;
  EXCEPTION WHEN OTHERS THEN
    v_errors := v_errors || jsonb_build_object('step', 'circle_health', 'error', SQLERRM);
    v_circles := 0;
  END;
  v_step_timings := v_step_timings || jsonb_build_object(
    'circle_health_ms', EXTRACT(MILLISECONDS FROM clock_timestamp() - v_step_start)::INTEGER
  );

  -- Step 4: Recalculate XnScores
  v_step_start := clock_timestamp();
  BEGIN
    SELECT recalculate_all_xn_scores() INTO v_xnscores;
  EXCEPTION WHEN OTHERS THEN
    v_errors := v_errors || jsonb_build_object('step', 'xnscores', 'error', SQLERRM);
    v_xnscores := 0;
  END;
  v_step_timings := v_step_timings || jsonb_build_object(
    'xnscores_ms', EXTRACT(MILLISECONDS FROM clock_timestamp() - v_step_start)::INTEGER
  );

  -- Step 5: Evaluate alerts
  v_step_start := clock_timestamp();
  BEGIN
    SELECT evaluate_score_alerts() INTO v_alerts;
  EXCEPTION WHEN OTHERS THEN
    v_errors := v_errors || jsonb_build_object('step', 'alerts', 'error', SQLERRM);
    v_alerts := 0;
  END;
  v_step_timings := v_step_timings || jsonb_build_object(
    'alerts_ms', EXTRACT(MILLISECONDS FROM clock_timestamp() - v_step_start)::INTEGER
  );

  -- Step 6: Compute Honor Scores [migration 037]
  v_step_start := clock_timestamp();
  BEGIN
    SELECT compute_all_honor_scores() INTO v_honor;
  EXCEPTION WHEN OTHERS THEN
    v_errors := v_errors || jsonb_build_object('step', 'honor_scores', 'error', SQLERRM);
    v_honor := 0;
  END;
  v_step_timings := v_step_timings || jsonb_build_object(
    'honor_scores_ms', EXTRACT(MILLISECONDS FROM clock_timestamp() - v_step_start)::INTEGER
  );

  -- Step 7: Evaluate Graduated Entry Tiers [NEW - migration 040]
  v_step_start := clock_timestamp();
  BEGIN
    SELECT evaluate_all_member_tiers() INTO v_tiers;
  EXCEPTION WHEN OTHERS THEN
    v_errors := v_errors || jsonb_build_object('step', 'tiers', 'error', SQLERRM);
    v_tiers := 0;
  END;
  v_step_timings := v_step_timings || jsonb_build_object(
    'tiers_ms', EXTRACT(MILLISECONDS FROM clock_timestamp() - v_step_start)::INTEGER
  );

  -- Finalize pipeline run
  UPDATE scoring_pipeline_runs SET
    profiles_computed = v_profiles,
    default_probs_computed = v_defaults,
    circle_scores_computed = v_circles,
    xnscores_recalculated = v_xnscores,
    alerts_generated = v_alerts,
    honor_scores_computed = v_honor,
    tiers_evaluated = v_tiers,
    step_timings = v_step_timings,
    total_duration_ms = EXTRACT(MILLISECONDS FROM clock_timestamp() - v_pipeline_start)::INTEGER,
    status = CASE
      WHEN v_errors = '[]'::JSONB THEN 'completed'
      WHEN v_profiles + v_defaults + v_circles + v_xnscores + v_honor + v_tiers > 0 THEN 'partial'
      ELSE 'failed'
    END,
    errors = v_errors,
    completed_at = NOW()
  WHERE id = v_run_id;

  RETURN jsonb_build_object(
    'run_id', v_run_id,
    'profiles', v_profiles,
    'default_probs', v_defaults,
    'circles', v_circles,
    'xnscores', v_xnscores,
    'alerts', v_alerts,
    'honor_scores', v_honor,
    'tiers', v_tiers,
    'duration_ms', EXTRACT(MILLISECONDS FROM clock_timestamp() - v_pipeline_start)::INTEGER,
    'errors', v_errors
  );
END;
$function$
;

CREATE OR REPLACE FUNCTION public.schedule_payment_reminders(p_obligation_id uuid)
 RETURNS integer
 LANGUAGE plpgsql
 SECURITY DEFINER
AS $function$
DECLARE
    v_obligation RECORD;
    v_loan RECORD;
    v_reminder_day INTEGER;
    v_channel reminder_channel;
    v_reminder_type reminder_type;
    v_scheduled_time TIMESTAMPTZ;
    v_title TEXT;
    v_message TEXT;
    v_count INTEGER := 0;
BEGIN
    SELECT * INTO v_obligation FROM loan_payment_obligations WHERE id = p_obligation_id;
    IF NOT FOUND THEN RETURN 0; END IF;

    SELECT * INTO v_loan FROM loans WHERE id = v_obligation.loan_id;
    IF NOT COALESCE(v_loan.reminders_enabled, TRUE) THEN RETURN 0; END IF;

    FOREACH v_reminder_day IN ARRAY COALESCE(v_loan.reminder_days_before, ARRAY[7, 3, 1])
    LOOP
        v_reminder_type := CASE
            WHEN v_reminder_day >= 7 THEN 'upcoming'::reminder_type
            WHEN v_reminder_day >= 3 THEN 'due_soon'::reminder_type
            WHEN v_reminder_day = 1 THEN 'due_tomorrow'::reminder_type
            ELSE 'due_today'::reminder_type
        END;

        v_scheduled_time := (v_obligation.due_date - v_reminder_day)::TIMESTAMPTZ + INTERVAL '9 hours';
        IF v_scheduled_time < now() THEN CONTINUE; END IF;

        v_title := format('Payment Due %s', CASE WHEN v_reminder_day = 0 THEN 'Today' WHEN v_reminder_day = 1 THEN 'Tomorrow' ELSE format('in %s days', v_reminder_day) END);
        v_message := format('Your payment of $%s is due on %s.', (v_obligation.total_due_cents / 100.0)::NUMERIC(10,2), to_char(v_obligation.due_date, 'Mon DD, YYYY'));

        FOREACH v_channel IN ARRAY COALESCE(v_loan.reminder_channels, ARRAY['push'::reminder_channel])
        LOOP
            INSERT INTO loan_payment_reminders (loan_id, user_id, obligation_id, reminder_type, channel, scheduled_for, days_before_due, title, message, amount_due_cents, due_date, status)
            VALUES (v_obligation.loan_id, v_obligation.user_id, p_obligation_id, v_reminder_type, v_channel, v_scheduled_time, v_reminder_day, v_title, v_message, v_obligation.total_due_cents, v_obligation.due_date, 'scheduled');
            v_count := v_count + 1;
        END LOOP;
    END LOOP;
    RETURN v_count;
END;
$function$
;

CREATE OR REPLACE FUNCTION public.send_contribution_reminders()
 RETURNS integer
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
    v_sent INTEGER := 0;
    v_member RECORD;
    v_days_before INTEGER;
    v_group RECORD;
BEGIN
    -- Get members with upcoming contributions (7 days and 1 day before)
    FOR v_member IN
        SELECT
            gm.user_id,
            gm.group_id,
            g.name AS group_name,
            g.contribution_amount,
            g.contribution_frequency,
            g.next_payout_date,
            u.full_name,
            EXTRACT(DAY FROM (g.next_payout_date - CURRENT_DATE)) AS days_until_due
        FROM group_members gm
        JOIN groups g ON g.id = gm.group_id
        JOIN users u ON u.id = gm.user_id
        WHERE g.status = 'active'
        AND gm.status = 'active'
        AND g.next_payout_date IS NOT NULL
        AND g.next_payout_date > CURRENT_DATE
        AND EXTRACT(DAY FROM (g.next_payout_date - CURRENT_DATE)) IN (1, 7)
        -- Don't send reminder if already contributed for this cycle
        AND NOT EXISTS (
            SELECT 1 FROM contributions c
            WHERE c.group_id = gm.group_id
            AND c.user_id = gm.user_id
            AND c.cycle_number = g.current_cycle
            AND c.status = 'completed'
        )
    LOOP
        v_days_before := v_member.days_until_due;

        -- Create notification
        INSERT INTO notifications (
            user_id,
            type,
            category,
            priority,
            title,
            body,
            data,
            related_entity_type,
            related_entity_id,
            action_url
        ) VALUES (
            v_member.user_id,
            'circle',
            'reminder',
            CASE WHEN v_days_before = 1 THEN 'high' ELSE 'normal' END,
            CASE
                WHEN v_days_before = 1 THEN 'Contribution Due Tomorrow!'
                ELSE 'Contribution Reminder'
            END,
            CASE
                WHEN v_days_before = 1 THEN
                    'Your contribution of $' || v_member.contribution_amount || ' for ' || v_member.group_name || ' is due tomorrow.'
                ELSE
                    'Your contribution of $' || v_member.contribution_amount || ' for ' || v_member.group_name || ' is due in 7 days.'
            END,
            jsonb_build_object(
                'group_id', v_member.group_id,
                'group_name', v_member.group_name,
                'amount', v_member.contribution_amount,
                'due_date', v_member.next_payout_date,
                'days_until_due', v_days_before
            ),
            'circle',
            v_member.group_id::TEXT,
            '/circles/' || v_member.group_id
        );

        -- Add to notification queue for push notification
        INSERT INTO notification_queue (
            notification_id,
            user_id,
            channel,
            payload,
            priority
        )
        SELECT
            currval('notifications_id_seq'),
            v_member.user_id,
            'push',
            jsonb_build_object(
                'title', CASE WHEN v_days_before = 1 THEN 'Contribution Due Tomorrow!' ELSE 'Contribution Reminder' END,
                'body', 'Your contribution of $' || v_member.contribution_amount || ' for ' || v_member.group_name || ' is due' ||
                        CASE WHEN v_days_before = 1 THEN ' tomorrow.' ELSE ' in 7 days.' END,
                'data', jsonb_build_object('circleId', v_member.group_id)
            ),
            CASE WHEN v_days_before = 1 THEN 'high' ELSE 'normal' END;

        v_sent := v_sent + 1;
    END LOOP;

    RAISE NOTICE 'Sent % contribution reminders', v_sent;
    RETURN v_sent;
END;
$function$
;

CREATE OR REPLACE FUNCTION public.send_due_reminders()
 RETURNS TABLE(reminders_processed integer, reminders_marked integer, errors_count integer)
 LANGUAGE plpgsql
 SECURITY DEFINER
AS $function$
DECLARE
    v_reminder RECORD;
    v_proc INTEGER := 0;
    v_marked INTEGER := 0;
    v_errors INTEGER := 0;
BEGIN
    FOR v_reminder IN
        SELECT r.*, o.status as ostatus FROM loan_payment_reminders r
        LEFT JOIN loan_payment_obligations o ON o.id = r.obligation_id
        WHERE r.status = 'scheduled' AND r.scheduled_for <= now() LIMIT 100
    LOOP
        BEGIN
            IF v_reminder.ostatus = 'paid' THEN
                UPDATE loan_payment_reminders SET status = 'cancelled', updated_at = now() WHERE id = v_reminder.id;
            ELSE
                UPDATE loan_payment_reminders SET status = 'sent', sent_at = now(), updated_at = now() WHERE id = v_reminder.id;
                v_marked := v_marked + 1;
            END IF;
            v_proc := v_proc + 1;
        EXCEPTION WHEN OTHERS THEN v_errors := v_errors + 1;
        END;
    END LOOP;
    RETURN QUERY SELECT v_proc, v_marked, v_errors;
END;
$function$
;

CREATE OR REPLACE FUNCTION public.send_loan_repayment_reminders()
 RETURNS integer
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
    v_sent INTEGER := 0;
    v_loan RECORD;
    v_days_before INTEGER;
    v_next_due DATE;
BEGIN
    -- Get active loans with upcoming repayment dates
    FOR v_loan IN
        SELECT
            l.id AS loan_id,
            l.borrower_id,
            l.amount,
            l.amount_due,
            l.monthly_payment,
            l.next_payment_date,
            l.group_id,
            g.name AS group_name,
            u.full_name,
            EXTRACT(DAY FROM (l.next_payment_date - CURRENT_DATE)) AS days_until_due
        FROM loans l
        JOIN groups g ON g.id = l.group_id
        JOIN users u ON u.id = l.borrower_id
        WHERE l.status = 'active'
        AND l.next_payment_date IS NOT NULL
        AND l.next_payment_date > CURRENT_DATE
        AND EXTRACT(DAY FROM (l.next_payment_date - CURRENT_DATE)) IN (1, 3, 7)
    LOOP
        v_days_before := v_loan.days_until_due;

        -- Create notification
        INSERT INTO notifications (
            user_id,
            type,
            category,
            priority,
            title,
            body,
            data,
            related_entity_type,
            related_entity_id,
            action_url
        ) VALUES (
            v_loan.borrower_id,
            'loan',
            'reminder',
            CASE
                WHEN v_days_before = 1 THEN 'urgent'
                WHEN v_days_before = 3 THEN 'high'
                ELSE 'normal'
            END,
            CASE
                WHEN v_days_before = 1 THEN 'Loan Payment Due Tomorrow!'
                WHEN v_days_before = 3 THEN 'Loan Payment Due in 3 Days'
                ELSE 'Loan Payment Reminder'
            END,
            'Your loan payment of $' || v_loan.monthly_payment || ' is due ' ||
            CASE
                WHEN v_days_before = 1 THEN 'tomorrow'
                WHEN v_days_before = 3 THEN 'in 3 days'
                ELSE 'in 7 days'
            END || '. Remaining balance: $' || v_loan.amount_due,
            jsonb_build_object(
                'loan_id', v_loan.loan_id,
                'group_id', v_loan.group_id,
                'group_name', v_loan.group_name,
                'monthly_payment', v_loan.monthly_payment,
                'amount_due', v_loan.amount_due,
                'due_date', v_loan.next_payment_date,
                'days_until_due', v_days_before
            ),
            'loan',
            v_loan.loan_id::TEXT,
            '/loans/' || v_loan.loan_id
        );

        -- Add to notification queue for push notification
        INSERT INTO notification_queue (
            notification_id,
            user_id,
            channel,
            payload,
            priority
        )
        SELECT
            currval('notifications_id_seq'),
            v_loan.borrower_id,
            'push',
            jsonb_build_object(
                'title', CASE
                    WHEN v_days_before = 1 THEN 'Loan Payment Due Tomorrow!'
                    WHEN v_days_before = 3 THEN 'Loan Payment Due in 3 Days'
                    ELSE 'Loan Payment Reminder'
                END,
                'body', 'Your loan payment of $' || v_loan.monthly_payment || ' is due ' ||
                    CASE
                        WHEN v_days_before = 1 THEN 'tomorrow'
                        WHEN v_days_before = 3 THEN 'in 3 days'
                        ELSE 'in 7 days'
                    END,
                'data', jsonb_build_object('loanId', v_loan.loan_id)
            ),
            CASE
                WHEN v_days_before = 1 THEN 'urgent'
                WHEN v_days_before = 3 THEN 'high'
                ELSE 'normal'
            END;

        v_sent := v_sent + 1;
    END LOOP;

    RAISE NOTICE 'Sent % loan repayment reminders', v_sent;
    RETURN v_sent;
END;
$function$
;

