CREATE OR REPLACE FUNCTION public.soft_delete_group(p_group_id uuid, p_admin_id uuid)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
    v_group RECORD;
BEGIN
    SELECT * INTO v_group FROM groups WHERE id = p_group_id;

    IF v_group IS NULL THEN
        RETURN jsonb_build_object('error', 'Group not found');
    END IF;

    IF v_group.admin_id != p_admin_id THEN
        RETURN jsonb_build_object('error', 'Only group admin can delete the group');
    END IF;

    IF v_group.status = 'active' THEN
        RETURN jsonb_build_object(
            'error', 'Cannot delete active group',
            'action_required', 'Please complete or cancel the group first'
        );
    END IF;

    -- Soft delete
    UPDATE groups
    SET deleted_at = NOW(), status = 'deleted', updated_at = NOW()
    WHERE id = p_group_id;

    RETURN jsonb_build_object(
        'success', true,
        'group_id', p_group_id,
        'deleted_at', NOW()
    );
END;
$function$
;

CREATE OR REPLACE FUNCTION public.start_recovery_period(p_user_id uuid, p_trigger text, p_trigger_id uuid DEFAULT NULL::uuid)
 RETURNS uuid
 LANGUAGE plpgsql
AS $function$
DECLARE
    v_score RECORD;
    v_trigger_type recovery_trigger_type;
    v_recovery_id UUID;
    v_recovery_days INTEGER := 90; -- 90 day recovery period
    v_multiplier DECIMAL := 1.50; -- 1.5x multiplier
BEGIN
    SELECT * INTO v_score FROM xn_scores WHERE user_id = p_user_id;

    IF NOT FOUND THEN
        RETURN NULL;
    END IF;

    -- Don't start if already in recovery
    IF v_score.in_recovery_period AND v_score.recovery_ends_at > now() THEN
        RETURN v_score.recovery_period_id;
    END IF;

    -- Must have had significant decay to qualify
    IF COALESCE(v_score.total_inactivity_penalty, 0) < 10 THEN
        RETURN NULL;
    END IF;

    -- Map trigger to enum
    v_trigger_type := CASE
        WHEN p_trigger LIKE '%contribution%' THEN 'first_contribution_after_inactivity'::recovery_trigger_type
        WHEN p_trigger LIKE '%payout%' THEN 'first_payout_received'::recovery_trigger_type
        WHEN p_trigger LIKE '%debt%' OR p_trigger LIKE '%repaid%' THEN 'debt_fully_repaid'::recovery_trigger_type
        WHEN p_trigger LIKE '%suspension%' THEN 'suspension_lifted'::recovery_trigger_type
        ELSE 'manual_recovery_granted'::recovery_trigger_type
    END;

    -- Create recovery period
    INSERT INTO xnscore_recovery_periods (
        user_id, trigger_type, trigger_event_id,
        ends_at, recovery_multiplier,
        score_at_start, decay_total_before_recovery
    ) VALUES (
        p_user_id, v_trigger_type, p_trigger_id,
        now() + (v_recovery_days || ' days')::INTERVAL, v_multiplier,
        v_score.total_score, v_score.total_inactivity_penalty
    )
    RETURNING id INTO v_recovery_id;

    -- Update xn_scores
    UPDATE xn_scores SET
        in_recovery_period = TRUE,
        recovery_period_id = v_recovery_id,
        recovery_ends_at = now() + (v_recovery_days || ' days')::INTERVAL,
        recovery_multiplier = v_multiplier,
        -- Reset inactivity tracking
        financial_inactive_days = 0,
        total_inactivity_penalty = 0,
        decay_floor_reached = FALSE,
        updated_at = now()
    WHERE xn_scores.user_id = p_user_id;

    -- Log to history
    INSERT INTO xnscore_history (
        user_id, score, previous_score, score_change,
        trigger_event, trigger_id, trigger_details
    ) VALUES (
        p_user_id, v_score.total_score, v_score.total_score, 0,
        'recovery_period_started', v_recovery_id,
        format('90-day recovery period started. 1.5x bonus multiplier active until %s',
            (now() + (v_recovery_days || ' days')::INTERVAL)::DATE)
    );

    RETURN v_recovery_id;
END;
$function$
;

CREATE OR REPLACE FUNCTION public.suspend_user(p_user_id uuid, p_reason text)
 RETURNS void
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
BEGIN
    UPDATE users
    SET is_suspended = true,
        updated_at = NOW()
    WHERE id = p_user_id;

    -- Log the action
    INSERT INTO admin_audit_log (admin_id, action, entity_type, entity_id, details)
    VALUES (auth.uid(), 'suspend_user', 'user', p_user_id, jsonb_build_object('reason', p_reason));
END;
$function$
;

CREATE OR REPLACE FUNCTION public.sync_contribution_on_payment_success()
 RETURNS trigger
 LANGUAGE plpgsql
 SECURITY DEFINER
AS $function$
DECLARE
    v_amount_dollars NUMERIC;
BEGIN
    -- Only fire when status changes to 'succeeded'
    IF NEW.status != 'succeeded' OR OLD.status = 'succeeded' THEN
        RETURN NEW;
    END IF;

    -- Convert cents to dollars for legacy tables that use DECIMAL
    v_amount_dollars := NEW.amount_cents / 100.0;

    -- 1. Mark contribution as paid if this is a circle contribution
    IF NEW.circle_id IS NOT NULL AND NEW.purpose = 'contribution' THEN
        UPDATE contributions
        SET status = 'paid',
            payment_method = 'stripe',
            transaction_id = NEW.stripe_payment_intent_id
        WHERE id = (
            SELECT id FROM contributions
            WHERE circle_id = NEW.circle_id
              AND user_id = NEW.member_id
              AND status IN ('pending', 'due', 'late')
            ORDER BY created_at ASC
            LIMIT 1
        );
    END IF;

    -- 2. Credit wallet if this is a wallet deposit
    IF NEW.purpose = 'wallet_deposit' THEN
        UPDATE wallets
        SET balance = balance + v_amount_dollars,
            updated_at = NOW()
        WHERE user_id = NEW.member_id;

        -- Create wallet if it doesn't exist
        IF NOT FOUND THEN
            INSERT INTO wallets (user_id, balance, currency, created_at, updated_at)
            VALUES (NEW.member_id, v_amount_dollars, UPPER(NEW.currency), NOW(), NOW());
        END IF;
    END IF;

    RETURN NEW;
END;
$function$
;

CREATE OR REPLACE FUNCTION public.sync_kyc_tier_to_profile()
 RETURNS trigger
 LANGUAGE plpgsql
 SECURITY DEFINER
AS $function$
BEGIN
    IF NEW.status = 'approved' AND (OLD.status IS DISTINCT FROM 'approved') THEN
        UPDATE profiles
        SET kyc_tier = NEW.kyc_tier,
            kyc_verified_at = NOW()
        WHERE id = NEW.member_id;
    END IF;
    RETURN NEW;
END;
$function$
;

CREATE OR REPLACE FUNCTION public.sync_xnscore_to_profile()
 RETURNS trigger
 LANGUAGE plpgsql
AS $function$
BEGIN
    UPDATE profiles SET xn_score = NEW.total_score::INTEGER WHERE id = NEW.user_id;
    RETURN NEW;
END;
$function$
;

CREATE OR REPLACE FUNCTION public.tally_proposal(p_proposal_id uuid)
 RETURNS text
 LANGUAGE plpgsql
 SECURITY DEFINER
AS $function$
DECLARE
  v_proposal RECORD;
  v_total_votes INTEGER;
  v_quorum_needed INTEGER;
  v_result TEXT;
  v_reason TEXT;
  v_weight_ratio DECIMAL;
BEGIN
  SELECT * INTO v_proposal FROM circle_proposals WHERE id = p_proposal_id;
  IF v_proposal IS NULL THEN
    RAISE EXCEPTION 'Proposal not found: %', p_proposal_id;
  END IF;
  IF v_proposal.status = 'closed' THEN
    RETURN v_proposal.result;
  END IF;

  v_total_votes := v_proposal.votes_for + v_proposal.votes_against + v_proposal.votes_abstain;
  v_quorum_needed := CEIL(v_proposal.eligible_voters * v_proposal.quorum_pct);

  IF v_total_votes < v_quorum_needed THEN
    v_result := 'no_quorum';
    v_reason := format('Quorum not met: %s of %s required votes (%s eligible)',
      v_total_votes, v_quorum_needed, v_proposal.eligible_voters);
  ELSE
    IF v_proposal.total_vote_weight > 0 THEN
      IF (v_proposal.weight_for + v_proposal.weight_against) > 0 THEN
        v_weight_ratio := v_proposal.weight_for / (v_proposal.weight_for + v_proposal.weight_against);
      ELSE
        v_weight_ratio := 0;
      END IF;
    ELSE
      IF (v_proposal.votes_for + v_proposal.votes_against) > 0 THEN
        v_weight_ratio := v_proposal.votes_for::DECIMAL / (v_proposal.votes_for + v_proposal.votes_against);
      ELSE
        v_weight_ratio := 0;
      END IF;
    END IF;

    IF v_weight_ratio >= v_proposal.threshold_pct THEN
      v_result := 'approved';
      v_reason := format('Approved: %.0f%% in favor (%s needed)',
        v_weight_ratio * 100, v_proposal.threshold_pct * 100);
    ELSE
      v_result := 'rejected';
      v_reason := format('Rejected: %.0f%% in favor (%s%% needed)',
        v_weight_ratio * 100, v_proposal.threshold_pct * 100);
    END IF;
  END IF;

  UPDATE circle_proposals SET
    status = 'closed',
    result = v_result,
    result_reason = v_reason,
    closed_at = NOW(),
    updated_at = NOW()
  WHERE id = p_proposal_id;

  RETURN v_result;
END;
$function$
;

CREATE OR REPLACE FUNCTION public.track_referral(p_referral_code text, p_referred_user_id uuid)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
    v_referral RECORD;
    v_referrer RECORD;
    v_referred RECORD;
BEGIN
    -- Find referral by code
    SELECT * INTO v_referral
    FROM referrals
    WHERE referral_code = UPPER(p_referral_code)
    AND status = 'pending'
    AND expires_at > NOW();

    IF v_referral IS NULL THEN
        RETURN jsonb_build_object(
            'error', 'Invalid or expired referral code',
            'code', 'INVALID_REFERRAL'
        );
    END IF;

    -- Prevent self-referral
    IF v_referral.referrer_id = p_referred_user_id THEN
        RETURN jsonb_build_object('error', 'Cannot use your own referral code', 'code', 'SELF_REFERRAL');
    END IF;

    -- Get referrer and referred user info
    SELECT * INTO v_referrer FROM users WHERE id = v_referral.referrer_id;
    SELECT * INTO v_referred FROM users WHERE id = p_referred_user_id;

    -- Update referral record
    UPDATE referrals
    SET
        referred_id = p_referred_user_id,
        status = 'signed_up',
        signed_up_at = NOW(),
        updated_at = NOW()
    WHERE id = v_referral.id;

    -- Notify referrer
    PERFORM create_notification(
        v_referral.referrer_id,
        'promo',
        'referral',
        'New Referral Sign-up! 🎉',
        COALESCE(v_referred.full_name, 'Someone') || ' signed up using your referral code! You''ll earn $' || v_referral.reward_amount || ' when they complete their first circle.',
        jsonb_build_object(
            'referral_id', v_referral.id,
            'referred_user', v_referred.full_name,
            'reward_amount', v_referral.reward_amount
        ),
        'normal',
        NULL,
        'referral',
        v_referral.id::TEXT,
        '/referrals'
    );

    RETURN jsonb_build_object(
        'success', true,
        'referral_id', v_referral.id,
        'referrer_name', v_referrer.full_name,
        'status', 'signed_up',
        'message', 'Referral tracked successfully'
    );
END;
$function$
;

