CREATE OR REPLACE FUNCTION public.trg_stress_score_status()
 RETURNS trigger
 LANGUAGE plpgsql
AS $function$
BEGIN
  NEW.status := CASE
    WHEN NEW.stress_score <= 30 THEN 'green'
    WHEN NEW.stress_score <= 60 THEN 'yellow'
    WHEN NEW.stress_score <= 80 THEN 'orange'
    ELSE 'red'
  END;

  -- Auto-trigger intervention for Orange and Red
  IF NEW.stress_score > 60 THEN
    NEW.intervention_triggered := true;
    IF NEW.stress_score <= 80 THEN
      NEW.intervention_type := 'payment_restructure';
    ELSE
      NEW.intervention_type := 'counselor_referral';
    END IF;
  END IF;

  RETURN NEW;
END;
$function$
;

CREATE OR REPLACE FUNCTION public.trigger_contribution_activity()
 RETURNS trigger
 LANGUAGE plpgsql
AS $function$
BEGIN
    -- Track when contribution is completed or late (both mean paid)
    IF NEW.status IN ('completed', 'late') AND (OLD IS NULL OR OLD.status NOT IN ('completed', 'late')) THEN
        PERFORM update_financial_activity(NEW.user_id, 'contribution', NEW.id);
    END IF;
    RETURN NEW;
END;
$function$
;

CREATE OR REPLACE FUNCTION public.trigger_payout_activity()
 RETURNS trigger
 LANGUAGE plpgsql
AS $function$
BEGIN
    IF NEW.execution_status = 'completed' AND (OLD IS NULL OR OLD.execution_status != 'completed') THEN
        PERFORM update_financial_activity(NEW.recipient_user_id, 'payout', NEW.id);
    END IF;
    RETURN NEW;
END;
$function$
;

CREATE OR REPLACE FUNCTION public.trigger_wallet_deposit_activity()
 RETURNS trigger
 LANGUAGE plpgsql
AS $function$
BEGIN
    IF NEW.transaction_type IN ('deposit', 'incoming_transfer')
       AND NEW.transaction_status = 'completed'
       AND (OLD IS NULL OR OLD.transaction_status != 'completed') THEN
        PERFORM update_financial_activity(NEW.user_id, 'wallet_deposit', NEW.id);
    END IF;
    RETURN NEW;
END;
$function$
;

CREATE OR REPLACE FUNCTION public.update_autopay_config(p_loan_id uuid, p_enabled boolean, p_method_id uuid DEFAULT NULL::uuid, p_type text DEFAULT 'scheduled'::text, p_fixed integer DEFAULT NULL::integer)
 RETURNS TABLE(config_id uuid, enabled boolean, autopay_type autopay_type, next_scheduled_at timestamp with time zone, message text)
 LANGUAGE plpgsql
 SECURITY DEFINER
AS $function$
DECLARE
    v_loan RECORD;
    v_config RECORD;
    v_config_id UUID;
    v_next TIMESTAMPTZ;
BEGIN
    SELECT * INTO v_loan FROM loans WHERE id = p_loan_id;
    IF NOT FOUND THEN RAISE EXCEPTION 'Loan not found'; END IF;

    SELECT * INTO v_config FROM loan_autopay_configs WHERE loan_id = p_loan_id;

    SELECT (o.due_date::TIMESTAMPTZ + INTERVAL '9 hours') INTO v_next FROM loan_payment_obligations o
    WHERE o.loan_id = p_loan_id AND o.status IN ('upcoming', 'due') ORDER BY o.due_date ASC LIMIT 1;

    IF p_enabled THEN
        IF v_config IS NULL THEN
            INSERT INTO loan_autopay_configs (loan_id, user_id, autopay_type, payment_method_id, fixed_amount_cents, status, next_scheduled_at)
            VALUES (p_loan_id, v_loan.user_id, p_type::autopay_type, p_method_id, p_fixed, 'active', v_next)
            RETURNING id INTO v_config_id;
        ELSE
            UPDATE loan_autopay_configs SET autopay_type = p_type::autopay_type, payment_method_id = COALESCE(p_method_id, payment_method_id),
                fixed_amount_cents = COALESCE(p_fixed, fixed_amount_cents), status = 'active', next_scheduled_at = v_next, updated_at = now()
            WHERE loan_id = p_loan_id RETURNING id INTO v_config_id;
        END IF;
        UPDATE loans SET autopay_enabled = TRUE, autopay_config_id = v_config_id, autopay_next_scheduled_at = v_next, updated_at = now() WHERE id = p_loan_id;
        RETURN QUERY SELECT v_config_id, TRUE, p_type::autopay_type, v_next, 'Enabled';
    ELSE
        IF v_config IS NOT NULL THEN
            UPDATE loan_autopay_configs SET status = 'disabled', next_scheduled_at = NULL, updated_at = now() WHERE loan_id = p_loan_id;
        END IF;
        UPDATE loans SET autopay_enabled = FALSE, autopay_next_scheduled_at = NULL, updated_at = now() WHERE id = p_loan_id;
        RETURN QUERY SELECT v_config.id, FALSE, v_config.autopay_type, NULL::TIMESTAMPTZ, 'Disabled';
    END IF;
END;
$function$
;

