CREATE OR REPLACE FUNCTION public.update_cycle_totals()
 RETURNS trigger
 LANGUAGE plpgsql
AS $function$
BEGIN
    UPDATE circle_cycles SET
        collected_amount = (SELECT COALESCE(SUM(contributed_amount),0) FROM cycle_contributions WHERE cycle_id=NEW.cycle_id AND contribution_status IN ('completed','covered')),
        received_contributions = (SELECT COUNT(*) FROM cycle_contributions WHERE cycle_id=NEW.cycle_id AND contribution_status IN ('completed','covered')),
        late_fees_collected = (SELECT COALESCE(SUM(late_fee_amount),0) FROM cycle_contributions WHERE cycle_id=NEW.cycle_id AND late_fee_paid=true),
        updated_at = NOW()
    WHERE id = NEW.cycle_id;
    RETURN NEW;
END; $function$
;

