CREATE OR REPLACE FUNCTION public.update_notification_queue_status(p_queue_id uuid, p_status character varying, p_error text DEFAULT NULL::text)
 RETURNS void
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
BEGIN
    UPDATE notification_queue
    SET
        status = p_status,
        attempts = attempts + 1,
        last_attempt_at = NOW(),
        last_error = p_error,
        next_attempt_at = CASE
            WHEN p_status = 'failed' THEN NOW() + (INTERVAL '1 minute' * POWER(2, attempts))
            ELSE next_attempt_at
        END,
        processed_at = CASE WHEN p_status = 'sent' THEN NOW() ELSE processed_at END
    WHERE id = p_queue_id;

    -- Update notification delivery status
    IF p_status = 'sent' THEN
        UPDATE notifications n
        SET
            push_sent = CASE WHEN (SELECT channel FROM notification_queue WHERE id = p_queue_id) = 'push' THEN TRUE ELSE push_sent END,
            push_sent_at = CASE WHEN (SELECT channel FROM notification_queue WHERE id = p_queue_id) = 'push' THEN NOW() ELSE push_sent_at END,
            email_sent = CASE WHEN (SELECT channel FROM notification_queue WHERE id = p_queue_id) = 'email' THEN TRUE ELSE email_sent END,
            email_sent_at = CASE WHEN (SELECT channel FROM notification_queue WHERE id = p_queue_id) = 'email' THEN NOW() ELSE email_sent_at END,
            updated_at = NOW()
        WHERE n.id = (SELECT notification_id FROM notification_queue WHERE id = p_queue_id);
    END IF;
END;
$function$
;

