CREATE OR REPLACE FUNCTION public.update_xnscore_for_event(p_user_id uuid, p_event_type text, p_entity_id uuid DEFAULT NULL::uuid)
 RETURNS void
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
    v_score_change DECIMAL(4,2);
    v_current_score DECIMAL(5,2);
    v_new_score DECIMAL(5,2);
BEGIN
    -- Get current score
    SELECT COALESCE(xn_score, 30) INTO v_current_score  -- Default starting score is 30
    FROM users
    WHERE id = p_user_id;

    IF v_current_score IS NULL THEN
        v_current_score := 30; -- Default starting score for new users
    END IF;

    -- Determine score change based on event type
    -- These values are calibrated for the 0-100 scale
    -- Payment History factor (35 pts max) - most impactful
    -- On-time rate contributes up to 20 pts, streak up to 10 pts, no defaults 5 pts
    CASE p_event_type
        WHEN 'on_time_contribution' THEN
            v_score_change := 0.5;  -- Small increment per on-time payment
        WHEN 'early_contribution' THEN
            v_score_change := 0.75; -- Slightly better than on-time
        WHEN 'missed_contribution' THEN
            v_score_change := -3;   -- Significant penalty, resets streak
        WHEN 'late_contribution' THEN
            v_score_change := -1;   -- Moderate penalty
        WHEN 'on_time_loan_payment' THEN
            v_score_change := 0.5;  -- Same as contribution
        WHEN 'early_loan_payment' THEN
            v_score_change := 1;    -- Reward early repayment
        WHEN 'missed_loan_payment' THEN
            v_score_change := -4;   -- Worse than missed contribution
        WHEN 'late_loan_payment' THEN
            v_score_change := -1.5; -- Moderate penalty
        WHEN 'loan_default' THEN
            v_score_change := -5;   -- Permanent scar (as per FAQ: defaults are permanent -5)
        WHEN 'completed_cycle' THEN
            v_score_change := 2;    -- Circle completion bonus (contributes to 25 pt factor)
        WHEN 'first_circle_completed' THEN
            v_score_change := 5;    -- One-time +5 first circle bonus
        WHEN 'early_exit' THEN
            v_score_change := -3;   -- Early exits cost 3 points (as per tip)
        WHEN 'group_creation' THEN
            v_score_change := 0.5;  -- Minor positive for engagement
        WHEN 'referral_success' THEN
            v_score_change := 1;    -- Social validation bonus
        WHEN 'voucher_received' THEN
            v_score_change := 1;    -- +1 per voucher (max 2 pts from vouchers)
        WHEN 'security_deposit_locked' THEN
            v_score_change := 0;    -- Handled separately based on deposit amount
        WHEN 'streak_milestone' THEN
            v_score_change := 2;    -- Payment streak bonus (e.g., 20 consecutive)
        ELSE
            v_score_change := 0;
    END CASE;

    -- Calculate new score (bounded between 0 and 100)
    v_new_score := GREATEST(0, LEAST(100, v_current_score + v_score_change));

    -- Only update if there's an actual change
    IF v_score_change != 0 THEN
        -- Update user score
        UPDATE users
        SET
            xn_score = v_new_score,
            updated_at = NOW()
        WHERE id = p_user_id;

        -- Log score change
        INSERT INTO xn_score_history (
            user_id,
            previous_score,
            new_score,
            change_amount,
            change_reason,
            related_entity_type,
            related_entity_id
        ) VALUES (
            p_user_id,
            v_current_score,
            v_new_score,
            v_score_change,
            p_event_type,
            CASE
                WHEN p_event_type LIKE '%contribution%' THEN 'contribution'
                WHEN p_event_type LIKE '%loan%' THEN 'loan'
                WHEN p_event_type LIKE '%group%' OR p_event_type LIKE '%cycle%' THEN 'group'
                ELSE 'system'
            END,
            p_entity_id
        );
    END IF;
END;
$function$
;

CREATE OR REPLACE FUNCTION public.update_xnscore_timestamp()
 RETURNS trigger
 LANGUAGE plpgsql
AS $function$
BEGIN
    NEW.updated_at = now();
    RETURN NEW;
END;
$function$
;

