-- ======================================================================
-- VIEWS
-- ======================================================================

CREATE VIEW public.conflict_prediction_dashboard AS
 SELECT score_date,
    count(*) AS total_pairs_scored,
    count(*) FILTER (WHERE tier = 'compatible'::text) AS compatible_count,
    count(*) FILTER (WHERE tier = 'watch'::text) AS watch_count,
    count(*) FILTER (WHERE tier = 'flag'::text) AS flag_count,
    count(*) FILTER (WHERE tier = 'separate'::text) AS separate_count,
    round(avg(friction_score), 2) AS avg_friction,
    max(friction_score) AS max_friction
   FROM member_pair_scores
  GROUP BY score_date
  ORDER BY score_date DESC;

CREATE VIEW public.intervention_dashboard AS
 SELECT level,
    count(*) AS total_interventions,
    count(*) FILTER (WHERE status = 'paid'::text) AS defaults_prevented,
    count(*) FILTER (WHERE status = 'ignored'::text) AS ignored,
    count(*) FILTER (WHERE status = 'escalated'::text) AS escalated,
    count(*) FILTER (WHERE default_prevented = true) AS success_count,
    count(*) FILTER (WHERE default_prevented = false) AS failure_count,
    round(count(*) FILTER (WHERE default_prevented = true)::numeric / NULLIF(count(*) FILTER (WHERE default_prevented IS NOT NULL), 0)::numeric * 100::numeric, 1) AS success_rate_pct,
    avg(EXTRACT(epoch FROM response_at - sent_at) / 3600::numeric)::numeric(6,1) AS avg_response_hours
   FROM member_interventions
  GROUP BY level
  ORDER BY level;

CREATE VIEW public.migration_summary AS
 SELECT wave,
    count(*) AS total,
    count(*) FILTER (WHERE status = 'mock'::text) AS mock,
    count(*) FILTER (WHERE status = 'in_progress'::text) AS in_progress,
    count(*) FILTER (WHERE status = 'connected'::text) AS connected,
    count(*) FILTER (WHERE status = 'verified'::text) AS verified,
    count(*) FILTER (WHERE status = 'blocked'::text) AS blocked,
    round(count(*) FILTER (WHERE status = ANY (ARRAY['connected'::text, 'verified'::text]))::numeric / NULLIF(count(*), 0)::numeric * 100::numeric, 1) AS completion_pct
   FROM migration_screens
  GROUP BY wave
  ORDER BY wave;

CREATE VIEW public.mood_detection_dashboard AS
 SELECT snapshot_date,
    count(*) AS total_scored,
    count(*) FILTER (WHERE tier = 'stable'::text) AS stable_count,
    count(*) FILTER (WHERE tier = 'drifting'::text) AS drifting_count,
    count(*) FILTER (WHERE tier = 'disengaging'::text) AS disengaging_count,
    count(*) FILTER (WHERE tier = 'at_risk'::text) AS at_risk_count,
    round(avg(composite_mood_score), 2) AS avg_score,
    count(*) FILTER (WHERE intervention_triggered) AS interventions_triggered,
    count(*) FILTER (WHERE trend = 'worsening'::text) AS worsening_count,
    count(*) FILTER (WHERE trend = 'improving'::text) AS improving_count
   FROM member_mood_snapshots
  GROUP BY snapshot_date
  ORDER BY snapshot_date DESC;

CREATE VIEW public.pool_health_dashboard AS
 SELECT pool_name,
    total_capital_cents,
    deployed_cents,
    available_cents,
    reserved_cents,
    utilization_pct,
    is_accepting_requests,
    fees_earned_cents,
    losses_cents,
    total_advances_issued,
    total_advances_repaid,
    total_advances_defaulted,
    default_rate_pct,
    ( SELECT count(*) AS count
           FROM liquidity_advances la
          WHERE la.pool_id = p.id AND (la.status = ANY (ARRAY['disbursed'::text, 'repaying'::text]))) AS active_advances,
    ( SELECT sum(la.disbursed_amount_cents) AS sum
           FROM liquidity_advances la
          WHERE la.pool_id = p.id AND (la.status = ANY (ARRAY['disbursed'::text, 'repaying'::text]))) AS active_deployed_cents,
    ( SELECT count(*) AS count
           FROM liquidity_advances la
          WHERE la.pool_id = p.id AND la.status = 'queued'::text) AS queued_count,
        CASE
            WHEN total_advances_issued > 0 THEN round(fees_earned_cents::numeric / total_advances_issued::numeric, 0)
            ELSE 0::numeric
        END AS avg_fee_per_advance_cents,
        CASE
            WHEN total_capital_cents > 0 THEN round(fees_earned_cents::numeric / total_capital_cents::numeric * 100::numeric, 2)
            ELSE 0::numeric
        END AS return_on_capital_pct
   FROM liquidity_pool p;

CREATE VIEW public.stress_prediction_dashboard AS
 SELECT score_date,
    count(*) AS total_scored,
    count(*) FILTER (WHERE status = 'green'::text) AS green_count,
    count(*) FILTER (WHERE status = 'yellow'::text) AS yellow_count,
    count(*) FILTER (WHERE status = 'orange'::text) AS orange_count,
    count(*) FILTER (WHERE status = 'red'::text) AS red_count,
    round(avg(stress_score), 2) AS avg_score,
    count(*) FILTER (WHERE intervention_triggered) AS interventions_triggered,
    count(*) FILTER (WHERE trend = 'worsening'::text) AS worsening_count,
    count(*) FILTER (WHERE trend = 'improving'::text) AS improving_count
   FROM member_stress_scores
  GROUP BY score_date
  ORDER BY score_date DESC;

CREATE VIEW public.v_active_dissolution_requests AS
 SELECT dr.id,
    dr.circle_id,
    dr.trigger_type,
    dr.status,
    dr.reason,
    dr.evidence_urls,
    dr.initiated_by,
    dr.initiated_by_system,
    dr.voting_starts_at,
    dr.voting_ends_at,
    dr.votes_for,
    dr.votes_against,
    dr.votes_abstain,
    dr.total_eligible_voters,
    dr.objection_window_starts_at,
    dr.objection_window_ends_at,
    dr.objection_count,
    dr.total_pool_amount,
    dr.total_refund_amount,
    dr.platform_fee_amount,
    dr.resolved_at,
    dr.resolved_by,
    dr.resolution_notes,
    dr.metadata,
    dr.created_at,
    dr.updated_at,
    c.name AS circle_name,
    dtc.tier,
    dtc.description AS trigger_description,
        CASE
            WHEN dr.status = 'voting'::dissolution_status THEN dr.voting_ends_at - now()
            WHEN dr.status = 'objection_window'::dissolution_status THEN dr.objection_window_ends_at - now()
            ELSE NULL::interval
        END AS time_remaining,
    ( SELECT count(*) AS count
           FROM dissolution_votes
          WHERE dissolution_votes.dissolution_request_id = dr.id) AS total_votes_cast
   FROM dissolution_requests dr
     JOIN circles c ON c.id = dr.circle_id
     JOIN dissolution_trigger_config dtc ON dtc.trigger_type = dr.trigger_type
  WHERE dr.status <> ALL (ARRAY['completed'::dissolution_status, 'rejected'::dissolution_status, 'cancelled'::dissolution_status]);

CREATE VIEW public.v_active_loans_dashboard AS
 SELECT l.id,
    l.user_id,
    p.full_name,
    lp.name AS product_name,
    l.principal_cents::numeric / 100.0 AS principal,
    l.apr,
    l.outstanding_principal_cents::numeric / 100.0 AS outstanding_principal,
    l.payments_made,
    l.payments_total,
    l.next_payment_date,
    l.next_payment_amount_cents::numeric / 100.0 AS next_payment_amount,
    l.days_past_due,
    l.is_delinquent,
    l.status
   FROM loans l
     JOIN profiles p ON p.id = l.user_id
     JOIN loan_products lp ON lp.id = l.loan_product_id
  WHERE l.status = 'active'::loan_status;

CREATE VIEW public.v_active_removal_requests AS
 SELECT mrr.id,
    mrr.circle_id,
    mrr.member_user_id,
    mrr.reason,
    mrr.reason_details,
    mrr.status,
    mrr.initiated_by,
    mrr.initiated_by_type,
    mrr.is_self_removal,
    mrr.total_contributed,
    mrr.total_received,
    mrr.has_received_payout,
    mrr.member_position,
    mrr.was_current_beneficiary,
    mrr.settlement_type,
    mrr.settlement_amount,
    mrr.exit_fee_amount,
    mrr.debt_amount,
    mrr.requires_vote,
    mrr.voting_starts_at,
    mrr.voting_ends_at,
    mrr.votes_for,
    mrr.votes_against,
    mrr.votes_abstain,
    mrr.grace_period_ends_at,
    mrr.can_be_cancelled_until,
    mrr.resolved_at,
    mrr.resolved_by,
    mrr.resolution_notes,
    mrr.metadata,
    mrr.created_at,
    mrr.updated_at,
    c.name AS circle_name,
    p.full_name AS member_name,
    ip.full_name AS initiated_by_name,
        CASE
            WHEN mrr.requires_vote AND mrr.voting_ends_at IS NOT NULL THEN mrr.voting_ends_at - now()
            ELSE NULL::interval
        END AS voting_time_remaining,
        CASE
            WHEN mrr.grace_period_ends_at IS NOT NULL THEN mrr.grace_period_ends_at - now()
            ELSE NULL::interval
        END AS grace_period_remaining
   FROM member_removal_requests mrr
     JOIN circles c ON c.id = mrr.circle_id
     LEFT JOIN profiles p ON p.id = mrr.member_user_id
     LEFT JOIN profiles ip ON ip.id = mrr.initiated_by
  WHERE mrr.status <> ALL (ARRAY['completed'::removal_status, 'rejected'::removal_status, 'cancelled'::removal_status]);

CREATE VIEW public.v_autopay_queue AS
 SELECT ac.id AS config_id,
    ac.loan_id,
    l.user_id,
    p.full_name,
    ac.autopay_type,
    ac.status,
    ac.next_scheduled_at,
    ac.consecutive_failures,
    o.id AS next_obligation_id,
    o.due_date AS next_due_date,
    o.total_due_cents::numeric / 100.0 AS next_amount_due,
    l.total_outstanding_cents::numeric / 100.0 AS total_outstanding
   FROM loan_autopay_configs ac
     JOIN loans l ON l.id = ac.loan_id
     JOIN profiles p ON p.id = l.user_id
     LEFT JOIN LATERAL ( SELECT loan_payment_obligations.id,
            loan_payment_obligations.loan_id,
            loan_payment_obligations.user_id,
            loan_payment_obligations.obligation_number,
            loan_payment_obligations.period_start_date,
            loan_payment_obligations.period_end_date,
            loan_payment_obligations.due_date,
            loan_payment_obligations.estimated_payment_cents,
            loan_payment_obligations.principal_due_cents,
            loan_payment_obligations.interest_due_cents,
            loan_payment_obligations.fees_due_cents,
            loan_payment_obligations.total_due_cents,
            loan_payment_obligations.principal_paid_cents,
            loan_payment_obligations.interest_paid_cents,
            loan_payment_obligations.fees_paid_cents,
            loan_payment_obligations.total_paid_cents,
            loan_payment_obligations.status,
            loan_payment_obligations.days_overdue,
            loan_payment_obligations.payment_id,
            loan_payment_obligations.paid_at,
            loan_payment_obligations.paid_via,
            loan_payment_obligations.late_fee_id,
            loan_payment_obligations.late_fee_applied,
            loan_payment_obligations.late_fee_cents,
            loan_payment_obligations.xnscore_event_triggered,
            loan_payment_obligations.xnscore_adjustment,
            loan_payment_obligations.notes,
            loan_payment_obligations.created_at,
            loan_payment_obligations.updated_at
           FROM loan_payment_obligations
          WHERE loan_payment_obligations.loan_id = ac.loan_id AND (loan_payment_obligations.status = ANY (ARRAY['upcoming'::obligation_status, 'due'::obligation_status]))
          ORDER BY loan_payment_obligations.due_date
         LIMIT 1) o ON true
  WHERE ac.status = 'active'::autopay_status AND l.status = 'active'::loan_status
  ORDER BY ac.next_scheduled_at;

CREATE VIEW public.v_circle_swap_statistics AS
 SELECT circle_id,
    count(*) AS total_requests,
    count(*) FILTER (WHERE swap_status = 'completed'::swap_request_status) AS completed_swaps,
    count(*) FILTER (WHERE swap_status = 'rejected'::swap_request_status) AS rejected_swaps,
    count(*) FILTER (WHERE swap_status = 'cancelled'::swap_request_status) AS cancelled_swaps,
    count(*) FILTER (WHERE swap_status = 'expired'::swap_request_status) AS expired_swaps,
    avg(EXTRACT(epoch FROM executed_at - created_at) / 3600::numeric) FILTER (WHERE swap_status = 'completed'::swap_request_status) AS avg_completion_hours
   FROM position_swap_requests
  GROUP BY circle_id;

CREATE VIEW public.v_decay_at_risk_users AS
 SELECT xs.user_id,
    p.full_name,
    p.email,
    xs.total_score,
    xs.score_tier,
    xs.financial_inactive_days,
    xs.last_financial_activity_at,
    xs.total_inactivity_penalty,
        CASE
            WHEN xs.financial_inactive_days >= 240 THEN 'critical'::text
            WHEN xs.financial_inactive_days >= 180 THEN 'severe'::text
            WHEN xs.financial_inactive_days >= 120 THEN 'high'::text
            WHEN xs.financial_inactive_days >= 90 THEN 'moderate'::text
            WHEN xs.financial_inactive_days >= 60 THEN 'warning'::text
            WHEN xs.financial_inactive_days >= 30 THEN 'low'::text
            ELSE 'none'::text
        END AS risk_level,
        CASE
            WHEN xs.financial_inactive_days >= 30 AND xs.financial_inactive_days < 60 THEN 60 - xs.financial_inactive_days
            WHEN xs.financial_inactive_days >= 60 AND xs.financial_inactive_days < 90 THEN 90 - xs.financial_inactive_days
            WHEN xs.financial_inactive_days >= 90 AND xs.financial_inactive_days < 120 THEN 120 - xs.financial_inactive_days
            WHEN xs.financial_inactive_days >= 120 AND xs.financial_inactive_days < 180 THEN 180 - xs.financial_inactive_days
            WHEN xs.financial_inactive_days >= 180 AND xs.financial_inactive_days < 240 THEN 240 - xs.financial_inactive_days
            WHEN xs.financial_inactive_days >= 240 AND xs.financial_inactive_days < 365 THEN 365 - xs.financial_inactive_days
            ELSE NULL::integer
        END AS days_until_next_decay,
    get_decay_rate(
        CASE
            WHEN xs.financial_inactive_days < 60 THEN 60
            WHEN xs.financial_inactive_days < 90 THEN 90
            WHEN xs.financial_inactive_days < 120 THEN 120
            WHEN xs.financial_inactive_days < 180 THEN 180
            WHEN xs.financial_inactive_days < 240 THEN 240
            ELSE 365
        END) AS next_decay_amount
   FROM xn_scores xs
     JOIN profiles p ON p.id = xs.user_id
  WHERE xs.financial_inactive_days >= 20 AND xs.score_frozen = false AND xs.total_score > 15::numeric
  ORDER BY xs.financial_inactive_days DESC;

CREATE VIEW public.v_dissolution_analytics AS
 SELECT trigger_type,
    count(*) AS total_requests,
    count(*) FILTER (WHERE status = 'completed'::dissolution_status) AS completed_count,
    count(*) FILTER (WHERE status = 'rejected'::dissolution_status) AS rejected_count,
    count(*) FILTER (WHERE status = 'cancelled'::dissolution_status) AS cancelled_count,
    avg(total_pool_amount) AS avg_pool_amount,
    avg(total_refund_amount) AS avg_refund_amount,
    avg(EXTRACT(epoch FROM resolved_at - created_at) / 3600::numeric) AS avg_resolution_hours
   FROM dissolution_requests
  GROUP BY trigger_type;

CREATE VIEW public.v_factor_performance_summary AS
 SELECT 'payment_reliability'::text AS factor,
    35 AS max_score,
    round(avg(xn_score_breakdown_cache.payment_reliability_score), 2) AS avg_score,
    count(*) FILTER (WHERE xn_score_breakdown_cache.payment_reliability_status = 'excellent'::factor_status) AS excellent_count,
    count(*) FILTER (WHERE xn_score_breakdown_cache.payment_reliability_status = 'good'::factor_status) AS good_count,
    count(*) FILTER (WHERE xn_score_breakdown_cache.payment_reliability_status = 'fair'::factor_status) AS fair_count,
    count(*) FILTER (WHERE xn_score_breakdown_cache.payment_reliability_status = 'needs_work'::factor_status) AS needs_work_count,
    count(*) FILTER (WHERE xn_score_breakdown_cache.payment_reliability_status = 'critical'::factor_status) AS critical_count
   FROM xn_score_breakdown_cache
UNION ALL
 SELECT 'circle_completion'::text AS factor,
    20 AS max_score,
    round(avg(xn_score_breakdown_cache.circle_completion_score), 2) AS avg_score,
    count(*) FILTER (WHERE xn_score_breakdown_cache.circle_completion_status = 'excellent'::factor_status) AS excellent_count,
    count(*) FILTER (WHERE xn_score_breakdown_cache.circle_completion_status = 'good'::factor_status) AS good_count,
    count(*) FILTER (WHERE xn_score_breakdown_cache.circle_completion_status = 'fair'::factor_status) AS fair_count,
    count(*) FILTER (WHERE xn_score_breakdown_cache.circle_completion_status = 'needs_work'::factor_status) AS needs_work_count,
    count(*) FILTER (WHERE xn_score_breakdown_cache.circle_completion_status = 'critical'::factor_status) AS critical_count
   FROM xn_score_breakdown_cache
UNION ALL
 SELECT 'tenure_activity'::text AS factor,
    15 AS max_score,
    round(avg(xn_score_breakdown_cache.tenure_activity_score), 2) AS avg_score,
    count(*) FILTER (WHERE xn_score_breakdown_cache.tenure_activity_status = 'excellent'::factor_status) AS excellent_count,
    count(*) FILTER (WHERE xn_score_breakdown_cache.tenure_activity_status = 'good'::factor_status) AS good_count,
    count(*) FILTER (WHERE xn_score_breakdown_cache.tenure_activity_status = 'fair'::factor_status) AS fair_count,
    count(*) FILTER (WHERE xn_score_breakdown_cache.tenure_activity_status = 'needs_work'::factor_status) AS needs_work_count,
    count(*) FILTER (WHERE xn_score_breakdown_cache.tenure_activity_status = 'critical'::factor_status) AS critical_count
   FROM xn_score_breakdown_cache
UNION ALL
 SELECT 'community_standing'::text AS factor,
    15 AS max_score,
    round(avg(xn_score_breakdown_cache.community_standing_score), 2) AS avg_score,
    count(*) FILTER (WHERE xn_score_breakdown_cache.community_standing_status = 'excellent'::factor_status) AS excellent_count,
    count(*) FILTER (WHERE xn_score_breakdown_cache.community_standing_status = 'good'::factor_status) AS good_count,
    count(*) FILTER (WHERE xn_score_breakdown_cache.community_standing_status = 'fair'::factor_status) AS fair_count,
    count(*) FILTER (WHERE xn_score_breakdown_cache.community_standing_status = 'needs_work'::factor_status) AS needs_work_count,
    count(*) FILTER (WHERE xn_score_breakdown_cache.community_standing_status = 'critical'::factor_status) AS critical_count
   FROM xn_score_breakdown_cache
UNION ALL
 SELECT 'financial_behavior'::text AS factor,
    15 AS max_score,
    round(avg(xn_score_breakdown_cache.financial_behavior_score), 2) AS avg_score,
    count(*) FILTER (WHERE xn_score_breakdown_cache.financial_behavior_status = 'excellent'::factor_status) AS excellent_count,
    count(*) FILTER (WHERE xn_score_breakdown_cache.financial_behavior_status = 'good'::factor_status) AS good_count,
    count(*) FILTER (WHERE xn_score_breakdown_cache.financial_behavior_status = 'fair'::factor_status) AS fair_count,
    count(*) FILTER (WHERE xn_score_breakdown_cache.financial_behavior_status = 'needs_work'::factor_status) AS needs_work_count,
    count(*) FILTER (WHERE xn_score_breakdown_cache.financial_behavior_status = 'critical'::factor_status) AS critical_count
   FROM xn_score_breakdown_cache;

CREATE VIEW public.v_guarantor_exposure AS
 SELECT g.guarantor_user_id,
    p.full_name AS guarantor_name,
    count(*) FILTER (WHERE g.status = 'active'::guarantee_status) AS active_guarantees,
    sum(g.max_liability_cents) FILTER (WHERE g.status = 'active'::guarantee_status)::numeric / 100.0 AS total_liability,
    500000::numeric / 100.0 - COALESCE(sum(g.max_liability_cents) FILTER (WHERE g.status = 'active'::guarantee_status), 0::bigint)::numeric / 100.0 AS remaining_capacity
   FROM loan_guarantees g
     JOIN profiles p ON p.id = g.guarantor_user_id
  GROUP BY g.guarantor_user_id, p.full_name;

CREATE VIEW public.v_improvement_opportunities AS
 SELECT c.user_id,
    p.full_name,
    xs.total_score,
    xs.score_tier,
    tip.value ->> 'factor'::text AS factor,
    tip.value ->> 'title'::text AS tip_title,
    tip.value ->> 'priority'::text AS priority,
    (tip.value ->> 'potential_points'::text)::numeric AS potential_points
   FROM xn_score_breakdown_cache c
     JOIN profiles p ON p.id = c.user_id
     JOIN xn_scores xs ON xs.user_id = c.user_id,
    LATERAL jsonb_array_elements(c.improvement_tips) tip(value)
  ORDER BY c.user_id, ((tip.value ->> 'potential_points'::text)::numeric) DESC;

CREATE VIEW public.v_interest_accrual_audit AS
 SELECT lia.id,
    lia.loan_id,
    l.user_id,
    lia.accrual_date,
    lia.days_in_period,
    lia.principal_balance_cents::numeric / 100.0 AS principal_balance,
    lia.rate_type,
    lia.annual_rate * 100::numeric AS annual_rate_percent,
    lia.interest_accrued_cents::numeric / 100.0 AS interest_accrued,
    lia.triggered_by,
    lia.created_at
   FROM loan_interest_accruals lia
     JOIN loans l ON l.id = lia.loan_id
  ORDER BY lia.created_at DESC;

CREATE VIEW public.v_loan_interest_summary AS
 SELECT l.id AS loan_id,
    l.user_id,
    p.full_name,
    l.principal_cents::numeric / 100.0 AS principal,
    l.outstanding_principal_cents::numeric / 100.0 AS outstanding_principal,
    l.interest_rate_type,
    l.apr,
    COALESCE(l.accrued_interest_cents, 0)::numeric / 100.0 AS accrued_interest,
    COALESCE(l.total_interest_paid_cents, 0)::numeric / 100.0 AS total_interest_paid,
    l.last_interest_accrual_date,
    l.promotional_rate,
    l.promotional_rate_end_date,
    l.status
   FROM loans l
     JOIN profiles p ON p.id = l.user_id;

CREATE VIEW public.v_loan_portfolio_summary AS
 SELECT lp.name AS product_name,
    count(*) AS total_loans,
    count(*) FILTER (WHERE l.status = 'active'::loan_status) AS active_loans,
    count(*) FILTER (WHERE l.status = 'paid_off'::loan_status) AS paid_off_loans,
    count(*) FILTER (WHERE l.status = 'defaulted'::loan_status) AS defaulted_loans,
    sum(l.principal_cents)::numeric / 100.0 AS total_principal,
    sum(l.outstanding_principal_cents) FILTER (WHERE l.status = 'active'::loan_status)::numeric / 100.0 AS outstanding_principal,
    avg(l.apr) AS avg_apr,
    count(*) FILTER (WHERE l.is_delinquent) AS delinquent_count
   FROM loans l
     JOIN loan_products lp ON lp.id = l.loan_product_id
  GROUP BY lp.name;

CREATE VIEW public.v_member_dissolution_summary AS
 SELECT dmp.user_id,
    dr.id AS dissolution_id,
    dr.circle_id,
    c.name AS circle_name,
    dr.trigger_type,
    dr.status,
    dmp.total_contributed,
    dmp.total_received,
    dmp.net_position,
    dmp.calculated_refund,
    dmp.adjusted_refund,
    dmp.refund_status,
    dmp.xn_score_change,
    dv.vote AS user_vote
   FROM dissolution_member_positions dmp
     JOIN dissolution_requests dr ON dr.id = dmp.dissolution_request_id
     JOIN circles c ON c.id = dr.circle_id
     LEFT JOIN dissolution_votes dv ON dv.dissolution_request_id = dr.id AND dv.user_id = dmp.user_id;

CREATE VIEW public.v_money_retention_stats AS
 SELECT 'platform'::text AS scope,
    count(DISTINCT user_id) AS total_users,
    sum(total_payouts_received_cents) / 100.0 AS total_payouts,
    sum(total_withdrawals_cents) / 100.0 AS total_withdrawals,
    sum(total_balance_cents) / 100.0 AS current_balances,
    round(avg(money_retention_rate) * 100::numeric, 2) AS avg_retention_rate
   FROM user_wallets w
  WHERE total_payouts_received_cents > 0;

CREATE VIEW public.v_monthly_payment_dashboard AS
 SELECT o.id AS obligation_id,
    o.loan_id,
    o.user_id,
    p.full_name,
    o.obligation_number,
    o.due_date,
    o.due_date - CURRENT_DATE AS days_until_due,
    o.total_due_cents::numeric / 100.0 AS total_due,
    o.total_paid_cents::numeric / 100.0 AS total_paid,
    (o.total_due_cents - o.total_paid_cents)::numeric / 100.0 AS remaining,
    o.status,
    o.late_fee_cents::numeric / 100.0 AS late_fee,
    l.autopay_enabled,
    ac.autopay_type,
    ac.status AS autopay_status
   FROM loan_payment_obligations o
     JOIN loans l ON l.id = o.loan_id
     JOIN profiles p ON p.id = o.user_id
     LEFT JOIN loan_autopay_configs ac ON ac.loan_id = o.loan_id
  WHERE o.status = ANY (ARRAY['upcoming'::obligation_status, 'due'::obligation_status, 'overdue'::obligation_status, 'partial'::obligation_status])
  ORDER BY o.due_date;

CREATE VIEW public.v_obligation_summary AS
 SELECT l.id AS loan_id,
    l.user_id,
    l.estimated_monthly_payment_cents::numeric / 100.0 AS monthly_payment,
    l.payment_day_of_month,
    l.autopay_enabled,
    count(o.id) AS total_obligations,
    count(o.id) FILTER (WHERE o.status = 'paid'::obligation_status) AS paid_count,
    count(o.id) FILTER (WHERE o.status = ANY (ARRAY['overdue'::obligation_status, 'partial'::obligation_status])) AS overdue_count,
    COALESCE(sum(o.total_due_cents), 0::bigint)::numeric / 100.0 AS total_due,
    COALESCE(sum(o.total_paid_cents), 0::bigint)::numeric / 100.0 AS total_paid,
    COALESCE(sum(o.late_fee_cents), 0::bigint)::numeric / 100.0 AS total_late_fees
   FROM loans l
     LEFT JOIN loan_payment_obligations o ON o.loan_id = l.id
  WHERE l.status = 'active'::loan_status
  GROUP BY l.id;

CREATE VIEW public.v_overdue_payments_dashboard AS
 SELECT ps.id AS schedule_id,
    ps.loan_id,
    l.user_id,
    p.full_name,
    ps.payment_number,
    ps.due_date,
    CURRENT_DATE - ps.due_date AS days_overdue,
    ps.total_due_cents::numeric / 100.0 AS amount_due,
    ps.total_paid_cents::numeric / 100.0 AS amount_paid,
    (ps.total_due_cents - ps.total_paid_cents)::numeric / 100.0 AS remaining_due,
    ps.status,
    ps.late_fee_applied,
    COALESCE(lf.calculated_fee_cents, 0)::numeric / 100.0 AS late_fee
   FROM loan_payment_schedule ps
     JOIN loans l ON l.id = ps.loan_id
     JOIN profiles p ON p.id = l.user_id
     LEFT JOIN loan_late_fees lf ON lf.scheduled_payment_id = ps.id
  WHERE (ps.status = ANY (ARRAY['scheduled'::payment_schedule_status, 'partial'::payment_schedule_status, 'late'::payment_schedule_status])) AND ps.due_date < CURRENT_DATE
  ORDER BY (CURRENT_DATE - ps.due_date) DESC;

CREATE VIEW public.v_payment_reminders_due AS
 SELECT r.id AS reminder_id,
    r.loan_id,
    r.user_id,
    p.full_name,
    p.email,
    r.reminder_type,
    r.channel,
    r.scheduled_for,
    r.title,
    r.message,
    r.amount_due_cents::numeric / 100.0 AS amount_due,
    r.due_date,
    r.status
   FROM loan_payment_reminders r
     JOIN profiles p ON p.id = r.user_id
  WHERE r.status = 'scheduled'::reminder_status AND r.scheduled_for <= now()
  ORDER BY r.scheduled_for;

CREATE VIEW public.v_payout_analytics AS
 SELECT date_trunc('week'::text, created_at) AS week,
    count(*) AS total_payouts,
    sum(net_amount_cents) / 100.0 AS total_amount,
    sum(platform_fee_cents) / 100.0 AS total_fees,
    sum(COALESCE((distribution ->> 'to_wallet'::text)::bigint, 0::bigint)) / 100.0 AS amount_to_wallets,
    sum(COALESCE(((distribution -> 'to_bank'::text) ->> 'amount_cents'::text)::bigint, 0::bigint)) / 100.0 AS amount_to_banks,
    count(*) FILTER (WHERE (distribution ->> 'to_bank'::text) IS NULL OR (distribution -> 'to_bank'::text) IS NULL) AS wallet_only_payouts,
    count(*) FILTER (WHERE (distribution ->> 'to_bank'::text) IS NOT NULL AND (distribution -> 'to_bank'::text) IS NOT NULL) AS external_payouts
   FROM payout_executions pe
  WHERE execution_status = 'completed'::text AND created_at >= (now() - '90 days'::interval)
  GROUP BY (date_trunc('week'::text, created_at))
  ORDER BY (date_trunc('week'::text, created_at)) DESC;

CREATE VIEW public.v_recovery_period_users AS
 SELECT xs.user_id,
    p.full_name,
    p.email,
    xs.total_score,
    xs.in_recovery_period,
    xs.recovery_ends_at,
    xs.recovery_multiplier,
    rp.trigger_type,
    rp.started_at AS recovery_started,
    rp.score_at_start,
    rp.decay_total_before_recovery,
    rp.bonus_events_during_recovery,
    rp.total_bonus_earned_during,
    EXTRACT(day FROM xs.recovery_ends_at - now())::integer AS days_remaining
   FROM xn_scores xs
     JOIN profiles p ON p.id = xs.user_id
     LEFT JOIN xnscore_recovery_periods rp ON rp.id = xs.recovery_period_id
  WHERE xs.in_recovery_period = true AND xs.recovery_ends_at > now()
  ORDER BY xs.recovery_ends_at;

CREATE VIEW public.v_removal_statistics AS
 SELECT reason,
    count(*) AS total_removals,
    count(*) FILTER (WHERE status = 'completed'::removal_status) AS completed_count,
    count(*) FILTER (WHERE status = 'rejected'::removal_status) AS rejected_count,
    avg(settlement_amount) AS avg_settlement_amount,
    avg(exit_fee_amount) AS avg_exit_fee,
    avg(debt_amount) FILTER (WHERE debt_amount > 0::numeric) AS avg_debt_created
   FROM member_removal_requests
  GROUP BY reason;

CREATE VIEW public.v_swap_history_summary AS
 SELECT msh.id,
    msh.user_id,
    msh.circle_id,
    msh.swap_request_id,
    msh.swap_role,
    msh.old_position,
    msh.new_position,
    msh.swap_partner_id,
    msh.was_generous,
    msh.xn_score_impact,
    msh.cycle_number,
    msh.created_at,
    c.name AS circle_name,
    p.full_name AS partner_name,
        CASE
            WHEN msh.old_position < msh.new_position THEN 'gave_up_earlier'::text
            ELSE 'received_earlier'::text
        END AS swap_direction
   FROM member_swap_history msh
     JOIN circles c ON c.id = msh.circle_id
     JOIN profiles p ON p.id = msh.swap_partner_id;

CREATE VIEW public.v_swap_requests_full AS
 SELECT psr.id,
    psr.circle_id,
    psr.requester_user_id,
    psr.requester_position,
    psr.requester_xn_score,
    psr.target_user_id,
    psr.target_position,
    psr.target_xn_score,
    psr.request_reason,
    psr.swap_status,
    psr.target_accepted_at,
    psr.target_response_reason,
    psr.requester_confirmed_at,
    psr.requester_confirmation_reason,
    psr.elder_approved_by,
    psr.elder_decision_at,
    psr.elder_decision_reason,
    psr.expires_at,
    psr.cooling_off_ends_at,
    psr.swap_fee_amount,
    psr.swap_fee_paid_by,
    psr.executed_at,
    psr.executed_by_system,
    psr.cycle_number,
    psr.metadata,
    psr.created_at,
    psr.updated_at,
    c.name AS circle_name,
    rp.full_name AS requester_name,
    tp.full_name AS target_name,
    ep.full_name AS elder_name,
        CASE
            WHEN psr.expires_at > now() THEN psr.expires_at - now()
            ELSE NULL::interval
        END AS time_remaining,
        CASE
            WHEN psr.swap_status = 'pending_confirmation'::swap_request_status AND psr.cooling_off_ends_at > now() THEN psr.cooling_off_ends_at - now()
            ELSE NULL::interval
        END AS cooling_off_remaining
   FROM position_swap_requests psr
     JOIN circles c ON c.id = psr.circle_id
     JOIN profiles rp ON rp.id = psr.requester_user_id
     JOIN profiles tp ON tp.id = psr.target_user_id
     LEFT JOIN profiles ep ON ep.id = psr.elder_approved_by;

CREATE VIEW public.v_tenure_eligible_users AS
 SELECT xs.user_id,
    p.full_name,
    p.email,
    xs.total_score,
    xs.tenure_bonus,
    xs.tenure_months_earned,
    EXTRACT(month FROM age(now(), p.created_at))::integer + EXTRACT(year FROM age(now(), p.created_at))::integer * 12 AS account_months,
    25::numeric - COALESCE(xs.tenure_bonus, 0::numeric) AS remaining_tenure_bonus,
    xs.next_tenure_check_date,
    xs.contributions_this_month,
        CASE
            WHEN xs.contributions_this_month > 0 THEN true
            ELSE false
        END AS active_this_month
   FROM xn_scores xs
     JOIN profiles p ON p.id = xs.user_id
  WHERE COALESCE(xs.tenure_bonus, 0::numeric) < 25::numeric AND xs.score_frozen = false
  ORDER BY xs.tenure_months_earned DESC, xs.total_score DESC;

CREATE VIEW public.v_user_debts AS
 SELECT md.id,
    md.user_id,
    md.circle_id,
    md.original_default_id,
    md.amount,
    md.reason,
    md.amount_paid,
    md.debt_status,
    md.created_at,
    md.updated_at,
    c.name AS circle_name,
    ( SELECT count(*) AS count
           FROM debt_payments
          WHERE debt_payments.debt_id = md.id) AS total_payments,
    ( SELECT COALESCE(sum(debt_payments.amount), 0::numeric) AS "coalesce"
           FROM debt_payments
          WHERE debt_payments.debt_id = md.id AND debt_payments.payment_status = 'completed'::text) AS total_paid
   FROM member_debts md
     JOIN circles c ON c.id = md.circle_id;

CREATE VIEW public.v_user_xnscore_details AS
 SELECT xs.id,
    xs.user_id,
    xs.total_score,
    xs.raw_score,
    xs.previous_score,
    xs.score_tier,
    xs.payment_history_score,
    xs.completion_score,
    xs.time_reliability_score,
    xs.deposit_score,
    xs.diversity_social_score,
    xs.engagement_score,
    xs.initial_score,
    xs.initial_score_breakdown,
    xs.initial_calculated_at,
    xs.age_cap_applied,
    xs.max_allowed_score,
    xs.account_age_days,
    xs.points_gained_this_week,
    xs.week_start_date,
    xs.velocity_warnings,
    xs.first_circle_bonus_applied,
    xs.first_circle_bonus_date,
    xs.voucher_reliability,
    xs.total_vouchee_defaults,
    xs.on_time_payment_pct,
    xs.payment_streak,
    xs.best_payment_streak,
    xs.has_defaults,
    xs.default_count,
    xs.completion_rate,
    xs.full_cycles_completed,
    xs.circles_participated,
    xs.circles_abandoned,
    xs.unique_circle_members_count,
    xs.unique_elders_count,
    xs.unique_communities_count,
    xs.active_months,
    xs.last_activity_at,
    xs.consecutive_inactive_days,
    xs.last_calculated_at,
    xs.next_review_date,
    xs.calculation_trigger,
    xs.is_repeat_offender,
    xs.has_active_restrictions,
    xs.manual_adjustment_applied,
    xs.score_frozen,
    xs.score_frozen_reason,
    xs.created_at,
    xs.updated_at,
    p.full_name,
    p.email,
    p.avatar_url,
    p.created_at AS account_created_at,
    sis.raw_initial_score,
    sis.capped_initial_score,
    sis.inviter_user_id,
    sis.inviter_xnscore_at_invite,
    ( SELECT count(*) AS count
           FROM vouches
          WHERE vouches.vouchee_user_id = xs.user_id AND vouches.vouch_status = 'active'::vouch_status) AS active_vouches_received,
    ( SELECT count(*) AS count
           FROM vouches
          WHERE vouches.voucher_user_id = xs.user_id AND vouches.vouch_status = 'active'::vouch_status) AS active_vouches_given,
        CASE
            WHEN xs.score_tier = 'elite'::xnscore_tier THEN '⭐'::text
            WHEN xs.score_tier = 'excellent'::xnscore_tier THEN '🏆'::text
            WHEN xs.score_tier = 'good'::xnscore_tier THEN '✓'::text
            WHEN xs.score_tier = 'fair'::xnscore_tier THEN '⚠️'::text
            WHEN xs.score_tier = 'poor'::xnscore_tier THEN '⚡'::text
            ELSE '🚫'::text
        END AS tier_emoji
   FROM xn_scores xs
     JOIN profiles p ON p.id = xs.user_id
     LEFT JOIN xnscore_initial_signals sis ON sis.user_id = xs.user_id;

CREATE VIEW public.v_xnscore_activity_summary AS
 SELECT xs.user_id,
    p.full_name,
    xs.total_score,
    xs.score_tier,
    xs.last_financial_activity_at,
    xs.last_contribution_at,
    xs.last_payout_received_at,
    xs.last_wallet_deposit_at,
    xs.last_savings_activity_at,
    xs.financial_inactive_days,
    xs.total_inactivity_penalty,
    xs.decay_floor_reached,
    xs.tenure_bonus,
    xs.tenure_months_earned,
    xs.in_recovery_period,
    xs.recovery_ends_at,
    xs.recovery_multiplier,
    xs.contributions_this_month,
    xs.on_time_payments_this_month,
        CASE
            WHEN xs.score_frozen THEN 'frozen'::text
            WHEN xs.in_recovery_period THEN 'recovering'::text
            WHEN xs.financial_inactive_days >= 90 THEN 'at_risk'::text
            WHEN xs.financial_inactive_days >= 30 THEN 'inactive'::text
            ELSE 'active'::text
        END AS activity_status
   FROM xn_scores xs
     JOIN profiles p ON p.id = xs.user_id;

CREATE VIEW public.v_xnscore_leaderboard AS
 SELECT xs.user_id,
    p.full_name,
    p.avatar_url,
    xs.total_score,
    xs.score_tier,
    xs.full_cycles_completed,
    xs.on_time_payment_pct,
    xs.payment_streak,
    rank() OVER (ORDER BY xs.total_score DESC) AS rank
   FROM xn_scores xs
     JOIN profiles p ON p.id = xs.user_id
  WHERE xs.score_frozen = false
  ORDER BY xs.total_score DESC;

CREATE VIEW public.v_xnscore_tier_distribution AS
 SELECT score_tier,
    count(*) AS user_count,
    round(avg(total_score), 2) AS avg_score,
    round(avg(account_age_days), 0) AS avg_account_age_days,
    round(avg(full_cycles_completed), 1) AS avg_cycles_completed
   FROM xn_scores
  GROUP BY score_tier
  ORDER BY (
        CASE score_tier
            WHEN 'elite'::xnscore_tier THEN 1
            WHEN 'excellent'::xnscore_tier THEN 2
            WHEN 'good'::xnscore_tier THEN 3
            WHEN 'fair'::xnscore_tier THEN 4
            WHEN 'poor'::xnscore_tier THEN 5
            WHEN 'critical'::xnscore_tier THEN 6
            ELSE NULL::integer
        END);

